def ensure_tesseract_installed():
    """Check and install Tesseract OCR if not available"""
    if shutil.which('tesseract') is None:
        logging.warning("⚠️ Tesseract OCR not found. Attempting to install...")
        try:
            subprocess.run(
                ['apt-get', 'update', '-qq'],
                check=True, capture_output=True, timeout=60
            )
            subprocess.run(
                ['apt-get', 'install', '-y', '-qq', 'tesseract-ocr', 'tesseract-ocr-spa', 'tesseract-ocr-eng', 'poppler-utils'],
                check=True, capture_output=True, timeout=120
            )
            logging.info("✅ Tesseract OCR installed successfully")
        except Exception as e:
            logging.error(f"❌ Failed to install Tesseract: {e}")
            logging.warning("OCR functionality for images will be limited")
    else:
        logging.info(f"✅ Tesseract OCR available at: {shutil.which('tesseract')}")

# Run check at startup
ensure_tesseract_installed()

