class _OpenAIClientProxy:
    """
    Thin proxy over AsyncOpenAI that injects the `openai/` model prefix when
    routing through OpenRouter (which requires `vendor/model` format). Pass-through
    for all other attributes/methods.
    """

    def __init__(self, real, route_to_openrouter: bool):
        self._real = real
        self._route = route_to_openrouter

    def __getattr__(self, name):
        return getattr(self._real, name)

    @property
    def chat(self):
        if not self._route:
            return self._real.chat

        outer_real = self._real

        class _Completions:
            async def create(self, *args, **kwargs):
                model = kwargs.get("model")
                if model and "/" not in model:
                    kwargs["model"] = f"openai/{model}"
                return await outer_real.chat.completions.create(*args, **kwargs)

        class _Chat:
            completions = _Completions()

        return _Chat()


openai_client = _OpenAIClientProxy(_real_openai_client, _use_openrouter)

