# Helper function for fast document processing with GPT-4o-mini
async def call_openai_mini(system_message: str, user_message: str, temperature: float = 0.3, max_tokens: int = 2000, timeout: int = 60) -> str:
    """
    Fast helper function using GPT-4o for document processing tasks
    10-20x faster and 60x cheaper than GPT-5
    Perfect for: CV analysis, document extraction, simple summaries
    
    Args:
        timeout: Maximum seconds to wait for response (default: 60, increased for larger requests)
    """
    try:
        logging.info(f"🔧 [call_openai_mini] Starting GPT-4o call")
        logging.info(f"📤 [call_openai_mini] Params: temp={temperature}, max_tokens={max_tokens}, timeout={timeout}s")
        logging.info(f"📊 [call_openai_mini] System msg: {len(system_message)} chars")
        logging.info(f"📊 [call_openai_mini] User msg: {len(user_message)} chars")
        
        logging.info(f"⏱️  [call_openai_mini] Initiating OpenAI API call...")
        response = await asyncio.wait_for(
            openai_client.chat.completions.create(
                model="gpt-4o",  # Fast model - universally available
                messages=[
                    {"role": "system", "content": system_message},
                    {"role": "user", "content": user_message}
                ],
                temperature=temperature,
                max_tokens=max_tokens
                # Note: timeout is controlled by asyncio.wait_for and httpx client timeout
            ),
            timeout=timeout + 5  # asyncio timeout (slightly longer than expected)
        )
        
        logging.info(f"✅ [call_openai_mini] API call completed successfully")
        
        # Log and track token usage
        if hasattr(response, 'usage') and response.usage:
            token_usage_tracker['total_prompt_tokens'] += response.usage.prompt_tokens
            token_usage_tracker['total_completion_tokens'] += response.usage.completion_tokens
            token_usage_tracker['total_tokens'] += response.usage.total_tokens
            token_usage_tracker['call_count'] += 1
            
            logging.info(f"💰 [call_openai_mini] Tokens: Prompt={response.usage.prompt_tokens}, Completion={response.usage.completion_tokens}, Total={response.usage.total_tokens}")
        
        content = response.choices[0].message.content
        finish_reason = response.choices[0].finish_reason
        
        logging.info(f"📥 [call_openai_mini] Response: {len(content)} chars, finish_reason={finish_reason}")
        
        return clean_content(content) if content else ""
        
    except asyncio.TimeoutError as e:
        logging.error(f"❌ [call_openai_mini] AsyncIO Timeout after {timeout}s")
        logging.error(f"   System msg length: {len(system_message)}")
        logging.error(f"   User msg length: {len(user_message)}")
        raise HTTPException(status_code=500, detail=f"Request timeout after {timeout}s")
    except Exception as e:
        logging.error(f"❌ [call_openai_mini] OpenAI GPT-4o API error: {e}")
        logging.error(f"   Error type: {type(e).__name__}")
        logging.error(f"   Error str: '{str(e)}'")
        logging.error(f"   Error repr: {repr(e)}")
        
        # Extract detailed error information
        error_detail = str(e) if str(e) else f"{type(e).__name__}: No error message"
        
        if hasattr(e, 'message'):
            logging.error(f"   Error.message: {e.message}")
            error_detail = e.message
        if hasattr(e, 'response'):
            logging.error(f"   Error.response: {e.response}")
        if hasattr(e, 'status_code'):
            logging.error(f"   Error.status_code: {e.status_code}")
        
        raise HTTPException(status_code=500, detail=f"Error calling OpenAI API: {error_detail}")

def update_token_usage(prompt_tokens: int, completion_tokens: int):
    """Update global token usage tracker"""
    token_usage_tracker['total_prompt_tokens'] += prompt_tokens
    token_usage_tracker['total_completion_tokens'] += completion_tokens
    token_usage_tracker['total_tokens'] += prompt_tokens + completion_tokens
    token_usage_tracker['call_count'] += 1

# Helper function for OpenAI GPT-4o calls (faster alternative)


# Helper function for OpenAI GPT-5.1 calls (slower but higher quality)


async def call_openai_gpt4o(system_message: str, user_message: str, temperature: float = 0.7, max_tokens: int = 4000) -> str:
    """Helper function to call OpenAI GPT-4o API with retry/backoff + OpenRouter fallback.

    Handles:
    - 429 Rate Limit (Too Many Requests) with exponential backoff
    - 5xx transient errors
    - Falls back to OpenRouter (openai/gpt-4o, anthropic/claude-sonnet, gemini) if OpenAI keeps failing
    - Strips markdown code-fence wrappers (```lang ... ```) that some LLMs (esp. Claude) add around entire responses
    """
    import httpx as _httpx
    import re as _re

    def _strip_outer_fences(text: str) -> str:
        """Remove accidental ```lang ... ``` wrappers around the ENTIRE LLM response.
        Does NOT touch inline/legitimate code blocks in the middle of content."""
        if not text:
            return text
        t = text.strip()
        # Full wrap: ```<lang>\n ... \n```
        m = _re.match(r'^```[a-zA-Z0-9_\-]*\s*\n(.*?)\n?```\s*$', t, flags=_re.DOTALL)
        if m:
            return m.group(1).strip()
        # Dangling leading fence only
        t = _re.sub(r'^```[a-zA-Z0-9_\-]*\s*\n', '', t)
        # Dangling trailing fence only
        t = _re.sub(r'\n```\s*$', '', t)
        return t.strip()

    logging.info(f"🔧 Calling GPT-4o with temp={temperature}, max_tokens={max_tokens}")
    logging.info(f"📤 System message length: {len(system_message)} chars")
    logging.info(f"📤 User message length: {len(user_message)} chars")

    # 1. Try OpenAI GPT-4o directly with retry + exponential backoff on 429/5xx
    last_error = None
    for attempt in range(3):
        try:
            response = await openai_client.chat.completions.create(
                model="gpt-4o",
                messages=[
                    {"role": "system", "content": system_message},
                    {"role": "user", "content": user_message}
                ],
                temperature=temperature,
                max_tokens=max_tokens
            )
            content = response.choices[0].message.content
            finish_reason = response.choices[0].finish_reason

            if hasattr(response, 'usage') and response.usage:
                token_usage_tracker['total_prompt_tokens'] += response.usage.prompt_tokens
                token_usage_tracker['total_completion_tokens'] += response.usage.completion_tokens
                token_usage_tracker['total_tokens'] += response.usage.total_tokens
                logging.info(f"📊 Token usage - Input: {response.usage.prompt_tokens}, Output: {response.usage.completion_tokens}, Total: {response.usage.total_tokens}")

            logging.info(f"✅ GPT-4o response received. Finish reason: {finish_reason}. Content length: {len(content) if content else 0}")

            if finish_reason == 'length':
                logging.error(f"⚠️ CRITICAL: GPT-4o response was truncated due to max_tokens limit ({max_tokens})")

            return _strip_outer_fences(content) if content else ""
        except Exception as e:
            last_error = e
            err_str = str(e)
            err_lower = err_str.lower()
            is_rate_limit = ('429' in err_str or 'rate limit' in err_lower or 'rate_limit' in err_lower or 'quota' in err_lower)
            is_transient = is_rate_limit or '503' in err_str or '502' in err_str or '500' in err_str or 'timeout' in err_lower

            if is_transient and attempt < 2:
                wait_s = (2 ** attempt) * 3  # 3s, 6s
                logging.warning(f"⚠️ GPT-4o {'rate-limited (429)' if is_rate_limit else 'transient error'} on attempt {attempt+1}/3: {err_str[:150]}. Retrying in {wait_s}s...")
                await asyncio.sleep(wait_s)
                continue
            # Not retryable or out of attempts -> break to OpenRouter fallback
            logging.warning(f"⚠️ GPT-4o failed after {attempt+1} attempts: {err_str[:200]}. Trying OpenRouter fallback...")
            break

    # 2. Fallback: OpenRouter (equivalent GPT-4o, then Claude Sonnet, then Gemini Pro)
    openrouter_key = os.environ.get('OPENROUTER_API_KEY')
    if openrouter_key:
        OR_HEADERS = {
            "Authorization": f"Bearer {openrouter_key}",
            "Content-Type": "application/json",
            "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
            "X-Title": "Monica Document Generator",
        }
        # Refusal patterns that indicate the model declined to answer.
        # If any of these match the start of the response (first 200 chars),
        # treat as failure and try the next model.
        _REFUSAL_PATTERNS = (
            "i'm sorry, but i can't",
            "i'm sorry, i can't",
            "i cannot assist",
            "i can't assist",
            "i am unable to",
            "i'm unable to",
            "lo siento, no puedo",
            "no puedo asistir",
            "i must decline",
            "as an ai",
        )
        for model_id in ["openai/gpt-4o", "anthropic/claude-sonnet-4.5", "google/gemini-2.5-pro"]:
            try:
                logging.warning(f"🔄 GPT-4o fallback → {model_id} via OpenRouter...")
                async with _httpx.AsyncClient(timeout=180.0) as client:
                    resp = await client.post(
                        "https://openrouter.ai/api/v1/chat/completions",
                        headers=OR_HEADERS,
                        json={
                            "model": model_id,
                            "messages": [
                                {"role": "system", "content": system_message},
                                {"role": "user", "content": user_message}
                            ],
                            "temperature": temperature,
                            "max_tokens": max_tokens
                        }
                    )
                if resp.status_code == 200:
                    data = resp.json()
                    content = data['choices'][0]['message']['content']
                    if content and len(content.strip()) > 0:
                        # Detect refusal responses (common when Claude/Gemini decline a prompt)
                        first_chars = content.strip().lower()[:200]
                        if any(p in first_chars for p in _REFUSAL_PATTERNS) and len(content.strip()) < 500:
                            logging.warning(f"⚠️ {model_id} refused to answer: '{content.strip()[:120]}...' — trying next fallback model")
                            continue
                        logging.warning(f"✅ {model_id} OK via OpenRouter ({len(content)} chars)")
                        return _strip_outer_fences(content)
                    logging.warning(f"⚠️ {model_id} returned empty content, trying next fallback")
                else:
                    logging.warning(f"⚠️ {model_id} HTTP {resp.status_code}: {resp.text[:200]}")
            except Exception as or_err:
                logging.warning(f"⚠️ {model_id} via OpenRouter failed: {str(or_err)[:200]}")
                continue

    # 3. All attempts exhausted
    logging.error(f"❌ GPT-4o + all OpenRouter fallbacks failed. Last error: {str(last_error)[:300] if last_error else 'unknown'}")
    raise last_error if last_error else Exception("GPT-4o and OpenRouter fallbacks all failed")


async def call_openai_gpt4o_vision(messages: list, max_tokens: int = 2000, temperature: float = 0.1) -> str:
    """Vision-capable GPT-4o helper with 429 retry + OpenRouter fallback.
    
    Accepts pre-built `messages` (list of dicts with multimodal content) to support
    image_url payloads. Fallback chain: OpenAI gpt-4o → OpenRouter openai/gpt-4o →
    OpenRouter google/gemini-2.5-pro (both support vision).
    """
    import httpx as _httpx
    last_error = None
    # 1. Try OpenAI GPT-4o Vision directly with retry on 429/5xx
    for attempt in range(3):
        try:
            response = await openai_client.chat.completions.create(
                model="gpt-4o",
                messages=messages,
                max_tokens=max_tokens,
                temperature=temperature
            )
            content = response.choices[0].message.content
            return content if content else ""
        except Exception as e:
            last_error = e
            err_str = str(e)
            err_lower = err_str.lower()
            is_rate_limit = ('429' in err_str or 'rate limit' in err_lower or 'rate_limit' in err_lower or 'quota' in err_lower)
            is_transient = is_rate_limit or '503' in err_str or '502' in err_str or '500' in err_str or 'timeout' in err_lower
            if is_transient and attempt < 2:
                wait_s = (2 ** attempt) * 3
                logging.warning(f"⚠️ GPT-4o Vision {'rate-limited (429)' if is_rate_limit else 'transient error'} on attempt {attempt+1}/3: {err_str[:150]}. Retrying in {wait_s}s...")
                await asyncio.sleep(wait_s)
                continue
            logging.warning(f"⚠️ GPT-4o Vision failed after {attempt+1} attempts: {err_str[:200]}. Trying OpenRouter fallback...")
            break

    # 2. Fallback to OpenRouter (vision-capable models)
    openrouter_key = os.environ.get('OPENROUTER_API_KEY')
    if openrouter_key:
        OR_HEADERS = {
            "Authorization": f"Bearer {openrouter_key}",
            "Content-Type": "application/json",
            "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
            "X-Title": "Monica Vision OCR",
        }
        for model_id in ["openai/gpt-4o", "google/gemini-2.5-pro"]:
            try:
                logging.info(f"🔄 GPT-4o Vision fallback → {model_id} via OpenRouter...")
                async with _httpx.AsyncClient(timeout=120.0) as client:
                    resp = await client.post(
                        "https://openrouter.ai/api/v1/chat/completions",
                        headers=OR_HEADERS,
                        json={
                            "model": model_id,
                            "messages": messages,
                            "max_tokens": max_tokens,
                            "temperature": temperature
                        }
                    )
                if resp.status_code == 200:
                    content = resp.json()['choices'][0]['message']['content']
                    if content:
                        logging.info(f"✅ {model_id} Vision OK via OpenRouter ({len(content)} chars)")
                        return content
            except Exception as or_err:
                logging.warning(f"⚠️ {model_id} Vision via OpenRouter failed: {str(or_err)[:200]}")
                continue

    logging.error(f"❌ GPT-4o Vision + all OpenRouter fallbacks failed. Last error: {str(last_error)[:300] if last_error else 'unknown'}")
    raise last_error if last_error else Exception("GPT-4o Vision and OpenRouter fallbacks all failed")


async def call_claude_opus(system_message: str, user_message: str, temperature: float = 0.7, max_tokens: int = 32000) -> str:
    """Helper to call Claude Opus via OpenRouter as PRIMARY model.
    
    Use this for premium long-form content generation (Policy Papers, Case Studies, Patents).
    Priority order:
    1. anthropic/claude-opus-4.7 (latest, best for long reports 10k+ words)
    2. anthropic/claude-opus-4.5 (previous generation, still excellent)
    3. anthropic/claude-sonnet-4.5 (fallback, fast + reliable)
    4. google/gemini-2.5-pro (last resort, 1M context, 64k output)
    
    Strips outer markdown code fences automatically and detects refusals.
    """
    import httpx as _httpx
    import re as _re

    def _strip_outer_fences(text: str) -> str:
        if not text:
            return text
        t = text.strip()
        m = _re.match(r'^```[a-zA-Z0-9_\-]*\s*\n(.*?)\n?```\s*$', t, flags=_re.DOTALL)
        if m:
            return m.group(1).strip()
        t = _re.sub(r'^```[a-zA-Z0-9_\-]*\s*\n', '', t)
        t = _re.sub(r'\n```\s*$', '', t)
        return t.strip()

    _REFUSAL_PATTERNS = (
        "i'm sorry, but i can't",
        "i'm sorry, i can't",
        "i cannot assist",
        "i can't assist",
        "i am unable to",
        "i'm unable to",
        "lo siento, no puedo",
        "no puedo asistir",
        "i must decline",
    )

    openrouter_key = os.environ.get('OPENROUTER_API_KEY')
    if not openrouter_key:
        raise Exception("OPENROUTER_API_KEY not set — cannot call Claude Opus")

    OR_HEADERS = {
        "Authorization": f"Bearer {openrouter_key}",
        "Content-Type": "application/json",
        "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
        "X-Title": "Monica Document Generator (Opus primary)",
    }

    # Priority chain: Opus 4.7 → Opus 4.5 → Sonnet 4.5 → Gemini 2.5 Pro
    model_chain = [
        "anthropic/claude-opus-4.7",
        "anthropic/claude-opus-4.5",
        "anthropic/claude-sonnet-4.5",
        "google/gemini-2.5-pro",
    ]

    last_error = None
    for model_id in model_chain:
        try:
            logging.warning(f"🎯 Calling Claude Opus primary → {model_id}...")
            async with _httpx.AsyncClient(timeout=600.0) as client:
                resp = await client.post(
                    "https://openrouter.ai/api/v1/chat/completions",
                    headers=OR_HEADERS,
                    json={
                        "model": model_id,
                        "messages": [
                            {"role": "system", "content": system_message},
                            {"role": "user", "content": user_message}
                        ],
                        "temperature": temperature,
                        "max_tokens": max_tokens
                    }
                )
            if resp.status_code == 200:
                data = resp.json()
                content = data.get('choices', [{}])[0].get('message', {}).get('content', '')
                if content and len(content.strip()) > 0:
                    # Detect refusals
                    first_chars = content.strip().lower()[:200]
                    if any(p in first_chars for p in _REFUSAL_PATTERNS) and len(content.strip()) < 500:
                        logging.warning(f"⚠️ {model_id} refused: '{content.strip()[:100]}...' — trying next model")
                        continue
                    logging.warning(f"✅ {model_id} OK ({len(content)} chars)")
                    return _strip_outer_fences(content)
                logging.warning(f"⚠️ {model_id} returned empty content, trying next")
            else:
                last_error = Exception(f"{model_id} HTTP {resp.status_code}: {resp.text[:200]}")
                logging.warning(f"⚠️ {model_id} HTTP {resp.status_code}: {resp.text[:200]}")
        except Exception as err:
            last_error = err
            logging.warning(f"⚠️ {model_id} error: {str(err)[:200]}")
            continue



async def call_cheap_evaluator(system_message: str, user_message: str, temperature: float = 0.3, max_tokens: int = 1500, json_mode: bool = True) -> str:
    """Cheap & fast LLM for evaluation/scoring tasks (coherence, quality, fabrication checks).
    
    Directly uses OpenRouter to avoid OpenAI 429s. Chain (cheapest → slightly more expensive):
    1. google/gemini-2.5-flash (~$0.075/1M input tokens — very cheap, 1M context)
    2. anthropic/claude-haiku-4.5 (~$1/1M input tokens — fast, solid JSON output)
    3. openai/gpt-4o-mini (~$0.15/1M input tokens — reliable JSON mode)
    
    When json_mode=True, instructs models to return ONLY valid JSON and appends a clear
    directive at the end of the user message to increase JSON compliance across models.
    """
    import httpx as _httpx
    openrouter_key = os.environ.get('OPENROUTER_API_KEY')

    if json_mode:
        system_message = system_message + "\n\nCRITICAL: Respond with ONLY valid JSON. No markdown fences, no preamble, no explanation outside the JSON object."
        user_message = user_message + "\n\nReturn ONLY the JSON object. Start your response directly with { and end with }."

    _REFUSAL_PATTERNS = (
        "i'm sorry, but i can't",
        "i cannot assist",
        "i can't assist",
        "i am unable to",
        "lo siento, no puedo",
    )

    last_error = None

    # ── Primary: OpenRouter cheap chain (Gemini Flash → Claude Haiku → GPT-4o-mini)
    if openrouter_key:
        OR_HEADERS = {
            "Authorization": f"Bearer {openrouter_key}",
            "Content-Type": "application/json",
            "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
            "X-Title": "Monica Evaluator (cheap)",
        }
        model_chain = [
            "google/gemini-2.5-flash",
            "anthropic/claude-haiku-4.5",
            "openai/gpt-4o-mini",
        ]
        for model_id in model_chain:
            try:
                logging.warning(f"💰 Cheap evaluator → {model_id}...")
                payload = {
                    "model": model_id,
                    "messages": [
                        {"role": "system", "content": system_message},
                        {"role": "user", "content": user_message}
                    ],
                    "temperature": temperature,
                    "max_tokens": max_tokens,
                }
                # Gemini and OpenAI support response_format for JSON mode; Claude doesn't strictly
                # need it because our prompt already enforces JSON-only output.
                if json_mode and model_id.startswith(("openai/", "google/")):
                    payload["response_format"] = {"type": "json_object"}

                async with _httpx.AsyncClient(timeout=120.0) as client:
                    resp = await client.post(
                        "https://openrouter.ai/api/v1/chat/completions",
                        headers=OR_HEADERS,
                        json=payload
                    )
                if resp.status_code == 200:
                    data = resp.json()
                    content = data.get('choices', [{}])[0].get('message', {}).get('content', '')
                    if content and len(content.strip()) > 0:
                        first_chars = content.strip().lower()[:200]
                        if any(p in first_chars for p in _REFUSAL_PATTERNS) and len(content.strip()) < 500:
                            logging.warning(f"⚠️ {model_id} refused: '{content.strip()[:100]}...' — trying next")
                            continue
                        logging.warning(f"✅ {model_id} evaluator OK ({len(content)} chars)")
                        return content
                    logging.warning(f"⚠️ {model_id} returned empty, trying next")
                else:
                    last_error = Exception(f"{model_id} HTTP {resp.status_code}: {resp.text[:200]}")
                    logging.warning(f"⚠️ {model_id} HTTP {resp.status_code}")
            except Exception as err:
                last_error = err
                logging.warning(f"⚠️ {model_id} error: {str(err)[:200]}")
                continue
        logging.warning(f"⚠️ OpenRouter cheap chain exhausted. Last: {str(last_error)[:200] if last_error else 'n/a'}")
    else:
        logging.warning("⚠️ OPENROUTER_API_KEY not set — using direct OpenAI fallback for evaluator")

    # ── Fallback: direct OpenAI/proxy via call_openai_mini (gpt-4o). This uses
    # the same auth path as the rest of the app, so the evaluator still works
    # when OpenRouter is unavailable as long as ANY provider key is configured.
    try:
        logging.warning("💰 Cheap evaluator → fallback call_openai_mini (gpt-4o)...")
        content = await call_openai_mini(
            system_message, user_message,
            temperature=temperature, max_tokens=max_tokens, timeout=90,
        )
        if content and content.strip():
            logging.warning(f"✅ Fallback evaluator OK ({len(content)} chars)")
            return content
        last_error = last_error or Exception("call_openai_mini returned empty")
    except Exception as err:
        last_error = err
        logging.warning(f"⚠️ call_openai_mini fallback failed: {str(err)[:200]}")

    logging.error(f"❌ All cheap evaluator providers failed. Last: {str(last_error)[:300] if last_error else 'unknown'}")
    raise last_error if last_error else Exception("All cheap evaluator providers failed")


    logging.error(f"❌ All Claude Opus + fallback models failed. Last error: {str(last_error)[:300] if last_error else 'unknown'}")
    raise last_error if last_error else Exception("All Opus/fallback models failed")





async def call_openai_gpt5(system_message: str, user_message: str, temperature: float = 0.7, max_tokens: int = 4000) -> str:
    """Helper function to call GPT-5.1 with timeout + OpenRouter fallback (Claude/Gemini)"""
    import httpx as _httpx
    openrouter_key = os.environ.get('OPENROUTER_API_KEY')
    OR_HEADERS = {
        "Authorization": f"Bearer {openrouter_key}",
        "Content-Type": "application/json",
        "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
        "X-Title": "Monica Patent Generator",
    }

    # 1. Try GPT-5.1 with 240s timeout
    try:
        logging.info(f"🔧 Calling GPT-5.1 (timeout=240s)...")
        response = await asyncio.wait_for(
            openai_client.chat.completions.create(
                model="gpt-5.1-2025-11-13",
                messages=[
                    {"role": "system", "content": system_message},
                    {"role": "user", "content": user_message}
                ],
                temperature=temperature,
                max_completion_tokens=max_tokens
            ),
            timeout=240.0
        )
        content = response.choices[0].message.content
        finish_reason = response.choices[0].finish_reason

        if hasattr(response, 'usage') and response.usage:
            token_usage_tracker['total_prompt_tokens'] += response.usage.prompt_tokens
            token_usage_tracker['total_completion_tokens'] += response.usage.completion_tokens
            token_usage_tracker['total_tokens'] += response.usage.total_tokens
            token_usage_tracker['call_count'] += 1

        if finish_reason == 'length':
            logging.error(f"⚠️ GPT-5.1 truncated at max_tokens={max_tokens}")

        if not content or len(content.strip()) == 0:
            raise Exception("GPT-5.1 returned empty content")

        logging.info(f"✅ GPT-5.1 OK ({len(content)} chars)")
        return clean_content(content)

    except asyncio.TimeoutError:
        logging.warning("⚠️ GPT-5.1 timed out after 240s. Trying Claude Opus via OpenRouter...")
    except Exception as e:
        logging.warning(f"⚠️ GPT-5.1 error: {str(e)[:100]}. Trying Claude Opus via OpenRouter...")

    # 2. Fallback: Claude Opus 4.5 via OpenRouter
    if openrouter_key:
        for model_id in ["anthropic/claude-opus-4.6", "google/gemini-3-pro-preview"]:
            try:
                logging.info(f"🔄 Fallback to {model_id} via OpenRouter...")
                async with _httpx.AsyncClient(timeout=300.0) as client:
                    resp = await client.post(
                        "https://openrouter.ai/api/v1/chat/completions",
                        headers=OR_HEADERS,
                        json={"model": model_id,
                              "messages": [{"role": "system", "content": system_message},
                                           {"role": "user", "content": user_message}],
                              "temperature": temperature, "max_tokens": max_tokens}
                    )
                if resp.status_code == 200:
                    content = resp.json()['choices'][0]['message']['content']
                    if content and len(content.strip()) > 100:
                        logging.info(f"✅ {model_id} OK ({len(content)} chars)")
                        return clean_content(content)
                    raise Exception(f"{model_id} empty/refused")
                raise Exception(f"{model_id} HTTP {resp.status_code}")
            except Exception as fe:
                logging.warning(f"⚠️ {model_id} failed: {str(fe)[:80]}")

    # 3. Last resort: GPT-4o with 180s timeout
    try:
        logging.info("🔄 Last resort: GPT-4o...")
        response = await asyncio.wait_for(
            openai_client.chat.completions.create(
                model="gpt-4o",
                messages=[{"role": "system", "content": system_message},
                           {"role": "user", "content": user_message}],
                temperature=temperature, max_tokens=max_tokens
            ),
            timeout=180.0
        )
        content = response.choices[0].message.content
        logging.info(f"✅ GPT-4o fallback OK ({len(content)} chars)")
        return clean_content(content) if content else ""
    except Exception as e:
        logging.error(f"❌ All models failed in call_openai_gpt5: {str(e)}")
        raise

