# ============================================================================
# CLAUDE SONNET 4 HELPER (For White Papers - Faster than Opus)
# ============================================================================

async def call_claude_sonnet_niw(system_message: str, user_message: str, temperature: float = 0.4, max_tokens: int = 16000) -> str:
    """Helper function to call Claude Sonnet 4 via OpenRouter for faster NIW generation"""
    import httpx
    
    openrouter_key = os.environ.get('OPENROUTER_API_KEY')
    
    if not openrouter_key:
        logging.warning("⚠️ OPENROUTER_API_KEY not found, falling back to GPT-4o")
        return await call_openai_gpt4o(system_message, user_message, temperature, min(max_tokens, 16000))
    
    try:
        logging.info(f"🔧 Calling Claude Sonnet 4 via OpenRouter (max_tokens={max_tokens})")
        print(f"   📤 Calling Claude Sonnet 4...")

        # Sonnet is faster - 180 seconds timeout should be enough for the
        # underlying socket read.  However httpx only times out when the socket
        # is idle; OpenRouter sometimes drip-feeds keep-alive bytes so an
        # individual call could run far longer than intended.  We wrap the
        # whole request in `asyncio.wait_for` with a hard deadline of 300 s
        # so the background generation never gets stuck forever.
        async def _do_request():
            async with httpx.AsyncClient(timeout=180.0) as client:
                return await client.post(
                    "https://openrouter.ai/api/v1/chat/completions",
                    headers={
                        "Authorization": f"Bearer {openrouter_key}",
                        "Content-Type": "application/json",
                        "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
                        "X-Title": "SmartDocs Creator - NIW White Paper Generator"
                    },
                    json={
                        "model": "anthropic/claude-sonnet-4.6",  # Using Sonnet 4.6 for faster generation
                        "messages": [
                            {"role": "system", "content": system_message},
                            {"role": "user", "content": user_message}
                        ],
                        "temperature": temperature,
                        "max_tokens": max_tokens
                    }
                )
        response = await asyncio.wait_for(_do_request(), timeout=600.0)

        if response.status_code == 200:
            result = response.json()
            content = result['choices'][0]['message']['content']
            finish_reason = result['choices'][0].get('finish_reason', 'unknown')

            logging.info(f"✅ Claude Sonnet 4 response. Finish: {finish_reason}. Length: {len(content) if content else 0}")
            print(f"   ✅ Claude Sonnet 4 responded ({len(content) if content else 0} chars)")

            # Check for refusal
            if content and ("I'm sorry" in content[:100] or "I cannot" in content[:100] or "I can't assist" in content[:100]):
                logging.warning(f"⚠️ Claude refused. Falling back to GPT-4o...")
                return await call_openai_gpt4o(system_message, user_message, temperature, min(max_tokens, 16000))

            return content if content else ""
        else:
            logging.warning(f"⚠️ OpenRouter error {response.status_code}: {response.text[:200]}")
            print(f"   ⚠️ OpenRouter error {response.status_code}, falling back to GPT-4o...")
            return await call_openai_gpt4o(system_message, user_message, temperature, min(max_tokens, 16000))

    except asyncio.TimeoutError:
        logging.error(f"❌ Claude Sonnet 4 HARD deadline exceeded (600s). Falling back to GPT-4o...")
        print(f"   ❌ Claude Sonnet 4 HARD TIMEOUT (10 min), falling back to GPT-4o...")
        return await call_openai_gpt4o(system_message, user_message, temperature, min(max_tokens, 8000))
    except httpx.TimeoutException:
        logging.error(f"❌ Claude Sonnet 4 timeout after 180s. Falling back to GPT-4o...")
        print(f"   ❌ Claude Sonnet 4 TIMEOUT, falling back to GPT-4o...")
        return await call_openai_gpt4o(system_message, user_message, temperature, min(max_tokens, 8000))
    except Exception as e:
        logging.error(f"❌ Claude Sonnet 4 API error: {str(e)[:100]}")
        print(f"   ❌ Claude Sonnet 4 ERROR: {str(e)[:50]}, falling back to GPT-4o...")
        return await call_openai_gpt4o(system_message, user_message, temperature, min(max_tokens, 16000))

