async def call_gemini_flash_lite(system_message: str, user_message: str, temperature: float = 0.7, max_tokens: int = 6000) -> str:
    """Helper function to call Google Gemini 2.0 Flash Lite API via emergentintegrations"""
    try:
        logging.info(f"🔧 Calling Gemini 2.0 Flash Lite with temp={temperature}, max_tokens={max_tokens}")
        logging.info(f"📤 System message length: {len(system_message)} chars")
        logging.info(f"📤 User message length: {len(user_message)} chars")
        
        # Get API key
        api_key = os.getenv("EMERGENT_LLM_KEY")
        if not api_key:
            logging.error("❌ EMERGENT_LLM_KEY not found in environment")
            return ""
        
        # Create chat instance with Gemini Flash Lite
        chat = LlmChat(
            api_key=api_key,
            session_id=f"recommendation_letter_{uuid.uuid4()}",
            system_message=system_message
        ).with_model("gemini", "gemini-2.0-flash-lite")
        
        # Send message
        user_msg = UserMessage(text=user_message)
        content = await chat.send_message(user_msg)
        
        logging.info(f"📥 Gemini Flash Lite response received. Content length: {len(content) if content else 0}")
        
        # Clean content
        if not content or len(content.strip()) == 0:
            logging.error(f"❌ WARNING Gemini Flash Lite returned empty content")
            logging.error(f"   System msg preview: {system_message[:200]}...")
            logging.error(f"   User msg preview: {user_message[:200]}...")
            return ""
        
        return clean_content(content) if content else ""
        
    except Exception as e:
        logging.error(f"❌ Gemini Flash Lite API error: {e}")
        logging.error(f"   System msg length: {len(system_message)}")
        logging.error(f"   User msg length: {len(user_message)}")
        import traceback
        logging.error(traceback.format_exc())
        return ""


# ============================================================================
# COHERENCE EVALUATION HELPER (Reutilizable para todos los módulos)
# ============================================================================

async def evaluate_niw_coherence_thorough(plan: dict) -> dict:
    """
    Evaluador de coherencia NIW multi-fase.
    Lee el CV completo y TODAS las secciones del documento.
    Hace múltiples llamadas para análisis exhaustivo.
    """
    import json as json_module
    
    applicant_name = plan.get('applicant_name', 'Solicitante')
    applicant_cv   = plan.get('applicant_cv', '')
    project_idea   = plan.get('project_idea', '')
    project_title  = plan.get('project_title', '')
    sections       = plan.get('sections', [])
    
    logging.info(f"🔍 [THOROUGH EVAL] Iniciando evaluación multi-fase para: {applicant_name}")
    logging.info(f"   CV: {len(applicant_cv)} chars | Secciones: {len(sections)}")
    
    # Filtrar sección de portada y compilar contenido completo por sección
    def get_section_content(sec):
        return sec.get('content_es') or sec.get('content_en') or sec.get('content') or ''
    
    section_map = {}
    for sec in sections:
        num = sec.get('number', 0)
        title = sec.get('title', f'Sección {num}')
        content = get_section_content(sec)
        if num >= 2 and content:  # skip cover page
            section_map[num] = {'title': title, 'content': content}
    
    NIW_DISPLAY = [
        "I. Resumen Ejecutivo", "II. Antecedentes del Solicitante",
        "III. Planteamiento del Problema", "IV. Importancia Nacional",
        "V. Solución Propuesta", "VI. Análisis de Mercado",
        "VII. Plan de Implementación", "VIII. Proyecciones Financieras",
        "IX. Creación de Empleo", "X. Justificación de Exención NIW",
        "XI. Análisis de Riesgos", "XII. Métricas de Éxito",
        "XIII. Gobernanza y Ética", "XIV. Monitoreo y Evaluación",
        "XV. Bibliografía", "XVI. Anexos"
    ]
    def display_title(db_num):
        idx = db_num - 2
        return NIW_DISPLAY[idx] if 0 <= idx < len(NIW_DISPLAY) else f"Sección {db_num}"

    # ─────────────────────────────────────────────────
    # FASE 1: COHERENCIA CV vs DOCUMENTO
    # Lee CV completo + secciones I y II completas
    # ─────────────────────────────────────────────────
    logging.info("🔍 [FASE 1] Verificando coherencia CV vs documento...")
    
    sec2_content = section_map.get(2, {}).get('content', '')  # Executive Summary
    sec3_content = section_map.get(3, {}).get('content', '')  # Applicant Background
    sec4_content = section_map.get(4, {}).get('content', '')  # Problem Statement (para verificar logros del sol.)
    
    phase1_prompt = f"""Eres un evaluador de documentos EB-2 NIW. Tu tarea es verificar si las afirmaciones sobre el HISTORIAL PERSONAL del solicitante coinciden con su CV.

═══════════════════════════════════════════════════
CV COMPLETO DEL SOLICITANTE: {applicant_name}
═══════════════════════════════════════════════════
{applicant_cv}

═══════════════════════════════════════════════════
SECCIÓN I - RESUMEN EJECUTIVO (texto completo):
═══════════════════════════════════════════════════
{sec2_content}

═══════════════════════════════════════════════════
SECCIÓN II - ANTECEDENTES DEL SOLICITANTE (texto completo):
═══════════════════════════════════════════════════
{sec3_content}

═══════════════════════════════════════════════════
EXTRACTO SECCIÓN III - PLANTEAMIENTO (para verificar logros mencionados):
═══════════════════════════════════════════════════
{sec4_content[:3000]}

═══════════════════════════════════════════════════
INSTRUCCIONES CRÍTICAS - LEE CON MUCHO CUIDADO:
═══════════════════════════════════════════════════

ALCANCE DE LA EVALUACIÓN:
Evalúa ÚNICAMENTE las afirmaciones sobre el HISTORIAL PERSONAL del solicitante:
  - Empresas donde trabajó, cargos, fechas
  - Logros personales pasados con métricas (ej: "logré 30% de crecimiento")
  - Títulos académicos, certificaciones
  - Años de experiencia

NO EVALÚES (ignorar completamente, NO son fabricaciones):
  - Proyecciones financieras del plan de negocios (ej: "$2M en ingresos proyectados", "ROI del 200%")
  - Estadísticas del mercado o la industria (ej: "el 60% de concesionarios...")
  - Objetivos futuros del proyecto (ej: "reducirá quejas en 40%", "generará $11M")
  - Datos de investigación o fuentes externas citadas
  - Propuestas de lo que el proyecto HARÁ vs lo que el solicitante YA HIZO
  Estas son partes normales y esperadas de un plan de negocios NIW.

REGLA 1 - FUENTES VÁLIDAS DEL CV: Todo el texto del CV es fuente válida:
  - El Perfil Profesional (resumen al inicio)
  - Descripciones de cada puesto (métricas, porcentajes, logros mencionados)
  - Reconocimientos y premios
  - Certificaciones, educación, proyectos

REGLA 2 - VERIFICACIÓN: Un dato personal se considera VERIFICADO si:
  - Aparece textualmente en el CV (en CUALQUIER sección)
  - Es una paráfrasis razonable de algo que dice el CV
  - Es un cálculo correcto basado en fechas/datos del CV

REGLA 3 - FABRICACIÓN (solo aplica a datos PERSONALES del solicitante):
  Un dato SOLO es fabricado si afirma algo sobre el PASADO del solicitante que NO está en el CV:
  - Menciona una empresa donde el solicitante NUNCA trabajó
  - Inventa un título académico o certificación que no aparece en el CV
  - Atribuye al solicitante logros PASADOS con métricas que no están en el CV
  - Atribuye logros de una empresa a otra diferente

TAREA: Extrae las afirmaciones sobre el historial personal del solicitante y verifica contra el CV.

Responde en JSON:
{{
  "cv_score": <0-100 — 100 si el historial personal refleja el CV correctamente>,
  "verified_claims": [
    {{"claim": "texto", "status": "VERIFIED|NOT_VERIFIED", "cv_evidence": "texto del CV", "comment": "explicación"}}
  ],
  "fabricated_data": [
    {{"type": "empresa_inexistente|titulo_falso|logro_personal_inventado", "document_text": "afirmación personal falsa", "correct_or_missing": "lo que dice el CV"}}
  ],
  "fabrication_count": <número de datos personales fabricados>,
  "experience_years_claimed": <años que dice el documento>,
  "experience_years_actual": <años calculados del CV>,
  "summary": "resumen de 2-3 líneas sobre coherencia del historial personal con el CV."
}}"""

    phase1_result = {}
    try:
        phase1_raw = await call_claude_sonnet_niw(
            "Eres un evaluador justo de documentos EB-2 NIW. IMPORTANTE: Solo evalúas si el HISTORIAL PERSONAL del solicitante coincide con su CV. Las proyecciones financieras ($2M, $11M, ROI), estadísticas de mercado y objetivos futuros del plan de negocios NO son fabricaciones — son partes normales de un plan de negocios. Solo marca como fabricado datos PERSONALES del solicitante que no estén en el CV. Responde SOLO con JSON válido.",
            phase1_prompt,
            temperature=0.1,
            max_tokens=8000
        )
        phase1_raw = phase1_raw.replace('```json', '').replace('```', '').strip()
        phase1_result = json_module.loads(phase1_raw)
        logging.info(f"✅ [FASE 1] CV Score: {phase1_result.get('cv_score', 'N/A')} | Fabricaciones: {phase1_result.get('fabrication_count', 0)}")
    except Exception as e:
        logging.warning(f"⚠️ [FASE 1] Error: {e}")
        phase1_result = {"cv_score": 50, "fabricated_data": [], "fabrication_count": 0, "summary": "No se pudo evaluar coherencia CV"}

    # ─────────────────────────────────────────────────
    # FASE 2: CRITERIOS DHANASAR (3 Prongs)
    # Evalúa secciones relevantes para cada prong
    # ─────────────────────────────────────────────────
    logging.info("🔍 [FASE 2] Evaluando criterios Dhanasar...")
    
    # Prong 1: Merit & National Importance → Secciones III, IV, V (Problem, National Importance, Solution)
    prong1_content = ""
    for db_num in [4, 5, 6]:  # Problem Statement, National Importance, Solution
        sec = section_map.get(db_num, {})
        if sec.get('content'):
            prong1_content += f"\n\n=== {display_title(db_num)} ===\n{sec['content'][:4000]}"
    
    # Prong 2: Well Positioned → Secciones I, II, XI (Exec Summary, Background, NIW Justification)
    prong2_content = ""
    for db_num in [2, 3, 11]:  # Exec Summary, Background, NIW Justification
        sec = section_map.get(db_num, {})
        if sec.get('content'):
            prong2_content += f"\n\n=== {display_title(db_num)} ===\n{sec['content'][:3000]}"
    
    # Prong 3: Waiver Beneficial → Sección X (NIW Justification) + IX (Job Creation)
    prong3_content = ""
    for db_num in [11, 10]:  # NIW Justification, Job Creation
        sec = section_map.get(db_num, {})
        if sec.get('content'):
            prong3_content += f"\n\n=== {display_title(db_num)} ===\n{sec['content'][:4000]}"

    phase2_prompt = f"""Eres un abogado de inmigración experto en EB-2 NIW bajo el estándar Matter of Dhanasar (2016). Evalúa este plan de negocio contra los 3 prongs de Dhanasar.

SOLICITANTE: {applicant_name}
PROYECTO: {project_title}
DESCRIPCIÓN DEL PROYECTO:
{project_idea[:2000]}

SECCIONES PARA PRONG 1 (Mérito Sustancial e Importancia Nacional):
{prong1_content}

SECCIONES PARA PRONG 2 (Bien Posicionado para Avanzar el Esfuerzo Propuesto):
{prong2_content}

SECCIONES PARA PRONG 3 (Beneficioso para EE.UU. Dispensar Requisito de Oferta de Trabajo):
{prong3_content}

═══════════════════════════════════════════════════
CRITERIOS DE EVALUACIÓN DHANASAR:

PRONG 1 — MÉRITO SUSTANCIAL E IMPORTANCIA NACIONAL:
✅ Excelente (90-100): Problema nacional claramente definido con fuentes .gov; solución con impacto medible; cifras concretas del impacto nacional
✅ Bueno (70-89): Problema documentado, importancia explicada, pero falta alguna fuente gubernamental
⚠️ Regular (50-69): Problema genérico, impacto no cuantificado, falta evidencia gubernamental
❌ Deficiente (0-49): Sin crisis nacional real, sin impacto medible, solo habla del negocio no del interés nacional

PRONG 2 — BIEN POSICIONADO:
✅ Excelente (90-100): Credenciales únicas verificables, experiencia directamente relevante, logros comprobables del CV, diferenciación clara
✅ Bueno (70-89): Buenas credenciales, pero falta demostrar unicidad o diferenciación competitiva
⚠️ Regular (50-69): Credenciales generales, sin demostrar por qué ES la persona correcta
❌ Deficiente (0-49): Sin conexión entre el CV y la capacidad de ejecutar el proyecto

PRONG 3 — RENUNCIA BENEFICIOSA:
✅ Excelente (90-100): Argumento explícito por qué el país se beneficia más con la renuncia que sin ella; urgencia clara
✅ Bueno (70-89): Beneficio explicado pero no completamente urgente o único
⚠️ Regular (50-69): Beneficio implícito pero no argumentado directamente
❌ Deficiente (0-49): No hay argumento de renuncia, solo habla del negocio

Responde en JSON:
{{
  "prong1": {{
    "score": <0-100>,
    "status": "EXCELLENT|GOOD|REGULAR|DEFICIENT",
    "strengths": ["fortaleza 1", "fortaleza 2"],
    "weaknesses": ["debilidad 1", "debilidad 2"],
    "missing_elements": ["qué falta para score 100"],
    "gov_sources_adequate": true/false,
    "national_crisis_documented": true/false
  }},
  "prong2": {{
    "score": <0-100>,
    "status": "EXCELLENT|GOOD|REGULAR|DEFICIENT",
    "strengths": ["fortaleza 1"],
    "weaknesses": ["debilidad 1"],
    "missing_elements": ["qué falta para score 100"],
    "unique_positioning_demonstrated": true/false,
    "cv_credentials_used": true/false
  }},
  "prong3": {{
    "score": <0-100>,
    "status": "EXCELLENT|GOOD|REGULAR|DEFICIENT",
    "strengths": ["fortaleza 1"],
    "weaknesses": ["debilidad 1"],
    "missing_elements": ["qué falta para score 100"]
  }},
  "dhanasar_overall_score": <promedio ponderado: prong1*35% + prong2*35% + prong3*30%>,
  "critical_issues": ["problema crítico 1 que hay que arreglar URGENTE"],
  "recommendations_for_100": ["acción concreta para llegar a 100 en cada prong"]
}}"""

    phase2_result = {}
    try:
        phase2_raw = await call_claude_sonnet_niw(
            "Eres un abogado de inmigración experto en EB-2 NIW. Evalúa rigurosamente cada prong de Dhanasar. Responde SOLO con JSON válido.",
            phase2_prompt,
            temperature=0.1,
            max_tokens=6000
        )
        phase2_raw = phase2_raw.replace('```json', '').replace('```', '').strip()
        phase2_result = json_module.loads(phase2_raw)
        logging.info(f"✅ [FASE 2] Dhanasar score: {phase2_result.get('dhanasar_overall_score', 'N/A')}")
        logging.info(f"   Prong1: {phase2_result.get('prong1', {}).get('score', 'N/A')} | Prong2: {phase2_result.get('prong2', {}).get('score', 'N/A')} | Prong3: {phase2_result.get('prong3', {}).get('score', 'N/A')}")
    except Exception as e:
        logging.warning(f"⚠️ [FASE 2] Error: {e}")
        phase2_result = {"prong1": {"score": 50, "status": "REGULAR", "strengths": [], "weaknesses": [], "missing_elements": []},
                        "prong2": {"score": 50, "status": "REGULAR", "strengths": [], "weaknesses": [], "missing_elements": []},
                        "prong3": {"score": 50, "status": "REGULAR", "strengths": [], "weaknesses": [], "missing_elements": []},
                        "dhanasar_overall_score": 50, "critical_issues": [], "recommendations_for_100": []}

    # ─────────────────────────────────────────────────
    # FASE 3: COMPLETITUD Y CALIDAD TÉCNICA
    # Verifica que todas las secciones tienen contenido
    # y cumplan con los estándares profesionales NIW
    # ─────────────────────────────────────────────────
    logging.info("🔍 [FASE 3] Verificando completitud y calidad técnica...")
    
    # Compilar todas las secciones para verificación de completitud
    all_sections_summary = ""
    for db_num in sorted(section_map.keys()):
        sec = section_map[db_num]
        content_len = len(sec.get('content', ''))
        all_sections_summary += f"- {display_title(db_num)}: {content_len} caracteres\n"
    
    # Revisar las secciones técnicas clave (Financial, Implementation, Risk)
    tech_content = ""
    for db_num in [8, 9, 10, 12]:  # Financial, Job Creation, NIW Justification, Risk
        sec = section_map.get(db_num, {})
        if sec.get('content'):
            tech_content += f"\n=== {display_title(db_num)} ===\n{sec['content'][:3000]}"

    phase3_prompt = f"""Eres un evaluador de planes de negocio EB-2 NIW. Evalúa la completitud y calidad técnica de este plan.

PROYECTO: {project_title} | SOLICITANTE: {applicant_name}

INVENTARIO DE SECCIONES:
{all_sections_summary}

SECCIONES TÉCNICAS (Financiero, Empleo, Justificación NIW, Riesgos):
{tech_content}

CRITERIOS A EVALUAR:

1. COMPLETITUD (¿Están todas las secciones con suficiente contenido?):
   - Mínimo aceptable por sección: 2,000 caracteres
   - Óptimo: 5,000+ caracteres para secciones principales

2. PROYECCIONES FINANCIERAS:
   - ¿Tiene tablas con año 1-5?
   - ¿Los números son realistas para inversión de $100K-$130K?
   - ¿Hay flujo de caja proyectado?

3. EMPLEO:
   - ¿Menciona empleos directos? ¿Son realistas (3-6 en 5 años)?
   - ¿Diferencia empleos directos vs indirectos?

4. BIBLIOGRAFÍA:
   - ¿Tiene 20+ fuentes?
   - ¿Incluye fuentes .gov?
   - ¿Formato APA/Chicago?

5. JUSTIFICACIÓN NIW:
   - ¿Aborda explícitamente los 3 criterios de Dhanasar?
   - ¿Argumenta por qué se debe dispensar la oferta de trabajo?

Responde en JSON:
{{
  "completeness_score": <0-100>,
  "sections_analysis": [
    {{"section": "nombre", "chars": número, "status": "COMPLETE|THIN|EMPTY", "min_required": 2000}}
  ],
  "financial_quality": {{"score": <0-100>, "has_5yr_table": true/false, "realistic_numbers": true/false, "issues": []}},
  "employment_quality": {{"score": <0-100>, "jobs_count_realistic": true/false, "issues": []}},
  "bibliography_quality": {{"score": <0-100>, "source_count": número, "has_gov_sources": true/false, "issues": []}},
  "niw_justification_quality": {{"score": <0-100>, "addresses_all_3_prongs": true/false, "has_waiver_argument": true/false, "issues": []}},
  "technical_overall_score": <promedio>,
  "critical_missing": ["elemento crítico faltante 1", "..."],
  "quick_wins": ["mejora fácil que subiría la puntuación 1", "..."]
}}"""

    phase3_result = {}
    try:
        phase3_raw = await call_claude_sonnet_niw(
            "Eres un evaluador técnico de planes de negocio EB-2 NIW. Responde SOLO con JSON válido.",
            phase3_prompt,
            temperature=0.1,
            max_tokens=4000
        )
        phase3_raw = phase3_raw.replace('```json', '').replace('```', '').strip()
        phase3_result = json_module.loads(phase3_raw)
        logging.info(f"✅ [FASE 3] Completitud: {phase3_result.get('completeness_score', 'N/A')} | Técnica: {phase3_result.get('technical_overall_score', 'N/A')}")
    except Exception as e:
        logging.warning(f"⚠️ [FASE 3] Error: {e}")
        phase3_result = {"completeness_score": 60, "technical_overall_score": 60, "critical_missing": [], "quick_wins": []}

    # ─────────────────────────────────────────────────
    # AGREGACIÓN FINAL: Calcular puntuación total
    # ─────────────────────────────────────────────────
    cv_score       = phase1_result.get('cv_score', 50)
    dhanasar_score = phase2_result.get('dhanasar_overall_score', 50)
    tech_score     = phase3_result.get('technical_overall_score', 60)
    completeness   = phase3_result.get('completeness_score', 60)

    # Ponderación: CV coherence 45% (prioridad: no fabricar) + Dhanasar 30% + Technical/Completeness 25%
    final_score = round(cv_score * 0.45 + dhanasar_score * 0.30 + ((tech_score + completeness) / 2) * 0.25)
    
    # Penalización por datos fabricados (solo datos REALMENTE fabricados, no paráfrasis)
    fabrication_count = phase1_result.get('fabrication_count', 0)
    if fabrication_count > 0:
        penalty = min(fabrication_count * 3, 15)  # max 15 puntos de penalización (más suave)
        final_score = max(0, final_score - penalty)
        logging.info(f"⚠️ [FINAL] Penalización por {fabrication_count} datos fabricados: -{penalty} puntos")

    # Compilar todos los issues
    all_issues = []
    for item in phase1_result.get('fabricated_data', []):
        all_issues.append({
            "section": "Antecedentes/Resumen",
            "issue": f"Dato fabricado ({item.get('type','')}): {item.get('document_text','')}",
            "severity": "HIGH",
            "fix": f"Corregir a: {item.get('correct_or_missing','Eliminar si no está en el CV')}"
        })
    for issue in phase2_result.get('critical_issues', []):
        all_issues.append({"section": "Criterios Dhanasar", "issue": issue, "severity": "HIGH", "fix": ""})
    for item in phase3_result.get('critical_missing', []):
        all_issues.append({"section": "Contenido técnico", "issue": item, "severity": "MEDIUM", "fix": ""})

    # Compilar recomendaciones para llegar a 100
    recommendations = []
    recommendations.extend(phase2_result.get('recommendations_for_100', []))
    recommendations.extend(phase3_result.get('quick_wins', []))
    if phase1_result.get('fabricated_data'):
        recommendations.insert(0, f"🚨 URGENTE: Corregir {len(phase1_result['fabricated_data'])} datos que no reflejan el CV real")

    logging.info(f"✅ [EVALUACIÓN COMPLETA] Score final: {final_score}/100")
    logging.info(f"   CV: {cv_score} | Dhanasar: {dhanasar_score} | Técnica: {tech_score} | Completitud: {completeness}")
    logging.info(f"   Issues encontrados: {len(all_issues)} | Fabricaciones: {fabrication_count}")

    # Determine legacy fields for backwards compatibility with frontend
    has_fabrications = fabrication_count > 0
    reflects_cv_val = "No" if cv_score < 50 else ("Parcialmente" if cv_score < 75 else "Sí")
    
    return {
        "coherence_score": final_score,
        # Legacy fields for frontend compatibility
        "reflects_cv": reflects_cv_val,
        "correct_companies": "Sí" if cv_score >= 75 else ("Parcialmente" if cv_score >= 50 else "No"),
        "correct_experience_years": "Sí" if cv_score >= 75 else ("Parcialmente" if cv_score >= 50 else "No"),
        "invented_info": "Sí" if has_fabrications else "No",
        "summary": phase1_result.get('summary', ''),
        "recommendation": recommendations[0] if recommendations else "El documento refleja correctamente el CV.",
        # Multi-phase fields
        "cv_coherence_score": cv_score,
        "dhanasar_score": dhanasar_score,
        "technical_score": tech_score,
        "completeness_score": completeness,
        "fabrication_count": fabrication_count,
        "fabricated_data": phase1_result.get('fabricated_data', []),
        "verified_claims": phase1_result.get('verified_claims', []),
        "experience_years_claimed": phase1_result.get('experience_years_claimed'),
        "experience_years_actual": phase1_result.get('experience_years_actual'),
        "cv_summary": phase1_result.get('summary', ''),
        "prong1": phase2_result.get('prong1', {}),
        "prong2": phase2_result.get('prong2', {}),
        "prong3": phase2_result.get('prong3', {}),
        "issues_found": all_issues,
        "recommendations": recommendations,
        "sections_analysis": phase3_result.get('sections_analysis', []),
        "financial_quality": phase3_result.get('financial_quality', {}),
        "bibliography_quality": phase3_result.get('bibliography_quality', {}),
        "evaluation_phases": {
            "phase1_cv": "completed" if phase1_result else "failed",
            "phase2_dhanasar": "completed" if phase2_result else "failed",
            "phase3_technical": "completed" if phase3_result else "failed"
        }
    }



async def evaluate_document_coherence(
    document_content: str,
    author_name: str = "",
    author_cv: str = "",
    project_description: str = "",
    patent_info: str = "",
    document_type: str = "documento"  # libro, plan de negocio, patente, estudio econométrico, etc.
) -> dict:
    """
    Evalúa la coherencia de un documento generado con la información del autor.
    Retorna un diccionario con la puntuación y detalles de la evaluación.
    """
    # json is imported globally at the top of the file (line 76)
    
    try:
        # Para estudios econométricos, el project_description ES la fuente principal
        # Para otros documentos, el CV es más importante
        is_econometric = "econométrico" in document_type.lower() or "econometric" in document_type.lower()
        
        # Extraer información clave del proyecto (título, inventor, campo)
        project_summary = ""
        if project_description:
            # Extraer las primeras líneas que suelen tener el título e inventor
            lines = project_description.split('\n')[:30]
            project_summary = '\n'.join(lines)
            
            # Si es una patente, extraer campos específicos
            if 'Patent' in project_description or 'Invention' in project_description:
                import re
                title_match = re.search(r'Title of the Invention:\s*(.+?)(?:\n|¶)', project_description)
                inventor_match = re.search(r'Inventor:\s*(.+?)(?:\n|¶)', project_description)
                field_match = re.search(r'FIELD OF THE INVENTION\s*(.+?)(?:¶\d{4}|BACKGROUND)', project_description, re.DOTALL)
                
                if title_match or inventor_match or field_match:
                    project_summary = f"""
TÍTULO DE INVENCIÓN: {title_match.group(1).strip() if title_match else 'No especificado'}
INVENTOR: {inventor_match.group(1).strip() if inventor_match else 'No especificado'}
CAMPO: {field_match.group(1).strip()[:500] if field_match else 'No especificado'}
"""
        
        # Construir información del autor
        if is_econometric and project_description and not author_cv:
            # Para estudios econométricos basados solo en proyecto/patente
            author_info = f"""
INFORMACIÓN DEL PROYECTO PROPORCIONADA:
- Nombre del aplicante: {author_name or 'No especificado'}
- Descripción del proyecto/patente: 
{project_summary[:2000] if project_summary else project_description[:2000]}

NOTA: Este estudio econométrico se generó basándose en el proyecto/patente proporcionado, no en un CV tradicional.
La evaluación debe verificar si el estudio refleja correctamente el contenido y alcance del proyecto.
"""
        else:
            author_info = f"""
INFORMACIÓN DEL AUTOR PROPORCIONADA:
- Nombre: {author_name or 'No especificado'}
- CV/Experiencia: {author_cv[:8000] if author_cv else 'No proporcionado'}
- Proyecto: {project_summary[:3000] if project_summary else (project_description[:3000] if project_description else 'No proporcionado')}
- Patente: {patent_info[:1500] if patent_info else 'No proporcionado'}
"""
        
        # Ajustar el prompt según el tipo de documento
        is_policy_paper = "reporte" in document_type.lower() or "social impact" in document_type.lower() or "policy" in document_type.lower()
        is_patent = "patent" in document_type.lower() or "patente" in document_type.lower()

        if is_econometric:
            eval_prompt = f"""Evalúa la coherencia del siguiente estudio econométrico con el proyecto/patente proporcionado.

{author_info}

CONTENIDO DEL ESTUDIO ECONOMÉTRICO (primeros 8000 caracteres):
{document_content[:8000]}

EVALUACIÓN REQUERIDA PARA ESTUDIO ECONOMÉTRICO:
1. ¿El estudio refleja correctamente el campo y alcance del proyecto? (Sí/No/Parcialmente)
2. ¿Se menciona correctamente el nombre del inventor/aplicante? (Sí/No/N/A)
3. ¿Las métricas y análisis son relevantes para el tipo de proyecto descrito? (Sí/No/N/A)
4. ¿El contenido técnico del proyecto se integró en el análisis econométrico? (Sí/No/N/A)
5. ¿Hay información inventada que no está relacionada con el proyecto? (Sí/No)

IMPORTANTE: Si NO se proporcionó CV pero SÍ se proporcionó un proyecto/patente, evalúa basándote en el proyecto.
Un estudio econométrico basado en una patente DEBE reflejar el campo de la invención y su potencial impacto.

PUNTUACIÓN DE COHERENCIA (0-100): Donde 100 = perfectamente coherente con el proyecto proporcionado.

Responde SOLO en formato JSON válido (sin markdown):
{{
    "coherence_score": <número 0-100>,
    "reflects_cv": "<Sí/No/Parcialmente - o 'Basado en proyecto' si no hay CV>",
    "correct_companies": "<Sí/No/N/A>",
    "correct_experience_years": "<Sí/No/N/A>",
    "project_integrated": "<Sí/No/N/A>",
    "invented_info": "<Sí/No>",
    "summary": "<resumen de 2-3 líneas sobre la coherencia del estudio con el proyecto>",
    "issues_found": ["<lista de problemas de coherencia encontrados>"],
    "recommendation": "<recomendación para mejorar la coherencia>"
}}"""
        elif is_policy_paper:
            eval_prompt = f"""Evalúa la coherencia del siguiente reporte de impacto social/policy paper con el proyecto proporcionado.

AUTOR: {author_name}

DESCRIPCIÓN DEL PROYECTO (documento fuente):
{project_description[:3000] if project_description else "No proporcionado"}

CONTENIDO DEL REPORTE (primeros 8000 caracteres):
{document_content[:8000]}

CRITERIOS: Para este documento NO se requiere CV. Evalúa si el reporte integra correctamente el contenido del proyecto fuente.

1. ¿El reporte describe el mismo proyecto del documento fuente? (Sí/No/Parcialmente)
2. ¿El nombre del autor aparece correctamente? (Sí/No/N/A)
3. ¿El campo/industria coincide con el proyecto? (Sí/No/Parcialmente)
4. ¿El reporte describe el impacto del proyecto específico? (Sí/No/Parcialmente)
5. ¿Hay información inventada que contradice el proyecto fuente? (Sí/No)

PUNTUACIÓN: 80-100=integra bien el proyecto, 60-79=integración parcial, 40-59=campo correcto pero falta integración, 0-39=no refleja el proyecto.

Responde SOLO en JSON válido:
{{
    "coherence_score": <0-100>,
    "reflects_cv": "N/A",
    "correct_companies": "N/A",
    "correct_experience_years": "N/A",
    "project_integrated": "<Sí/No/Parcialmente>",
    "invented_info": "<Sí/No>",
    "summary": "<2-3 líneas sobre integración del proyecto>",
    "issues_found": [],
    "recommendation": "<recomendación específica>"
}}"""
        elif is_patent:
            eval_prompt = f"""Evalúa la coherencia de la siguiente solicitud de patente con el perfil y proyecto del inventor.

{author_info}

CONTENIDO DE LA PATENTE (primeros 8000 caracteres):
{document_content[:8000]}

EVALUACIÓN:
1. ¿La patente refleja el campo de experiencia del inventor (según CV/proyecto)? (Sí/No/Parcialmente)
2. ¿El nombre del inventor aparece correctamente? (Sí/No)
3. ¿La invención está relacionada con el proyecto/experiencia del inventor? (Sí/No/Parcialmente)
4. ¿La complejidad/profundidad técnica de la patente es consistente con la experiencia del inventor? (Sí/No/Parcialmente — usa N/A SOLO si no hay CV ni proyecto)
5. ¿Hay información técnica inventada que no corresponde al perfil? (Sí/No)

PUNTUACIÓN: 80-100=coherente con el perfil, 60-79=parcialmente coherente, 0-59=información inventada o no relacionada.

IMPORTANTE: Responde cada campo con un valor concreto (Sí/No/Parcialmente). Usa "N/A" únicamente cuando realmente no haya información para evaluar ese punto.

Responde SOLO en JSON válido:
{{
    "coherence_score": <0-100>,
    "reflects_cv": "<Sí/No/Parcialmente>",
    "correct_companies": "<Sí/No/N/A>",
    "correct_experience_years": "<Sí/No/Parcialmente/N/A>",
    "project_integrated": "<Sí/No/Parcialmente>",
    "invented_info": "<Sí/No>",
    "summary": "<2-3 líneas>",
    "issues_found": [],
    "recommendation": "<recomendación>"
}}"""
        else:
            eval_prompt = f"""Evalúa la coherencia del siguiente {document_type} con la información del autor proporcionada.

{author_info}

CONTENIDO DEL DOCUMENTO (primeros 8000 caracteres):
{document_content[:8000]}

EVALUACIÓN REQUERIDA:
1. ¿El documento refleja la experiencia real del autor según su CV? (Sí/No/Parcialmente)
2. ¿Se mencionan correctamente las empresas/instituciones donde trabajó el autor? (Sí/No/N/A)
3. ¿Los años de experiencia mencionados coinciden con el CV? (Sí/No/N/A)
4. ¿El contenido del proyecto/patente se integró correctamente? (Sí/No/N/A)
5. ¿Hay información inventada que no aparece en los datos del autor? (Sí/No)

PUNTUACIÓN DE COHERENCIA (0-100): Donde 100 = perfectamente coherente con los datos del autor.

Responde SOLO en formato JSON válido (sin markdown):
{{
    "coherence_score": <número 0-100>,
    "reflects_cv": "<Sí/No/Parcialmente>",
    "correct_companies": "<Sí/No/N/A>",
    "correct_experience_years": "<Sí/No/N/A>",
    "project_integrated": "<Sí/No/N/A>",
    "invented_info": "<Sí/No>",
    "summary": "<resumen de 2-3 líneas sobre la coherencia del documento>",
    "issues_found": ["<lista de problemas de coherencia encontrados>"],
    "recommendation": "<recomendación para el operador>"
}}"""

        try:
            result = await call_cheap_evaluator(
                "Eres un evaluador de calidad de documentos. Evalúas si el contenido es coherente con la información proporcionada del autor. Siempre respondes en JSON válido sin markdown.",
                eval_prompt,
                temperature=0.3,
                max_tokens=1500,
                json_mode=True,
            )
        except Exception as api_error:
            logging.warning(f"⚠️ Coherence evaluation API failed: {str(api_error)[:100]}")
            # Return a default evaluation if API fails
            return {
                "coherence_score": 70,
                "reflects_cv": "N/A",
                "correct_companies": "N/A",
                "correct_experience_years": "N/A",
                "project_integrated": "N/A",
                "invented_info": "N/A",
                "summary": "Evaluación automática no disponible temporalmente",
                "issues_found": [],
                "recommendation": "El documento fue generado correctamente. Revise manualmente si es necesario."
            }
        
        # Parsear resultado JSON (robusto contra preámbulos/markdown de modelos OpenRouter)
        clean_result = (result or "").strip()
        # Strip markdown code fences (```json ... ```  or  ``` ... ```)
        if clean_result.startswith('```json'):
            clean_result = clean_result[7:]
        elif clean_result.startswith('```'):
            clean_result = clean_result[3:]
        if clean_result.endswith('```'):
            clean_result = clean_result[:-3]
        clean_result = clean_result.strip()
        
        # Claude/Gemini sometimes add a preamble like "Here's the evaluation:\n{...}".
        # Extract the JSON object by finding the first { and the matching last }.
        try:
            evaluation = json.loads(clean_result)
        except json.JSONDecodeError:
            first_brace = clean_result.find('{')
            last_brace = clean_result.rfind('}')
            if first_brace != -1 and last_brace > first_brace:
                candidate = clean_result[first_brace:last_brace + 1]
                try:
                    evaluation = json.loads(candidate)
                    logging.info("✅ Coherence JSON recovered by brace-extraction fallback")
                except json.JSONDecodeError:
                    logging.warning(f"⚠️ Brace-extraction fallback failed. Raw response (first 500 chars): {clean_result[:500]}")
                    raise
            else:
                logging.warning(f"⚠️ No JSON braces found in coherence response (first 500 chars): {clean_result[:500]}")
                raise
        
        logging.info(f"✅ Coherence evaluation completed: Score {evaluation.get('coherence_score', 'N/A')}")
        return evaluation
        
    except json.JSONDecodeError as e:
        logging.warning(f"⚠️ Could not parse coherence evaluation JSON: {str(e)}")
        # Return a neutral score (70) instead of 0 so the document is not flagged
        # as incoherent just because the evaluator model returned malformed JSON.
        return {
            "coherence_score": 70,
            "reflects_cv": "N/A",
            "correct_companies": "N/A",
            "correct_experience_years": "N/A",
            "project_integrated": "N/A",
            "invented_info": "N/A",
            "summary": "Evaluación automática no disponible (respuesta del evaluador malformada)",
            "issues_found": [],
            "recommendation": "Documento generado correctamente. La evaluación de coherencia no pudo ejecutarse automáticamente — revise manualmente si es necesario."
        }
    except Exception as e:
        logging.warning(f"⚠️ Error in coherence evaluation: {str(e)}")
        # Return neutral score (70) instead of 0 so the document is not flagged
        # as incoherent just because the evaluator failed due to transient errors.
        return {
            "coherence_score": 70,
            "reflects_cv": "N/A",
            "correct_companies": "N/A",
            "correct_experience_years": "N/A",
            "project_integrated": "N/A",
            "invented_info": "N/A",
            "summary": f"Evaluación no disponible: {str(e)[:100]}",
            "issues_found": [],
            "recommendation": "Documento generado correctamente. Revise manualmente el contenido si es necesario."
        }


# ============================================================================
# ECONOMETRIC STUDY V2: 2-CALL GENERATION SYSTEM
# ============================================================================

async def generate_complete_econometric_study_v2(
    project_description: str,
    language: str = 'en'
) -> dict:
    """
    New 2-call method for generating complete econometric studies.
    Call 1: GPT-5.1 generates full 16-section study in English
    Call 2: GPT-4o translates to Spanish
    
    Returns dict with:
        - content_en: Full English study (markdown)
        - content_es: Full Spanish study (markdown)
        - metadata: Generation statistics
    """
    from dotenv import load_dotenv
    load_dotenv()
    
    logging.info("🚀 Starting V2 Econometric Study Generation (2-call method)")
    logging.info(f"   Project description length: {len(project_description)} chars")
    logging.info(f"   Target language: {language}")
    
    # Import prompts
    from econometric_prompt_v2 import (
        SYSTEM_MESSAGE_GENERATION,
        USER_PROMPT_GENERATION_TEMPLATE,
        SYSTEM_MESSAGE_TRANSLATION,
        USER_PROMPT_TRANSLATION_TEMPLATE
    )
    
    # ============================================================================
    # CALL 1: Generate complete study in English using GPT-5.1
    # ============================================================================
    logging.info("📝 CALL 1/2: Generating complete 16-section study in English with GPT-5.1...")
    start_time_call1 = time.time()
    
    try:
        # Prepare user prompt
        user_prompt_en = USER_PROMPT_GENERATION_TEMPLATE.format(
            business_plan_text=project_description
        )
        
        logging.info(f"   Prompt length: {len(user_prompt_en)} chars")
        logging.info("   🎯 Sending to Claude Opus 4.7 PRIMARY (may take 90-180 seconds, with Opus 4.5/Sonnet/Gemini fallback)...")
        
        # 🎯 PRIMARY: Claude Opus 4.7 (fallback: Opus 4.5 → Sonnet 4.5 → Gemini 2.5 Pro)
        # This avoids the 9s delay from OpenAI 429 retries and produces longer, more consistent studies.
        # If Opus chain fails entirely, fall back to GPT-5.1 (which itself has OpenRouter fallback).
        try:
            content_en = await call_claude_opus(
                system_message=SYSTEM_MESSAGE_GENERATION,
                user_message=user_prompt_en,
                temperature=0.3,
                max_tokens=32000,  # Opus max output
            )
            logging.info(f"✅ Claude Opus generated econometric study: {len(content_en)} chars")
        except Exception as opus_err:
            logging.warning(f"⚠️ Claude Opus chain failed ({str(opus_err)[:150]}), falling back to GPT-5.1...")
            content_en = await call_openai_gpt5(
                system_message=SYSTEM_MESSAGE_GENERATION,
                user_message=user_prompt_en,
                temperature=0.3,
                max_tokens=128000
            )
        
        elapsed_call1 = time.time() - start_time_call1
        logging.info(f"✅ CALL 1 COMPLETE in {elapsed_call1:.1f}s")
        logging.info(f"   English study length: {len(content_en)} chars")
        
        if not content_en or len(content_en) < 10000:
            raise ValueError(f"Generated content too short: {len(content_en)} chars")
            
    except Exception as e:
        logging.error(f"❌ CALL 1 FAILED: {e}")
        raise HTTPException(status_code=500, detail=f"Failed to generate English study: {str(e)}")
    
    # ============================================================================
    # CALL 2: Translate to Spanish — section by section (avoids 16k token limit)
    # ============================================================================
    if language == 'es':
        logging.info("🌐 Translating econometric study to Spanish — section by section...")
        start_time_call2 = time.time()
        
        import asyncio
        
        async def _translate_section(sec: dict) -> dict:
            try:
                content_es = await translate_text_to_spanish(sec['content'])
                return {**sec, 'content': content_es}
            except Exception as te:
                logging.warning(f"⚠️ Translation failed for section {sec.get('section_number','?')}: {te} — keeping English")
                # Keep English content but mark as untranslated (do NOT silently pass English as Spanish)
                return {**sec, 'content': sec['content'], '_translation_failed': True}
        
        # Parse English sections first, then translate each one
        sections_en_raw = parse_markdown_sections(content_en, num_sections=16)
        sections_en = [{**s, 'content': clean_content(s['content'])} for s in sections_en_raw]
        
        translate_tasks = [_translate_section(s) for s in sections_en]
        sections_es_list = await asyncio.gather(*translate_tasks)
        sections_es = [{**s, 'content': clean_content(s['content'])} for s in sections_es_list]
        
        # Rebuild the full Spanish content from translated sections
        content_es = '\n\n'.join([f"## Section {s['number']}: {s['title']}\n\n{s['content']}" 
                                   for s in sections_es])
        content_es = clean_content(content_es)
        
        elapsed_call2 = time.time() - start_time_call2
        failed = sum(1 for s in sections_es if s.get('_translation_failed'))
        logging.info(f"✅ Section-by-section translation complete in {elapsed_call2:.1f}s")
        logging.info(f"   Sections translated: {len(sections_es) - failed}/{len(sections_es)}")
        if failed:
            logging.warning(f"   ⚠️ {failed} sections kept in English due to translation failure")
    else:
        # English requested: parse sections from English content
        sections_en_raw = parse_markdown_sections(content_en, num_sections=16)
        sections_en = [{**s, 'content': clean_content(s['content'])} for s in sections_en_raw]
        sections_es = sections_en  # same content for both
        content_es = content_en
        elapsed_call2 = 0
        logging.info("ℹ️ Spanish translation skipped (language=en)")

    # ============================================================================
    # 🔧 AUTO-RECOVERY: fill in any section that came back empty or too short.
    #
    # Claude Opus occasionally stops early (token budget, refusal, truncation)
    # leaving sections 13 (Limitations), 14 (Conclusions), 15 (Phases), or
    # 16 (Appendices) with empty content. Instead of emitting the useless
    # "Content not available for this section." placeholder in the final PDF,
    # we detect the gap here and issue a targeted follow-up generation call
    # for EACH missing section using the full 16-section titles list as
    # context. Generated content is spliced into both sections_en and
    # sections_es (re-translating only if Spanish was requested).
    # ============================================================================
    MIN_CONTENT_CHARS = 300  # sections under this length are considered missing

    # Build lookup by section number for quick checking
    sections_by_num_en = {s.get('number'): s for s in sections_en if s.get('number')}

    # Identify which of the 16 canonical sections are missing or too short
    missing_sections = []
    for i, title in enumerate(ECONOMETRIC_SECTIONS_EN, start=1):
        existing = sections_by_num_en.get(i)
        content_len = len((existing or {}).get('content', '') or '')
        if content_len < MIN_CONTENT_CHARS:
            missing_sections.append((i, title, content_len))

    if missing_sections:
        logging.warning(
            f"🔧 AUTO-RECOVERY: {len(missing_sections)} section(s) are empty/too short — "
            f"regenerating: {[(n, t, l) for n, t, l in missing_sections]}"
        )

        # Build a compact context summary from the sections we DO have, so the
        # follow-up calls produce content coherent with the rest of the study.
        def _summary_of_existing():
            parts = []
            for s in sections_en:
                num = s.get('number')
                if num and num not in {m[0] for m in missing_sections}:
                    txt = (s.get('content') or '').strip()
                    if txt:
                        # First 400 chars of each good section as context
                        parts.append(f"Section {num} ({s.get('title','')}):\n{txt[:400]}")
            return '\n\n'.join(parts)[:6000]

        context_summary = _summary_of_existing()

        async def _regenerate_missing_section(num: int, title: str, prev_len: int) -> dict:
            recovery_prompt = f"""You are completing a single missing section of an EB-2 NIW
econometric study. The rest of the 16-section study has been drafted and is
summarized below.

Generate ONLY Section {num}: {title}
Target length: 700–1,200 words. Write in professional econometric prose with
specific numbers, references to U.S. federal data sources (BLS, NSF, HHS,
NIH, DOE, USDA as appropriate), and analytical depth consistent with the
study below.

FORMAT RULES (MANDATORY):
- Begin with the heading EXACTLY as:   ## Section {num}: {title}
- Use Markdown only (no HTML tags, no code fences, no LaTeX, no bracketed flowcharts).
- Include 3-5 paragraphs with concrete metrics.
- Do NOT include ```plaintext / ```markdown wrappers.
- Do NOT cite Matter of Dhanasar (this is the quantitative study, not the legal brief).

## Project description:
{project_description[:2500]}

## Summary of the other sections already drafted:
{context_summary}

Now produce Section {num}: {title}."""
            try:
                generated = await call_claude_opus(
                    system_message="You are an expert econometrician completing a technical section of an EB-2 NIW impact study.",
                    user_message=recovery_prompt,
                    temperature=0.3,
                    max_tokens=4000,
                )
            except Exception as opus_err:
                logging.warning(f"  ⚠️ Opus recovery failed for section {num} ({opus_err}); trying GPT-5.1...")
                try:
                    generated = await call_openai_gpt5(
                        system_message="You are an expert econometrician completing a technical section of an EB-2 NIW impact study.",
                        user_message=recovery_prompt,
                        temperature=0.3,
                        max_tokens=4000,
                    )
                except Exception as gpt_err:
                    logging.error(f"  ❌ Both Opus and GPT-5.1 failed for section {num}: {gpt_err}")
                    return {'number': num, 'title': title, 'content': '', '_recovery_failed': True}

            # Parse the single generated section (should yield 1 section)
            parsed = parse_markdown_sections(generated, num_sections=1)
            if parsed and parsed[0].get('content') and len(parsed[0]['content']) >= MIN_CONTENT_CHARS:
                logging.info(
                    f"  ✅ Recovered section {num} ({title}): {len(parsed[0]['content'])} chars "
                    f"(was {prev_len})"
                )
                return {
                    'number': num,
                    'title': parsed[0].get('title') or title,
                    'content': clean_content(parsed[0]['content']),
                }
            # Fall back: use the raw generated text minus any header line
            raw_cleaned = re.sub(r'^\s*#{1,4}[^\n]*\n', '', generated, count=1).strip()
            raw_cleaned = clean_content(raw_cleaned)
            if len(raw_cleaned) >= MIN_CONTENT_CHARS:
                logging.info(
                    f"  ✅ Recovered section {num} via raw fallback: {len(raw_cleaned)} chars"
                )
                return {'number': num, 'title': title, 'content': raw_cleaned}
            logging.warning(f"  ⚠️ Recovery produced insufficient content for section {num}")
            return {'number': num, 'title': title, 'content': raw_cleaned, '_recovery_short': True}

        # Regenerate all missing sections in parallel (each is short, so this is fast)
        import asyncio as _asyncio
        recovery_results = await _asyncio.gather(
            *[_regenerate_missing_section(n, t, l) for n, t, l in missing_sections],
            return_exceptions=True,
        )

        # Splice recovered sections back into sections_en
        for res in recovery_results:
            if isinstance(res, Exception) or not res or not res.get('content'):
                continue
            num = res['number']
            # Find existing slot (if any) and replace, else append
            replaced = False
            for idx, s in enumerate(sections_en):
                if s.get('number') == num:
                    sections_en[idx] = {**s, **res}
                    replaced = True
                    break
            if not replaced:
                sections_en.append(res)

        # Re-sort by section number so the 16-section loop downstream works
        sections_en = sorted(sections_en, key=lambda s: s.get('number', 999))

        # If Spanish was requested, translate the newly-recovered sections
        if language == 'es':
            recovered_nums = {m[0] for m in missing_sections}
            async def _translate_recovered(sec):
                if sec.get('number') not in recovered_nums or not sec.get('content'):
                    return sec
                try:
                    sec_es_content = await translate_text_to_spanish(sec['content'])
                    return {**sec, 'content': clean_content(sec_es_content)}
                except Exception as te:
                    logging.warning(f"  ⚠️ Translation failed for recovered section {sec['number']}: {te}")
                    return sec
            # Rebuild sections_es: start from existing (which has good sections already translated)
            # and overlay the freshly translated recovered ones.
            existing_es_by_num = {s.get('number'): s for s in sections_es}
            merged_es = []
            for sec_en in sections_en:
                num = sec_en.get('number')
                if num in recovered_nums:
                    merged_es.append(await _translate_recovered(sec_en))
                elif num in existing_es_by_num:
                    merged_es.append(existing_es_by_num[num])
                else:
                    merged_es.append(sec_en)
            sections_es = sorted(merged_es, key=lambda s: s.get('number', 999))
        else:
            sections_es = list(sections_en)

        # Rebuild content strings
        content_en = '\n\n'.join(
            [f"## Section {s['number']}: {s['title']}\n\n{s['content']}" for s in sections_en]
        )
        if language == 'es':
            content_es = '\n\n'.join(
                [f"## Section {s['number']}: {s['title']}\n\n{s['content']}" for s in sections_es]
            )
        else:
            content_es = content_en
    # ============================================================================
    # END AUTO-RECOVERY
    # ============================================================================

    # ============================================================================
    # Sections are already parsed and cleaned inside the if/else above.
    # Just clean the full content strings for legacy uses.
    # ============================================================================
    logging.info("🧹 Final content cleanup...")
    content_en = clean_content(content_en)
    logging.info("   ✅ Content cleaned successfully")
    
    # ============================================================================
    # Parse sections and return structured data
    # ============================================================================
    total_time = time.time() - start_time_call1
    logging.info(f"🎉 GENERATION COMPLETE! Total time: {total_time:.1f}s (Call1: {elapsed_call1:.1f}s, Call2: {elapsed_call2:.1f}s)")
    logging.info(f"   sections_en parsed: {len(sections_en)}, sections_es parsed: {len(sections_es)}")
    
    return {
        "content_en": content_en,
        "content_es": content_es,
        "sections_en": sections_en,
        "sections_es": sections_es,
        "metadata": {
            "generation_time_seconds": total_time,
            "call1_time_seconds": elapsed_call1,
            "call2_time_seconds": elapsed_call2,
            "english_length_chars": len(content_en),
            "spanish_length_chars": len(content_es) if language == 'es' else 0,
            "method": "v2_2call",
            "model_generation": "gpt-5.1",
            "model_translation": "gpt-4o" if language == 'es' else None
        }
    }



async def generate_complete_whitepaper_v2(
    project_title: str,
    author_name: str,
    author_credentials: str,
    project_description: str,
    target_audience: str,
    technical_domain: str,
    language: str = 'en'
) -> dict:
    """
    New 2-call method for generating complete whitepapers.
    Call 1: GPT-5.1 generates full 16-section whitepaper in English
    Call 2: GPT-4o translates to Spanish
    
    Returns dict with:
        - content_en: Full English whitepaper (markdown)
        - content_es: Full Spanish whitepaper (markdown)
        - metadata: Generation statistics
    """
    from dotenv import load_dotenv
    load_dotenv()
    
    logging.info("🚀 Starting V2 Whitepaper Generation (2-call method)")
    logging.info(f"   Project: {project_title}")
    logging.info(f"   Technical domain: {technical_domain}")
    logging.info(f"   Target language: {language}")
    
    # Import prompts
    from whitepaper_prompt_v2 import (
        SYSTEM_MESSAGE_GENERATION,
        USER_PROMPT_GENERATION_TEMPLATE,
        SYSTEM_MESSAGE_TRANSLATION,
        USER_PROMPT_TRANSLATION_TEMPLATE
    )
    
    # ============================================================================
    # CALL 1: Generate complete whitepaper in English using GPT-5.1
    # ============================================================================
    logging.info("📝 CALL 1/2: Generating complete 16-section whitepaper in English with GPT-5.1...")
    start_time_call1 = time.time()
    
    try:
        # Prepare user prompt
        user_prompt_en = USER_PROMPT_GENERATION_TEMPLATE.format(
            project_title=project_title,
            author_name=author_name,
            author_credentials=author_credentials,
            project_description=project_description,
            target_audience=target_audience,
            technical_domain=technical_domain
        )
        
        logging.info(f"   Prompt length: {len(user_prompt_en)} chars")
        logging.info("   Sending to GPT-5.1 (may take 90-120 seconds, with OpenRouter fallback)...")
        
        # Use call_openai_gpt5 which has built-in OpenRouter fallback (Claude Opus / Gemini Pro)
        content_en = await call_openai_gpt5(
            system_message=SYSTEM_MESSAGE_GENERATION,
            user_message=user_prompt_en,
            temperature=0.3,
            max_tokens=128000
        )
        
        elapsed_call1 = time.time() - start_time_call1
        logging.info(f"✅ CALL 1 COMPLETE in {elapsed_call1:.1f}s")
        logging.info(f"   English whitepaper length: {len(content_en)} chars")
        
        if not content_en or len(content_en) < 10000:
            raise ValueError(f"Generated content too short: {len(content_en)} chars")
            
    except Exception as e:
        logging.error(f"❌ CALL 1 FAILED: {e}")
        raise Exception(f"Failed to generate English whitepaper: {str(e)}")
    
    # ============================================================================
    # CALL 2: Translate to Spanish — chunked by paragraph to avoid 16k token limit
    # ============================================================================
    content_es = ""
    elapsed_call2 = 0
    
    if language == 'es':
        logging.info("🌐 Translating whitepaper to Spanish — chunked by paragraphs...")
        start_time_call2 = time.time()
        
        try:
            content_es = await translate_text_to_spanish(content_en)
            elapsed_call2 = time.time() - start_time_call2
            logging.info(f"✅ Translation complete in {elapsed_call2:.1f}s ({len(content_es)} chars)")
            
            if not content_es or len(content_es) < 5000:
                raise ValueError(f"Translated whitepaper too short: {len(content_es)} chars")
                
        except Exception as e:
            logging.error(f"❌ Whitepaper translation FAILED: {e}")
            raise Exception(f"Failed to translate to Spanish: {str(e)}")
    else:
        logging.info("ℹ️ Spanish translation skipped (language=en)")
    
    total_time = elapsed_call1 + elapsed_call2
    logging.info(f"🎉 V2 WHITEPAPER GENERATION COMPLETE")
    logging.info(f"   Total time: {total_time:.1f}s")
    logging.info(f"   English: {len(content_en)} chars")
    if language == 'es':
        logging.info(f"   Spanish: {len(content_es)} chars")
    
    return {
        "content_en": content_en,
        "content_es": content_es,
        "metadata": {
            "generation_time_seconds": total_time,
            "call1_time_seconds": elapsed_call1,
            "call2_time_seconds": elapsed_call2,
            "english_length_chars": len(content_en),
            "spanish_length_chars": len(content_es) if language == 'es' else 0,
            "method": "v2_2call",
            "model_generation": "gpt-5.1",
            "model_translation": "gpt-4o" if language == 'es' else None
        }
    }



def parse_markdown_sections(markdown_text: str, num_sections: int = 16) -> list:
    """
    Parse markdown study into individual sections.
    Returns list of dicts with section_number, title, and content.
    Supports multiple header formats:
    - ## Section N: Title
    - ## Sección N: Title
    - # Section N: Title
    - ### Section N: Title
    - <h2>Section N: Title</h2>
    - **Section N: Title**
    - SECTION N: TITLE (all caps)
    """
    import re
    sections = []

    if not markdown_text:
        return sections

    # Unified section header regex — handles all formats the AI might generate
    SECTION_RE = re.compile(
        r'^(?:'
        r'#{1,4}\s+(?:Section|Secci[oó]n)\s+(\d+)\s*[:\-\.]\s*(.*)'  # ## Section N: Title
        r'|<h[1-4][^>]*>\s*(?:Section|Secci[oó]n)\s+(\d+)\s*[:\-\.]\s*(.*?)\s*</h[1-4]>'  # <h2>Section N: Title</h2>
        r'|\*\*(?:Section|Secci[oó]n)\s+(\d+)\s*[:\-\.]\s*(.*?)\*\*'  # **Section N: Title**
        r'|(?:SECTION|SECCIÓN|SECCION)\s+(\d+)\s*[:\-\.]\s*(.*)'  # SECTION N: TITLE
        r'|#{1,4}\s+(\d+)\s*[\.:]\s+(.+)'  # ## N. Title  or  ## N: Title  (Claude Opus format)
        r'|\*\*(\d+)\s*[\.:]\s+(.+?)\*\*'  # **N. Title** (bold numbered)
        r')',
        re.IGNORECASE
    )

    current_section = None
    current_content = []

    for line in markdown_text.split('\n'):
        m = SECTION_RE.match(line.strip())
        if m:
            # Save previous section
            if current_section:
                sections.append({
                    'number': current_section['number'],
                    'title':  current_section['title'],
                    'content': '\n'.join(current_content).strip()
                })
            # Extract number + title from whichever group matched
            groups = m.groups()  # 12 groups: 6 patterns * 2 groups each
            section_num  = None
            section_title = None
            for i in range(0, len(groups), 2):
                if groups[i] is not None:
                    section_num   = int(groups[i])
                    section_title = (groups[i+1] or '').strip()
                    # Strip residual HTML tags from title
                    section_title = re.sub(r'<[^>]+>', '', section_title).strip()
                    break
            if section_num is None:
                continue
            current_section = {'number': section_num, 'title': section_title or f'Section {section_num}'}
            current_content = []
        else:
            if current_section:
                current_content.append(line)

    # Add last section
    if current_section:
        sections.append({
            'number': current_section['number'],
            'title':  current_section['title'],
            'content': '\n'.join(current_content).strip()
        })

    logging.info(f"📄 Parsed {len(sections)} sections from markdown (input length: {len(markdown_text)} chars)")

    # 🔁 Fallback parser: if the strict regex matched 0 sections OR fewer than half
    # of the expected num_sections, try a permissive second pass that splits on ANY
    # top-level heading (## or #) and numbers them sequentially. This saves studies
    # where the LLM emitted headings like "## Cover Page" without explicit "Section N".
    if len(sections) < max(1, num_sections // 2):
        logging.warning(f"⚠️ Strict parse yielded only {len(sections)} sections; trying permissive fallback...")
        permissive = []
        current = None
        current_buf = []
        # Match any top-level heading: # / ## / ### / #### followed by text
        generic_re = re.compile(r'^(#{1,4})\s+(.+?)\s*$')
        # Detect sub-section numbering like "5.2", "5.2.1", "A.3"; these should
        # NOT start a new section — they are sub-headings inside the current section.
        subsection_re = re.compile(r'^\s*[A-Za-z]?\d+\.\d+')
        for line in markdown_text.split('\n'):
            stripped = line.strip()
            m = generic_re.match(stripped)
            if m and len(m.group(1)) <= 2:  # only # or ## (top-level)
                raw_title = m.group(2).strip().lstrip('#').strip()
                # Skip if the title starts with sub-section numbering (5.1, 5.2, etc.)
                # → keep it as content of the current section.
                if subsection_re.match(raw_title):
                    if current is not None:
                        current_buf.append(line)
                    continue
                # Close previous section
                if current is not None:
                    permissive.append({
                        'number': len(permissive) + 1,
                        'title': current,
                        'content': '\n'.join(current_buf).strip()
                    })
                # Strip leading numbering like "1. " or "1: " (but NOT "5.2 ")
                raw_title = re.sub(r'^\d+\s*[\.:]\s+', '', raw_title).strip()
                # Strip bold wrappers
                raw_title = raw_title.strip('*').strip()
                current = raw_title or f'Section {len(permissive)+1}'
                current_buf = []
            else:
                if current is not None:
                    current_buf.append(line)
        if current is not None:
            permissive.append({
                'number': len(permissive) + 1,
                'title': current,
                'content': '\n'.join(current_buf).strip()
            })

        # Keep only sections with meaningful content
        permissive = [s for s in permissive if len(s['content']) > 80]

        if len(permissive) > len(sections):
            logging.warning(f"✅ Permissive parser recovered {len(permissive)} sections (vs {len(sections)} strict)")
            sections = permissive[:num_sections]
            # Re-number sequentially to match expected 1..N
            for i, s in enumerate(sections):
                s['number'] = i + 1

    return sections


