# ⭐ Global exception handler for validation errors
@app.exception_handler(RequestValidationError)
async def validation_exception_handler(request: Request, exc: RequestValidationError):
    """Log detailed validation errors"""
    logging.error(f"❌ Validation error on {request.method} {request.url.path}")
    
    # Handle errors safely for JSON serialization
    try:
        errors = exc.errors()
        # Convert any bytes in errors to string representation
        safe_errors = []
        for error in errors:
            safe_error = {}
            for key, value in error.items():
                if isinstance(value, bytes):
                    safe_error[key] = f"<bytes: {len(value)} bytes>"
                else:
                    safe_error[key] = value
            safe_errors.append(safe_error)
    except Exception as e:
        safe_errors = [{"error": f"Could not parse validation errors: {str(e)}"}]
    
    logging.error(f"   Errors: {safe_errors}")
    
    # Handle body safely for JSON serialization
    body_info = "N/A"
    if hasattr(exc, 'body') and exc.body:
        if isinstance(exc.body, bytes):
            body_info = f"<bytes: {len(exc.body)} bytes>"
        else:
            body_info = str(exc.body)
    
    logging.error(f"   Body: {body_info}")
    
    return JSONResponse(
        status_code=422,
        content={"detail": safe_errors, "body": body_info},
    )

