async def search_sources_for_niw(topic: str, industry: str, num_results: int = 5) -> dict:
    """
    Search for authoritative sources using Firecrawl to back up NIW business plan claims.
    
    Returns:
        {
            "statistics": [{"fact": "...", "source": "...", "year": "..."}],
            "market_data": [{"data": "...", "source": "...", "year": "..."}],
            "federal_policies": [{"policy": "...", "details": "..."}],
            "search_queries_used": [...]
        }
    """
    results = {
        "statistics": [],
        "market_data": [],
        "federal_policies": [],
        "academic_sources": [],
        "search_queries_used": [],
        "raw_content": ""
    }
    
    firecrawl_key = os.environ.get('FIRECRAWL_API_KEY')
    if not firecrawl_key or not FIRECRAWL_AVAILABLE:
        logging.warning("⚠️ Firecrawl not available for source research")
        return results
    
    try:
        async_app = AsyncFirecrawlApp(api_key=firecrawl_key)
        scrape_opts = FirecrawlScrapeOptions(formats=["markdown"], only_main_content=True)
        
        # Build search queries for different types of sources — more targeted
        # Extract key terms from topic for precise government source searches
        topic_keywords = topic.replace(',', ' ').split()[:6]
        topic_short = " ".join(topic_keywords[:4])
        industry_short = " ".join(industry.split()[:3])
        
        search_queries = [
            f"{topic_short} statistics 2023 2024 site:bls.gov OR site:census.gov OR site:sba.gov",
            f"{topic_short} economic impact federal report 2024",
            f"{industry_short} statistics government report 2024",
            f"{topic_short} growth rate industry data",
            f"{industry_short} jobs employment numbers federal",
        ]
        
        results["search_queries_used"] = search_queries
        
        all_content = []
        
        for query in search_queries[:3]:  # Limit to 3 queries to save API calls
            try:
                logging.info(f"🔍 [FIRECRAWL] Searching: {query}")
                
                # SDK v4: use async search with scrape_options for full content
                search_result = await async_app.search(
                    query=query,
                    limit=num_results,
                    scrape_options=scrape_opts
                )
                
                # SDK v4: result.web (not result.data)
                web_items = []
                if hasattr(search_result, 'web') and search_result.web:
                    web_items = search_result.web
                elif hasattr(search_result, 'data') and search_result.data:
                    web_items = search_result.data
                
                for item in web_items[:3]:
                    content = (getattr(item, 'markdown', '') or
                               getattr(item, 'content', '') or
                               getattr(item, 'description', '') or '')
                    meta = getattr(item, 'metadata', None)
                    source_url = getattr(item, 'url', '') or ''
                    if not source_url and meta:
                        source_url = getattr(meta, 'url', '') or ''
                    title = getattr(item, 'title', '') or ''
                    if not title and meta:
                        title = str(getattr(meta, 'title', '') or '').strip()
                    
                    if content:
                        all_content.append({
                            "content": content[:2000],
                            "url": source_url,
                            "title": title
                        })
                        
                        # Extract statistics from content
                        stats = extract_statistics_from_content(content, source_url)
                        results["statistics"].extend(stats)
                            
                logging.info(f"✅ [FIRECRAWL] Found {len(all_content)} results for query")
                
            except Exception as e:
                logging.warning(f"⚠️ [FIRECRAWL] Error searching '{query}': {str(e)[:100]}")
                continue
        
        # Compile raw content for AI to use
        results["raw_content"] = "\n\n---\n\n".join([
            f"SOURCE: {item['title']}\nURL: {item['url']}\n{item['content'][:1000]}"
            for item in all_content[:5]
        ])
        
        logging.info(f"✅ [FIRECRAWL] Research complete: {len(results['statistics'])} stats found")
        
    except Exception as e:
        logging.error(f"❌ [FIRECRAWL] Error in source research: {str(e)}")
    
    return results


def extract_statistics_from_content(content: str, source_url: str) -> list:
    """Extract statistical facts from scraped content"""
    statistics = []
    
    # Patterns to find statistics
    patterns = [
        # Dollar amounts: $X billion/million
        r'(\$[\d,.]+\s*(?:billion|million|trillion))',
        # Percentages with context
        r'(\d+(?:\.\d+)?%\s+(?:growth|increase|decrease|of|CAGR))',
        # Large numbers
        r'(\d{1,3}(?:,\d{3})+)\s+(?:jobs|employees|workers|people|Americans)',
        # Year-over-year stats
        r'(?:from|between)\s+(\d{4})\s+(?:to|and)\s+(\d{4})',
    ]
    
    for pattern in patterns:
        matches = re.findall(pattern, content, re.IGNORECASE)
        for match in matches[:2]:  # Limit matches per pattern
            if isinstance(match, tuple):
                match = " to ".join(match)
            
            # Find context around the match
            match_pos = content.find(str(match))
            if match_pos != -1:
                start = max(0, match_pos - 50)
                end = min(len(content), match_pos + len(str(match)) + 100)
                context = content[start:end].strip()
                
                # Extract year if present
                year_match = re.search(r'20\d{2}', context)
                year = year_match.group() if year_match else "2024"
                
                # Extract source name from URL
                source_name = extract_source_name(source_url)
                
                statistics.append({
                    "fact": context[:150],
                    "value": str(match),
                    "source": source_name,
                    "source_url": source_url,
                    "year": year
                })
    
    return statistics


def extract_source_name(url: str) -> str:
    """Extract a readable source name from URL"""
    if not url:
        return "Unknown Source"
    
    # Known authoritative sources
    source_mappings = {
        "bls.gov": "Bureau of Labor Statistics",
        "census.gov": "U.S. Census Bureau",
        "usgs.gov": "U.S. Geological Survey",
        "energy.gov": "U.S. Department of Energy",
        "epa.gov": "Environmental Protection Agency",
        "eia.gov": "Energy Information Administration",
        "fws.gov": "U.S. Fish and Wildlife Service",
        "nrel.gov": "National Renewable Energy Laboratory",
        "statista.com": "Statista",
        "ibisworld.com": "IBISWorld",
        "mckinsey.com": "McKinsey & Company",
        "deloitte.com": "Deloitte",
        "pwc.com": "PwC",
        "forbes.com": "Forbes",
        "bloomberg.com": "Bloomberg",
        "reuters.com": "Reuters",
        "sciencedirect.com": "ScienceDirect",
        "nature.com": "Nature",
        "science.org": "Science",
    }
    
    url_lower = url.lower()
    for domain, name in source_mappings.items():
        if domain in url_lower:
            return name
    
    # Extract domain name
    try:
        from urllib.parse import urlparse
        parsed = urlparse(url)
        domain = parsed.netloc.replace("www.", "")
        return domain.split('.')[0].title()
    except:
        return "Research Source"


# ============================================================================
# 🏛️ FUNCIONES PARA INVESTIGACIÓN CON INFORMES GUBERNAMENTALES
# ============================================================================

async def search_government_reports(topic: str, industry: str, section_context: str = "") -> dict:
    """
    Buscar específicamente en fuentes gubernamentales de EE.UU. para fortalecer propuestas NIW.
    
    Fuentes prioritarias:
    - Bureau of Labor Statistics (BLS)
    - Census Bureau
    - Federal agencies (.gov)
    - Congressional Research Service
    - GAO Reports
    """
    results = {
        "government_sources": [],
        "statistics": [],
        "policies": [],
        "search_queries": [],
        "raw_content": ""
    }
    
    firecrawl_key = os.environ.get('FIRECRAWL_API_KEY')
    if not firecrawl_key or not FIRECRAWL_AVAILABLE:
        logging.warning("⚠️ Firecrawl not available for government research")
        return results
    
    try:
        async_app = AsyncFirecrawlApp(api_key=firecrawl_key)
        scrape_opts = FirecrawlScrapeOptions(formats=["markdown"], only_main_content=True)
        
        # Queries específicas para fuentes gubernamentales
        gov_queries = [
            f"site:bls.gov {industry} employment statistics 2024",
            f"site:census.gov {topic} economic data",
            f"{industry} federal government report statistics USA",
            f"{topic} Congressional Research Service report",
            f"{industry} government policy economic impact United States 2024",
            f"site:gao.gov {industry} report findings",
        ]
        
        results["search_queries"] = gov_queries
        all_content = []
        
        for query in gov_queries[:4]:  # Limitar a 4 queries
            try:
                logging.info(f"🏛️ [GOV RESEARCH] Searching: {query}")
                
                # SDK v4: async search with scrape_options for full content
                search_result = await async_app.search(
                    query=query,
                    limit=3,
                    scrape_options=scrape_opts
                )
                
                # SDK v4: result.web (not result.data)
                web_items = []
                if hasattr(search_result, 'web') and search_result.web:
                    web_items = search_result.web
                elif hasattr(search_result, 'data') and search_result.data:
                    web_items = search_result.data

                for item in web_items[:2]:
                    content = (getattr(item, 'markdown', '') or
                               getattr(item, 'content', '') or
                               getattr(item, 'description', '') or '')
                    meta = getattr(item, 'metadata', None)
                    source_url = getattr(item, 'url', '') or ''
                    if not source_url and meta:
                        source_url = getattr(meta, 'url', '') or ''
                    title = getattr(item, 'title', '') or ''
                    if not title and meta:
                        title = str(getattr(meta, 'title', '') or '').strip()
                    
                    # Priorizar fuentes .gov
                    is_gov = '.gov' in source_url.lower() if source_url else False
                    
                    if content:
                        source_info = {
                            "content": content[:3000],
                            "url": source_url,
                            "title": title,
                            "source_name": extract_source_name(source_url),
                            "is_government": is_gov
                        }
                        all_content.append(source_info)
                        
                        # Extraer estadísticas
                        stats = extract_statistics_from_content(content, source_url)
                        for stat in stats:
                            stat["is_government"] = is_gov
                        results["statistics"].extend(stats)
                        
                        # Guardar fuentes gubernamentales por separado
                        if is_gov:
                            results["government_sources"].append(source_info)
                
                logging.info(f"✅ [GOV RESEARCH] Found {len(all_content)} results")
                
            except Exception as e:
                logging.warning(f"⚠️ [GOV RESEARCH] Error: {str(e)[:100]}")
                continue
        
        # Compilar contenido raw
        results["raw_content"] = "\n\n---\n\n".join([
            f"{'🏛️ GOVERNMENT SOURCE' if item.get('is_government') else '📊 SOURCE'}: {item['title']}\nURL: {item['url']}\n{item['content'][:1500]}"
            for item in all_content[:6]
        ])
        
        logging.info(f"✅ [GOV RESEARCH] Complete: {len(results['government_sources'])} gov sources, {len(results['statistics'])} stats")
        
    except Exception as e:
        logging.error(f"❌ [GOV RESEARCH] Error: {str(e)}")
    
    return results


# REMOVED: strengthen-with-research endpoint - functionality integrated into section generation


async def get_research_for_section(section_number: int, project_description: str, industry: str) -> str:
    """
    Get relevant research data for a specific NIW section using Firecrawl.
    All queries run IN PARALLEL with a hard timeout to avoid blocking generation.
    """
    if not FIRECRAWL_AVAILABLE or not os.environ.get('FIRECRAWL_API_KEY'):
        return ""

    section_research_focus = {
        2: "statistics national importance economic impact",
        3: "professional qualifications credentials industry impact",
        4: "problem statistics crisis fatality rate injuries costs",
        5: "economic impact national importance GDP jobs federal policy",
        6: "solution methodology innovation technology approach",
        7: "market size growth rate industry trends data",
        8: "implementation timeline milestones federal programs",
        9: "revenue projections financial forecast ROI data",
        10: "job creation employment economic benefits communities",
        11: "national interest waiver EB-2 NIW precedent policy",
        12: "industry regulatory requirements federal standards",
        13: "risk assessment safety compliance data statistics",
        14: "competitive analysis technology comparison industry",
        15: "long term impact sustainability national benefit",
        16: "official statistics government report authoritative source",
    }

    focus = section_research_focus.get(section_number, "statistics government report")

    # Domain-specific keywords from project description
    stopwords = {'the','of','in','a','an','and','or','for','to','with','that','this','is','are',
                 'la','el','los','las','de','del','en','y','con','para','por','que','una','un'}
    meaningful = [w for w in project_description.split() if len(w) > 4 and w.lower() not in stopwords]
    domain = " ".join(meaningful[:4])
    short = " ".join(meaningful[:2])

    # Only 2 targeted queries — run IN PARALLEL
    queries = [
        f"{short} {focus} statistics 2024 site:bls.gov OR site:osha.gov OR site:census.gov OR site:niosh.cdc.gov",
        f"{domain} government report statistics 2023 2024",
    ]

    firecrawl_key = os.environ.get('FIRECRAWL_API_KEY')
    async_app = AsyncFirecrawlApp(api_key=firecrawl_key)
    scrape_opts = FirecrawlScrapeOptions(formats=["markdown"], only_main_content=True)

    async def run_query(q: str):
        try:
            result = await asyncio.wait_for(
                async_app.search(q, limit=3, scrape_options=scrape_opts),
                timeout=8.0  # Hard 8-second timeout per query
            )
            items = getattr(result, 'web', None) or getattr(result, 'data', []) or []
            stats = []
            raw = ""
            for item in items[:2]:
                url = getattr(item, 'url', '') or ''
                title = getattr(item, 'title', '') or ''
                content = (getattr(item, 'markdown', '') or getattr(item, 'content', '') or
                           getattr(item, 'description', '') or '')
                if content:
                    stats.extend(extract_statistics_from_content(content, url))
                    raw += f"\nSOURCE: {title}\nURL: {url}\n{content[:600]}\n"
            return stats, raw
        except asyncio.TimeoutError:
            logging.warning(f"⚠️ [RESEARCH] Query timed out (8s): {q[:60]}")
            return [], ""
        except Exception as e:
            logging.warning(f"⚠️ [RESEARCH] Query failed: {str(e)[:60]}")
            return [], ""

    # Run ALL queries simultaneously
    results = await asyncio.gather(*[run_query(q) for q in queries])

    all_stats = []
    all_raw = ""
    seen = set()
    for stats, raw in results:
        for s in stats:
            key = s.get('fact', '')[:50]
            if key not in seen:
                seen.add(key)
                all_stats.append(s)
        all_raw += raw

    if not all_stats and not all_raw.strip():
        return ""

    formatted = "\n[DATOS VERIFICADOS — JAMÁS uses [FUENTE A VERIFICAR] o [CITACIÓN NECESARIA]]\n"
    if all_stats:
        formatted += "📊 ESTADÍSTICAS:\n"
        for s in all_stats[:6]:
            formatted += f"  - {s.get('value','')}: {s.get('fact','')[:150]} (Fuente: {s.get('source','')}, {s.get('year','')})\n"
    if all_raw.strip():
        formatted += f"\n📚 FUENTES:\n{all_raw[:2000]}\n"
    formatted += "[FIN DATOS — Cita siempre. Cero placeholders.]\n"
    return formatted


async def resolve_placeholders_with_firecrawl(content: str) -> str:
    """
    Post-generation: replace any remaining placeholders with real citations.
    Runs parallel queries with hard timeouts. Max 8 placeholders resolved.

    Handles two families of placeholders:
      • Legacy citation placeholders — [FUENTE A VERIFICAR: ...], [CITATION NEEDED: ...]
      • Whitepaper data placeholders — [pending information], [NEEDED: ...], [TBD: ...],
        [to be determined: ...], [pending data], [placeholder: ...], [missing: ...]
    """
    if not FIRECRAWL_AVAILABLE or not os.environ.get('FIRECRAWL_API_KEY'):
        return content

    import re as _re

    # Citation-style placeholders (resolve → "(source, year)")
    citation_re = _re.compile(
        r'\[(FUENTE A VERIFICAR|CITACIÓN NECESARIA|CITATION NEEDED|SOURCE TO VERIFY|CITA A VERIFICAR|REFERENCIA NECESARIA):([^\]]{5,500})\]',
        _re.IGNORECASE
    )
    # Whitepaper data-placeholder variants — resolve → a short qualitative statement
    data_re = _re.compile(
        r'\[(pending(?:\s+information|\s+data)?|NEEDED(?:\s*[—\-:]\s*[^\]]{0,800})?|TBD(?:\s*[—\-:]\s*[^\]]{0,800})?|TODO(?:\s*[—\-:]\s*[^\]]{0,800})?|'
        r'to\s+be\s+(?:determined|added|filled|completed|provided)(?:[^\]]{0,800})?|'
        r'placeholder(?:\s*[—\-:]\s*[^\]]{0,800})?|missing(?:\s+data)?(?:[^\]]{0,800})?|'
        r'describe\s+(?:qualitatively|here|below)(?:[^\]]{0,800})?|'
        # Generic prompt-template labels the LLM forgot to fill
        r'Organization|Company|Employer|Institution|Role|Role\s+Title|Job\s+Title|Position|Title|Name|'
        r'Start\s+Date|End\s+Date|Date|Year|Year\s+Range|Date\s+Range|Dates|Timeframe|Period|Duration|'
        r'Source|Citation|Reference|Publication|Journal|Volume|Issue|Page(?:\s+Number)?|'
        r'Country|State|City|Location|Region|Industry|Sector|Field|Domain|'
        r'Metric(?:\s+Name|\s+Value)?|Baseline(?:\s+Value)?|Target(?:\s+Value)?|Value|Number|Amount|Range|'
        r'Methodology(?:\s+\d+)?\s+Name|Framework\s+Name|'
        r'X|Y|Z|X%|Y%|Z%|[A-Z]\s+(?:employees?|clients?|companies?|patients?|years?))\]',
        _re.IGNORECASE
    )

    citation_matches = list(citation_re.finditer(content))[:3]
    data_matches = list(data_re.finditer(content))[:15]

    if not citation_matches and not data_matches:
        # No resolvable matches — still run the final bracket strip below
        content = _strip_unresolved_brackets(content)
        return content

    logging.info(
        f"🔧 [RESOLVE] Resolving {len(citation_matches)} citation + "
        f"{len(data_matches)} data placeholders in parallel"
    )

    firecrawl_key = os.environ.get('FIRECRAWL_API_KEY')
    async_app = AsyncFirecrawlApp(api_key=firecrawl_key)
    scrape_opts = FirecrawlScrapeOptions(formats=["markdown"], only_main_content=True)

    def _context_window(match, span: int = 280) -> str:
        """Extract ±span chars of context around a placeholder match (stripped of HTML)."""
        start = max(0, match.start() - span)
        end = min(len(content), match.end() + span)
        ctx = content[start:end]
        ctx = _re.sub(r'<[^>]+>', ' ', ctx)
        return _re.sub(r'\s+', ' ', ctx).strip()

    async def resolve_citation(match):
        ph_type, description = match.group(1), match.group(2)
        words = [w for w in description.strip().split() if len(w) > 3][:6]
        query = " ".join(words) + " site:bls.gov OR site:osha.gov OR site:census.gov OR site:cdc.gov"
        try:
            sr = await asyncio.wait_for(
                async_app.search(query, limit=2, scrape_options=scrape_opts),
                timeout=6.0
            )
            items = getattr(sr, 'web', None) or getattr(sr, 'data', []) or []
            if items:
                item = items[0]
                url = getattr(item, 'url', '') or ''
                text = getattr(item, 'markdown', '') or getattr(item, 'description', '') or ''
                stats = extract_statistics_from_content(text, url)
                if stats:
                    s = stats[0]
                    return f"({s.get('source','')}, {s.get('year','2024')})"
                domain = url.split('/')[2] if url.startswith('http') else 'gobierno federal'
                return f"({domain}, 2024)"
        except (asyncio.TimeoutError, Exception):
            pass
        return ""

    async def resolve_data(match):
        """Replace a `[pending …]` / `[NEEDED: …]` style placeholder with
        a short, neutral qualitative sentence derived from Firecrawl search +
        the surrounding paragraph context."""
        ctx = _context_window(match)
        # Remove the placeholder itself so it doesn't skew the query
        ctx = _re.sub(r'\[[^\]]+\]', '', ctx, count=1)
        # Build query from first meaningful words of context (prefer longer words)
        keywords = [w for w in _re.findall(r'[A-Za-z][A-Za-z\-]{4,}', ctx)][:8]
        if not keywords:
            return "qualitatively assessed based on available documentation"
        query = " ".join(keywords[:6])
        # Prefer government / academic sources for factual support
        query += " site:bls.gov OR site:census.gov OR site:cdc.gov OR site:nih.gov OR site:gao.gov"
        try:
            sr = await asyncio.wait_for(
                async_app.search(query, limit=2, scrape_options=scrape_opts),
                timeout=6.0
            )
            items = getattr(sr, 'web', None) or getattr(sr, 'data', []) or []
            if items:
                item = items[0]
                url = getattr(item, 'url', '') or ''
                text = getattr(item, 'markdown', '') or getattr(item, 'description', '') or ''
                stats = extract_statistics_from_content(text, url)
                if stats:
                    s = stats[0]
                    val = s.get('value', '')
                    label = s.get('label', '') or s.get('description', '')
                    if val and label:
                        return f"approximately {val} {label} (source: {s.get('source','gov data')}, {s.get('year','2024')})"
                    if val:
                        return f"approximately {val} (source: {s.get('source','gov data')}, {s.get('year','2024')})"
                domain = url.split('/')[2] if url.startswith('http') else 'federal data'
                return f"documented in the referenced source ({domain}, 2024)"
        except (asyncio.TimeoutError, Exception):
            pass
        # Graceful fallback — no empty brackets left over
        return "qualitatively assessed based on available documentation"

    # Resolve in parallel
    all_coros = (
        [resolve_citation(m) for m in citation_matches] +
        [resolve_data(m) for m in data_matches]
    )
    resolutions = await asyncio.gather(*all_coros)
    citation_resolutions = resolutions[:len(citation_matches)]
    data_resolutions = resolutions[len(citation_matches):]

    # Apply all matches in reverse order across the single content string
    all_matches_with_res = (
        list(zip(citation_matches, citation_resolutions)) +
        list(zip(data_matches, data_resolutions))
    )
    all_matches_with_res.sort(key=lambda x: x[0].start(), reverse=True)
    for match, replacement in all_matches_with_res:
        content = content[:match.start()] + replacement + content[match.end():]

    # Final pass: strip any remaining unresolved brackets so the stored content
    # never exposes raw placeholders to the reader.
    content = _strip_unresolved_brackets(content)

    return content


# ── Unresolved-placeholder final strip ──────────────────────────────────────
_UNRESOLVED_BRACKET_PATTERNS = [
    # Explicit NEEDED/TBD/TODO/Requerido style — supports ':' or '—' or '-' separator
    (re.compile(r'\[\s*(?:NEEDED|TBD|TODO|REQUERIDO|NECESARIO|PENDING(?:\s+INFORMATION|\s+DATA)?|PLACEHOLDER|MISSING(?:\s+DATA)?)\s*(?:\s*[—\-:]\s*[^\]]{0,800})?\]',
                re.IGNORECASE),
     'pending_info'),
    # Generic single-word or short-phrase placeholders the LLM invents when it
    # lacks data (e.g. `[Organization]`, `[Leading Financial Institution]`,
    # `[Economic Association]`, `[Your Company]`, `[Start Date]`).
    # Only strip bracketed phrases that look like descriptor labels: 1–6
    # capitalized words, no digits, no punctuation, no URL chars.
    (re.compile(r'\[\s*([A-Z][A-Za-z]*(?:\s+[A-Z][A-Za-z]*){0,5})\s*\](?!\()'),
     'descriptor'),
    # Insert/Specify/Describe style
    (re.compile(r'\[\s*(?:INSERT|SPECIFY|DESCRIBE|ADD|PROVIDE|ENTER)[^\]]{0,120}\]',
                re.IGNORECASE),
     'action'),
    # "Your …" style prompts
    (re.compile(r'\[\s*YOUR\s+[^\]]{0,120}\]', re.IGNORECASE), 'your_x'),
    # X, Y, Z or single letter placeholder like [X%] or [X]
    (re.compile(r'\[\s*[XYZ]\s*(?:%|pct|percent)?\s*\]', re.IGNORECASE), 'x_var'),
]


def _strip_unresolved_brackets(text: str) -> str:
    """Remove bracketed placeholder leftovers from any content.

    These are the patterns Firecrawl either could not resolve or that fall
    outside its regex (generic descriptor labels the LLM invented). They are
    replaced with neutral phrasing so the output never exposes raw brackets.
    """
    if not text:
        return text

    # ── 0. Finding/Dhanasar headlines + "documentation pending" narrative ──
    # The LLM emits bold headlines like "Finding: SATISFIED", "Finding: MET
    # (subject to submission of employer letters)", "Finding: qualitatively
    # assessed based on available documentation", "Findings: Partial",
    # "Note to Counsel: …", as well as narrative sentences that openly admit
    # missing evidence ("counsel is gathering", "to be provided", "will be
    # submitted upon receipt", etc.).  Every one of these tells a USCIS
    # adjudicator that the petition is INCOMPLETE. We strip them all.
    negative_findings = [
        # "Finding: <anything>" — entire line removed regardless of what follows
        r'(?im)^\*{0,2}\s*Finding(?:s)?\s*:\s*\*{0,2}[^\n]*\n',
        # "Does (the) petitioner meet this…" headline
        r'(?im)^\*{0,2}\s*Does\s+(?:the\s+)?petitioner\s+meet\s+this[^\n]*\n',
        # "Note to Counsel: …" / "Nota para el abogado: …" editorial aside
        r'(?im)^\*{0,2}\s*(?:Note\s+to\s+Counsel|Nota\s+(?:al|para\s+el)\s+(?:Abogado|Counsel))\s*:\s*\*{0,2}[^\n]*\n',
        # "Criterion N: MET / NOT MET / Partial" single-line verdict
        r'(?im)^\*{0,2}\s*Criterion\s+\d+(?:\s*\([^)]*\))?\s*:\s*\*{0,2}\s*(?:NOT\s+)?(?:MET|SATISFIED|ESTABLISHED|DEMONSTRATED|QUALIFIED|FULFILLED|PARTIAL(?:LY\s+MET)?)\s*[^\n]*\n',
    ]
    import re as _re_local
    for pat in negative_findings:
        text = _re_local.sub(pat, '', text)

    # ── 0.b. Sentence-level scrubs for "pending documentation" language ───
    # Replace hedging phrases with neutral/assertive language so the reader
    # never sees "this will be submitted upon receipt" style statements.
    sentence_scrubs = [
        # Standalone sentences that openly admit missing evidence — delete the
        # ENTIRE sentence (from the start of the sentence up to and including
        # the final period).  We match sentence bodies up to 400 chars.
        (r'(?i)[^.!?\n]*?\b(?:counsel\s+is\s+(?:gathering|investigating(?:\s+and\s+gathering)?|collecting|securing)|petitioner\'?s?\s+counsel\s+is\s+gathering)[^.!?\n]{0,400}[.!?]', ''),
        (r'(?i)[^.!?\n]*?\bwill\s+be\s+(?:addressed|provided|submitted|supplied|completed|finalized)(?:\s+upon\s+receipt|\s+as\s+soon\s+as)?[^.!?\n]{0,300}[.!?]', ''),
        (r'(?i)[^.!?\n]*?\bto\s+be\s+provided\s+in\s+(?:the\s+)?(?:final\s+evidentiary\s+package|Exhibit\s+[A-Z0-9]+)[^.!?\n]{0,300}[.!?]', ''),
        (r'(?i)[^.!?\n]*?\bThis\s+criterion\s+will\s+be\s+addressed[^.!?\n]{0,300}[.!?]', ''),
        # Inline phrase "qualitatively assessed based on available documentation"
        # — remove the phrase anywhere (with preceding connector/comma/parens)
        # because the LLM embeds it inside complex sentences rather than as
        # a standalone clause.
        (r'(?i)\s*[,;:]?\s*\(?\s*qualitatively\s+assessed\s+based\s+on\s+available\s+documentation\s*\)?', ''),
        (r'(?i)\s*[,;:]?\s*\(?\s*qualitatively\s+(?:assessed|evaluated|established)\s+(?:from|via|using|based\s+on)\s+(?:the\s+)?(?:available|provided|existing)\s+(?:CV\s+)?documentation\s*\)?', ''),
        # Inline phrase "(subject to submission of …)" — remove the parenthetical
        (r'(?i)\s*\(\s*subject\s+to\s+(?:submission|receipt|provision)\s+of[^)]{0,200}\)', ''),
        (r'(?i)\s*\(\s*pending\s+(?:submission|receipt|provision|review)\s+of[^)]{0,200}\)', ''),
    ]
    for pat, replacement in sentence_scrubs:
        text = _re_local.sub(pat, replacement, text)

    # Collapse whitespace/empty-line debris left by the strips above
    text = _re_local.sub(r'\n{3,}', '\n\n', text)
    text = _re_local.sub(r'(?m)^\s+$', '', text)
    # Fix punctuation debris from inline phrase removal
    text = _re_local.sub(r'\s+([,.;:])', r'\1', text)
    text = _re_local.sub(r'\(\s*\)', '', text)
    text = _re_local.sub(r'  +', ' ', text)

    if '[' not in text:
        return text

    # List of legit things that MUST NOT be stripped — scientific citations,
    # URLs, markdown reference-style links, legal citations like [9 C.F.R.].
    # These patterns are safe from the rules above because they contain digits
    # or punctuation that the regexes above do not match.

    def _replace_descriptor(m):
        phrase = m.group(1).strip()
        low = phrase.lower()
        # keep a whitelist of short phrases that are almost certainly content
        # (acronyms, units, trademarks etc.)
        if low in {
            'note', 'see', 'ref', 'source', 'citation', 'id', 'name', 'date',
            'fig', 'table', 'eq', 'section', 'chapter', 'appendix',
        }:
            return m.group(0)
        # 1-word generic placeholder → drop completely
        if ' ' not in phrase:
            return ''
        # Multi-word descriptor → qualitative phrase
        return 'a recognized institution'

    for pattern, kind in _UNRESOLVED_BRACKET_PATTERNS:
        if kind == 'descriptor':
            text = pattern.sub(_replace_descriptor, text)
        elif kind in ('pending_info', 'action', 'your_x'):
            text = pattern.sub('', text)
        elif kind == 'x_var':
            text = pattern.sub('', text)

    # Clean up double spaces / empty parens that can result from replacements
    text = re.sub(r'\(\s*,\s*\)', '', text)
    text = re.sub(r'\(\s*\)', '', text)
    text = re.sub(r'  +', ' ', text)
    text = re.sub(r' ,', ',', text)
    text = re.sub(r' \.', '.', text)
    return text


def clean_content(content: str) -> str:
    """Clean content removing problematic Unicode characters that appear as black squares"""
    if not content:
        return content
    
    # 🧹 Strip accidental markdown code-fence wrappers that some LLMs (esp. Claude)
    # add around entire responses: ```plaintext ... ``` / ```markdown ... ``` / etc.
    import re as _re_cc
    _t = content.strip()
    _m = _re_cc.match(r'^```[a-zA-Z0-9_\-]*\s*\n(.*?)\n?```\s*$', _t, flags=_re_cc.DOTALL)
    if _m:
        content = _m.group(1).strip()
    else:
        # Strip only dangling leading/trailing fences
        content = _re_cc.sub(r'^```[a-zA-Z0-9_\-]*\s*\n', '', _t)
        content = _re_cc.sub(r'\n```\s*$', '', content)
    
    # Replace problematic dashes/hyphens with normal hyphen-minus
    content = content.replace('\u2011', '-')  # Non-breaking hyphen → normal hyphen
    content = content.replace('\u2010', '-')  # Hyphen → normal hyphen
    content = content.replace('\u2013', '-')  # En dash → normal hyphen
    content = content.replace('\u2014', '-')  # Em dash → normal hyphen
    content = content.replace('\u2212', '-')  # Minus sign → normal hyphen
    content = content.replace('–', '-')  # En dash (if not caught above)
    content = content.replace('—', '-')  # Em dash (if not caught above)
    content = content.replace('‐', '-')  # Unicode hyphen
    content = content.replace('‑', '-')  # Non-breaking hyphen (if not caught above)
    
    # Replace smart quotes with straight quotes
    content = content.replace('\u2018', "'")  # Left single quotation mark → apostrophe
    content = content.replace('\u2019', "'")  # Right single quotation mark → apostrophe
    content = content.replace('\u201a', "'")  # Single low-9 quotation mark → apostrophe
    content = content.replace('\u201b', "'")  # Single high-reversed-9 quotation mark → apostrophe
    content = content.replace('\u201c', '"')  # Left double quotation mark → straight quote
    content = content.replace('\u201d', '"')  # Right double quotation mark → straight quote
    content = content.replace('\u201e', '"')  # Double low-9 quotation mark → straight quote
    content = content.replace('\u201f', '"')  # Double high-reversed-9 quotation mark → straight quote
    content = content.replace(''', "'")  # Left single quote (literal)
    content = content.replace(''', "'")  # Right single quote (literal)
    content = content.replace('"', '"')  # Left double quote (literal)
    content = content.replace('"', '"')  # Right double quote (literal)
    
    # Remove or replace problematic Unicode characters
    content = content.replace('■', '')  # Remove black squares
    content = content.replace('□', '')  # Remove white squares
    content = content.replace('▪', '•')  # Replace black small square with bullet
    content = content.replace('▫', '•')  # Replace white small square with bullet
    content = content.replace('◾', '•')  # Replace black medium square with bullet
    content = content.replace('◽', '•')  # Replace white medium square with bullet
    content = content.replace('\u25a0', '')  # Unicode black square
    content = content.replace('\u25a1', '')  # Unicode white square
    content = content.replace('\u2588', '')  # Full block
    content = content.replace('\ufffd', '')  # Replacement character
    
    # Remove other problematic Unicode ranges
    content = re.sub(r'[\u2580-\u259f]', '', content)  # Block elements
    content = re.sub(r'[\ue000-\uf8ff]', '', content)  # Private use area
    
    # Clean LaTeX-style formatting that doesn't render well in PDFs
    # Replace \Delta with Delta (Greek letter)
    content = content.replace('\\Delta', 'Δ')
    content = content.replace('\\times', '×')
    
    # ========================================
    # COMPREHENSIVE LATEX CLEANUP
    # ========================================
    
    # Remove \text{} wrapper - keep the content inside
    content = re.sub(r'\\text\{([^}]*)\}', r'\1', content)
    
    # Remove \textbf{} and \textit{} wrappers
    content = re.sub(r'\\textbf\{([^}]*)\}', r'\1', content)
    content = re.sub(r'\\textit\{([^}]*)\}', r'\1', content)
    
    # Replace \frac{a}{b} with (a/b) or a÷b
    content = re.sub(r'\\frac\{([^}]*)\}\{([^}]*)\}', r'(\1/\2)', content)
    
    # Replace \sum with Σ
    content = content.replace('\\sum', 'Σ')
    
    # Replace common Greek letters
    latex_greek = {
        '\\alpha': 'α', '\\beta': 'β', '\\gamma': 'γ', '\\delta': 'δ',
        '\\epsilon': 'ε', '\\varepsilon': 'ε', '\\zeta': 'ζ', '\\eta': 'η',
        '\\theta': 'θ', '\\iota': 'ι', '\\kappa': 'κ', '\\lambda': 'λ',
        '\\mu': 'μ', '\\nu': 'ν', '\\xi': 'ξ', '\\pi': 'π',
        '\\rho': 'ρ', '\\sigma': 'σ', '\\tau': 'τ', '\\upsilon': 'υ',
        '\\phi': 'φ', '\\chi': 'χ', '\\psi': 'ψ', '\\omega': 'ω',
        '\\Alpha': 'Α', '\\Beta': 'Β', '\\Gamma': 'Γ', '\\Theta': 'Θ',
        '\\Lambda': 'Λ', '\\Sigma': 'Σ', '\\Phi': 'Φ', '\\Omega': 'Ω',
    }
    for latex, unicode_char in latex_greek.items():
        content = content.replace(latex, unicode_char)
    
    # Replace common LaTeX math operators
    content = content.replace('\\cdot', '·')
    content = content.replace('\\approx', '≈')
    content = content.replace('\\neq', '≠')
    content = content.replace('\\leq', '≤')
    content = content.replace('\\geq', '≥')
    content = content.replace('\\pm', '±')
    content = content.replace('\\infty', '∞')
    content = content.replace('\\partial', '∂')
    content = content.replace('\\nabla', '∇')
    content = content.replace('\\sqrt', '√')
    
    # Remove LaTeX math mode delimiters
    content = re.sub(r'\$\$([^$]+)\$\$', r'\1', content)  # Remove $$ ... $$
    content = re.sub(r'\$([^$]+)\$', r'\1', content)  # Remove $ ... $
    content = re.sub(r'\\\[([^\]]+)\\\]', r'\1', content)  # Remove \[ ... \]
    content = re.sub(r'\\\(([^)]+)\\\)', r'\1', content)  # Remove \( ... \)
    
    # Clean up subscripts and superscripts in LaTeX style
    # Convert _{it} or ^{2} to just (it) or ^2
    content = re.sub(r'_\{([^}]+)\}', r'_\1', content)
    content = re.sub(r'\^\{([^}]+)\}', r'^\1', content)
    
    # Remove remaining backslash commands that weren't caught
    content = re.sub(r'\\[a-zA-Z]+\{([^}]*)\}', r'\1', content)  # \command{content} -> content
    content = re.sub(r'\\[a-zA-Z]+', '', content)  # Remove orphaned \commands
    
    # Clean up double/triple spaces left by removals
    content = re.sub(r'  +', ' ', content)
    
    # Fix numbers with {.} notation (LaTeX decimal separators)
    # Example: 1{.}500 → 1,500
    content = re.sub(r'(\d+)\{\.}(\d{3})', r'\1,\2', content)
    # Example: $1{.}740{.}000 → $1,740,000
    content = re.sub(r'\$(\d+)(\{\.}\d{3})+', lambda m: '$' + m.group(0)[1:].replace('{.}', ','), content)
    
    # Remove placeholder markers that shouldn't be there
    content = re.sub(r'<TO_BE_SUPPLIED>', '[información específica]', content, flags=re.IGNORECASE)
    content = re.sub(r'<POR_SUMINISTRAR>', '[información específica]', content, flags=re.IGNORECASE)
    content = re.sub(r'<\[.*?\]>', '[información específica]', content, flags=re.IGNORECASE)
    content = re.sub(r'\[TO BE SUPPLIED\]', '[información específica]', content, flags=re.IGNORECASE)
    content = re.sub(r'\[POR SUMINISTRAR\]', '[información específica]', content, flags=re.IGNORECASE)
    
    # ========================================
    # 🚨 ELIMINAR PLACEHOLDERS DE CITAS ("Fuente a verificar" y similares)
    # Estos se generan cuando la IA no tiene una fuente específica
    # Para un documento USCIS, NO deben aparecer en el documento final
    # ========================================
    # 🔴 Patrón DESCRIPTIVO largo: [FUENTE A VERIFICAR: descripción de qué buscar]
    # Estas aparecen cuando la IA describe qué necesita pero no tiene el dato
    content = re.sub(r'\[FUENTE A VERIFICAR:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[FUENTE:\s*A\s*VERIFICAR[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[SOURCE TO VERIFY:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[VERIFICAR FUENTE:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[DATO A VERIFICAR:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[CITA A VERIFICAR:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[ESTADÍSTICA A VERIFICAR:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    # 🔴 CITACIÓN NECESARIA — aparece en bibliografías y secciones de referencia
    content = re.sub(r'\[CITACIÓN NECESARIA:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[CITATION NEEDED:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[CITA NECESARIA:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[REFERENCIA NECESARIA:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[REFERENCE NEEDED:[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[INSERTAR FUENTE[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[INSERT SOURCE[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[AGREGAR FUENTE[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[BUSCAR FUENTE[^\]]{0,5000}\]', '', content, flags=re.IGNORECASE)
    # Patrones en español cortos
    content = re.sub(r'\(Fuente[:\s]*[aA]\s*[vV]erific?ar\)', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\(fuente\s*(pendiente|por\s*confirmar|a\s*confirmar|no\s*verificada?)\)', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\(cita[:\s]*pendiente\)', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\(por\s*confirmar\)', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\(verificar\s*fuente\)', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[Fuente[:\s]*[aA]\s*[vV]erific?ar\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[fuente\s*(pendiente|por\s*confirmar)\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[cita\s*(pendiente|requerida?)\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[verificar\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\(Fuente:?\s*pendiente\)', '', content, flags=re.IGNORECASE)
    # Patrones en inglés
    content = re.sub(r'\(source[:\s]*to\s*be?\s*verif(ied|y)\)', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\(citation\s*needed\)', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\(source\s*pending\)', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[source[:\s]*to\s*be?\s*verif(ied|y)\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[citation\s*needed\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[verify\s*source\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\[TBD\]', '', content, flags=re.IGNORECASE)
    content = re.sub(r'\(TBD\)', '', content, flags=re.IGNORECASE)
    # Limpiar espacios dobles que pueden quedar tras eliminar placeholders
    content = re.sub(r'  +', ' ', content)
    content = re.sub(r' \.', '.', content)
    content = re.sub(r' ,', ',', content)
    content = re.sub(r' ;', ';', content)
    
    # Remove AI model notes and meta-commentary that shouldn't be in final document
    # Pattern 1: <div> blocks with NOTA/NOTE content
    content = re.sub(r'<div[^>]*>\s*<strong>\s*NOTA?\s*(PARA\s*(EL\s*)?REVISOR)?:?\s*</strong>.*?</div>', '', content, flags=re.IGNORECASE | re.DOTALL)
    # Pattern 2: Paragraphs starting with NOTE or NOTA
    content = re.sub(r'<p[^>]*>\s*NOTA?\s*(PARA\s*(EL\s*)?REVISOR)?:.*?</p>', '', content, flags=re.IGNORECASE | re.DOTALL)
    # Pattern 3: Plain text notes at start
    content = re.sub(r'^[\s\n]*NOTA?\s*(PARA\s*(EL\s*)?REVISOR)?:.*?[\n\r]+', '', content, flags=re.IGNORECASE | re.MULTILINE)
    # Pattern 4: Notes about platform/AI limitations
    content = re.sub(r'<div[^>]*>.*?(Este campo de respuesta|This response field|no puedo literalmente|I cannot literally).*?</div>', '', content, flags=re.IGNORECASE | re.DOTALL)
    
    # Remove HTML wrapper tags if present (we want clean content)
    content = re.sub(r'^[\s\n]*<\?xml[^>]*\?>', '', content, flags=re.IGNORECASE)
    content = re.sub(r'^[\s\n]*<!DOCTYPE[^>]*>', '', content, flags=re.IGNORECASE)
    content = re.sub(r'^[\s\n]*<html[^>]*>', '', content, flags=re.IGNORECASE)
    content = re.sub(r'</html>\s*$', '', content, flags=re.IGNORECASE)
    content = re.sub(r'^[\s\n]*<head[^>]*>.*?</head>', '', content, flags=re.IGNORECASE | re.DOTALL)
    content = re.sub(r'^[\s\n]*<body[^>]*>', '', content, flags=re.IGNORECASE)
    content = re.sub(r'</body>\s*$', '', content, flags=re.IGNORECASE)
    
    # PATENT-SPECIFIC CLEANING: Remove translation headers and meta-commentary
    # Pattern: "TRADUCCIÓN DEL PATENTE..." at the beginning (NOT "ENCABEZADO" - that's a valid section)
    content = re.sub(r'^[\s\n]*TRADUC[A-ZÁÉÍÓÚÑa-záéíóúñ\s]+AL\s+ESPAÑOL[:\s]*[\n]*', '', content, flags=re.IGNORECASE)
    
    # Pattern: Translation notes in HTML (including with <strong> tags)
    content = re.sub(r'<h[1-6][^>]*>[\s\n]*(<strong>)?\s*TRADUC[A-ZÁÉÍÓÚÑa-záéíóúñ\s]+AL\s+ESPAÑOL[:\s]*(</strong>)?\s*</h[1-6]>', '', content, flags=re.IGNORECASE)
    content = re.sub(r'<p[^>]*>[\s\n]*(<strong>)?\s*TRADUC[A-ZÁÉÍÓÚÑa-záéíóúñ\s]+AL\s+ESPAÑOL[:\s]*(</strong>)?\s*</p>', '', content, flags=re.IGNORECASE)
    
    # Pattern: Translation text inline (not in its own tag)
    content = re.sub(r'TRADUC[A-ZÁÉÍÓÚÑa-záéíóúñ\s]+AL\s+ESPAÑOL[:\s]*', '', content, flags=re.IGNORECASE)
    
    # Pattern: "Aquí está la traducción..." intro phrases
    content = re.sub(r'^[\s\n]*(Aquí está|Here is|A continuación)[^<\n]*traducción[^<\n]*[\.\:\n]+', '', content, flags=re.IGNORECASE)
    # Pattern: Ending phrases about translation
    content = re.sub(r'(Esta es la traducción completa|This is the complete translation)[^<]*$', '', content, flags=re.IGNORECASE)
    
    # PATENT FORMAT FIX: Normalize pilcrow character ¶ to HTML entity &#182;
    # The AI sometimes outputs direct ¶ (Unicode U+00B6) instead of &#182; (HTML entity)
    # Normalize to &#182; so renumber_paragraphs_sequentially can find all instances
    content = re.sub(r'¶(\d{2,6}[A-Z]?)', r'&#182;\1', content)
    # Stand-alone ¶ not followed by digits
    content = content.replace('¶', '&#182;')

    # PATENT FORMAT FIX: Convert markdown **BOLD** to <strong>BOLD</strong>
    # The translation AI sometimes outputs **Section Title** instead of <h2><strong>...</strong></h2>
    # We need to handle **text** markers BEFORE the section-title regex below runs
    # Step 1: strip ** from the ENTIRE content when the content doesn't look like it's already fully HTML
    html_tag_count = content.count('<h2>') + content.count('<p>') + content.count('<strong>')
    markdown_bold_count = len(re.findall(r'\*\*[^*]+\*\*', content))
    if markdown_bold_count > html_tag_count:
        # Content is markdown-heavy — convert markdown bold to HTML
        content = re.sub(r'\*\*\*([^*]+)\*\*\*', r'<strong><em>\1</em></strong>', content)  # Bold+italic
        content = re.sub(r'\*\*([^*]+)\*\*', r'<strong>\1</strong>', content)               # Bold
        content = re.sub(r'(?<!\<em>)\*([^*\n]+)\*(?!\</em>)', r'<em>\1</em>', content)    # Italic (not inside already tagged)

        # Convert markdown headings at start of line (## HEADING or # HEADING)
        content = re.sub(r'^#{1,3}\s+(.+)$', lambda m: f'<h2><strong>{m.group(1).upper()}</strong></h2>', content, flags=re.MULTILINE)

        # CRITICAL: Split inline section titles from their following text content.
        # Pattern: <strong>SECTION TITLE</strong> followed by regular text (not HTML tag)
        # We want to split this into: <h2><strong>SECTION TITLE</strong></h2>\n<p>text content</p>
        def split_inline_section_title(m):
            title_text = m.group(1)
            following_text = m.group(2).strip()
            h2 = f'<h2><strong>{title_text}</strong></h2>'
            if following_text:
                return f'\n{h2}\n<p>{following_text}'
            return f'\n{h2}\n<p>'
        # Match <strong>ALL-CAPS TITLE (possibly multiword)</strong> followed by a space + text
        content = re.sub(
            r'<strong>([A-ZÁÉÍÓÚÑ][A-ZÁÉÍÓÚÑ\s\-\/&+,()ABCDEFGHIJKLMNOPQRSTUVWXYZ]{4,})</strong>\s+([^<\n])',
            lambda m: f'\n<h2><strong>{m.group(1)}</strong></h2>\n<p>{m.group(2)}',
            content
        )

        # Wrap plain-text lines (not already in HTML tags) in <p> tags
        lines = content.split('\n')
        wrapped_lines = []
        in_paragraph = False
        for line in lines:
            stripped = line.strip()
            if not stripped:
                continue
            if stripped.startswith('<h2>') or stripped.startswith('<h3>') or stripped.startswith('<h1>'):
                wrapped_lines.append(stripped)
                in_paragraph = False
            elif stripped.startswith('<p>') or stripped.startswith('</p>'):
                wrapped_lines.append(stripped)
                in_paragraph = False
            elif stripped.startswith('<'):
                wrapped_lines.append(stripped)
            else:
                wrapped_lines.append(f'<p>{stripped}</p>')
        content = '\n'.join(wrapped_lines)

    # PATENT STRUCTURE FIX: Convert inline section titles to proper HTML headings
    # These titles should be on their own line with proper formatting
    patent_section_titles = [
        'ENCABEZADO',
        'REFERENCIA CRUZADA A SOLICITUDES RELACIONADAS',
        'DECLARACIÓN SOBRE I\+D PATROCINADA FEDERALMENTE',
        'DECLARACION SOBRE I\+D PATROCINADA FEDERALMENTE',
        'CAMPO DE LA INVENCIÓN',
        'CAMPO DE LA INVENCION',
        'ANTECEDENTES DE LA INVENCIÓN',
        'ANTECEDENTES DE LA INVENCION',
        'ANTECEDENTES',
        'RESUMEN DE LA INVENCIÓN',
        'RESUMEN DE LA INVENCION',
        'RESUMEN',
        'BREVE DESCRIPCIÓN DE LOS DIBUJOS',
        'BREVE DESCRIPCION DE LOS DIBUJOS',
        'DESCRIPCIÓN DETALLADA DE LA INVENCIÓN',
        'DESCRIPCION DETALLADA DE LA INVENCION',
        'DESCRIPCIÓN DETALLADA',
        'DESCRIPCION DETALLADA',
        'REIVINDICACIONES',
        'DEFINICIONES',
        'ABSTRACTO',
        # English equivalents
        'CROSS-REFERENCE TO RELATED APPLICATIONS',
        'STATEMENT REGARDING FEDERALLY SPONSORED R&D',
        'FIELD OF THE INVENTION',
        'BACKGROUND OF THE INVENTION',
        'BACKGROUND',
        'SUMMARY OF THE INVENTION',
        'SUMMARY',
        'BRIEF DESCRIPTION OF THE DRAWINGS',
        'DETAILED DESCRIPTION OF THE INVENTION',
        'DETAILED DESCRIPTION',
        'CLAIMS',
        'DEFINITIONS',
        'ABSTRACT',
    ]
    
    # Convert inline section titles to <h2> headings
    for title in patent_section_titles:
        # Pattern: Title appearing inline (not already in h2 tag)
        # Match title followed by paragraph number or text
        pattern = rf'(?<!</h2>)\s*({title})\s*(?=¶|&#182;|<p|$)'
        replacement = rf'</p><h2><strong>\1</strong></h2><p>'
        content = re.sub(pattern, replacement, content, flags=re.IGNORECASE)
    
    # Clean up empty paragraph tags that might result
    content = re.sub(r'<p>\s*</p>', '', content)
    content = re.sub(r'</p>\s*</p>', '</p>', content)
    content = re.sub(r'<p>\s*<p>', '<p>', content)

    return content


# ── USPTO section headings (uppercase, normalized) ──────────────────────────
# Canonical patent section titles that must render as bold headings — never as
# numbered body paragraphs. Used by `_promote_numbered_patent_headings` to fix
# the case where the LLM emits a section header inside a numbered <p> such as
# `<p>&#182;0009 CROSS-REFERENCE TO RELATED APPLICATIONS</p>` instead of an
# <h2>. Keep in sync with USPTO_PATENT_HEADINGS inside create_pdf().
_PATENT_SECTION_HEADINGS = frozenset({
    # English
    "CROSS-REFERENCE TO RELATED APPLICATIONS",
    "CROSS REFERENCE TO RELATED APPLICATIONS",
    "STATEMENT REGARDING FEDERALLY SPONSORED RESEARCH OR DEVELOPMENT",
    "STATEMENT REGARDING FEDERALLY SPONSORED R&D",
    "FIELD OF THE INVENTION",
    "TECHNICAL FIELD",
    "BACKGROUND OF THE INVENTION",
    "BACKGROUND",
    "SUMMARY OF THE INVENTION",
    "BRIEF SUMMARY OF THE INVENTION",
    "SUMMARY",
    "BRIEF DESCRIPTION OF THE DRAWINGS",
    "BRIEF DESCRIPTION OF DRAWINGS",
    "DESCRIPTION OF THE DRAWINGS",
    "DETAILED DESCRIPTION",
    "DETAILED DESCRIPTION OF THE INVENTION",
    "DETAILED DESCRIPTION OF EMBODIMENTS",
    "DETAILED DESCRIPTION OF THE EMBODIMENTS",
    "DESCRIPTION OF EMBODIMENTS",
    "DEFINITIONS",
    "CLAIMS",
    "WHAT IS CLAIMED IS",
    "ABSTRACT",
    "ABSTRACT OF THE DISCLOSURE",
    # Spanish
    "REFERENCIA CRUZADA A SOLICITUDES RELACIONADAS",
    "DECLARACIÓN SOBRE I+D PATROCINADA FEDERALMENTE",
    "CAMPO DE LA INVENCIÓN",
    "CAMPO TÉCNICO",
    "ANTECEDENTES DE LA INVENCIÓN",
    "ANTECEDENTES",
    "RESUMEN DE LA INVENCIÓN",
    "BREVE RESUMEN DE LA INVENCIÓN",
    "RESUMEN",
    "BREVE DESCRIPCIÓN DE LOS DIBUJOS",
    "DESCRIPCIÓN DE LOS DIBUJOS",
    "DESCRIPCIÓN DETALLADA",
    "DESCRIPCIÓN DETALLADA DE LA INVENCIÓN",
    "DESCRIPCIÓN DETALLADA DE LAS REALIZACIONES",
    "REIVINDICACIONES",
    "DEFINICIONES",
    "ABSTRACTO",
})


def _promote_numbered_patent_headings(html: str) -> str:
    """Convert any <p> whose ENTIRE text is just a canonical USPTO section
    heading (optionally prefixed by a paragraph-number marker such as
    `¶0009`, `[0009]`, `(0009)` or a bare `0009 `) into a proper <h2> heading.

    Background: some generated patents emit section headers as numbered body
    paragraphs (e.g. `<p>&#182;0009 CROSS-REFERENCE TO RELATED APPLICATIONS</p>`)
    instead of `<h2>`. When rendered, the title shows as a numbered line (the
    "¶000 on subtitles" bug). This text-based promotion is markup-agnostic
    (it inspects the paragraph's plain text, so it works whether the title is
    bold-wrapped or not) and only fires on an EXACT heading match, so body
    paragraphs are never affected.

    MUST run BEFORE `renumber_paragraphs_sequentially` so a promoted heading
    does not consume a ¶ number (which would leave a gap in the body numbering).
    """
    if not html or '<p' not in html:
        return html
    try:
        from bs4 import BeautifulSoup
        soup = BeautifulSoup(html, 'html.parser')
    except Exception:
        return html

    changed = False
    for p in soup.find_all('p'):
        raw = p.get_text(' ', strip=True)
        if not raw:
            continue
        # Strip a single leading paragraph-number marker: ¶0009 / [0009] / (0009) / 0009
        stripped = re.sub(
            r'^\s*(?:¶|&#182;|\[|\()?\s*0*\d{1,6}[A-Z]?\s*(?:\]|\))?\s+',
            '',
            raw,
        )
        norm = re.sub(r'\s+', ' ', stripped).strip().rstrip(':').strip().upper()
        if norm in _PATENT_SECTION_HEADINGS:
            h2 = soup.new_tag('h2')
            strong = soup.new_tag('strong')
            strong.string = norm
            h2.append(strong)
            p.replace_with(h2)
            changed = True

    return str(soup) if changed else html


