# Document processing functions
def extract_text_from_file(file_content: bytes, filename: str) -> str:
    """
    Extract text from uploaded document - FAST extraction without AI
    Supports: .pdf, .docx, .txt
    """
    try:
        if filename.endswith('.docx'):
            doc = docx.Document(io.BytesIO(file_content))
            text_parts = []
            # Extract from paragraphs
            for para in doc.paragraphs:
                if para.text.strip():
                    text_parts.append(para.text)
            # Extract from tables (many CVs use tables for layout)
            for table in doc.tables:
                for row in table.rows:
                    for cell in row.cells:
                        if cell.text.strip():
                            text_parts.append(cell.text)
            return '\n\n'.join(text_parts)
        elif filename.endswith('.pdf'):
            reader = PdfReader(io.BytesIO(file_content))
            text_parts = []
            for page in reader.pages:
                text = page.extract_text()
                if text.strip():
                    text_parts.append(text)
            return '\n\n'.join(text_parts)
        elif filename.endswith('.txt'):
            return file_content.decode('utf-8')
        else:
            raise HTTPException(status_code=400, detail="Formato no soportado. Use .docx, .pdf o .txt")
    except Exception as e:
        logging.error(f"Error extracting text from {filename}: {e}")
        raise HTTPException(status_code=500, detail=f"Error al procesar archivo: {str(e)}")

async def process_document_with_ai(content: str, design_description: str, should_summarize: bool) -> str:
    """Process document content with AI based on design requirements"""
    if should_summarize:
        prompt = f"""Analiza el siguiente documento y crea una versión resumida que mantenga los puntos clave y la esencia del contenido.

Instrucciones de diseño y formato deseado:
{design_description}

Documento original:
{content}

Genera el contenido resumido manteniendo la estructura y aplicando las indicaciones de diseño."""
    else:
        prompt = f"""Analiza el siguiente documento y mejora su estructura y presentación sin eliminar ningún contenido.

Instrucciones de diseño y formato deseado:
{design_description}

Documento original:
{content}

Reorganiza y estructura el contenido de manera profesional aplicando las indicaciones de diseño, pero SIN eliminar ninguna palabra del contenido original."""
    
    return await call_openai_gpt4o("Eres un diseñador editorial experto especializado en estructurar y formatear documentos de manera profesional y visualmente atractiva.", prompt)

async def generate_with_gamma(content: str, title: str, design_description: str) -> dict:
    """Generate document using Gamma API"""
    gamma_api_key = os.environ.get('GAMMA_API_KEY')
    
    if not gamma_api_key:
        raise HTTPException(status_code=500, detail="Gamma API key not configured")
    
    # Prepare the prompt combining content and design instructions
    full_prompt = f"""Create a professionally designed document with the following specifications:

Design Instructions: {design_description}

Content (MAINTAIN ALL TEXT EXACTLY AS PROVIDED):
{content}

IMPORTANT: Keep all the original content intact. Do not summarize or remove any information. Only apply visual design and formatting improvements."""
    
    # Call Gamma API v1.0
    url = "https://public-api.gamma.app/v1.0/generations"
    headers = {
        "X-API-KEY": gamma_api_key,
        "Content-Type": "application/json",
        "accept": "application/json"
    }
    
    payload = {
        "inputText": full_prompt,
        "textMode": "preserve",  # Keep all content as instructed - REQUIRED
        "format": "document",  # presentation, document, webpage, social
        "exportAs": "pdf",  # Export to PDF format
        "additionalInstructions": design_description[:2000] if design_description else ""  # Max 2000 chars
    }
    
    try:
        logging.info(f"Sending request to Gamma API: format={payload['format']}, textMode={payload['textMode']}")
        response = requests.post(url, json=payload, headers=headers, timeout=120)
        response.raise_for_status()
        
        result = response.json()
        logging.info(f"Gamma API response: {result}")
        
        # Gamma API returns a generationId
        if 'generationId' in result:
            generation_id = result['generationId']
            logging.info(f"Gamma generation started: {generation_id}")
            
            # Poll for completion (max 10 minutes - Gamma can take time for large documents)
            for attempt in range(60):  # 60 * 10 seconds = 10 minutes
                time.sleep(10)
                
                try:
                    status_response = requests.get(
                        f"https://public-api.gamma.app/v1.0/generations/{generation_id}",
                        headers=headers,
                        timeout=30
                    )
                    
                    if status_response.status_code == 200:
                        status_data = status_response.json()
                        current_status = status_data.get('status')
                        
                        logging.info(f"Gamma status (attempt {attempt + 1}): {current_status}")
                        
                        # Check if completed
                        if current_status == 'completed':
                            # Get the gamma URL and export URL
                            gamma_url = status_data.get('webUrl') or status_data.get('url')
                            
                            # Get PDF export URL if available
                            exports = status_data.get('exports', {})
                            pdf_url = None
                            if exports and 'pdf' in exports:
                                pdf_url = exports['pdf'].get('url')
                            
                            logging.info(f"Gamma completed: URL={gamma_url}, PDF={pdf_url}")
                            
                            return {
                                'gamma_url': gamma_url,
                                'pdf_url': pdf_url,
                                'status': 'completed'
                            }
                        elif current_status == 'failed':
                            error_msg = status_data.get('error', 'Unknown error')
                            logging.error(f"Gamma generation failed: {error_msg}")
                            raise HTTPException(status_code=500, detail=f"Gamma generation failed: {error_msg}")
                        elif current_status in ['pending', 'processing', 'queued']:
                            # Still processing, continue polling
                            continue
                        else:
                            logging.warning(f"Unknown Gamma status: {current_status}")
                    else:
                        logging.warning(f"Gamma status check failed: {status_response.status_code}")
                        
                except requests.exceptions.RequestException as e:
                    logging.error(f"Error checking Gamma status: {str(e)}")
                    continue
            
            # Timeout - but return the Gamma URL anyway so user can check manually
            logging.error(f"Gamma generation timeout after 10 minutes: {generation_id}")
            return {
                'gamma_url': f"https://gamma.app/docs/{generation_id}",
                'pdf_url': None,
                'status': 'timeout',
                'message': 'Generation taking longer than expected. Check Gamma dashboard.'
            }
        
        return result
        
    except requests.exceptions.RequestException as e:
        logging.error(f"Gamma API error: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Gamma API error: {str(e)}")

def create_designed_pdf(title: str, content: str, design_description: str, author_name: str = None, author_affiliation: str = None) -> bytes:
    """Create a professionally designed PDF with custom styling
    
    Args:
        title: PDF title
        content: Content to include
        design_description: Description of the design style
        author_name: Name of the document author (defaults to generic if not provided)
        author_affiliation: Institutional affiliation of the author (optional)
    """
    # Use provided author name or default to generic
    pdf_author = author_name if author_name else "AI Document Generation"
    pdf_creator = author_affiliation if author_affiliation else "Document Generation Platform"
    
    buffer = io.BytesIO()
    doc = SimpleDocTemplate(buffer, pagesize=A4,
                           rightMargin=60, leftMargin=60,
                           topMargin=60, bottomMargin=72,  # igual al superior
                           title=title,
                           author=pdf_author,
                           subject="Designed Document",
                           creator=pdf_creator)
    
    elements = []
    styles = getSampleStyleSheet()
    
    # Custom styles based on design description
    styles.add(ParagraphStyle(
        name='DesignedTitle',
        parent=styles['Heading1'],
        fontSize=28,
        textColor=colors.HexColor('#1a1a1a'),
        spaceAfter=30,
        alignment=TA_CENTER,
        fontName='Times-Bold'
    ))
    
    styles.add(ParagraphStyle(
        name='DesignedHeading',
        parent=styles['Heading2'],
        fontSize=18,
        textColor=colors.HexColor('#2a2a2a'),
        spaceAfter=16,
        spaceBefore=20,
        fontName='Times-Bold',
        borderPadding=10,
        leftIndent=0
    ))
    
    styles.add(ParagraphStyle(
        name='DesignedSubheading',
        parent=styles['Heading3'],
        fontSize=14,
        textColor=colors.HexColor('#3a3a3a'),
        spaceAfter=12,
        spaceBefore=12,
        fontName='Times-Bold'
    ))
    
    styles.add(ParagraphStyle(
        name='DesignedBody',
        parent=styles['BodyText'],
        fontSize=11,
        alignment=TA_JUSTIFY,
        spaceAfter=12,
        leading=16,
        fontName='Times-Roman'
    ))
    
    styles.add(ParagraphStyle(
        name='DesignedQuote',
        parent=styles['BodyText'],
        fontSize=11,
        alignment=TA_LEFT,
        leftIndent=30,
        rightIndent=30,
        textColor=colors.HexColor('#4a4a4a'),
        spaceAfter=16,
        spaceBefore=16,
        fontName='Times-Italic',
        borderColor=colors.HexColor('#cccccc'),
        borderWidth=0,
        borderPadding=10
    ))
    
    # Title page
    elements.append(Spacer(1, 2*inch))
    elements.append(Paragraph(title, styles['DesignedTitle']))
    elements.append(Spacer(1, 0.5*inch))
    
    # Add design description as subtitle
    if design_description:
        subtitle_style = ParagraphStyle(
            'Subtitle',
            parent=styles['BodyText'],
            fontSize=10,
            textColor=colors.HexColor('#666666'),
            alignment=TA_CENTER,
            spaceAfter=30
        )
        elements.append(Paragraph(f"<i>{design_description[:200]}...</i>", subtitle_style))
    
    elements.append(PageBreak())
    
    # Process content
    paragraphs = content.split('\n\n')
    
    for para in paragraphs:
        if not para.strip():
            continue
            
        # Detect heading levels (robust regex: tolerates missing space etc.)
        _stripped = para.strip()
        _h_m = re.match(r'^(#{1,6})\s*(.+?)\s*$', _stripped)
        if _h_m:
            _hashes, _htxt = _h_m.groups()
            _htxt = _htxt.lstrip('#').strip()
            if len(_hashes) == 1:
                elements.append(Paragraph(_htxt, styles['DesignedTitle']))
            elif len(_hashes) == 2:
                elements.append(Paragraph(_htxt, styles['DesignedHeading']))
            else:  # 3+
                elements.append(Paragraph(_htxt, styles['DesignedSubheading']))
        elif para.strip().startswith('Capítulo') or para.strip().startswith('CAPÍTULO') or para.strip().startswith('Chapter'):
            elements.append(PageBreak())
            elements.append(Spacer(1, 0.5*inch))
            elements.append(Paragraph(para.strip(), styles['DesignedHeading']))
        elif para.strip().startswith('>') or para.strip().startswith('"'):
            quote_text = para.strip().lstrip('>').strip()
            elements.append(Paragraph(quote_text, styles['DesignedQuote']))
        elif para.strip().startswith('**') and para.strip().endswith('**'):
            title_text = para.strip().strip('*')
            elements.append(Paragraph(f"<b>{title_text}</b>", styles['DesignedHeading']))
        else:
            # Regular paragraph - escape special characters
            clean_para = para.strip()
            elements.append(Paragraph(clean_para, styles['DesignedBody']))
    
    # Build PDF
    doc.build(elements)
    
    pdf_bytes = buffer.getvalue()
    buffer.close()
    
    return pdf_bytes


def create_book_pdf_with_toc(title: str, author_name: str, chapters: list, synopsis: str = "", language: str = "es") -> bytes:
    """
    Create a professional book PDF with:
    - Cover page
    - Copyright page
    - Table of Contents with page numbers
    - Numbered chapters
    - Page numbers on all pages (except cover)
    - Conclusion and acknowledgments
    
    Uses a two-pass approach to accurately capture page numbers for TOC.
    
    Args:
        title: Book title
        author_name: Author's name
        chapters: List of chapter dicts with 'title', 'content' or 'content_es'/'content_en'
        synopsis: Book synopsis
        language: 'es' or 'en'
    """
    from reportlab.lib.pagesizes import letter
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, PageBreak, Table, TableStyle, Flowable
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_JUSTIFY, TA_LEFT, TA_RIGHT
    from reportlab.lib import colors
    from reportlab.lib.units import inch
    from bs4 import BeautifulSoup
    import re
    
    # Page setup
    page_width, page_height = letter
    margin = 72  # 1 inch
    
    # Styles
    styles = getSampleStyleSheet()
    
    # Custom styles
    title_style = ParagraphStyle(
        'BookTitle',
        parent=styles['Title'],
        fontSize=32,
        textColor=colors.HexColor('#2c3e50'),
        spaceAfter=30,
        alignment=TA_CENTER,
        fontName='Times-Bold'
    )
    
    author_style = ParagraphStyle(
        'AuthorName',
        parent=styles['Normal'],
        fontSize=18,
        textColor=colors.HexColor('#34495e'),
        alignment=TA_CENTER,
        fontName='Times-Roman'
    )
    
    synopsis_style = ParagraphStyle(
        'Synopsis',
        parent=styles['Normal'],
        fontSize=12,
        textColor=colors.HexColor('#555555'),
        alignment=TA_CENTER,
        fontName='Times-Italic',
        leading=18
    )
    
    toc_title_style = ParagraphStyle(
        'TOCTitle',
        parent=styles['Heading1'],
        fontSize=24,
        textColor=colors.black,
        spaceAfter=30,
        alignment=TA_CENTER,
        fontName='Times-Bold'
    )
    
    toc_entry_style = ParagraphStyle(
        'TOCEntry',
        parent=styles['Normal'],
        fontSize=12,
        fontName='Times-Roman',
        leading=24
    )
    
    chapter_title_style = ParagraphStyle(
        'ChapterTitle',
        parent=styles['Heading1'],
        fontSize=20,
        textColor=colors.black,
        spaceAfter=20,
        spaceBefore=10,
        fontName='Times-Bold'
    )
    
    body_style = ParagraphStyle(
        'BookBody',
        parent=styles['Normal'],
        fontSize=11,
        fontName='Times-Roman',
        alignment=TA_JUSTIFY,
        spaceAfter=8,
        leading=16
    )
    
    copyright_style = ParagraphStyle(
        'Copyright',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.gray,
        alignment=TA_CENTER,
        fontName='Times-Roman'
    )
    
    # Labels based on language
    intro_label = "Introducción" if language == 'es' else "Introduction"
    conclusion_label = "Conclusión" if language == 'es' else "Conclusion"
    acknowledgments_label = "Agradecimientos" if language == 'es' else "Acknowledgments"
    toc_title_label = "Tabla de Contenido" if language == 'es' else "Table of Contents"
    chapter_label = "Capítulo" if language == 'es' else "Chapter"
    
    # ========== PAGE NUMBER TRACKING ==========
    # Dictionary to store page numbers for each section
    section_pages = {}
    
    class PageNumberCapture(Flowable):
        """A flowable that captures its page number when rendered"""
        def __init__(self, key, page_dict):
            Flowable.__init__(self)
            self.key = key
            self.page_dict = page_dict
            self.width = 0
            self.height = 0
        
        def draw(self):
            # Capture the current page number
            page_num = self.canv.getPageNumber()
            self.page_dict[self.key] = page_num
    
    # ========== HTML TO PARAGRAPHS HELPER ==========
    def html_to_paragraphs(html_content, style):
        """Convert HTML content to ReportLab paragraphs.
        Properly escapes XML special characters to prevent ReportLab parsing errors."""
        if not html_content:
            return []
        
        from xml.sax.saxutils import escape as xml_escape
        
        # Map Unicode sub/superscripts to ASCII so Helvetica/Times-Roman don't
        # render them as black squares (CO₂ → CO2, A₁ → A1, etc.). This applies
        # to every paragraph that goes into the book PDF.
        _subs_map = str.maketrans({
            '\u2080': '0', '\u2081': '1', '\u2082': '2', '\u2083': '3', '\u2084': '4',
            '\u2085': '5', '\u2086': '6', '\u2087': '7', '\u2088': '8', '\u2089': '9',
            '\u208a': '+', '\u208b': '-', '\u208c': '=', '\u208d': '(', '\u208e': ')',
            '\u2090': 'a', '\u2091': 'e', '\u2092': 'o', '\u2093': 'x', '\u2095': 'h',
            '\u2096': 'k', '\u2097': 'l', '\u2098': 'm', '\u2099': 'n', '\u209a': 'p',
            '\u209b': 's', '\u209c': 't',
            '\u2074': '4', '\u2075': '5', '\u2076': '6', '\u2077': '7', '\u2078': '8',
            '\u2079': '9', '\u207a': '+', '\u207b': '-', '\u207c': '=',
            '\u207d': '(', '\u207e': ')', '\u207f': 'n',
            '\u00b2': '2', '\u00b3': '3', '\u00b9': '1', '\u2070': '0',
        })
        
        def _safe(t):
            return xml_escape((t or '').translate(_subs_map))
        
        soup = BeautifulSoup(html_content, 'html.parser')
        paragraphs = []
        
        for element in soup.find_all(['p', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'li', 'blockquote', 'pre']):
            # Skip nested paragraphs/blockquotes whose ancestor is already going to be
            # rendered by this loop (avoids duplicate rendering of the same text).
            if element.name in ('p', 'blockquote', 'pre') and element.find_parent(['li', 'blockquote']):
                # The parent element already holds this text
                continue
            text = element.get_text().strip()
            if text:
                # ⭐ CRITICAL: escape XML AND convert Unicode sub/superscripts
                safe_text = _safe(text)
                try:
                    if element.name in ['h1', 'h2', 'h3', 'h4', 'h5', 'h6']:
                        paragraphs.append(Paragraph(f"<b>{safe_text}</b>", style))
                    elif element.name == 'li':
                        paragraphs.append(Paragraph(f"• {safe_text}", style))
                    elif element.name == 'blockquote':
                        # Render blockquote as italic indented paragraph
                        paragraphs.append(Paragraph(f"<i>{safe_text}</i>", style))
                    elif element.name == 'pre':
                        paragraphs.append(Paragraph(f"<font face='Courier'>{safe_text}</font>", style))
                    else:
                        paragraphs.append(Paragraph(safe_text, style))
                    paragraphs.append(Spacer(1, 6))
                except Exception:
                    # Last resort: strip all non-ASCII and retry
                    try:
                        clean_text = xml_escape(text.encode('ascii', 'ignore').decode('ascii'))
                        paragraphs.append(Paragraph(clean_text, style))
                        paragraphs.append(Spacer(1, 6))
                    except Exception:
                        pass  # Skip unrenderable paragraph
        
        # If no structured content found, treat as plain text
        if not paragraphs:
            text = soup.get_text()
            for para in text.split('\n\n'):
                if para.strip():
                    try:
                        paragraphs.append(Paragraph(_safe(para.strip()), style))
                        paragraphs.append(Spacer(1, 8))
                    except Exception:
                        pass
        
        return paragraphs
    
    # ========== CLEAN CHAPTER TITLE HELPER ==========
    # Delegates to the shared book_utils helpers so the PDF and the
    # Word (.docx) exporter share IDENTICAL cleanup logic.  Any new
    # regex should land in book_utils, not here.
    from book_utils import (
        clean_book_chapter_title as _clean_book_chapter_title,
        clean_book_synopsis as _clean_synopsis_for_cover,
    )

    def clean_chapter_title(raw_title, chapter_num):
        """Delegate to the shared helper for consistency between PDF & DOCX."""
        return _clean_book_chapter_title(raw_title, chapter_num, language=language)

    # ========== BUILD ELEMENTS FUNCTION ==========
    def build_elements(include_toc_placeholder=True):
        """Build document elements, optionally with TOC placeholder for first pass"""
        elements = []
        
        # ========== COVER PAGE ==========
        elements.append(Spacer(1, 150))
        elements.append(Paragraph(title, title_style))
        elements.append(Spacer(1, 50))
        if synopsis:
            cleaned_syn = _clean_synopsis_for_cover(synopsis)
            if cleaned_syn:
                elements.append(Paragraph(cleaned_syn[:300] + ('...' if len(cleaned_syn) > 300 else ''), synopsis_style))
        elements.append(Spacer(1, 100))
        elements.append(Paragraph(author_name, author_style))
        elements.append(PageBreak())
        
        # ========== COPYRIGHT PAGE ==========
        current_year = datetime.now().year
        copyright_text = f"""
        <b>{title}</b><br/><br/>
        © {current_year} {author_name}<br/>
        {'Todos los derechos reservados.' if language == 'es' else 'All rights reserved.'}<br/><br/>
        {'Este libro ha sido creado como evidencia de expertise profesional.' if language == 'es' else 'This book was created as evidence of professional expertise.'}<br/><br/>
        {'Ninguna parte de esta publicación puede ser reproducida sin autorización.' if language == 'es' else 'No part of this publication may be reproduced without permission.'}
        """
        elements.append(Spacer(1, 300))
        elements.append(Paragraph(copyright_text, copyright_style))
        elements.append(PageBreak())
        
        # ========== TABLE OF CONTENTS ==========
        elements.append(Paragraph(toc_title_label, toc_title_style))
        elements.append(Spacer(1, 20))
        
        if include_toc_placeholder:
            # First pass: placeholder TOC without page numbers
            toc_entries = [intro_label]
            for i, chapter in enumerate(chapters, 1):
                # Prefer the in-content LLM heading (right language).
                from book_utils import extract_leading_chapter_title
                if language == 'es':
                    _ch_content = chapter.get('content_es', chapter.get('content', ''))
                else:
                    _ch_content = chapter.get('content_en', chapter.get('content', ''))
                in_content_title = extract_leading_chapter_title(_ch_content)
                raw_title = in_content_title or chapter.get('title', f"{chapter_label} {i}")
                chapter_title_text = clean_chapter_title(raw_title, i)
                toc_entries.append(f"{chapter_label} {i}. {chapter_title_text}")
            toc_entries.append(conclusion_label)
            toc_entries.append(acknowledgments_label)
            
            toc_table_data = []
            for entry in toc_entries:
                entry_text = f"{entry} {'.' * 40}"
                toc_table_data.append([Paragraph(entry_text, toc_entry_style)])
            
            toc_table = Table(toc_table_data, colWidths=[450])
            toc_table.setStyle(TableStyle([
                ('ALIGN', (0, 0), (-1, -1), 'LEFT'),
                ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
            ]))
            elements.append(toc_table)
        else:
            # Second pass: TOC with actual page numbers
            toc_entries = []
            toc_entries.append((intro_label, section_pages.get('intro', '?')))
            
            for i, chapter in enumerate(chapters, 1):
                from book_utils import extract_leading_chapter_title
                if language == 'es':
                    _ch_content = chapter.get('content_es', chapter.get('content', ''))
                else:
                    _ch_content = chapter.get('content_en', chapter.get('content', ''))
                in_content_title = extract_leading_chapter_title(_ch_content)
                raw_title = in_content_title or chapter.get('title', f"{chapter_label} {i}")
                chapter_title_text = clean_chapter_title(raw_title, i)
                page_num = section_pages.get(f'chapter_{i}', '?')
                toc_entries.append((f"{chapter_label} {i}. {chapter_title_text}", page_num))
            
            toc_entries.append((conclusion_label, section_pages.get('conclusion', '?')))
            toc_entries.append((acknowledgments_label, section_pages.get('acknowledgments', '?')))
            
            # Build TOC table with dotted leaders and page numbers
            toc_table_data = []
            for entry_title, page_num in toc_entries:
                # Calculate dots needed to fill space
                # Truncate long titles if needed
                max_title_len = 55
                if len(entry_title) > max_title_len:
                    entry_title = entry_title[:max_title_len-3] + "..."
                
                dots_needed = max(5, 60 - len(entry_title) - len(str(page_num)))
                entry_text = f"{entry_title} {'.' * dots_needed} {page_num}"
                toc_table_data.append([Paragraph(entry_text, toc_entry_style)])
            
            toc_table = Table(toc_table_data, colWidths=[450])
            toc_table.setStyle(TableStyle([
                ('ALIGN', (0, 0), (-1, -1), 'LEFT'),
                ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
            ]))
            elements.append(toc_table)
        
        elements.append(PageBreak())
        
        # ========== INTRODUCTION ==========
        elements.append(PageNumberCapture('intro', section_pages))
        elements.append(Paragraph(intro_label, chapter_title_style))
        if language == 'es':
            intro_text = f"""Este libro representa una compilación de conocimientos y experiencias profesionales del autor, {author_name}. 
            A través de los siguientes capítulos, exploraremos conceptos fundamentales, metodologías innovadoras y casos prácticos 
            que demuestran expertise y contribución original en el campo profesional."""
        else:
            intro_text = f"""This book represents a compilation of professional knowledge and experiences from the author, {author_name}. 
            Through the following chapters, we will explore fundamental concepts, innovative methodologies, and practical cases 
            that demonstrate expertise and original contribution in the professional field."""
        elements.append(Paragraph(intro_text, body_style))
        elements.append(PageBreak())
        
        # ========== CHAPTERS ==========
        for i, chapter in enumerate(chapters, 1):
            # Get content based on language
            if language == 'es':
                content = chapter.get('content_es', chapter.get('content', ''))
            else:
                content = chapter.get('content_en', chapter.get('content', ''))

            # Prefer the LLM-written chapter heading inside the content
            # (which is already in the requested language) over the
            # stored `title` field (often populated only in English).
            from book_utils import (
                strip_leading_chapter_heading,
                extract_leading_chapter_title,
            )
            in_content_title = extract_leading_chapter_title(content)
            raw_title = in_content_title or chapter.get('title', f"{chapter_label} {i}")
            chapter_title_text = clean_chapter_title(raw_title, i)

            # Capture page number for this chapter
            elements.append(PageNumberCapture(f'chapter_{i}', section_pages))
            
            # Single combined title: "Chapter X: Title"
            combined_title = f"{chapter_label} {i}: {chapter_title_text}"
            elements.append(Paragraph(combined_title, chapter_title_style))
            elements.append(Spacer(1, 20))

            # 🔥 Strip leading duplicate chapter title that the LLM often prepends.
            # Without this, the PDF renders the chapter title twice — once from
            # `combined_title` (added above) and once from the LLM's own
            # <h1>/<h2>Chapter N ...</h2> at the top of `content`.
            content = strip_leading_chapter_heading(content)

            # Convert HTML to paragraphs
            chapter_paragraphs = html_to_paragraphs(content, body_style)
            elements.extend(chapter_paragraphs)
            
            elements.append(PageBreak())
        
        # ========== CONCLUSION ==========
        elements.append(PageNumberCapture('conclusion', section_pages))
        elements.append(Paragraph(conclusion_label, chapter_title_style))
        if language == 'es':
            conclusion_text = """Este libro ha presentado una visión integral de los conceptos, metodologías y experiencias que 
            definen la contribución profesional del autor. Los frameworks y enfoques discutidos representan años de práctica 
            profesional y están diseñados para proporcionar valor tangible a profesionales y organizaciones en el campo."""
        else:
            conclusion_text = """This book has presented a comprehensive view of the concepts, methodologies, and experiences that 
            define the author's professional contribution. The frameworks and approaches discussed represent years of professional 
            practice and are designed to provide tangible value to professionals and organizations in the field."""
        elements.append(Paragraph(conclusion_text, body_style))
        elements.append(PageBreak())
        
        # ========== ACKNOWLEDGMENTS ==========
        elements.append(PageNumberCapture('acknowledgments', section_pages))
        elements.append(Paragraph(acknowledgments_label, chapter_title_style))
        if language == 'es':
            acknowledgments_text = f"""El autor agradece a todos aquellos que han contribuido a su desarrollo profesional 
            y a la realización de este libro. Un agradecimiento especial a colegas, mentores y a todos los que han sido 
            parte de este viaje profesional."""
        else:
            acknowledgments_text = f"""The author thanks all those who have contributed to their professional development 
            and to the realization of this book. Special thanks to colleagues, mentors, and all who have been part of 
            this professional journey."""
        elements.append(Paragraph(acknowledgments_text, body_style))
        
        return elements
    
    # ========== PAGE NUMBER CALLBACK ==========
    def add_page_number(canvas, doc):
        """Add page number to each page (except first)"""
        page_num = canvas.getPageNumber()
        if page_num > 1:  # Skip cover page
            text = f"— {page_num} —"
            canvas.saveState()
            canvas.setFont('Times-Roman', 10)
            canvas.drawCentredString(page_width / 2, 30, text)
            canvas.restoreState()
    
    # ========== TWO-PASS BUILD ==========
    # First pass: capture page numbers
    buffer1 = io.BytesIO()
    doc1 = SimpleDocTemplate(
        buffer1, 
        pagesize=letter,
        rightMargin=margin, 
        leftMargin=margin,
        topMargin=margin, 
        bottomMargin=margin + 20,
        title=title,
        author=author_name
    )
    
    elements1 = build_elements(include_toc_placeholder=True)
    doc1.build(elements1, onFirstPage=lambda c, d: None, onLaterPages=add_page_number)
    buffer1.close()
    
    logging.info(f"📚 TOC page numbers captured: {section_pages}")
    
    # Second pass: build final PDF with actual page numbers in TOC
    buffer2 = io.BytesIO()
    doc2 = SimpleDocTemplate(
        buffer2, 
        pagesize=letter,
        rightMargin=margin, 
        leftMargin=margin,
        topMargin=margin, 
        bottomMargin=margin + 20,
        title=title,
        author=author_name
    )
    
    elements2 = build_elements(include_toc_placeholder=False)
    doc2.build(elements2, onFirstPage=lambda c, d: None, onLaterPages=add_page_number)
    
    pdf_bytes = buffer2.getvalue()
    buffer2.close()
    
    return pdf_bytes


def create_pdf(title: str, content: str, doc_type: str, diagram_elements: list = None, author_name: str = None, author_affiliation: str = None, project_title: str = None, applicant_name: str = None, language: str = "en") -> bytes:
    """Create a professional PDF document from HTML content with optional SVG diagrams
    
    Args:
        title: PDF title
        content: HTML content
        doc_type: Type of document
        diagram_elements: Optional list of ReportLab Drawing objects (vectorial SVG diagrams)
        author_name: Name of the document author (defaults to generic if not provided)
        author_affiliation: Institutional affiliation of the author (optional)
        project_title: Project title for cover page (optional, for NIW/Business Plans)
        applicant_name: Applicant name for cover page (optional, for NIW/Business Plans)
        language: Language for cover page text ("en" or "es")
    """
    
    # 🔧 FIX: Split long paragraphs into shorter ones for better readability
    def fix_long_paragraphs(html_content):
        """Split long paragraphs into smaller chunks for better PDF formatting"""
        from bs4 import BeautifulSoup
        soup = BeautifulSoup(html_content, 'html.parser')
        
        for p_tag in soup.find_all('p'):
            text = p_tag.get_text().strip()
            # If paragraph is longer than 800 characters, split it
            if len(text) > 800:
                # Get all content including nested tags
                p_html = str(p_tag)
                
                # Split by sentence endings followed by space
                sentences = []
                current = []
                words = text.split()
                current_length = 0
                
                for word in words:
                    current.append(word)
                    current_length += len(word) + 1
                    
                    # Check if we should create a new paragraph
                    # Split at sentence ends (. ! ?) when length > 400 chars
                    if current_length > 400 and word.endswith(('.', '!', '?')):
                        sentences.append(' '.join(current))
                        current = []
                        current_length = 0
                
                # Add remaining words
                if current:
                    sentences.append(' '.join(current))
                
                # If we have multiple sentences, replace the long paragraph
                if len(sentences) > 1:
                    # Create new paragraphs
                    new_paragraphs = ''.join([f'<p>{s.strip()}</p>\n' for s in sentences if s.strip()])
                    # Replace the original paragraph
                    p_tag.replace_with(BeautifulSoup(new_paragraphs, 'html.parser'))
        
        return str(soup)
    
    logging.info(f"🔧 Fixing long paragraphs in content...")
    content = fix_long_paragraphs(content)
    logging.info(f"✅ Paragraphs fixed")
    
    # Use provided author name or default to generic
    pdf_author = author_name if author_name else "AI Document Generation"
    pdf_creator = author_affiliation if author_affiliation else "Document Generation Platform"
    
    buffer = io.BytesIO()
    
    # Define page size and margins (all equal at 72 points = 1 inch)
    page_width, page_height = letter
    left_margin = 72
    right_margin = 72
    top_margin = 72
    bottom_margin = 72  # IGUAL al margen superior
    
    # Create document with equal margins
    doc = SimpleDocTemplate(buffer, pagesize=letter,
                           rightMargin=right_margin, 
                           leftMargin=left_margin,
                           topMargin=top_margin, 
                           bottomMargin=bottom_margin,
                           title=title,
                           author=pdf_author,
                           subject=f"{doc_type} Document",
                           creator=pdf_creator)
    
    # Create custom Frame and PageTemplate to enforce margins
    from reportlab.platypus import Frame, PageTemplate
    
    frame_width = page_width - left_margin - right_margin
    frame_height = page_height - top_margin - bottom_margin
    
    frame = Frame(
        left_margin, bottom_margin,  # x, y position
        frame_width, frame_height,   # width, height
        leftPadding=0, rightPadding=0,
        topPadding=0, bottomPadding=0,
        id='normal'
    )

    # 🔢 Generic page-number footer for every non-econometric PDF.
    # Attached to the PageTemplate.onPage callback so it fires even on the
    # first page (doc.build's onFirstPage is ignored once custom
    # PageTemplates are installed).
    _page_label_bottom = "Página" if (language or "").lower().startswith("es") else "Page"
    _apply_generic_footer = not (doc_type == "econometric_study")

    # Per-subdocument page numbering state.
    # When a patent PDF contains several logical documents (Specification /
    # Drawings / Numbered Document), numbering must restart from 1 in each one.
    # `last_reset_page` is the absolute page number on which the current
    # sub-document starts (recorded by PageResetFlowable via pending_reset flag).
    # `current_label` is an optional sub-document label shown in the footer.
    _subdoc_state = {
        "last_reset_page": 1,
        "current_label": None,
        "pending_reset": False,
        "pending_label": None,
    }

    def _apply_pending_reset(canvas):
        """If a PageResetFlowable was rendered since the last footer draw,
        commit the reset now — using the CURRENT page number (guaranteed to
        be the first page of the new sub-document because the reset flowable
        was inserted immediately after a PageBreak)."""
        if _subdoc_state.get("pending_reset"):
            _subdoc_state["last_reset_page"] = canvas.getPageNumber()
            _subdoc_state["current_label"] = _subdoc_state.get("pending_label")
            _subdoc_state["pending_reset"] = False
            _subdoc_state["pending_label"] = None

    def _footer_text_for(canvas):
        _apply_pending_reset(canvas)
        abs_page = canvas.getPageNumber()
        rel_page = abs_page - _subdoc_state["last_reset_page"] + 1
        if rel_page < 1:
            rel_page = abs_page  # fallback before any reset
        # Footer: always just "Página N" / "Page N" (no sub-document label,
        # per user preference). The counter still restarts per sub-document
        # via the reset flowable; we just don't print the label.
        return f"{_page_label_bottom} {rel_page}"

    def _onpage_footer(canvas, doc_):
        if not _apply_generic_footer:
            return
        try:
            canvas.saveState()
            canvas.setFont("Helvetica", 9)
            canvas.setFillColorRGB(0.2, 0.2, 0.2)
            canvas.drawCentredString(612 / 2, 30, _footer_text_for(canvas))
            canvas.restoreState()
        except Exception:
            pass

    template = PageTemplate(id='main', frames=[frame])
    doc.addPageTemplates([template])

    # Custom canvas that draws the page-number footer inside showPage().
    # This is fundamentally different from PageTemplate callbacks:
    #   • PageTemplate.onPage / onLaterPages fire BEFORE flowables are rendered,
    #     so pending_reset set by PageResetFlowable isn't available yet.
    #   • PageTemplate.onPageEnd only fires reliably on page 1 in ReportLab 4.x
    #     when a custom PageTemplate is installed.
    # By overriding showPage(), we draw the footer AFTER all flowables (including
    # the invisible PageResetFlowable) have been rendered on the current page,
    # guaranteeing the pending_reset flag has already been committed.
    from reportlab.pdfgen import canvas as _rlcanvas

    class _FooterCanvas(_rlcanvas.Canvas):
        def showPage(self):
            try:
                if _apply_generic_footer:
                    _onpage_footer(self, None)
            except Exception:
                pass
            _rlcanvas.Canvas.showPage(self)
    
    # Container for the 'Flowable' objects
    elements = []
    
    logging.info(f"📄 create_pdf called with diagram_elements: {diagram_elements is not None}")
    if diagram_elements:
        logging.info(f"   Diagram elements count: {len(diagram_elements)}")
    
    # Keep track of temp files to clean up later
    temp_files = []
    
    # Import inch globally for use throughout the function
    from reportlab.lib.units import inch
    from reportlab.platypus import Flowable as _RLFlowable
    
    # ============================================================================
    # USPTO Patent Center PDF Bookmarks / Outlines
    # ----------------------------------------------------------------------------
    # USPTO Patent Center requires standard patent section headings to be
    # detectable via PDF bookmarks (outlines). Without them, the uploader shows:
    #   "A supported heading was not detected"
    # We normalize each h1/h2 text and, if it matches a recognized USPTO patent
    # heading, inject a BookmarkFlowable that writes canvas.bookmarkPage() +
    # canvas.addOutlineEntry() at draw time.
    # ============================================================================
    USPTO_PATENT_HEADINGS = {
        # English canonical form -> outline title used by USPTO
        "CROSS-REFERENCE TO RELATED APPLICATIONS": "Cross-Reference to Related Applications",
        "CROSS REFERENCE TO RELATED APPLICATIONS": "Cross-Reference to Related Applications",
        "STATEMENT REGARDING FEDERALLY SPONSORED RESEARCH OR DEVELOPMENT": "Statement Regarding Federally Sponsored R&D",
        "STATEMENT REGARDING FEDERALLY SPONSORED R&D": "Statement Regarding Federally Sponsored R&D",
        "FIELD OF THE INVENTION": "Field of the Invention",
        "TECHNICAL FIELD": "Field of the Invention",
        "FIELD": "Field of the Invention",
        "BACKGROUND OF THE INVENTION": "Background of the Invention",
        "BACKGROUND": "Background of the Invention",
        "SUMMARY OF THE INVENTION": "Summary of the Invention",
        "BRIEF SUMMARY OF THE INVENTION": "Summary of the Invention",
        "BRIEF SUMMARY": "Summary of the Invention",
        "SUMMARY": "Summary of the Invention",
        "DEFINITIONS": "Definitions",
        "BRIEF DESCRIPTION OF THE DRAWINGS": "Brief Description of the Drawings",
        "BRIEF DESCRIPTION OF DRAWINGS": "Brief Description of the Drawings",
        "DESCRIPTION OF THE DRAWINGS": "Brief Description of the Drawings",
        "DETAILED DESCRIPTION": "Detailed Description",
        "DETAILED DESCRIPTION OF THE INVENTION": "Detailed Description",
        "DETAILED DESCRIPTION OF EMBODIMENTS": "Detailed Description",
        "DETAILED DESCRIPTION OF THE EMBODIMENTS": "Detailed Description",
        "DETAILED DESCRIPTION OF THE PREFERRED EMBODIMENTS": "Detailed Description",
        "DESCRIPTION OF EMBODIMENTS": "Detailed Description",
        "CLAIMS": "Claims",
        "WHAT IS CLAIMED IS": "Claims",
        "ABSTRACT": "Abstract",
        "ABSTRACT OF THE DISCLOSURE": "Abstract",
        "APPENDICES": "Appendices",
        # Spanish variants mapped to English USPTO outline titles
        "REFERENCIA CRUZADA A SOLICITUDES RELACIONADAS": "Cross-Reference to Related Applications",
        "DECLARACIÓN SOBRE I+D PATROCINADA FEDERALMENTE": "Statement Regarding Federally Sponsored R&D",
        "CAMPO DE LA INVENCIÓN": "Field of the Invention",
        "CAMPO TÉCNICO": "Field of the Invention",
        "CAMPO": "Field of the Invention",
        "ANTECEDENTES DE LA INVENCIÓN": "Background of the Invention",
        "ANTECEDENTES": "Background of the Invention",
        "RESUMEN DE LA INVENCIÓN": "Summary of the Invention",
        "BREVE RESUMEN DE LA INVENCIÓN": "Summary of the Invention",
        "BREVE RESUMEN": "Summary of the Invention",
        "RESUMEN": "Summary of the Invention",
        "DEFINICIONES": "Definitions",
        "BREVE DESCRIPCIÓN DE LOS DIBUJOS": "Brief Description of the Drawings",
        "DESCRIPCIÓN DE LOS DIBUJOS": "Brief Description of the Drawings",
        "DESCRIPCIÓN DETALLADA": "Detailed Description",
        "DESCRIPCIÓN DETALLADA DE LA INVENCIÓN": "Detailed Description",
        "DESCRIPCIÓN DETALLADA DE LAS REALIZACIONES": "Detailed Description",
        "DESCRIPCIÓN DETALLADA DE LAS REALIZACIONES PREFERIDAS": "Detailed Description",
        "REIVINDICACIONES": "Claims",
        "ABSTRACTO": "Abstract",
        "APÉNDICES": "Appendices",
    }

    def _normalize_uspto_heading(raw_text: str) -> str:
        """Normalize a heading string for USPTO matching (uppercase, strip punctuation/numbering)."""
        import re as _re
        t = (raw_text or "").strip()
        # Strip leading paragraph-number markers the LLM sometimes glues to
        # the heading (e.g. "[0004] CROSS-REFERENCE", "¶0004 …", "(0004) …").
        t = _re.sub(r'^\s*(?:\[|¶|\()\s*0*\d{1,5}\s*(?:\]|\))?\s*', '', t)
        # Strip a pure digit run of 3-5 digits followed by whitespace and
        # uppercase (e.g. "0004 CROSS-REFERENCE …").
        t = _re.sub(r'^\s*0*\d{3,5}\s+(?=[A-Z])', '', t)
        # Strip leading numbering like "I.", "II.", "1.", "1)", "A.", etc.
        t = _re.sub(r'^\s*(?:[IVXLCDM]+|[0-9]+|[A-Z])[\.\)\-:]\s*', '', t, flags=_re.IGNORECASE)
        # Strip trailing paragraph-number markers (e.g. "DETAILED DESCRIPTION … [0033]")
        t = _re.sub(r'\s*(?:\[|¶|\()\s*0*\d{1,5}\s*(?:\]|\))?\s*$', '', t)
        t = t.strip().rstrip(':').strip()
        t = _re.sub(r'\s+', ' ', t)
        return t.upper()

    def _match_uspto_heading(raw_text: str):
        """Return canonical USPTO outline title if heading matches, else None."""
        norm = _normalize_uspto_heading(raw_text)
        if not norm:
            return None
        if norm in USPTO_PATENT_HEADINGS:
            return USPTO_PATENT_HEADINGS[norm]
        # Also try a prefix match (e.g. "DETAILED DESCRIPTION OF ALGORITHM ...")
        for key, val in USPTO_PATENT_HEADINGS.items():
            if norm.startswith(key + " ") or norm.startswith(key + ":"):
                return val
        return None

    # Counter to produce unique bookmark keys across the document
    _bookmark_state = {"counter": 0, "outline_titles": []}
    # Flag: are we rendering a patent PDF? (enables bookmarks + showOutline)
    _is_patent_pdf = isinstance(doc_type, str) and doc_type.startswith("patent")

    class BookmarkFlowable(_RLFlowable):
        """Invisible flowable that writes a PDF bookmark + outline entry at draw time."""
        def __init__(self, outline_title: str, key: str, level: int = 0):
            _RLFlowable.__init__(self)
            self.outline_title = outline_title
            self.key = key
            self.level = level
            self.width = 0
            self.height = 0
        def wrap(self, availWidth, availHeight):
            return (0, 0)
        def draw(self):
            try:
                self.canv.bookmarkPage(self.key)
                self.canv.addOutlineEntry(self.outline_title, self.key, level=self.level, closed=0)
            except Exception:
                pass

    class ShowOutlineFlowable(_RLFlowable):
        """Invisible flowable that tells the PDF viewer to open with the bookmarks panel visible."""
        def __init__(self):
            _RLFlowable.__init__(self)
            self.width = 0
            self.height = 0
        def wrap(self, availWidth, availHeight):
            return (0, 0)
        def draw(self):
            try:
                self.canv.showOutline()
            except Exception:
                pass

    class PageResetFlowable(_RLFlowable):
        """Invisible flowable that restarts the per-subdocument page counter.
        When a patent PDF bundles Specification + Drawings + Numbered-Document
        in a single file, each sub-document must have its own '... Page N'
        numbering. This flowable sets a `pending_reset` flag; the reset is
        committed the next time the footer callback fires on a new page
        (guaranteed to be the first page of the new sub-document because
        PageResetFlowable is inserted immediately after a PageBreak)."""
        def __init__(self, label: str = None):
            _RLFlowable.__init__(self)
            self.label = label
            self.width = 0
            self.height = 0
        def wrap(self, availWidth, availHeight):
            return (0, 0)
        def draw(self):
            try:
                _subdoc_state["pending_reset"] = True
                _subdoc_state["pending_label"] = self.label
            except Exception:
                pass

    def _maybe_add_uspto_bookmark(raw_heading_text: str, level: int = 0):
        """If the heading matches a USPTO section, append a BookmarkFlowable to `elements`."""
        if not _is_patent_pdf:
            return
        outline_title = _match_uspto_heading(raw_heading_text)
        if not outline_title:
            return
        # Avoid duplicate outline entries for the same USPTO section
        if outline_title in _bookmark_state["outline_titles"]:
            return
        _bookmark_state["counter"] += 1
        key = f"uspto_h_{_bookmark_state['counter']}"
        _bookmark_state["outline_titles"].append(outline_title)
        elements.append(BookmarkFlowable(outline_title, key, level=level))

    # For patent PDFs: ask the viewer to open with the bookmarks panel visible
    # (USPTO Patent Center uses these bookmarks/outlines to detect sections).
    if _is_patent_pdf:
        elements.append(ShowOutlineFlowable())

    # Define styles
    styles = getSampleStyleSheet()
    
    # ============================================================================
    # FONT VARIATION FOR ECONOMETRIC STUDIES ONLY (Black & White, no bullets)
    # ============================================================================
    import random
    
    # Font families for econometric studies
    ECONOMETRIC_FONTS = [
        {"name": "Times New Roman", "regular": "Times-Roman", "bold": "Times-Bold", "italic": "Times-Italic"},
        {"name": "Helvetica (Arial)", "regular": "Helvetica", "bold": "Helvetica-Bold", "italic": "Helvetica-Oblique"},
    ]
    
    # Select random font for econometric studies
    if doc_type == "econometric_study":
        font_scheme = random.choice(ECONOMETRIC_FONTS)
        font_regular = font_scheme["regular"]
        font_bold = font_scheme["bold"]
        font_italic = font_scheme["italic"]
        logging.warning(f"🎨 [ECONOMETRIC] Using font: {font_scheme['name']}")
    else:
        font_regular = "Times-Roman"
        font_bold = "Times-Bold"
        font_italic = "Times-Italic"
    
    # Custom styles - Black & White, font varies for econometric studies
    styles.add(ParagraphStyle(
        name='CustomTitle',
        parent=styles['Heading1'],
        fontSize=24,
        textColor=colors.black,
        spaceAfter=20,
        alignment=TA_CENTER,
        fontName=font_bold
    ))
    
    styles.add(ParagraphStyle(
        name='CustomH1',
        parent=styles['Heading1'],
        fontSize=18,
        textColor=colors.black,
        spaceAfter=10,
        spaceBefore=18,
        fontName=font_bold
    ))
    
    styles.add(ParagraphStyle(
        name='CustomH2',
        parent=styles['Heading2'],
        fontSize=16,
        textColor=colors.black,
        spaceAfter=8,
        spaceBefore=14,
        fontName=font_bold
    ))
    
    styles.add(ParagraphStyle(
        name='CustomH3',
        parent=styles['Heading3'],
        fontSize=14,
        textColor=colors.black,
        spaceAfter=6,
        spaceBefore=10,
        fontName=font_bold
    ))
    
    styles.add(ParagraphStyle(
        name='CustomH4',
        parent=styles['BodyText'],
        fontSize=12,
        textColor=colors.black,
        spaceAfter=4,
        spaceBefore=8,
        fontName=font_bold
    ))
    
    styles.add(ParagraphStyle(
        name='CustomBody',
        parent=styles['BodyText'],
        fontSize=11,
        fontName=font_regular,
        alignment=TA_JUSTIFY,
        spaceAfter=8,
        spaceBefore=2,
        leading=14
    ))
    
    # BulletPoint style - for econometric studies, no bullet, just indented paragraph
    styles.add(ParagraphStyle(
        name='BulletPoint',
        parent=styles['BodyText'],
        fontSize=11,
        fontName=font_regular,
        leftIndent=0 if doc_type == "econometric_study" else 20,  # No indent for econometric
        bulletIndent=0 if doc_type == "econometric_study" else 10,
        alignment=TA_JUSTIFY,
        spaceAfter=6,
        leading=14
    ))
    
    # Estilo especial para párrafos numerados de patentes (&#182;0001, &#182;0002, etc.)
    styles.add(ParagraphStyle(
        name='NumberedPatentParagraph',
        parent=styles['BodyText'],
        fontSize=11,
        fontName=font_regular,
        alignment=TA_JUSTIFY,
        spaceAfter=10,
        spaceBefore=4,
        leading=14,
        firstLineIndent=0
    ))
    
    # Add title ONLY for non-patent documents (patents already carry their own
    # USPTO header in the body). `patent_complete` and `patent_numbered` both
    # embed the "UNITED STATES PATENT AND TRADEMARK OFFICE / Provisional Patent
    # Application" header in their content, so rendering `title` on top would
    # duplicate it (the spurious "USPTO Numbered Patent: …" heading bug).
    if doc_type not in ("patent_complete", "patent_numbered"):
        # Check if this is a NIW/Business Plan document that needs a professional cover page
        is_niw_document = doc_type == "business_plan" and ("NIW" in title or "EB-2" in title or "National Interest" in title)
        
        if is_niw_document:
            # ========== PROFESSIONAL COVER PAGE FOR NIW ==========
            from datetime import datetime
            
            # Extract project title and applicant name from the title or parameters
            actual_project_title = project_title if project_title else title.split(":")[-1].strip() if ":" in title else title
            actual_applicant = applicant_name if applicant_name else "Applicant"
            
            # ⭐ FIX: Language-aware date formatting
            _now = datetime.now()
            if language == "es":
                _spanish_months = {1:"enero",2:"febrero",3:"marzo",4:"abril",5:"mayo",6:"junio",
                                   7:"julio",8:"agosto",9:"septiembre",10:"octubre",11:"noviembre",12:"diciembre"}
                current_date = f"{_now.day} de {_spanish_months[_now.month]} de {_now.year}"
            else:
                current_date = _now.strftime("%B %d, %Y")
            
            # Cover page styles
            cover_title_style = ParagraphStyle(
                name='CoverTitle',
                parent=styles['Heading1'],
                fontSize=28,
                textColor=colors.black,
                alignment=TA_CENTER,
                fontName='Times-Bold',
                leading=36,
                spaceBefore=0,
                spaceAfter=0
            )
            
            cover_subtitle_style = ParagraphStyle(
                name='CoverSubtitle',
                parent=styles['Heading2'],
                fontSize=18,
                textColor=colors.black,
                alignment=TA_CENTER,
                fontName='Times-Roman',
                spaceBefore=0,
                spaceAfter=0
            )
            
