@api_router.post("/auth/register", response_model=dict)
async def register(user_data: UserRegister):
    """Register a new user"""
    try:
        # Check if user already exists
        existing_user = await db.users.find_one({"email": user_data.email})
        if existing_user:
            # Verificar si está eliminado (soft-deleted)
            if existing_user.get('status') == 'deleted':
                raise HTTPException(
                    status_code=400, 
                    detail="Este email fue previamente registrado y eliminado. Por favor, contacta al administrador para restaurar tu cuenta."
                )
            raise HTTPException(
                status_code=400, 
                detail="Este email ya se encuentra registrado en el sistema. Por favor, contacta al administrador si necesitas recuperar el acceso a tu cuenta."
            )
        
        # 🔑 Lista de emails pre-autorizados como ADMIN
        # Estos emails automáticamente obtienen rol ADMIN al registrarse
        ADMIN_WHITELIST = [
            "leidi@gmail.com",
            "leidipelaez@gmail.com",
            "dau@urpeailab.com",
            "diego@urpeailab.com",
            "admin@urpe.com",
            "fl@urpeailab.com",
        ]
        
        # Determinar el rol basado en el email
        user_role = "ADMIN" if user_data.email.lower() in ADMIN_WHITELIST else "USER"
        
        # Create new user
        hashed_password = get_password_hash(user_data.password)
        user = User(
            email=user_data.email,
            full_name=user_data.full_name,
            language_preference=user_data.language_preference,
            role=user_role  # Asignar rol automáticamente
        )
        
        user_dict = user.model_dump()
        user_dict['password'] = hashed_password
        user_dict['created_at'] = user_dict['created_at'].isoformat()
        
        # Log si es un registro de admin
        if user_role == "ADMIN":
            logger.info(f"🔑 AUTO-ADMIN: Usuario {user_data.email} registrado automáticamente como ADMIN")
        
        await db.users.insert_one(user_dict)
        
        # Create access token
        access_token = create_access_token(
            data={"sub": user.email},
            expires_delta=timedelta(minutes=30 * 24 * 60)
        )
        
        return {
            "access_token": access_token,
            "token_type": "bearer",
            "user": {
                "id": user.id,
                "email": user.email,
                "full_name": user.full_name,
                "role": user.role,  # Incluir rol en la respuesta
                "language_preference": user.language_preference
            }
        }
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"❌ Error en registro: {str(e)}")
        raise HTTPException(
            status_code=500, 
            detail=f"Error al crear la cuenta. Por favor, intenta nuevamente o contacta al soporte."
        )

