@api_router.post("/auth/guest", response_model=dict)
async def create_guest_session():
    """
    Crea una sesión de invitado para usuarios que llegan sin token del panel.
    Permite acceso abierto al dashboard sin login obligatorio.
    """
    guest_email = "guest@monica.system"
    guest_user = await db.users.find_one({"email": guest_email}, {"_id": 0, "password": 0})

    if not guest_user:
        import uuid as _uuid
        guest_doc = {
            "id": str(_uuid.uuid4()),
            "email": guest_email,
            "full_name": "Invitado",
            "role": "OPERATOR",
            "language_preference": "es",
            "status": "active",
            "created_at": datetime.now(timezone.utc).isoformat(),
        }
        await db.users.insert_one(guest_doc)
        guest_user = {k: v for k, v in guest_doc.items() if k != "_id"}

    access_token = create_access_token(
        data={"sub": guest_email},
        expires_delta=timedelta(hours=24),
    )

    return {
        "access_token": access_token,
        "token_type": "bearer",
        "user": {
            "id": guest_user["id"],
            "email": guest_user["email"],
            "full_name": guest_user["full_name"],
            "role": guest_user["role"],
            "language_preference": guest_user.get("language_preference", "es"),
        },
    }

# ============================================================================
# ADMIN MIDDLEWARE - Verificación de rol ADMIN
# ============================================================================

async def get_admin_user(current_user: User = Depends(get_current_user)) -> User:
    """Middleware to verify user has ADMIN role"""
    if current_user.role != "ADMIN":
        raise HTTPException(
            status_code=403, 
            detail="Access denied. Admin privileges required."
        )
    return current_user

