@api_router.post("/admin/users")
async def create_user_by_admin(
    user_data: UserCreate,
    admin_user: User = Depends(get_admin_user)
):
    """Create a new user (ADMIN only)"""
    try:
        # Check if user already exists
        existing_user = await db.users.find_one({"email": user_data.email})
        if existing_user:
            raise HTTPException(status_code=400, detail="Email already registered")
        
        # Si no se especifica rol, por defecto USER
        role = user_data.role if user_data.role else "USER"
        
        # Validate role
        if role not in ["ADMIN", "USER", "OPERATOR"]:
            raise HTTPException(status_code=400, detail="Invalid role. Must be ADMIN, USER, or OPERATOR")
        
        # Create new user
        hashed_password = get_password_hash(user_data.password)
        user = User(
            email=user_data.email,
            full_name=user_data.full_name,
            role=role,
            language_preference=user_data.language_preference,
            created_by=admin_user.id
        )
        
        user_dict = user.model_dump()
        user_dict['password'] = hashed_password
        user_dict['created_at'] = user_dict['created_at'].isoformat()
        
        result = await db.users.insert_one(user_dict)
        
        # Return user without password and _id
        created_user = await db.users.find_one({"id": user.id}, {"_id": 0, "password": 0})
        
        return {
            "message": "User created successfully",
            "user": created_user
        }
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error creating user: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.put("/admin/users/{user_id}")
async def update_user_by_admin(
    user_id: str,
    user_data: UserUpdate,
    admin_user: User = Depends(get_admin_user)
):
    """Update user information (ADMIN only)"""
    try:
        # Find user
        user = await db.users.find_one({"id": user_id})
        if not user:
            raise HTTPException(status_code=404, detail="User not found")
        
        # Prepare update data
        update_data = {}
        
        if user_data.full_name is not None:
            update_data["full_name"] = user_data.full_name
        
        if user_data.email is not None:
            # Check if email is already taken by another user
            existing = await db.users.find_one({"email": user_data.email, "id": {"$ne": user_id}})
            if existing:
                raise HTTPException(status_code=400, detail="Email already taken by another user")
            update_data["email"] = user_data.email
        
        if user_data.password is not None:
            update_data["password"] = get_password_hash(user_data.password)
        
        if user_data.role is not None:
            if user_data.role not in ["ADMIN", "USER", "OPERATOR"]:
                raise HTTPException(status_code=400, detail="Invalid role. Must be ADMIN, USER, or OPERATOR")
            update_data["role"] = user_data.role
        
        if user_data.language_preference is not None:
            update_data["language_preference"] = user_data.language_preference
        
        if not update_data:
            raise HTTPException(status_code=400, detail="No data to update")
        
        # Update user
        result = await db.users.update_one(
            {"id": user_id},
            {"$set": update_data}
        )
        
        if result.modified_count == 0:
            raise HTTPException(status_code=400, detail="No changes made")
        
        # Get updated user
        updated_user = await db.users.find_one({"id": user_id}, {"_id": 0, "password": 0})
        
        return {
            "message": "User updated successfully",
            "user": updated_user
        }
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error updating user: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.delete("/admin/users/{user_id}")
async def delete_user_by_admin(
    user_id: str,
    admin_user: User = Depends(get_admin_user)
):
    """Soft delete a user (ADMIN only)"""
    try:
        # Prevent self-deletion
        if user_id == admin_user.id:
            raise HTTPException(
                status_code=400, 
                detail="Cannot delete your own account"
            )
        
        # Find user
        user = await db.users.find_one({"id": user_id, "status": {"$ne": "deleted"}})
        if not user:
            raise HTTPException(status_code=404, detail="User not found or already deleted")
        
        # Soft delete: marcar como eliminado en lugar de eliminar
        result = await db.users.update_one(
            {"id": user_id},
            {
                "$set": {
                    "status": "deleted",
                    "deleted_at": datetime.now(timezone.utc).isoformat(),
                    "deleted_by": admin_user.id
                }
            }
        )
        
        if result.modified_count == 0:
            raise HTTPException(status_code=400, detail="Failed to delete user")
        
        return {
            "message": "User deleted successfully (soft delete)",
            "deleted_user_email": user.get("email"),
            "note": "User data is preserved and can be restored if needed"
        }
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error deleting user: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.post("/admin/import-database")
async def import_database(
    file: UploadFile = File(...),
    admin_user: User = Depends(get_admin_user)
):
    """Import database from uploaded JSON export file. Restricted to ADMIN users.

    Usa bulk_upsert nativo de Supabase (un batch por chunk) para soportar archivos grandes.
    Las colecciones cuya tabla no existe en Supabase se reportan como skipped.
    """
    if not file.filename.endswith(".json"):
        raise HTTPException(status_code=400, detail="El archivo debe ser un JSON (.json)")

    BATCH_SIZE = 100  # bulk_upsert hace split adaptativo si Postgres timea out

    try:
        content = await file.read()
        export_data = json.loads(content.decode("utf-8"))

        collections = export_data.get("collections", {})
        results: dict = {}
        skipped_collections: list = []
        total_upserted = 0

        # Pre-fetch emails de usuarios existentes (un solo round-trip)
        existing_emails: set = set()
        if isinstance(collections.get("users"), list) and collections["users"]:
            async for u in db.users.find({}):
                if u.get("email"):
                    existing_emails.add(u["email"])

        for collection_name, documents in collections.items():
            if not isinstance(documents, list) or not documents:
                results[collection_name] = {"skipped": True, "total": 0, "upserted": 0}
                continue

            upserted = 0
            errors = 0
            batch: list = []
            missing_table = False

            for raw in documents:
                if not isinstance(raw, dict):
                    errors += 1
                    continue
                doc = {k: v for k, v in raw.items() if k != "_id"}

                if collection_name == "users":
                    email = doc.get("email")
                    if not email:
                        errors += 1
                        continue
                    if email in existing_emails:
                        # Usuario existente: actualizar SIN tocar password
                        doc.pop("password", None)
                        try:
                            await db.users.update_one({"email": email}, {"$set": doc})
                            upserted += 1
                        except Exception as e:
                            logging.error(f"Error actualizando user {email}: {e}")
                            errors += 1
                        continue
                    else:
                        # Nuevo usuario: password placeholder si no viene una válida
                        if not doc.get("password"):
                            doc["password"] = get_password_hash("changeme123")
                        existing_emails.add(email)

                batch.append(doc)
                if len(batch) >= BATCH_SIZE:
                    res = await db[collection_name].bulk_upsert(batch)
                    if res.get("missing_table"):
                        missing_table = True
                        skipped_collections.append({"name": collection_name, "reason": "Tabla no existe en Supabase"})
                        batch = []
                        break
                    upserted += res.get("upserted", 0)
                    errors += res.get("errors", 0)
                    batch = []

            if batch and not missing_table:
                res = await db[collection_name].bulk_upsert(batch)
                if res.get("missing_table"):
                    skipped_collections.append({"name": collection_name, "reason": "Tabla no existe en Supabase"})
                else:
                    upserted += res.get("upserted", 0)
                    errors += res.get("errors", 0)

            results[collection_name] = {
                "total": len(documents),
                "upserted": upserted,
                "errors": errors,
                "missing_table": missing_table,
            }
            total_upserted += upserted
            logging.info(f"✅ Colección '{collection_name}': {upserted}/{len(documents)} upserted, {errors} errores{' [MISSING TABLE]' if missing_table else ''}")

        return {
            "message": "Importación completada",
            "database_name": export_data.get("database_name", "unknown"),
            "export_date": export_data.get("export_date", "unknown"),
            "total_collections": len(collections),
            "total_upserted": total_upserted,
            "total_modified": 0,  # Supabase upsert no distingue insert vs update; todo cuenta como upserted
            "collections": results,
            "skipped_collections": skipped_collections,
        }
    except json.JSONDecodeError as e:
        raise HTTPException(status_code=400, detail=f"Error al leer el archivo JSON: {str(e)}")
    except Exception as e:
        logging.error(f"Error en importación de base de datos: {e}")
        raise HTTPException(status_code=500, detail=f"Error en importación: {str(e)}")


@api_router.post("/admin/users/{user_id}/restore")
async def restore_user_by_admin(
    user_id: str,
    admin_user: User = Depends(get_admin_user)
):
    """Restore a soft-deleted user (ADMIN only)"""
    try:
        # Find deleted user
        user = await db.users.find_one({"id": user_id, "status": "deleted"})
        if not user:
            raise HTTPException(status_code=404, detail="Deleted user not found")
        
        # Restore user
        result = await db.users.update_one(
            {"id": user_id},
            {
                "$set": {
                    "status": "active"
                },
                "$unset": {
                    "deleted_at": "",
                    "deleted_by": ""
                }
            }
        )
        
        if result.modified_count == 0:
            raise HTTPException(status_code=400, detail="Failed to restore user")
        
        # Get restored user
        restored_user = await db.users.find_one({"id": user_id}, {"_id": 0, "password": 0})
        
        return {
            "message": "User restored successfully",
            "user": restored_user
        }
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error restoring user: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))



