# ============================================================================
# TRASH/RECYCLE BIN - Sistema de Papelera para Documentos
# ============================================================================

class TrashItem(BaseModel):
    """Modelo para item en papelera"""
    id: str
    collection: str  # books, patents, niw_in_progress, etc.
    document_id: str
    document_type: str  # "Libro", "Patente", "NIW", etc.
    title: str
    client_id: Optional[str] = None
    client_name: Optional[str] = None
    deleted_at: datetime
    deleted_by: str
    original_data: dict  # Para poder restaurar

@api_router.get("/trash")
async def get_trash_items(
    client_id: Optional[str] = None,
    current_user: User = Depends(get_current_user)
):
    """Obtener todos los documentos en papelera del usuario, opcionalmente filtrados por cliente"""
    try:
        trash_items = []
        
        # Lista de colecciones a revisar
        collections_map = {
            "books": "Libro",
            "books_in_progress": "Borrador de Libro",
            "patents": "Patente",
            "patents_in_progress": "Solicitud de Patente",
            "niw_in_progress": "Caso NIW",
            "expert_letters": "Carta de Experto",
            "recommendation_letters": "Carta de Recomendación",
            "policy_papers": "Reporte de Impacto Social",
            "business_plans": "Plan de Negocios",
            "whitepapers": "Whitepaper",
            "econometric_studies": "Estudio Econométrico",
            "econometric_studies_in_progress": "Borrador de Estudio",
            "self_petition_letters": "Carta de Auto-Petición"
        }
        
        for collection_name, doc_type in collections_map.items():
            collection = db[collection_name]
            
            # Buscar documentos eliminados del usuario
            query = {
                "status": "deleted",
                "deleted_at": {"$exists": True}
            }
            
            # Filtrar por cliente si se especifica
            if client_id:
                query["client_id"] = client_id
            
            # Filtrar por operator_id si existe
            if current_user.role != "ADMIN":
                query["$or"] = [
                    {"operator_id": current_user.id},
                    {"user_id": current_user.id}
                ]
            
            docs = await collection.find(query, {"_id": 0}).to_list(1000)
            
            for doc in docs:
                # Obtener información del cliente si existe
                client_name = None
                if doc.get('client_id'):
                    client = await db.clients.find_one(
                        {"id": doc['client_id']},
                        {"_id": 0, "name": 1}
                    )
                    if client:
                        client_name = client.get('name')
                
                # Determinar el título
                title = (
                    doc.get('title') or 
                    doc.get('project_title') or 
                    doc.get('patent_title') or
                    doc.get('book_title') or
                    doc.get('name') or
                    f"{doc_type} sin título"
                )
                
                trash_items.append({
                    "id": doc.get('id'),
                    "collection": collection_name,
                    "document_type": doc_type,
                    "title": title,
                    "client_id": doc.get('client_id'),
                    "client_name": client_name,
                    "deleted_at": doc.get('deleted_at'),
                    "deleted_by": doc.get('deleted_by')
                })
        
        # Ordenar por fecha de eliminación (más reciente primero)
        trash_items.sort(key=lambda x: x['deleted_at'], reverse=True)
        
        return {
            "items": trash_items,
            "total": len(trash_items)
        }
        
    except Exception as e:
        logging.error(f"Error fetching trash: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.post("/trash/{collection}/{document_id}/restore")
async def restore_from_trash(
    collection: str,
    document_id: str,
    current_user: User = Depends(get_current_user)
):
    """Restaurar un documento desde la papelera"""
    try:
        # Validar colección
        valid_collections = [
            "books", "books_in_progress", "patents", "patents_in_progress",
            "niw_in_progress", "expert_letters", "recommendation_letters",
            "policy_papers", "business_plans", "whitepapers",
            "econometric_studies", "econometric_studies_in_progress",
            "self_petition_letters"
        ]
        
        if collection not in valid_collections:
            raise HTTPException(status_code=400, detail="Invalid collection")
        
        # Buscar documento
        col = db[collection]
        doc = await col.find_one({
            "id": document_id,
            "status": "deleted"
        })
        
        if not doc:
            raise HTTPException(status_code=404, detail="Document not found in trash")
        
        # TODOS los usuarios pueden restaurar TODOS los documentos
        logging.info(f"🔄 Restoring document {document_id} from {collection} by user {current_user.email}")
        
        # Restaurar documento
        result = await col.update_one(
            {"id": document_id},
            {
                "$set": {"status": "active"},
                "$unset": {
                    "deleted_at": "",
                    "deleted_by": ""
                }
            }
        )
        
        if result.modified_count == 0:
            raise HTTPException(status_code=400, detail="Failed to restore document")
        
        return {
            "message": "Document restored successfully",
            "document_id": document_id,
            "collection": collection
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error restoring document: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.delete("/trash/{collection}/{document_id}/permanent")
async def permanent_delete_from_trash(
    collection: str,
    document_id: str,
    current_user: User = Depends(get_current_user)
):
    """Eliminar permanentemente un documento de la papelera"""
    try:
        # Solo ADMIN puede eliminar permanentemente
        if current_user.role != "ADMIN":
            raise HTTPException(
                status_code=403,
                detail="Only administrators can permanently delete documents"
            )
        
        valid_collections = [
            "books", "books_in_progress", "patents", "patents_in_progress",
            "niw_in_progress", "expert_letters", "recommendation_letters",
            "policy_papers", "business_plans", "whitepapers",
            "econometric_studies", "econometric_studies_in_progress",
            "self_petition_letters"
        ]
        
        if collection not in valid_collections:
            raise HTTPException(status_code=400, detail="Invalid collection")
        
        col = db[collection]
        result = await col.delete_one({
            "id": document_id,
            "status": "deleted"
        })
        
        if result.deleted_count == 0:
            raise HTTPException(status_code=404, detail="Document not found in trash")
        
        return {
            "message": "Document permanently deleted",
            "document_id": document_id
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error permanently deleting document: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

