def auto_remove_conclusions(content: str) -> str:
    """
    Automatically detect and remove conclusion paragraphs from generated content.
    This is a safety net in case the LLM ignores instructions.
    """
    import re
    
    # Conclusion trigger phrases (case insensitive)
    conclusion_patterns = [
        r'<p>\s*In summary[,\s]',
        r'<p>\s*In conclusion[,\s]',
        r'<p>\s*To conclude[,\s]',
        r'<p>\s*Overall[,\s]',
        r'<p>\s*Thus[,\s]',
        r'<p>\s*Therefore[,\s]',
        r'<p>\s*Through these',
        r'<p>\s*The ultimate objective',
        r'<p>\s*In short[,\s]',
        r'<p>\s*To sum up[,\s]',
        r'<p>\s*As demonstrated',
        r'<p>\s*This demonstrates that',
        r'<p>\s*En resumen[,\s]',
        r'<p>\s*En conclusión[,\s]',
        r'<p>\s*Para concluir[,\s]',
        r'<p>\s*Por lo tanto[,\s]',
        r'<p>\s*A través de estos',
        r'<p>\s*El objetivo final',
    ]
    
    # Check if content has conclusion paragraph
    paragraphs = re.findall(r'<p>.*?</p>', content, re.DOTALL | re.IGNORECASE)
    
    if len(paragraphs) < 2:
        return content  # Too short to have a removable conclusion
    
    last_paragraph = paragraphs[-1]
    
    # Check if last paragraph matches conclusion patterns
    for pattern in conclusion_patterns:
        if re.search(pattern, last_paragraph, re.IGNORECASE):
            logging.warning(f"🚨 CONCLUSION DETECTED in last paragraph: {last_paragraph[:100]}...")
            
            # Remove the last paragraph
            # Find the last </p> and remove everything from the last <p> before it
            last_p_close = content.rfind('</p>')
            if last_p_close > 0:
                # Find the <p> that corresponds to this </p>
                content_before_last = content[:last_p_close]
                second_last_p_close = content_before_last.rfind('</p>')
                
                if second_last_p_close > 0:
                    # Remove from the last <p> onwards
                    cleaned_content = content[:second_last_p_close + 4]  # +4 for </p>
                    logging.info(f"✅ Removed conclusion paragraph automatically")
                    return cleaned_content
            
            break
    
    # Also check if last paragraph repeats "substantial merit and national importance"
    if 'substantial merit and national importance' in last_paragraph.lower() or \
       'mérito sustancial e importancia nacional' in last_paragraph.lower():
        logging.warning(f"🚨 REPETITION DETECTED in last paragraph: substantial merit phrase")
        
        # Count occurrences in previous content
        full_phrase_count = content.lower().count('substantial merit and national importance')
        full_phrase_count += content.lower().count('mérito sustancial e importancia nacional')
        
        if full_phrase_count > 1:  # If phrase appears more than once
            # Remove last paragraph
            last_p_close = content.rfind('</p>')
            if last_p_close > 0:
                content_before_last = content[:last_p_close]
                second_last_p_close = content_before_last.rfind('</p>')
                if second_last_p_close > 0:
                    cleaned_content = content[:second_last_p_close + 4]
                    logging.info(f"✅ Removed repetitive paragraph automatically")
                    return cleaned_content
    
    return content

async def evaluate_section_quality(content: str, section_type: str, previous_content: str = "") -> dict:
    """AI evaluator to check if section meets quality requirements"""
    evaluation_prompt = f"""You are a strict quality evaluator for EB-2 NIW proposals. Evaluate the following section:

**SECTION TYPE:** {section_type}

**SECTION CONTENT:**
{content}

**PREVIOUS APPROVED CONTENT (to check for repetitions):**
{previous_content[:1000] if previous_content else "No previous content"}

**CRITICAL EVALUATION RULES:**

🚨 **RULE #1 - ABSOLUTELY NO PLACEHOLDERS (CRITICAL):**
- MUST NOT contain `<POR_SUMINISTRAR>`, `<TO_BE_SUPPLIED>`, `<[INFORMATION]>`, or any placeholder markers
- MUST NOT have missing information markers or empty brackets
- ALL content must be complete and professional
- If placeholders are found, this is an automatic FAILURE
- This shows incomplete or unprofessional content

🚨 **RULE #2 - ABSOLUTELY NO CONCLUSIONS (CRITICAL - AUTO FAIL):**
- Individual sections MUST NOT have conclusion paragraphs
- MUST NOT end with phrases like: "In conclusion", "To conclude", "In summary", "Finally", "To sum up", "Overall", "Thus", "Therefore", "Through these", "The ultimate objective", "As demonstrated", "This demonstrates that", "In short"
- MUST NOT wrap up or summarize the section at the end
- MUST NOT repeat key phrases like "substantial merit and national importance" at the end
- Section should end with NEW substantive content, NOT with a closing statement
- Be EXTREMELY strict about this - even subtle conclusion phrases should FAIL
- ONLY the final section (XVII) of the entire document can have a conclusion

**CRITICAL CHECK:** Read the LAST paragraph of the section. If it:
- Starts with any conclusion trigger phrase → AUTOMATIC FAILURE
- Repeats information already stated → AUTOMATIC FAILURE
- Summarizes instead of adding new info → AUTOMATIC FAILURE

**OTHER RULES:**
3. Must NOT repeat information from previous sections
4. Must be professional and USCIS-aligned
5. Must demonstrate substantial merit and national importance (Prong 1)
6. Content should be specific to the applicant's work

🚨 **RULE #7 - SPECIFICITY & UNIQUENESS (CRITICAL):**
- Content must clearly articulate WHY this SPECIFIC applicant is uniquely qualified
- MUST include specific examples, metrics, or past achievements from the applicant's background
- MUST NOT rely primarily on generic industry statements or future projections

**Critical Test:** Could this exact text be used for another applicant in the same field?
  - If YES → This is an automatic FAILURE
  - If MOSTLY YES → Flag as 'needs_personalization'

**Look for these REQUIRED elements:**
- Phrases like: 'the applicant has previously...', 'based on their experience in...', 'having successfully...', 'unlike other professionals in the field, [Applicant]...'
- Specific numbers, dates, institutions, locations tied to the applicant
- Concrete examples from applicant's past work
- Clear differentiation from what any qualified professional could claim

**Red flags for FAILURE:**
- Content is >60% generic field description vs. <40% applicant-specific narrative
- No concrete past examples in Sections III, VIII, X, or XII
- Excessive use of future tense without past tense foundation
- Could be copy-pasted into another similar professional's application

⚠️ **RULE #8 - AI-GENERIC LANGUAGE DETECTION:**

Flag if section contains excessive use of these terms WITHOUT immediate specific evidence:

**Tier 1 Red Flags (require immediate specific evidence):**
- 'innovative' / 'innovation'
- 'transformative' / 'transform'
- 'cutting-edge' / 'groundbreaking'
- 'pioneering' / 'pioneer'
- 'significant impact'
- 'substantial contribution'

**Scoring:**
- 1-2 instances of Tier 1 terms without evidence: WARNING
- 3+ instances of Tier 1 terms without evidence: FAILURE
- >50% passive voice + lack of specific examples: FLAG for rewrite

**What counts as 'immediate specific evidence':**
- ✅ 'innovative approach, as demonstrated by [Applicant]'s 2022 pilot program where retention increased by 34%'
- ❌ 'innovative approach that will transform the field'

📊 **RULE #9 - EVIDENCE RATIO CHECK:**

For Sections III, IV, X, and XII, evaluate the ratio:
- **Past/Present Evidence** (what has been done, what currently exists) vs.
- **Future Projections** (what will happen, what is expected)

**Required Ratio:**
- Sections III & IV: Minimum 70% evidence, maximum 30% projection
- Section X: Minimum 60% evidence, maximum 40% projection
- Section XII: Minimum 50% evidence, maximum 50% projection

**Automatic FAILURE if:**
- Section is >70% future-focused without evidence foundation
- Contains phrases like 'will', 'is expected to', 'should', 'has potential to' in >60% of sentences
- No concrete past examples in Section XII

**YOUR TASK:**
Evaluate if the section PASSES or FAILS these rules. Be EXTREMELY strict about Rules #1, #2, and #7. Be MODERATE on AI-generic language (Rule #8).

**RESPOND IN JSON FORMAT:**
{{
  "passes": true/false,
  "block_generation": true/false,
  "regeneration_instructions": "specific instructions on what to fix (if block_generation is true)",
  "character_count": [actual count],
  "has_placeholders": true/false,
  "has_conclusion": true/false,
  "has_repetition": true/false,
  "is_specific_to_applicant": true/false,
  "is_too_generic": true/false,
  "ai_generic_language_count": [number],
  "evidence_vs_projection_ratio": "[X]% evidence / [Y]% projection",
  "federal_policy_connections": [number of specific policies mentioned],
  "concrete_examples_count": [number],
  "issues": ["list of specific issues found"],
  "feedback": "Brief feedback on what needs to be fixed",
  "strength_score": [1-10 scale],
  "personalization_score": [1-10 scale]
}}

**IMPORTANT - block_generation LOGIC:**
Set `block_generation: true` if ANY of these critical failures occur:
- has_conclusion == true (violates Rule #2)
- has_placeholders == true (violates Rule #1)
- has_repetition == true AND it's substantial (>20% of content)
- ai_generic_language_count >= 5 AND no evidence backing them

When `block_generation: true`, provide specific `regeneration_instructions` such as:
- "Remove the final paragraph starting with 'In summary...'. End with the previous paragraph about [specific topic]."
- "Replace placeholders <TO_BE_SUPPLIED> with actual content or omit that section."
- "Add specific evidence immediately after each use of 'innovative', 'transformative', etc."

Only return the JSON, nothing else."""

    system_message = "You are a strict quality evaluator. Be thorough and critical."
    response_text = await call_cheap_evaluator(system_message, evaluation_prompt, temperature=0.3, max_tokens=3000, json_mode=True)
    
    # Parse JSON response
    try:
        import json
        # Clean response
        cleaned = response_text.strip()
        if cleaned.startswith("```json"):
            cleaned = cleaned[7:]
        if cleaned.startswith("```"):
            cleaned = cleaned[3:]
        if cleaned.endswith("```"):
            cleaned = cleaned[:-3]
        cleaned = cleaned.strip()
        
        evaluation = json.loads(cleaned)
        return evaluation
    except:
        # If parsing fails, return a default fail
        return {
            "passes": False,
            "character_count": len(content),
            "has_conclusion": False,
            "has_repetition": False,
            "issues": ["Could not parse evaluation"],
            "feedback": "Evaluation parsing failed"
        }

class WhitepaperInput(BaseModel):
    project_title: str
    author_name: str
    author_credentials: str
    project_description: str
    target_audience: str
    technical_domain: str
    language: str = "es"
    client_id: Optional[str] = None
    # Enhanced CV data fields
    full_cv_data: Optional[dict] = None  # Complete extracted CV data
    employment_summary: Optional[List[str]] = None  # Key employment with metrics
    years_of_experience: Optional[str] = None

class WhitepaperSection(BaseModel):
    model_config = ConfigDict(extra="allow")  # ✅ Permitir campos adicionales
    
    number: int
    title: str
    content: str = ""  # ✅ Default vacío para compatibilidad
    content_es: str = ""  # ✅ Contenido en español
    content_en: str = ""  # ✅ Contenido en inglés
    approved: bool = False
    edit_history: List[dict] = []
