# ============================================================================
# Sistema de Deshacer Cambios / Restaurar Versión Anterior
# ============================================================================

class UndoChangeRequest(BaseModel):
    section_number: int
    history_index: int  # Index of the change to undo to (restore to state before this change)

@api_router.post("/business-plans/{niw_id}/undo-change")
async def undo_section_change(niw_id: str, request: UndoChangeRequest, current_user: User = Depends(get_current_user)):
    """Undo a specific change by restoring the original content from change_history"""
    try:
        # Find the document (sin filtrar por user_id para compatibilidad)
        plan = await db.business_plans.find_one({"id": niw_id}, {"_id": 0})
        found_in = "business_plans"
        if not plan:
            plan = await db.niw_in_progress.find_one({"id": niw_id}, {"_id": 0})
            found_in = "niw_in_progress"
        if not plan:
            plan = await db.business_plans_in_progress.find_one({"id": niw_id}, {"_id": 0})
            found_in = "business_plans_in_progress"
        sections = plan.get('sections', [])
        section = next((s for s in sections if s.get('number') == request.section_number), None)
        
        if not section:
            raise HTTPException(status_code=404, detail="Sección no encontrada")
        
        change_history = section.get('change_history', [])
        if not change_history or request.history_index >= len(change_history):
            raise HTTPException(status_code=400, detail="Índice de historial inválido")
        
        # Get the original content from the specified change
        change_to_undo = change_history[request.history_index]
        restored_content = change_to_undo.get('original_content', '')
        
        if not restored_content:
            raise HTTPException(status_code=400, detail="No hay contenido original para restaurar")
        
        # Determine language field
        language = plan.get('language', 'es')
        content_field = 'content_es' if language == 'es' else 'content_en'
        
        # Update the section with restored content and remove changes from history
        collection = db.business_plans if found_in == "business_plans" else db.niw_in_progress
        
        # Remove all changes from this index onwards
        new_history = change_history[:request.history_index]
        
        result = await collection.update_one(
            {"id": niw_id, "sections.number": request.section_number},
            {
                "$set": {
                    f"sections.$.{content_field}": restored_content,
                    "sections.$.content": restored_content,
                    "sections.$.change_history": new_history,
                    "sections.$.ai_edit_timestamp": datetime.now(timezone.utc).isoformat(),
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )
        
        if result.modified_count > 0:
            logging.info(f"✅ Cambio deshecho en sección {request.section_number}")
            return {
                "success": True,
                "message": f"Sección {request.section_number} restaurada exitosamente",
                "restored_content": restored_content[:500] + "..." if len(restored_content) > 500 else restored_content
            }
        else:
            raise HTTPException(status_code=500, detail="No se pudo restaurar la sección")
            
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"❌ Error deshaciendo cambio: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error: {str(e)}")

@api_router.post("/business-plans/{niw_id}/restore-initial")
async def restore_initial_version(niw_id: str, current_user: User = Depends(get_current_user)):
    """Restore all sections to their initial state (first version in history)"""
    try:
        # Find the document (sin filtrar por user_id para compatibilidad)
        plan = await db.business_plans.find_one({"id": niw_id}, {"_id": 0})
        found_in = "business_plans"
        if not plan:
            plan = await db.niw_in_progress.find_one({"id": niw_id}, {"_id": 0})
            found_in = "niw_in_progress"
        if not plan:
            plan = await db.business_plans_in_progress.find_one({"id": niw_id}, {"_id": 0})
            found_in = "business_plans_in_progress"
        
        if not plan:
            raise HTTPException(status_code=404, detail="Plan no encontrado")
        
        collection = db.business_plans if found_in == "business_plans" else db.niw_in_progress
        language = plan.get('language', 'es')
        content_field = 'content_es' if language == 'es' else 'content_en'
        
        sections_restored = 0
        sections = plan.get('sections', [])
        
        for section in sections:
            change_history = section.get('change_history', [])
            if change_history and len(change_history) > 0:
                # Get the original content from the first change
                first_change = change_history[0]
                original_content = first_change.get('original_content', '')
                
                if original_content:
                    await collection.update_one(
                        {"id": niw_id, "sections.number": section['number']},
                        {
                            "$set": {
                                f"sections.$.{content_field}": original_content,
                                "sections.$.content": original_content,
                                "sections.$.change_history": [],
                                "sections.$.ai_edited": False,
                                "updated_at": datetime.now(timezone.utc).isoformat()
                            }
                        }
                    )
                    sections_restored += 1
        
        logging.info(f"✅ {sections_restored} secciones restauradas a versión inicial")
        return {
            "success": True,
            "message": f"{sections_restored} sección(es) restaurada(s) a su versión inicial",
            "sections_restored": sections_restored
        }
            
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"❌ Error restaurando versión inicial: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error: {str(e)}")

