@api_router.post("/business-plans/approve-section/{niw_id}")
async def approve_niw_section(niw_id: str, section_data: dict, current_user: User = Depends(get_current_user)):
    """Approve and save NIW section"""
    try:
        section_data['approved'] = True
        
        # ⭐ DEBUG: Verificar que los datos bilingües lleguen correctamente
        has_content_es = bool(section_data.get('content_es'))
        has_content_en = bool(section_data.get('content_en'))
        content_es_len = len(section_data.get('content_es', ''))
        content_en_len = len(section_data.get('content_en', ''))
        
        logging.info(f"📝 Aprobando sección {section_data.get('number')} para NIW {niw_id}")
        logging.info(f"   ├── content_es: {'✅' if has_content_es else '❌'} ({content_es_len} chars)")
        logging.info(f"   └── content_en: {'✅' if has_content_en else '❌'} ({content_en_len} chars)")
        
        # Si solo tenemos content pero no content_es/content_en, duplicar para retrocompatibilidad
        if not has_content_es and section_data.get('content'):
            section_data['content_es'] = section_data['content']
            logging.info(f"   ⚠️ Copiando content a content_es")
        if not has_content_en and section_data.get('content'):
            section_data['content_en'] = section_data['content']
            logging.info(f"   ⚠️ Copiando content a content_en")
        
        result = await db.niw_in_progress.update_one(
            {"id": niw_id},
            {
                "$pull": {"sections": {"number": section_data['number']}},
                "$set": {"updated_at": datetime.now(timezone.utc).isoformat()}
            }
        )
        
        await db.niw_in_progress.update_one(
            {"id": niw_id},
            {
                "$push": {"sections": section_data},
                "$set": {
                    "current_section": section_data['number'] + 1,
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )
        
        # Auto-save version
        await auto_save_version(
            document_id=niw_id,
            document_type='niw',
            user_id=current_user.id,
            change_description=f"Sección {section_data['number']} aprobada",
            change_type='section_approval',
            sections_changed=[section_data['number']]
        )
        
        return {"message": "Sección aprobada exitosamente"}
        
    except Exception as e:
        logging.error(f"Error approving NIW section: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.post("/business-plans/finalize/{niw_id}", response_model=BusinessPlan)
async def finalize_niw(niw_id: str, current_user: User = Depends(get_current_user)):
    """Finalize NIW proposal and move to completed"""
    try:
        # 🔥 CRITICAL FIX: Check both completed and in-progress NIWs
        # Try completed NIWs first (business_plans collection)
        niw_in_progress = await db.business_plans.find_one(
            {"id": niw_id, "user_id": current_user.id},
            {"_id": 0}
        )
        
        # If not found, check in-progress NIWs
        if not niw_in_progress:
            niw_in_progress = await db.niw_in_progress.find_one({"id": niw_id, "user_id": current_user.id})
        
        if not niw_in_progress:
            raise HTTPException(status_code=404, detail="NIW proposal not found")
        
        # ⭐ Compile all sections into BILINGUAL content
        sections = sorted(niw_in_progress.get('sections', []), key=lambda x: x['number'])
        
        # ⚠️ CRITICAL FIX: Limpiar títulos duplicados antes de compilar
        import re
        
        compiled_sections_es = []
        compiled_sections_en = []
        
        for sec in sections:
            section_title = sec.get('title', '')
            section_number = sec.get('number', 0)
            
            # Función para limpiar títulos duplicados del contenido
            def clean_duplicate_titles(content, title):
                cleaned = content.strip()
                # Eliminar marcadores de código markdown
                if cleaned.startswith('```html'):
                    cleaned = cleaned[7:]
                if cleaned.startswith('```'):
                    cleaned = cleaned[3:]
                if cleaned.endswith('```'):
                    cleaned = cleaned[:-3]
                cleaned = cleaned.strip()
                
                # Eliminar cualquier encabezado (h1, h2, h3, h4) al inicio que contenga el título de la sección
                # Patrones a buscar: <h2>Title</h2>, <h3>Title</h3>, <h2><strong>Title</strong></h2>, etc.
                patterns = [
                    r'^\s*<h[1-4][^>]*>.*?</h[1-4]>\s*',  # Cualquier h1-h4 al inicio
                    r'^\s*<strong>.*?</strong>\s*',  # <strong> al inicio
                ]
                for pattern in patterns:
                    while re.match(pattern, cleaned, flags=re.IGNORECASE | re.DOTALL):
                        cleaned = re.sub(pattern, '', cleaned, count=1, flags=re.IGNORECASE | re.DOTALL)
                
                return cleaned.strip()
            
            # Procesar versión en ESPAÑOL
            content_es_raw = sec.get('content_es', sec.get('content', ''))
            content_es_clean = clean_duplicate_titles(content_es_raw, section_title)
            # Agregar título una sola vez
            compiled_sections_es.append(f"<h2><strong>{section_title}</strong></h2>\n\n{content_es_clean}")
            
            # Procesar versión en INGLÉS
            content_en_raw = sec.get('content_en', sec.get('content', ''))
            content_en_clean = clean_duplicate_titles(content_en_raw, section_title)
            # Agregar título una sola vez
            compiled_sections_en.append(f"<h2><strong>{section_title}</strong></h2>\n\n{content_en_clean}")
        
        # Unir las secciones limpias
        content_es = "\n\n\n".join(compiled_sections_es)
        content_en = "\n\n\n".join(compiled_sections_en)
        
        # Mantener content para retrocompatibilidad (usar versión inglés por defecto)
        content = content_en
        
        # ⭐ Create final proposal with BILINGUAL content
        plan = BusinessPlan(
            user_id=current_user.id,
            client_id=niw_in_progress.get('client_id'),
            project_title=niw_in_progress['project_title'],
            applicant_name=niw_in_progress['applicant_name'],
            applicant_cv=niw_in_progress['applicant_cv'],
            project_idea=niw_in_progress['project_idea'],
            patent_info=niw_in_progress.get('patent_info', ''),
            content=content,  # Backward compatibility (English version)
            content_es=content_es,  # ⭐ Spanish version
            content_en=content_en,  # ⭐ English version
            sections=sections,  # ⭐ Include bilingual sections
            language=niw_in_progress['language'],
            has_graphic_design=niw_in_progress['has_graphic_design'],
            design_description=niw_in_progress.get('design_description', '')
        )
        
        doc = plan.model_dump()
        doc['created_at'] = doc['created_at'].isoformat()
        doc['updated_at'] = doc['updated_at'].isoformat()
        
        await db.business_plans.insert_one(doc)
        
        # Apply Gamma if requested
        if niw_in_progress['has_graphic_design'] and niw_in_progress.get('design_description'):
            try:
                gamma_result = await generate_with_gamma(
                    content=content,
                    title=niw_in_progress['project_title'],
                    design_description=niw_in_progress['design_description']
                )
                
                if gamma_result.get('gamma_url'):
                    await db.business_plans.update_one(
                        {"id": plan.id},
                        {"$set": {
                            "gamma_url": gamma_result.get('gamma_url'),
                            "gamma_pdf_url": gamma_result.get('pdf_url')
                        }}
                    )
                    plan.gamma_url = gamma_result.get('gamma_url')
                    plan.gamma_pdf_url = gamma_result.get('pdf_url')
                    
                logging.info(f"Gamma design applied to NIW {plan.id}")
            except Exception as gamma_error:
                logging.error(f"Gamma processing failed (non-critical): {str(gamma_error)}")
        
        # Mark in-progress as completed
        await db.niw_in_progress.update_one(
            {"id": niw_id},
            {"$set": {"status": "completed"}}
        )
        
        # Auto-save version for finalization
        await auto_save_version(
            document_id=niw_id,
            document_type='niw',
            user_id=current_user.id,
            change_description="Documento finalizado",
            change_type='finalize'
        )
        
        # Save to Supabase if client has supabase_id
        if plan.client_id:
            try:
                client_doc = await db.clients.find_one({"id": plan.client_id}, {"_id": 0})
                if client_doc and client_doc.get('supabase_id'):
                    document_data = {
                        "id": plan.id,
                        "title": plan.project_title,
                        "applicant_name": plan.applicant_name,
                        "content": content,
                        "language": plan.language,
                        "created_at": doc['created_at'],
                        "status": "completed"
                    }
                    await save_document_to_supabase(
                        cliente_supabase_id=client_doc['supabase_id'],
                        cliente_nombre=client_doc.get('name', 'Unknown'),
                        tipo="NIW",
                        document_data=document_data
                    )
            except Exception as supabase_error:
                logging.error(f"Error saving to Supabase (non-critical): {str(supabase_error)}")
        
        return plan
        
    except Exception as e:
        logging.error(f"Error finalizing NIW: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

