def compute_document_constants(project_info: dict, cv_info: dict) -> dict:
    """
    Pre-compute all critical document constants BEFORE any section is generated.
    
    These elements are injected as CONCRETE DATA into the user message, not as
    instructions. The LLM follows concrete examples far more reliably than abstract rules.
    
    Fixes:
    - Title drift: the model copies the literal 3-line block instead of inferring it
    - Entity name inconsistency: one name computed once, injected everywhere
    - Benefit calculation errors: math pre-computed in code, model fills only narratives
    - Implementation table garbage rows: skeleton pre-built, model fills only content cols
    """
    import math as _math
    import re as _re

    petitioner_name = (
        cv_info.get("author_name") or
        project_info.get("author_name") or
        "Petitioner Full Name"
    ).strip()
    last_name = petitioner_name.split()[-1] if petitioner_name.split() else "Petitioner"

    project_title = (
        project_info.get("project_title") or
        project_info.get("endeavor_name") or
        "Proposed Endeavor"
    ).strip()

    # Narrow the title to 5-8 words
    title_words = project_title.split()
    narrow_title = " ".join(title_words[:8]) if len(title_words) > 8 else project_title

    state = (project_info.get("state") or project_info.get("location") or "[State]").strip()

    # ── Entity name formula: [Last Name] [Field] [Service] LLC ───────────────
    # Derive a 2-3 word field/service descriptor from the project title
    # Remove common stopwords and take first 2-3 meaningful words
    stop = {'for', 'and', 'of', 'in', 'the', 'a', 'an', 'to', 'with', 'on', 'by',
            'from', 'at', 'into', 'through', 'via', 'using', 'based', 'driven'}
    meaningful = [w for w in title_words if w.lower() not in stop and w[0].isupper()][:2]
    if len(meaningful) < 2:
        meaningful = [w for w in title_words if w.lower() not in stop][:2]
    field_service = " ".join(meaningful) if meaningful else "Industrial Safety"
    entity_name = f"{last_name} {field_service} LLC"

    # ── Benefit calculation: REMOVED — per-client benefit math is prohibited (P17) ──────
    # Evaluators reject NIW plans that auto-generate "X clients × $Y = $Z total impact"
    # without a published, verifiable methodology for $Y.
    # Economic impact must be stated qualitatively or via sector-level gov statistics.
    per_client_benefit = 0  # kept in dict for backward compat only — not injected
    actual_total = 0

    benefit_calc_lines = ["Economic impact: Use Approach A (direct revenue $1,490,000) or Approach B (BLS sector data)"]
    benefit_calculation = "\n".join(benefit_calc_lines)

    # ── Implementation table pre-structure ───────────────────────────────────
    implementation_table = (
        "| Phase | Timeframe | Key Activities | Resources | Deliverable | Success Criteria |\n"
        "|---|---|---|---|---|---|\n"
        f"| Phase 1: Foundation | Months 1-6 | [fill: specific activities] | $22,000 | [fill: deliverable] | [fill: measurable criterion] |\n"
        f"| Phase 2: Pilot Deployment | Months 7-12 | Upon approval of the NIW petition: [fill: specific activities] | $23,000 | [fill: deliverable] | First 12-15 paying clients |\n"
        f"| Phase 3: Market Expansion | Months 13-24 | [fill: specific activities] | $35,000 | [fill: deliverable] | 25-35 active clients |\n"
        f"| Phase 4: Regional Leadership | Months 25-36 | [fill: specific activities] | $30,000 | [fill: deliverable] | 45-60 active clients |\n"
        f"| Phase 5: Sustainable Growth | Months 37-60 | [fill: specific activities] | Operational budget | [fill: deliverable] | 100-120 active clients |"
    )

    return {
        "petitioner_name": petitioner_name,
        "last_name": last_name,
        "narrow_title": narrow_title,
        "entity_name": entity_name,
        "state": state,
        "per_client_benefit": per_client_benefit,
        "benefit_calculation": benefit_calculation,
        "actual_total": actual_total,
        "implementation_table": implementation_table,
        "title_block": (
            f"EB-2 National Interest Waiver Business Plan\n"
            f"{petitioner_name}\n"
            f"{narrow_title}"
        ),
    }


def build_v3_group_prompt(
    group_sections: list,
    section_titles_map: dict,
    project_info: dict,
    cv_info: dict,
    overrides: dict,
    anchor_context: str = "",
    doc_constants: dict = None
) -> str:
    """Build a grouped prompt asking the LLM to write multiple V3 sections in ONE call.

    Sections in the same group share full context → eliminates geographic inconsistency
    and prevents duplicate calculations across sections.

    doc_constants may be an enriched 'brief' dict from run_brief_builder_agent(),
    adding verified_stats_block and credentials_block to the pre-resolved data.
    """
    from business_plan_prompt_v3 import get_section_prompt_v3

    parts = []

    if anchor_context:
        parts.append(anchor_context)

    n = len(group_sections)
    sec_labels = " | ".join([f"Section {num}" for num in group_sections])

    # ── Pre-resolved constants block ──────────────────────────────────────────
    pre_resolved = ""
    if doc_constants:
        dc = doc_constants
        pre_resolved_parts = [
            "╔══════════════════════════════════════════════════════════════════════╗",
            "║  PRE-RESOLVED DOCUMENT CONSTANTS — COPY EXACTLY AS SHOWN           ║",
            "║  These are fixed. Do not generate alternatives. Do not vary them.   ║",
            "╚══════════════════════════════════════════════════════════════════════╝",
            "",
            f"DOCUMENT TITLE — First 3 lines of the document, nothing before them:",
            f"  {dc['title_block'].replace(chr(10), chr(10) + '  ')}",
            "",
            f"ENTITY / LLC NAME (use THIS exact name in EVERY section, verbatim):",
            f"  {dc['entity_name']}",
            "",
            f"PETITIONER: {dc['petitioner_name']}",
            f"STATE: {dc['state']}",
        ]

        # Implementation table — only for sections that need it (section 3)
        if any(s in group_sections for s in [3]):
            pre_resolved_parts += [
                "",
                "IMPLEMENTATION TABLE — Use this skeleton. Fill ONLY the [fill] columns.",
                "DO NOT add rows. DO NOT change Phase names, Timeframes, or Resource amounts:",
                dc['implementation_table'],
            ]

        # Financial anchor for sections 5 & 6 — revenue and jobs only (NO per-client benefit arithmetic)
        if any(s in group_sections for s in [5, 6]):
            pre_resolved_parts += [
                "",
                "FINANCIAL ANCHOR — Use ONLY these pre-resolved figures for Sections V and VI:",
                "  5-Year Cumulative Revenue: $1,490,000",
                "  Direct Employees Year 5: 5-6",
                "  Break-even: Year 2",
                "",
                "⛔ ABSOLUTE PROHIBITION (P17):",
                "  DO NOT calculate or state a 'per-client economic benefit' in dollar amounts.",
                "  DO NOT write 'X clients × $Y per client = $Z total impact'.",
                "  EVALUATORS WILL REJECT THIS AS UNSUPPORTED. See P17 in System Prompt.",
                "  For economic impact: use Approach A (direct revenue + payroll) or",
                "  Approach B (sector BLS/Census data) from Section 6.3 instructions.",
            ]

        # ── Brief Builder Block B: Verified statistics → injected for Section II ──
        if any(s in group_sections for s in [2]) and dc.get('verified_stats_block'):
            pre_resolved_parts += [
                "",
                dc['verified_stats_block'],
            ]

        # ── Brief Builder Block D: Verified credentials → injected for Section IV ──
        if any(s in group_sections for s in [4]) and dc.get('credentials_block'):
            pre_resolved_parts += [
                "",
                dc['credentials_block'],
            ]
            # Append CV↔Endeavor alignment note if there is a misalignment warning
            if dc.get('cv_alignment_warning'):
                pre_resolved_parts += [
                    "",
                    f"⚠️ ALIGNMENT NOTE FOR SECTION IV:",
                    dc['cv_alignment_warning'],
                ]

        # ── Brief Builder Block E: Endeavor definition → injected for Section III ──
        if any(s in group_sections for s in [3]) and dc.get('endeavor_block'):
            pre_resolved_parts += [
                "",
                "ENDEAVOR DEFINITION (from petitioner's brief):",
                dc['endeavor_block'],
            ]

        # ── Brief Builder Block C (Risk): 5 pre-defined risk titles → Section VIII ──
        if any(s in group_sections for s in [8]) and dc.get('risk_titles_block'):
            pre_resolved_parts += [
                "",
                dc['risk_titles_block'],
            ]

        pre_resolved_parts += [
            "",
            "══════════════════════════════════════════════════════════════════════",
        ]
        pre_resolved = "\n".join(pre_resolved_parts) + "\n\n"

    parts.append(pre_resolved)

    parts.append(f"""{'='*70}
WRITE {n} SECTIONS IN THIS SINGLE RESPONSE — {sec_labels}

CONSISTENCY MANDATE: These sections are generated TOGETHER in one pass.
They MUST use the entity name, state, and financial figures shown above EXACTLY.
{'='*70}
""")

    for num in group_sections:
        title = section_titles_map[num]
        sec_prompt = get_section_prompt_v3(num, title, project_info, cv_info, overrides)
        parts.append(f"""{'─'*70}
WRITE → SECTION {num}: {title}
{'─'*70}
{sec_prompt}
""")

    delimiters = "\n".join([
        f"===SECTION {num}===\n[Complete content for Section {num}: {section_titles_map[num]}]"
        for num in group_sections
    ])
    parts.append(f"""{'='*70}
MANDATORY OUTPUT FORMAT — USE THESE EXACT DELIMITERS ON THEIR OWN LINE:
{'='*70}
{delimiters}

Write ALL {n} sections. Do NOT skip any section. Each ===SECTION N=== marker must appear on its own line.
""")

    return "\n".join(parts)


def fix_document_title(section1_content: str, petitioner_name: str, narrow_title: str) -> str:
    """
    Post-processing v2: Force the correct 3-line document title at the start of Section I.

    Improvements over v1:
    - Strips h1-h6 (not only h1-h3) — handles all heading levels used by the model
    - Also strips leading <p><strong> paragraphs that look like document titles
    - Strips leading <p><em> single-line italic paragraphs containing the endeavor name
    - Always prepends the pre-computed correct title block unconditionally
    """
    import re as _re

    CORRECT_TITLE_BLOCK = (
        f"<p><strong>EB-2 National Interest Waiver Business Plan</strong></p>\n"
        f"<p><strong>{petitioner_name}</strong></p>\n"
        f"<p><em>{narrow_title}</em></p>\n\n"
    )

    content = section1_content.strip()

    # Step 1: Strip ALL leading h1-h6 elements (any heading the LLM may emit)
    leading_heading_pattern = _re.compile(
        r'^\s*<h[1-6][^>]*>.*?</h[1-6]>\s*',
        _re.S | _re.I
    )
    removed_headings = 0
    while leading_heading_pattern.match(content) and removed_headings < 12:
        stripped = leading_heading_pattern.sub('', content, count=1).strip()
        if stripped == content:
            break
        logging.info(f"🔧 [TitleFixer v2] Removed leading h-tag #{removed_headings + 1}")
        content = stripped
        removed_headings += 1

    # Step 2: Strip leading <p><strong> paragraphs that look like document/plan titles
    TITLE_KEYWORDS = [
        'business plan', 'national interest waiver', 'eb-2', 'eb2',
        'proposed endeavor', 'plan de negocios', 'petitioner',
    ]
    title_para_pattern = _re.compile(
        r'^\s*<p>\s*(?:<strong>|<b>)([^<]{3,200})(?:</strong>|</b>)\s*</p>\s*',
        _re.S | _re.I
    )
    removed_paras = 0
    while removed_paras < 6:
        m = title_para_pattern.match(content)
        if not m:
            break
        para_text = m.group(1).strip().lower()
        if any(kw in para_text for kw in TITLE_KEYWORDS):
            logging.info(f"🔧 [TitleFixer v2] Removed leading title-like <strong> para: '{m.group(1).strip()[:60]}'")
            content = content[m.end():].strip()
            removed_paras += 1
        else:
            break

    # Step 3: Strip short leading <p><em> paragraph that IS just the endeavor name
    short_em_pattern = _re.compile(
        r'^\s*<p>\s*<em>([^<]{3,150})</em>\s*</p>\s*',
        _re.S | _re.I
    )
    m = short_em_pattern.match(content)
    if m:
        em_text = m.group(1).strip().lower()
        narrow_lower = narrow_title.lower()
        # Only strip if it's effectively the endeavor title or a generic label
        if (narrow_lower in em_text or em_text in narrow_lower or
                any(kw in em_text for kw in ['business plan', 'eb-2', 'national interest'])):
            logging.info(f"🔧 [TitleFixer v2] Removed leading <em> para (endeavor title): '{m.group(1).strip()[:60]}'")
            content = content[m.end():].strip()
            removed_paras += 1

    total_removed = removed_headings + removed_paras
    if total_removed > 0:
        logging.info(f"✅ [TitleFixer v2] Removed {total_removed} leading garbage element(s); prepending correct title")
    else:
        logging.info(f"✅ [TitleFixer v2] No leading garbage found; prepending correct title unconditionally")

    return CORRECT_TITLE_BLOCK + content


def clean_garbage_table_rows(html_content: str) -> str:
    """
    Post-processing v3: Remove garbage/residual rows from HTML tables.

    V3 improvements (V13 patterns):
    - Extended year detection: catches 2000-2021 (not just 2015-2020)
    - Column-header-as-value detection: catches "Likelihood", "Impact", etc. in data cells
    - Innovation Matrix all-identical cells: "Data Management | Data Management | Data Management"
    - Risk Matrix numeric noise: "0.00" / "1.00" as standalone probability/impact values
    - Regex year detection: catches "Year 2018", "January 2018" in short cells
    """
    import re as _re

    GARBAGE_VALUES = {
        '1.000', '0.000', '1,000', '0,000', 'TBD', 'N/A', 'tbd', 'n/a',
        'Semi-Operational', 'Suggested', '[TBD]', 'Placeholder', '—', '-',
        '[fill]', '[fill: fill]', 'Fill', 'FILL', 'n.a.', 'N.A.',
    }
    PLACEHOLDER_KEYWORDS = [
        'Semi-Operational', 'Suggested', '[TBD]', 'Placeholder',
        'Risk Reduction', 'Risk Name', '[fill:', 'Insert ',
    ]
    # Column headers that appear as data values (Risk Matrix, Innovation Matrix)
    # These are NEVER valid data values — they are LLM hallucinations of the header row
    COLUMN_HEADERS_AS_DATA = {
        'likelihood', 'impact', 'probability', 'mitigation strategy',
        'risk level', 'severity', 'residual risk', 'risk category',
        'innovation area', 'differentiator', 'description', 'metric',
        'timeline', 'owner', 'status', 'evidence', 'source',
    }

    # Phantom implementation phases the LLM may add beyond the defined 5
    # Valid phases: Foundation, Pilot Deployment, Market Expansion, Regional Leadership, Sustainable Growth
    PHANTOM_PHASE_KEYWORDS = [
        'retention', 'phase 6', 'phase 7', 'phase 8',
        'compliance phase', 'scaling phase', 'optimization phase',
        'consolidation', 'maturity phase', 'exit', 'wind-down',
    ]
    # Only valid Phase labels for the implementation table (first-column check)
    VALID_IMPL_PHASES = {
        'phase 1', 'phase 2', 'phase 3', 'phase 4', 'phase 5',
        'phase 1:', 'phase 2:', 'phase 3:', 'phase 4:', 'phase 5:',
        'foundation', 'pilot', 'expansion', 'leadership', 'growth',
        'pilot deployment', 'market expansion', 'regional leadership', 'sustainable growth',
    }

    def _is_version_noise(cell: str) -> bool:
        """
        Detect Innovation Matrix noise cells — outline/version number patterns.
        Examples: '1.1.1.1.2.1', '1.1.1.2.2', '1.100000000'
        """
        if not cell:
            return False
        # Pattern A: outline-style number (3+ dot-separated digit groups) e.g. 1.1.2.1.3
        if _re.match(r'^\d+(\.\d+){3,}$', cell.strip()):
            return True
        # Pattern B: float with 5+ decimal places e.g. 1.10000, 0.000000
        if _re.match(r'^\d+\.\d{5,}$', cell.strip()):
            return True
        return False

    def _is_old_year(cell: str) -> bool:
        """
        Detect cells that are or contain an old year (2000-2021) used as data.
        Catches: "2018", "2008", "Year 2018", "January 2018", "2018-2019"
        """
        if not cell:
            return False
        s = cell.strip()
        # Exact standalone year 2000-2021
        if _re.match(r'^(200[0-9]|201[0-9]|2020|2021)$', s):
            return True
        # Short cell (< 25 chars) containing a year from 2000-2021 as a word boundary
        if len(s) < 25 and _re.search(r'\b(200[0-9]|201[0-9]|2020|2021)\b', s):
            return True
        return False

    def is_garbage_row(cells: list) -> bool:
        if not cells or len(cells) < 2:
            return False
        cell_texts = [c.strip() for c in cells]
        # Skip if all cells are empty
        if all(not c for c in cell_texts):
            return False
        non_empty = [c for c in cell_texts if c]

        # All identical non-empty values (copy-paste artifact)
        if len(non_empty) >= 3 and len(set(non_empty)) == 1:
            return True

        # Contains known garbage values
        if any(c in GARBAGE_VALUES for c in cell_texts):
            return True

        # Year-as-data in any cell (extended: 2000-2021, not just 2015-2020)
        for c in cell_texts:
            if _is_old_year(c):
                return True

        # Column headers appearing as data values (Risk Matrix / Innovation Matrix)
        # e.g. "Likelihood" in the Impact column, "Mitigation Strategy" in the Mitigation column
        non_first_non_empty = [c for c in cell_texts[1:] if c]
        if any(c.lower() in COLUMN_HEADERS_AS_DATA for c in non_first_non_empty):
            return True

        # Contains placeholder keywords
        for kw in PLACEHOLDER_KEYWORDS:
            if any(kw.lower() in c.lower() for c in cell_texts):
                return True

        # Innovation Matrix / Implementation Table noise:
        # Version-number or float-noise cells (1.1.1.2.1, 1.100000...)
        if any(_is_version_noise(c) for c in cell_texts):
            return True

        # Value columns (cells 1+) are all '0' or '1' — label cell may be non-numeric
        value_cells = [c for c in cell_texts[1:] if c]  # skip first label cell
        if value_cells and all(c in {'0', '1', '0.0', '1.0', '0.00', '1.00'} for c in value_cells):
            return True

        # Innovation Matrix: ALL value cells are identical and non-numeric (repetition artifact)
        # e.g. | Data | Data Management | Data Management | Data Management |
        if (len(value_cells) >= 2 and
                len(set(value_cells)) == 1 and
                not _re.match(r'^[\$£€]?[\d,]+\.?\d*\s*%?$', value_cells[0])):
            return True

        # "100% of the total population" type garbage
        generic_percentage = _re.compile(r'^100\s*%\s+of\s+(the\s+)?(total|all|entire)', _re.I)
        if any(generic_percentage.match(c) for c in cell_texts):
            return True
        # Pure "100%" in a value column
        if len(cell_texts) >= 2 and _re.match(r'^100\s*%$', cell_texts[1].strip()):
            return True
        return False

    def is_phantom_phase_row(cell_texts: list) -> bool:
        """Detect rows that are phantom/extra implementation phases beyond Phase 1-5."""
        if not cell_texts:
            return False
        first = cell_texts[0].lower().strip()
        # Matches any phantom phase keyword in the first cell
        if any(kw in first for kw in PHANTOM_PHASE_KEYWORDS):
            return True
        # If first cell looks like a numbered phase > 5
        m = _re.match(r'phase\s+(\d+)', first, _re.I)
        if m and int(m.group(1)) > 5:
            return True
        return False

    def is_incomplete_row(cell_texts: list) -> bool:
        """
        Detect rows that are structurally incomplete (Startup Costs pattern).
        A row with a label in col-0 but empty/dash cost/value columns is incomplete.
        """
        if not cell_texts or len(cell_texts) < 3:
            return False
        EMPTY_MARKERS = {'', '—', '-', 'N/A', 'TBD', '[TBD]', 'n/a'}
        # Non-empty cells excluding common empty markers
        real_cells = [c for c in cell_texts if c.strip() not in EMPTY_MARKERS]
        # If fewer than 2 real cells in a row that has at least 3 columns → incomplete
        if len(real_cells) < 2:
            return True
        return False

    # Process <tr> tags with their <td>/<th> content
    def clean_table_rows(match):
        table_html = match.group(0)
        rows = _re.findall(r'<tr[^>]*>(.*?)</tr>', table_html, _re.S | _re.I)
        kept_rows = []
        last_source = None
        seen_first_col = set()  # for duplicate key detection

        for row_idx, row_content in enumerate(rows):
            cells_raw = _re.findall(r'<t[dh][^>]*>(.*?)</t[dh]>', row_content, _re.S | _re.I)
            cell_texts = [_re.sub(r'<[^>]+>', '', c).strip() for c in cells_raw]
            is_header = bool(cells_raw) and all(_re.search(r'^<th', c.strip(), _re.I) for c in cells_raw)

            if is_header:
                # Always keep header rows; reset dedup state for this table
                seen_first_col.clear()
                kept_rows.append(f"<tr>{row_content}</tr>")
                continue

            # ── Check 1: standard garbage values ──────────────────────────────
            if is_garbage_row(cell_texts):
                logging.info(f"🧹 [TableCleaner v2] Removed garbage row: {cell_texts[:3]}")
                continue

            # ── Check 2: phantom implementation phases ─────────────────────────
            if is_phantom_phase_row(cell_texts):
                logging.info(f"🧹 [TableCleaner v2] Removed phantom phase row: {cell_texts[:2]}")
                continue

            # ── Check 3: incomplete rows (Startup Costs pattern) ───────────────
            if is_incomplete_row(cell_texts):
                logging.info(f"🧹 [TableCleaner v2] Removed incomplete row: {cell_texts[:3]}")
                continue

            # ── Check 4: duplicate first-column key (Qualifications Matrix) ───
            # Only apply when first column looks like a qualification/skill name
            # (i.e. not a number, not a phase label, not empty)
            first_key = cell_texts[0].strip() if cell_texts else ""
            if (first_key and len(first_key) > 3 and
                    not _re.match(r'^\d+[\.,]?\d*$', first_key) and
                    not _re.match(r'^phase\s*\d', first_key, _re.I)):
                if first_key.lower() in seen_first_col:
                    logging.info(f"🧹 [TableCleaner v2] Removed duplicate key row: '{first_key[:40]}'")
                    continue
                seen_first_col.add(first_key.lower())

            # ── Check 5: duplicate source + generic value (Problem Statistics) ─
            if len(cell_texts) >= 3:
                source_col = cell_texts[2]
                if source_col and source_col == last_source:
                    value_col = cell_texts[1] if len(cell_texts) >= 2 else ""
                    generic_value_patterns = [r'100\s*%', r'N/?A', r'^\d+\s*%\s*of\s+the', r'^Total$']
                    if any(_re.match(p, value_col, _re.I) for p in generic_value_patterns):
                        logging.info(f"🧹 [TableCleaner v2] Removed dup-source row: {cell_texts[:3]}")
                        continue
                last_source = source_col

            kept_rows.append(f"<tr>{row_content}</tr>")

        # Reconstruct table preserving its opening tag
        table_open_match = _re.match(r'(<table[^>]*>)', table_html, _re.I)
        table_open = table_open_match.group(1) if table_open_match else '<table>'
        return table_open + '\n'.join(kept_rows) + '</table>'

    cleaned = _re.sub(
        r'<table[^>]*>.*?</table>',
        clean_table_rows,
        html_content,
        flags=_re.S | _re.I
    )
    return cleaned


def enforce_entity_name_consistency(sections: list, doc_constants: dict) -> list:
    """
    Post-generation pass: normalize all LLC name variations across sections.

    The LLM sometimes generates different LLC names between sections (e.g. "Jones Fire LLC"
    in Section I vs "Jones Safety Services LLC" in Section III). This function:
    1. Extracts the first LLC name that appears in Section I (LLM's own choice in the summary)
    2. Replaces ALL other LLC names starting with the petitioner's last name with the correct one

    This respects the LLM's chosen entity name from Section I but enforces it everywhere else.
    Fallback: uses the pre-computed entity_name from doc_constants.
    """
    import re as _re

    correct_name = doc_constants.get('entity_name', '')
    last_name = doc_constants.get('last_name', '')

    if not last_name:
        return sections

    # Build pattern: [LastName] followed by 1-5 words then "LLC" (case-insensitive)
    llc_pattern = _re.compile(
        rf'\b({_re.escape(last_name)}(?:\s+\w+){{1,5}}\s+LLC)\b',
        _re.I
    )

    # Step 1: Try to extract the canonical entity name from Section I
    canonical_name = correct_name  # fallback to pre-computed
    s1 = next((s for s in sections if s.get('number') == 1), None)
    if s1:
        s1_text = _re.sub(r'<[^>]+>', ' ', s1.get('content', ''))
        matches = llc_pattern.findall(s1_text)
        if matches:
            # Use the first match from Section I as the canonical name
            canonical_name = matches[0].strip()
            logging.info(f"🏷️ [EntityFixer] Canonical entity name from Section I: '{canonical_name}'")
        else:
            logging.info(f"🏷️ [EntityFixer] No LLC found in Section I; using pre-computed: '{canonical_name}'")

    if not canonical_name:
        return sections

    # Step 2: Replace all other LastName-prefixed LLC names in ALL sections
    replacements_total = 0
    for i, section in enumerate(sections):
        content = section.get('content', '')
        if not content:
            continue

        def replace_wrong_name(m):
            found = m.group(1).strip()
            if found == canonical_name:
                return found  # already correct
            logging.info(
                f"🔧 [EntityFixer] Section {section.get('number')}: "
                f"'{found}' → '{canonical_name}'"
            )
            return canonical_name

        new_content, n_replacements = llc_pattern.subn(replace_wrong_name, content)
        if n_replacements:
            sections[i] = {**section, 'content': new_content}
            replacements_total += n_replacements

    if replacements_total:
        logging.info(f"✅ [EntityFixer] Normalized {replacements_total} LLC name occurrence(s) → '{canonical_name}'")
    else:
        logging.info(f"✅ [EntityFixer] Entity name already consistent across all sections: '{canonical_name}'")

    return sections


