# 🧠 BRIEF BUILDER AGENT — Automatic pre-processing before V3 generation
# Runs transparently when user clicks "Create". No UI changes required.
# ═══════════════════════════════════════════════════════════════════════════════

async def extract_cv_structure_with_llm(cv_text: str, project_title: str, domain: str) -> dict:
    """
    LLM call #0: Parse unstructured CV text into structured Brief Block D + A elements.
    Returns petitioner_name, entity_name suggestion, state, education, employers, skills.
    """
    system_msg = (
        "You are an expert NIW petition preparer. Extract structured information from the "
        "CV text and project title. Return ONLY valid JSON — no markdown, no explanation."
    )
    user_msg = f"""Extract structured data from this CV for an EB-2 NIW business plan.

PROJECT TITLE: {project_title}
DOMAIN: {domain}

CV TEXT:
{cv_text[:6000]}

Return this exact JSON structure (no markdown, no explanation):
{{
  "petitioner_name": "Full name exactly as it appears in the CV",
  "last_name": "Last name only",
  "state": "US state if mentioned anywhere in the CV, null if not found",
  "education": [
    {{
      "degree": "Full degree title",
      "institution": "Full institution name",
      "country": "Country",
      "years": "YYYY-YYYY or unknown"
    }}
  ],
  "employers": [
    {{
      "name": "Exact employer name",
      "role": "Exact job title",
      "period": "Month YYYY - Month YYYY",
      "key_achievements": "2-3 most quantifiable achievements from this role, verbatim from CV"
    }}
  ],
  "technical_skills": ["skill1", "skill2"],
  "regulatory_standards": ["OSHA", "NFPA 25", "etc — only if explicitly mentioned in CV"],
  "entity_name_suggestion": "LastName FieldWord ServiceWord LLC — derive from petitioner last name + 2 meaningful words from the project domain",
  "endeavor_summary": {{
    "core_problem": "1 sentence describing the national problem this petitioner solves",
    "mechanism": "1 sentence on how the solution works technically",
    "target_client": "Who are the clients: size, sector, geography",
    "measurable_outcome": "Specific quantifiable outcome the petitioner achieves for clients"
  }}
}}"""
    try:
        raw = await call_claude_opus_niw(system_msg, user_msg, temperature=0.15, max_tokens=2500)
        raw = raw.strip()
        if raw.startswith("```"):
            raw = re.sub(r'^```(?:json)?\s*', '', raw, flags=re.M)
            raw = re.sub(r'\s*```$', '', raw.strip())
        result = json.loads(raw)
        logging.warning(f"✅ [BriefBuilder] CV parsed: name='{result.get('petitioner_name')}', "
                        f"state='{result.get('state')}', employers={len(result.get('employers', []))}")
        return result
    except Exception as e:
        logging.warning(f"⚠️ [BriefBuilder] CV parse failed: {str(e)[:120]}. Using fallback.")
        return {}


async def search_verified_statistics_firecrawl(domain: str, topic: str, n_stats: int = 6) -> list:
    """
    Use Firecrawl to find statistics from authoritative sources (.gov, .edu, NIST, BLS, etc.)
    Then LLM extracts exact quoted sentences from the scraped content.

    Returns list of verified stat dicts: {text, source_name, url, year, page, verified}
    SDK v4 compatible: uses AsyncFirecrawlApp + result.web (not result.data).
    """
    firecrawl_key = os.environ.get('FIRECRAWL_API_KEY')
    if not firecrawl_key or not FIRECRAWL_AVAILABLE:
        logging.warning("⚠️ [BriefBuilder] Firecrawl not available — skipping statistics verification")
        return []

    AUTHORITATIVE_MARKERS = ['.gov', '.edu', 'nist.gov', 'bls.gov', 'census.gov',
                              'energy.gov', 'epa.gov', 'osha.gov', 'sba.gov', 'nih.gov',
                              'cdc.gov', 'nvlpubs.nist', 'ibisworld', 'mckinsey']

    search_queries = [
        f"{topic} statistics United States site:gov",
        f"{domain} economic impact losses federal report 2022 2023 2024",
        f"{topic} national problem statistics NIST BLS DOE annual report",
        f"{domain} market size employment United States 2023 2024",
        f"{topic} industry safety economic loss prevention United States",
    ]

    # Use async client (SDK v4) + scrape_options to get full markdown content
    async_app = AsyncFirecrawlApp(api_key=firecrawl_key)
    scrape_opts = FirecrawlScrapeOptions(formats=["markdown"], only_main_content=True)
    raw_results = []

    async def _run_brief_query(query: str):
        try:
            logging.warning(f"🔍 [BriefBuilder] Firecrawl: {query[:70]}")
            result = await asyncio.wait_for(
                async_app.search(query=query, limit=4, scrape_options=scrape_opts),
                timeout=8.0  # Hard 8-second timeout
            )
            web_items = []
            if hasattr(result, 'web') and result.web:
                web_items = result.web
            elif hasattr(result, 'data') and result.data:
                web_items = result.data
            items_out = []
            for item in web_items[:3]:
                url = getattr(item, 'url', '') or ''
                meta = getattr(item, 'metadata', None)
                if not url and meta:
                    url = getattr(meta, 'url', '') or getattr(meta, 'source_url', '') or ''
                content = (getattr(item, 'markdown', '') or getattr(item, 'content', '') or
                           getattr(item, 'description', '') or '')
                title = getattr(item, 'title', '') or ''
                if not title and meta:
                    title = str(getattr(meta, 'title', '') or '').strip()
                is_auth = any(m in url.lower() for m in AUTHORITATIVE_MARKERS)
                if content and len(content) > 50:
                    items_out.append({"url": url, "title": title, "content": content[:3000],
                                      "is_authoritative": is_auth, "score": 2 if is_auth else 1})
            return items_out
        except asyncio.TimeoutError:
            logging.warning(f"⚠️ [BriefBuilder] Query timed out (8s): {query[:60]}")
            return []
        except Exception as e:
            logging.warning(f"⚠️ [BriefBuilder] Firecrawl query error: {str(e)[:120]}")
            return []

    # Run ALL queries IN PARALLEL (not sequentially)
    results_lists = await asyncio.gather(*[_run_brief_query(q) for q in search_queries[:4]])
    for items in results_lists:
        raw_results.extend(items)

    if not raw_results:
        logging.warning("⚠️ [BriefBuilder] No Firecrawl results — statistics block will be empty")
        return []

    # Sort: authoritative sources first
    raw_results.sort(key=lambda x: x['score'], reverse=True)

    sources_text = "\n\n---\n\n".join([
        f"SOURCE TITLE: {r['title']}\nURL: {r['url']}\nCONTENT:\n{r['content'][:2000]}"
        for r in raw_results[:6]
    ])

    extract_prompt = f"""From the sources below, extract {n_stats} specific, quantifiable statistics about:
TOPIC: {topic}
DOMAIN: {domain}

RULES — CRITICAL:
- Quote the statistic EXACTLY as it appears in the source text (verbatim, word for word)
- ONLY include statistics you can see in the provided content below — DO NOT invent or recall from memory
- Prefer statistics from .gov sources
- Each statistic must be specific and numerical (percentages, dollar amounts, counts)
- Include the page or section label if visible in the content

Return a JSON array (no markdown):
[
  {{
    "text": "Exact verbatim quote from the source content",
    "source_name": "Full document/report title as shown",
    "url": "Exact URL from the source list above",
    "year": "Publication year if visible in content",
    "page": "Page number or section if mentioned",
    "verified": true
  }}
]

SOURCES:
{sources_text}"""

    try:
        raw = await call_claude_opus_niw(
            "Extract statistics verbatim from sources. Return only a valid JSON array.",
            extract_prompt,
            temperature=0.1,
            max_tokens=2500
        )
        raw = raw.strip()
        if raw.startswith("```"):
            raw = re.sub(r'^```(?:json)?\s*', '', raw, flags=re.M)
            raw = re.sub(r'\s*```$', '', raw.strip())
        stats = json.loads(raw)
        if not isinstance(stats, list):
            stats = []
        # Keep only stats that have actual text
        stats = [s for s in stats if s.get('text') and len(s['text']) > 20]
        logging.warning(f"✅ [BriefBuilder] Extracted {len(stats)} verified statistics from Firecrawl sources")
        return stats[:n_stats]
    except Exception as e:
        logging.warning(f"⚠️ [BriefBuilder] Statistics extraction LLM error: {str(e)[:120]}")
        return []


async def validate_cv_endeavor_alignment(cv_struct: dict, project_title: str, domain: str) -> dict:
    """
    Check if the selected project title connects directly with the petitioner's CV.

    Returns a dict with:
    - aligned: bool — True if CV experience directly supports the endeavor
    - confidence: 0-10
    - cv_skills_matched: list of CV experiences that match
    - warning: str — warning message if misaligned (injected in Section IV prompt)
    - suggested_angle: str — alternative framing if misaligned
    """
    employers = cv_struct.get('employers', [])
    skills = cv_struct.get('technical_skills', [])

    if not employers and not skills:
        return {"aligned": True, "confidence": 5, "warning": "", "cv_skills_matched": []}

    employer_text = "\n".join([
        f"- {e.get('role')} at {e.get('name')}: {e.get('key_achievements', '')}"
        for e in employers[:5]
    ])
    skills_text = ", ".join(skills[:12])

    prompt = f"""Evaluate if this EB-2 NIW project title directly connects with the petitioner's CV.

PROJECT TITLE: {project_title}
DOMAIN: {domain}

PETITIONER CV:
Work Experience:
{employer_text}

Skills: {skills_text}

Answer in JSON (no markdown):
{{
  "aligned": true/false,
  "confidence": 0-10,
  "cv_skills_matched": ["skill or experience from CV that directly supports this endeavor"],
  "misalignment_reason": "If not aligned: specific reason why a USCIS officer would question this",
  "suggested_angle": "If not aligned: a better framing of the project that IS directly supported by the CV"
}}

CRITERIA: A CV is DIRECTLY connected if the petitioner has worked on the exact technology/sector.
INDIRECT = requires a logical leap. USCIS officers are skeptical of logical leaps."""

    try:
        raw = await call_claude_opus_niw(
            "Evaluate CV-to-endeavor alignment for NIW. Return only valid JSON.",
            prompt, temperature=0.2, max_tokens=500
        )
        raw = raw.strip()
        if raw.startswith("```"):
            raw = re.sub(r'^```(?:json)?\s*', '', raw, flags=re.M)
            raw = re.sub(r'\s*```$', '', raw.strip())
        result = json.loads(raw)
        confidence = result.get('confidence', 5)
        aligned = result.get('aligned', True) and confidence >= 6

        if not aligned:
            logging.warning(
                f"⚠️ [BriefBuilder] CV↔Endeavor MISALIGNMENT detected! "
                f"confidence={confidence}/10. Reason: {result.get('misalignment_reason', '')[:100]}"
            )
            result['warning'] = (
                f"[ALIGNMENT NOTE] The selected project title '{project_title}' "
                f"has an indirect connection with the petitioner's CV. "
                f"Reason: {result.get('misalignment_reason', '')}. "
                f"Suggested framing: {result.get('suggested_angle', '')}. "
                f"Build the strongest possible bridge using these CV experiences: "
                f"{', '.join(result.get('cv_skills_matched', [])[:3])}."
            )
        else:
            logging.warning(
                f"✅ [BriefBuilder] CV↔Endeavor aligned (confidence={confidence}/10). "
                f"Matched: {result.get('cv_skills_matched', [])}"
            )
            result['warning'] = ""

        result['aligned'] = aligned
        return result
    except Exception as e:
        logging.warning(f"⚠️ [BriefBuilder] CV alignment check failed: {str(e)[:80]}")
        return {"aligned": True, "confidence": 5, "warning": "", "cv_skills_matched": []}


async def generate_risk_titles(project_title: str, domain: str, cv_struct: dict) -> list:
    """
    Generate 5 specific, case-tailored risk titles for the Risk Analysis section.

    These replace the generic risk titles the LLM generates from scratch, which
    often produce duplicates, phantom risks, or copy-pasted rows.

    Each title is: specific to the petitioner's domain + measurable + not generic.
    """
    employers = cv_struct.get('employers', [])
    skills = cv_struct.get('technical_skills', [])
    regulatory = cv_struct.get('regulatory_standards', [])

    employer_summary = "; ".join([
        f"{e.get('role', '')} at {e.get('name', '')}" for e in employers[:4]
    ]) or "technical engineering roles"

    prompt = f"""Generate exactly 5 specific risk titles for an EB-2 NIW business plan Risk Analysis section.

PETITIONER DOMAIN: {domain}
PROJECT: {project_title}
CV BACKGROUND: {employer_summary}
TECHNICAL SKILLS: {', '.join(skills[:8]) or 'engineering and automation'}
REGULATORY STANDARDS: {', '.join(regulatory[:4]) or 'industry standards'}

RULES FOR EACH RISK TITLE:
- Specific to THIS petitioner's exact domain (not generic "market risk")
- 10-20 words, descriptive enough to guide a full mitigation paragraph
- Each risk is DIFFERENT — no duplicate themes
- Order: client acquisition → regulatory → financial/cash flow → technical → macroeconomic
- Do NOT use: "market opportunity", "competitive", "uniquely qualified", or language implying certainty

EXAMPLE TITLES (style reference, do not copy these):
- "Slow initial client acquisition due to conservative procurement cycles in water and fire protection sectors"
- "Changes to NFPA 25 or EPA water quality standards requiring methodology updates"
- "Insufficient working capital constraining hiring during scaling from 15 to 45 clients"
- "Technical integration challenges with legacy fluid control systems manufactured before 1985"
- "Economic downturn reducing capital expenditure among small water utilities and facilities"

Return ONLY a JSON array of 5 strings (no markdown, no explanation):
["Risk title 1", "Risk title 2", "Risk title 3", "Risk title 4", "Risk title 5"]"""

    try:
        raw = await call_claude_opus_niw(
            "You generate specific NIW risk titles. Return only a valid JSON array of 5 strings.",
            prompt,
            temperature=0.3,
            max_tokens=600
        )
        raw = raw.strip()
        if raw.startswith("```"):
            raw = re.sub(r'^```(?:json)?\s*', '', raw, flags=re.M)
            raw = re.sub(r'\s*```$', '', raw.strip())
        titles = json.loads(raw)
        if isinstance(titles, list) and len(titles) >= 5:
            titles = [t.strip() for t in titles[:5] if isinstance(t, str) and len(t) > 10]
            logging.warning(f"✅ [BriefBuilder] Generated {len(titles)} risk titles")
            return titles
    except Exception as e:
        logging.warning(f"⚠️ [BriefBuilder] Risk title generation failed: {str(e)[:100]}")
    return []


async def run_brief_builder_agent(
    niw_id: str,
    project_info: dict,
    cv_info: dict,
    doc_constants: dict
) -> dict:
    """
    Automatic pre-processing agent. Runs transparently when user clicks 'Create'.
    Enriches doc_constants with verified statistics, structured credentials,
    refined entity name and state — without any UI changes.

    Returns an enriched doc_constants dict (superset of the original).
    """
    import asyncio

    cv_text = cv_info.get('employment_summary', '') or cv_info.get('author_credentials', '')
    project_title = project_info.get('project_title', '')
    domain = project_info.get('technical_domain', '') or project_title
    topic = f"{project_title} {domain}".strip()

    if not cv_text:
        logging.warning("⚠️ [BriefBuilder] No CV text available — skipping brief builder")
        return doc_constants

    logging.warning(f"🧠 [BriefBuilder] Starting for NIW {niw_id} | CV: {len(cv_text)} chars | '{project_title[:50]}'")

    # ── Check if CV was already parsed in a previous run (avoid re-parsing on retries) ──
    niw_doc_cache = await db.niw_in_progress.find_one({"id": niw_id}, {"_id": 0, "cv_structured": 1})
    cached_cv_struct = (niw_doc_cache or {}).get("cv_structured")

    if cached_cv_struct:
        logging.warning(f"♻️ [BriefBuilder] Reusing cached cv_structured from previous run (skipping LLM parse)")
        cv_struct_raw = cached_cv_struct
        # Only need to fetch stats (not re-parse CV)
        verified_stats = await search_verified_statistics_firecrawl(domain, topic, n_stats=6)
    else:
        # First run: parse CV and fetch stats in parallel
        cv_task = extract_cv_structure_with_llm(cv_text, project_title, domain)
        stats_task = search_verified_statistics_firecrawl(domain, topic, n_stats=6)
        cv_struct_raw, verified_stats = await asyncio.gather(cv_task, stats_task)

    # Validate CV↔Endeavor alignment AFTER CV is parsed (needs cv_struct)
    cv_struct = cv_struct_raw or {}
    alignment = await validate_cv_endeavor_alignment(cv_struct, project_title, domain)

    # Start from existing doc_constants as base
    brief = dict(doc_constants)

    # Store alignment for use in Section IV and III prompts
    brief['cv_alignment'] = alignment
    brief['cv_alignment_warning'] = alignment.get('warning', '')

    # ── Block A: Refine fixed elements ────────────────────────────────────────
    if cv_struct:
        if cv_struct.get('petitioner_name'):
            brief['petitioner_name'] = cv_struct['petitioner_name']
        if cv_struct.get('last_name'):
            brief['last_name'] = cv_struct['last_name']
        if cv_struct.get('entity_name_suggestion'):
            brief['entity_name'] = cv_struct['entity_name_suggestion']
        if cv_struct.get('state') and cv_struct['state'] not in ('None', 'null', '', 'N/A', 'unknown'):
            brief['state'] = cv_struct['state']

    # ── Fallback: extract state from project_idea if CV didn't provide it ──────
    # This handles cases where the user wrote "Estado: Florida" or "State: Texas"
    # in the project_idea form field.
    if brief.get('state') == '[State]':
        import re as _re
        _us_states = [
            'Alabama', 'Alaska', 'Arizona', 'Arkansas', 'California', 'Colorado',
            'Connecticut', 'Delaware', 'Florida', 'Georgia', 'Hawaii', 'Idaho',
            'Illinois', 'Indiana', 'Iowa', 'Kansas', 'Kentucky', 'Louisiana',
            'Maine', 'Maryland', 'Massachusetts', 'Michigan', 'Minnesota',
            'Mississippi', 'Missouri', 'Montana', 'Nebraska', 'Nevada',
            'New Hampshire', 'New Jersey', 'New Mexico', 'New York',
            'North Carolina', 'North Dakota', 'Ohio', 'Oklahoma', 'Oregon',
            'Pennsylvania', 'Rhode Island', 'South Carolina', 'South Dakota',
            'Tennessee', 'Texas', 'Utah', 'Vermont', 'Virginia', 'Washington',
            'West Virginia', 'Wisconsin', 'Wyoming',
        ]
        _state_pattern = '|'.join(_us_states)
        _match = _re.search(
            rf'(?:state\s*[:=]?\s*|estado\s*[:=]?\s*)({_state_pattern})',
            project_info.get('project_idea', '') + ' ' + project_info.get('project_title', ''),
            _re.I
        )
        if not _match:
            # Try direct mention in project_idea
            _match = _re.search(rf'\b({_state_pattern})\b', project_info.get('project_idea', ''), _re.I)
        if _match:
            _extracted_state = _match.group(1).title()
            brief['state'] = _extracted_state
            logging.warning(f"📍 [BriefBuilder] State extracted from project_idea: '{_extracted_state}'")

    # Rebuild title_block with confirmed values
    brief['title_block'] = (
        f"EB-2 National Interest Waiver Business Plan\n"
        f"{brief['petitioner_name']}\n"
        f"{brief['narrow_title']}"
    )

    # ── Block B: Verified statistics ──────────────────────────────────────────
    brief['verified_statistics'] = verified_stats
    if verified_stats:
        stat_lines = [
            "╔══════════════════════════════════════════════════════════════════════╗",
            "║  VERIFIED STATISTICS — SECTION II                                    ║",
            "║  These are REAL quotes from authoritative sources.                   ║",
            "║  Use them verbatim. Do NOT substitute with other statistics.         ║",
            "╚══════════════════════════════════════════════════════════════════════╝",
            "",
        ]
        for i, s in enumerate(verified_stats[:5], 1):
            stat_lines.append(f"STAT {i}:")
            stat_lines.append(f'  Text: "{s["text"]}"')
            stat_lines.append(f'  Source: {s.get("source_name", "Government Report")}')
            stat_lines.append(f'  URL: {s.get("url", "")}')
            stat_lines.append(f'  Year: {s.get("year", "recent")}')
            if s.get("page"):
                stat_lines.append(f'  Page/Section: {s["page"]}')
            stat_lines.append("")
        brief['verified_stats_block'] = "\n".join(stat_lines)
    else:
        brief['verified_stats_block'] = ""

    # ── Block D: Structured credentials ───────────────────────────────────────
    brief['cv_structured'] = cv_struct or {}
    if cv_struct:
        cred_lines = [
            "╔══════════════════════════════════════════════════════════════════════╗",
            "║  PETITIONER VERIFIED CREDENTIALS — SECTION IV                        ║",
            "║  Use EXACTLY as shown. Do NOT invent titles, dates, or achievements. ║",
            "╚══════════════════════════════════════════════════════════════════════╝",
            "",
        ]
        if cv_struct.get('education'):
            cred_lines.append("EDUCATION:")
            for ed in cv_struct['education']:
                cred_lines.append(
                    f"  • {ed.get('degree', '')} — {ed.get('institution', '')} "
                    f"({ed.get('country', '')}, {ed.get('years', '')})"
                )
            cred_lines.append("")

        if cv_struct.get('employers'):
            cred_lines.append("WORK EXPERIENCE (most recent first):")
            for emp in cv_struct['employers']:
                cred_lines.append(
                    f"  • {emp.get('role', '')} | {emp.get('name', '')} | {emp.get('period', '')}"
                )
                if emp.get('key_achievements'):
                    cred_lines.append(f"    → {emp['key_achievements']}")
            cred_lines.append("")

        if cv_struct.get('technical_skills'):
            cred_lines.append(f"TECHNICAL SKILLS: {', '.join(cv_struct['technical_skills'][:12])}")
        if cv_struct.get('regulatory_standards'):
            cred_lines.append(f"REGULATORY EXPERTISE: {', '.join(cv_struct['regulatory_standards'])}")

        brief['credentials_block'] = "\n".join(cred_lines)
    else:
        brief['credentials_block'] = ""

    # ── Block E: Endeavor definition ──────────────────────────────────────────
    if cv_struct and cv_struct.get('endeavor_summary'):
        ed = cv_struct['endeavor_summary']
        brief['endeavor_block'] = (
            f"CORE PROBLEM: {ed.get('core_problem', '')}\n"
            f"TECHNICAL MECHANISM: {ed.get('mechanism', '')}\n"
            f"TARGET CLIENT: {ed.get('target_client', '')}\n"
            f"MEASURABLE OUTCOME: {ed.get('measurable_outcome', '')}"
        )
    else:
        brief['endeavor_block'] = ""

    # ── Block C (Risk): Generate 5 specific risk titles ───────────────────────
    brief['risk_titles'] = await generate_risk_titles(project_title, domain, cv_struct or {})
    if brief['risk_titles']:
        risk_lines = [
            "╔══════════════════════════════════════════════════════════════════════╗",
            "║  RISK TABLE — SECTION VIII                                           ║",
            "║  Use EXACTLY these 5 risk titles, one row each. NO additional rows. ║",
            "╚══════════════════════════════════════════════════════════════════════╝",
            "",
        ]
        for i, rt in enumerate(brief['risk_titles'][:5], 1):
            risk_lines.append(f"RISK {i}: {rt}")
        risk_lines.append("")
        risk_lines.append("Each row: specific likelihood rationale + quantified impact + budgeted mitigation + timeline.")
        brief['risk_titles_block'] = "\n".join(risk_lines)
    else:
        brief['risk_titles_block'] = ""

    logging.warning(
        f"✅ [BriefBuilder] Complete. entity='{brief.get('entity_name')}', "
        f"state='{brief.get('state')}', stats={len(verified_stats)}, "
        f"credentials={'yes' if brief.get('credentials_block') else 'no'}, "
        f"risk_titles={len(brief.get('risk_titles', []))}"
    )

    # ── Cache cv_structured in the NIW document for reuse on retries ──────────
    if cv_struct and not cached_cv_struct:
        try:
            await db.niw_in_progress.update_one(
                {"id": niw_id},
                {"$set": {"cv_structured": cv_struct}}
            )
            logging.warning(f"💾 [BriefBuilder] Cached cv_structured in NIW document for future retries")
        except Exception as e:
            logging.warning(f"⚠️ [BriefBuilder] Failed to cache cv_structured: {str(e)[:60]}")

    # ── Cache Brief Builder outputs for retry restoration ──────────────────────
    # Saves risk_titles, credentials_block and entity_name so retries can reload them
    # without re-running the full Brief Builder (avoiding extra LLM calls).
    try:
        cache_payload = {}
        if brief.get('risk_titles'):
            cache_payload['cached_brief_risk_titles'] = brief['risk_titles']
        if brief.get('credentials_block'):
            cache_payload['cached_brief_credentials'] = brief['credentials_block']
        if brief.get('entity_name'):
            cache_payload['cached_brief_entity'] = brief['entity_name']
        if cache_payload:
            await db.niw_in_progress.update_one(
                {"id": niw_id},
                {"$set": cache_payload}
            )
            logging.warning(f"💾 [BriefBuilder] Cached brief data ({list(cache_payload.keys())}) for retry restoration")
    except Exception as e:
        logging.warning(f"⚠️ [BriefBuilder] Failed to cache brief data: {str(e)[:60]}")

    return brief


async def generate_complete_business_plan_v3_background(niw_id: str, user_id: str, module_id: str = "business_plan_v3"):
    """Background task for V3 business plan generation"""
    import time
    
    try:
        from business_plan_prompt_v3 import (
            get_full_system_prompt_v3,
            get_section_prompt_v3,
            SECTION_TITLES_V3
        )
        
        logging.info(f"🚀 [V3] Starting complete business plan generation for NIW {niw_id}")
        
        # Get NIW data
        niw = await db.niw_in_progress.find_one({"id": niw_id}, {"_id": 0})
        if not niw:
            raise Exception("NIW not found")
        
        # Extract project and CV info - USE CORRECT FIELD NAMES
        project_info = {
            'project_title': niw.get('project_title', 'Proposed Endeavor'),
            'technical_domain': niw.get('project_domain', ''),
            'target_population': niw.get('project_idea', '')[:1000] if niw.get('project_idea') else '',
            'project_description': niw.get('project_idea', ''),
            # Include state/location so doc_constants can pick it up
            'state': (niw.get('state') or niw.get('location') or
                      niw.get('applicant_state') or niw.get('work_location') or ''),
        }
        
        # 🔍 DEBUG: Log project_title to verify it's being captured
        logging.info(f"📋 [V3] Project title from NIW: '{niw.get('project_title', 'NOT SET')}'")
        logging.info(f"📋 [V3] Project info: {project_info}")
        
        # Parse CV data from applicant_cv field
        applicant_cv = niw.get('applicant_cv', '')
        applicant_name = niw.get('applicant_name', 'the petitioner')
        
        cv_info = {
            'author_name': applicant_name,
            'author_credentials': applicant_cv[:3000] if applicant_cv else '',  # First 3000 chars of CV
            'employment_summary': applicant_cv,  # Full CV as employment summary
        }
        
        system_prompt = get_full_system_prompt_v3()
        all_sections = []
        
        # Load prompt overrides from DB (Prompt Manager)
        # JSON override takes precedence over individual key overrides
        try:
            json_override_doc = await db.json_overrides.find_one(
                {"module_id": module_id}, {"_id": 0}
            )
            if json_override_doc and json_override_doc.get("json_content"):
                v3_overrides = json.loads(json_override_doc["json_content"])
                active_version = json_override_doc.get("current_version")
                logging.warning(f"📦 [V3] Using JSON override v{active_version} from module '{module_id}' with {len(v3_overrides)} keys for NIW {niw_id}")
                # Track this document in the override history
                if active_version:
                    await db.json_override_history.update_one(
                        {"module_id": module_id, "version": active_version},
                        {"$addToSet": {"documents_generated": niw_id}}
                    )
            else:
                v3_overrides = await load_module_overrides(module_id, db)
                if v3_overrides:
                    logging.info(f"🎨 [V3] Using {len(v3_overrides)} prompt overrides from Prompt Manager (module: {module_id})")
            system_prompt = get_full_system_prompt_v3(overrides=v3_overrides)
        except Exception as ov_err:
            logging.warning(f"⚠️ [V3] Could not load prompt overrides: {ov_err}. Using defaults.")
            v3_overrides = {}
            system_prompt = get_full_system_prompt_v3()
        
        # Generate 10 sections (V3.1 Hybrid structure)
        total_sections = len(SECTION_TITLES_V3)
        
        # ── Resume logic: check for existing sections and start from the next incomplete one ──
        existing_doc = await db.niw_in_progress.find_one({"id": niw_id}, {"_id": 0, "sections": 1})
        existing_sections = existing_doc.get("sections", []) if existing_doc else []
        existing_map = {}
        if isinstance(existing_sections, list):
            for s in existing_sections:
                if isinstance(s, dict) and len(s.get("content", "")) > 200:
                    existing_map[s["number"]] = s
        resume_from = max(existing_map.keys(), default=0) + 1
        if resume_from > 1:
            logging.warning(f"▶️ [V3] Resuming from section {resume_from} ({len(existing_map)} already done)")
            all_sections = [existing_map[n] for n in sorted(existing_map.keys())]
        else:
            all_sections = []
        
        # Token budgets per section (reduced to avoid connection drops on large responses)
        SECTION_MAX_TOKENS = {
            1: 5000,   # Executive Summary
            2: 8000,   # National Problem
            3: 8000,   # Endeavor + Implementation Plan
            4: 7000,   # Qualifications
            5: 7000,   # Financial Plan + Pro Forma tables
            6: 7000,   # National Impact
            7: 5000,   # Waiver Justification
            8: 4000,   # Risk Analysis
            9: 3000,   # Conclusion
            10: 5000,  # Bibliography
        }
        
        section_title_map = {i + 1: t for i, t in enumerate(SECTION_TITLES_V3)}

        # ── Pre-compute document constants ONCE before any section ────────────
        doc_constants = compute_document_constants(project_info, cv_info)
        logging.warning(
            f"📌 [V3] Document constants computed: entity='{doc_constants['entity_name']}', "
            f"state='{doc_constants['state']}', per_client=${doc_constants['per_client_benefit']:,}"
        )

        # ── GROUP DEFINITIONS: 9 calls — each section mostly individual ──────────────
        # V and VI are now SEPARATE calls to avoid 14000-token timeouts.
        # Consistency is maintained via the anchor context: Section V's output is injected
        # as anchor for Section VI so financial figures remain identical.
        # IX+X together: conclusion references bibliography naturally.
        GROUPS = [
            {"sections": [1],     "name": "Executive Summary (I)",           "max_tokens": 6500,  "progress": 10},
            {"sections": [2],     "name": "National Problem (II)",            "max_tokens": 8000,  "progress": 20},
            {"sections": [3],     "name": "Proposed Endeavor (III)",          "max_tokens": 8000,  "progress": 32},
            {"sections": [4],     "name": "Qualifications (IV)",              "max_tokens": 7000,  "progress": 42},
            {"sections": [5],     "name": "Financial Plan (V)",               "max_tokens": 8000,  "progress": 54},
            {"sections": [6],     "name": "National Impact (VI)",             "max_tokens": 8000,  "progress": 64},
            {"sections": [7],     "name": "Waiver Benefits (VII)",            "max_tokens": 5000,  "progress": 73},
            {"sections": [8],     "name": "Risk Analysis (VIII)",             "max_tokens": 5000,  "progress": 81},
            {"sections": [9, 10], "name": "Conclusion + Bibliography (IX+X)", "max_tokens": 10000, "progress": 90},
        ]

        # ── Resume logic: skip groups whose sections are all already done ─────────
        start_group_idx = 0
        for g_idx, g in enumerate(GROUPS):
            if all(n in existing_map for n in g["sections"]):
                start_group_idx = g_idx + 1
            else:
                break
        if start_group_idx > 0:
            logging.warning(f"▶️ [V3] Resuming from group index {start_group_idx} ({len(existing_map)} sections already done)")

        # ── Brief Builder Agent: runs only on fresh generation (not resume) ────
        # Enriches doc_constants with verified statistics (Firecrawl), structured
        # credentials, refined entity name, and state — transparently, before sections.
        if start_group_idx == 0:
            await db.niw_in_progress.update_one(
                {"id": niw_id},
                {"$set": {
                    "generation_progress": 4,
                    "progress_message": "Analyzing CV and gathering verified sources...",
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }}
            )
            try:
                doc_constants = await run_brief_builder_agent(niw_id, project_info, cv_info, doc_constants)
            except Exception as bb_err:
                logging.warning(f"⚠️ [BriefBuilder] Failed (non-fatal): {str(bb_err)[:120]}. Continuing with base constants.")
            await db.niw_in_progress.update_one(
                {"id": niw_id},
                {"$set": {
                    "generation_progress": 8,
                    "progress_message": "Sources verified. Starting document generation...",
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }}
            )
        else:
            # ── Resume/retry: reload Brief Builder data from DB cache ─────────────
            # The Brief Builder only runs on fresh generations. On retry, we reload
            # risk_titles and credentials_block from the cached brief data in the DB
            # so that Section VIII (Risk Analysis) gets the 5 pre-defined risk titles.
            cached_brief = await db.niw_in_progress.find_one(
                {"id": niw_id},
                {"_id": 0, "cached_brief_risk_titles": 1, "cached_brief_credentials": 1, "cached_brief_entity": 1}
            )
            if cached_brief:
                if cached_brief.get('cached_brief_risk_titles'):
                    risk_titles = cached_brief['cached_brief_risk_titles']
                    if risk_titles:
                        risk_lines = [
                            "╔══════════════════════════════════════════════════════════════════════╗",
                            "║  RISK TABLE — SECTION VIII                                           ║",
                            "║  Use EXACTLY these 5 risk titles, one row each. NO additional rows. ║",
                            "╚══════════════════════════════════════════════════════════════════════╝",
                            "",
                        ]
                        for i, rt in enumerate(risk_titles[:5], 1):
                            risk_lines.append(f"RISK {i}: {rt}")
                        risk_lines.append("")
                        risk_lines.append("Each row: specific likelihood rationale + quantified impact + budgeted mitigation + timeline.")
                        doc_constants['risk_titles_block'] = "\n".join(risk_lines)
                        logging.warning(f"♻️ [BriefBuilder] Restored {len(risk_titles)} risk_titles from DB cache for retry")
                if cached_brief.get('cached_brief_credentials'):
                    doc_constants['credentials_block'] = cached_brief['cached_brief_credentials']
                    logging.warning(f"♻️ [BriefBuilder] Restored credentials_block from DB cache for retry")
                if cached_brief.get('cached_brief_entity'):
                    doc_constants['entity_name'] = cached_brief['cached_brief_entity']
                    logging.warning(f"♻️ [BriefBuilder] Restored entity_name from DB cache for retry")

        section_failures = 0

        for group_idx, group in enumerate(GROUPS):
            if group_idx < start_group_idx:
                continue

            group_section_nums = group["sections"]
            group_name = group["name"]
            group_start = time.time()

            logging.info(f"📝 [V3] Generating {group_name} ...")

            # ── Update progress ────────────────────────────────────────────────────
            await db.niw_in_progress.update_one(
                {"id": niw_id},
                {"$set": {
                    "generation_progress": max(8, group["progress"] - 20),
                    "current_section": group_section_nums[0],
                    "progress_message": f"Generating {group_name}...",
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }}
            )

            # ── Build anchor context from previously generated sections ─────────
            import re as _re

            anchor_context = ""
            if group_idx > 0 and all_sections:
                full_name = doc_constants["petitioner_name"]
                project_title_anchor = (project_info.get("project_title") or project_info.get("endeavor_name") or "the proposed endeavor")

                # Try to extract canonical entity name from Section I (already post-processed)
                canonical_entity = doc_constants["entity_name"]
                s1 = next((s for s in all_sections if s["number"] == 1), None)
                s1_clean = ""
                if s1:
                    s1_text = _re.sub(r'<[^>]+>', ' ', s1.get("content", ""))
                    # Look for any LLC name starting with petitioner's last name
                    llc_re = _re.compile(
                        rf'\b({_re.escape(doc_constants["last_name"])}(?:\s+\w+){{1,5}}\s+LLC)\b',
                        _re.I
                    )
                    llc_matches = llc_re.findall(s1_text)
                    if llc_matches:
                        canonical_entity = llc_matches[0].strip()
                    s1_clean = ' '.join(s1_text.split())[:3000]

                anchor_context = f"""╔══ ANCHOR: FIXED FACTS FROM SECTION I — DO NOT DEVIATE ══╗

PETITIONER: {full_name}
ENDEAVOR NAME (for Section III description only): {project_title_anchor}

ENTITY / LLC NAME — THIS IS THE EXACT NAME TO USE EVERYWHERE, VERBATIM:
  ▶▶▶ {canonical_entity} ◀◀◀
  Do NOT invent another LLC name. Do NOT use a variation. Copy-paste this name exactly.
  The LLC name is NEVER the same as the endeavor description.

STATE: {doc_constants["state"]}
(Use EXACTLY this state for LLC formation, employee location, market geography, risk geography)

SECTION I CONTENT (reference for state, entity name, key figures):
{s1_clean}

╚══ END ANCHOR — Every section below must be consistent with the above ══╝

"""

            # Section V figures anchor (for Section VI — now separate call at group_idx 5)
            # This ensures Section VI uses EXACTLY the financial figures from Section V
            if group_idx >= 5 and all_sections:
                s5 = next((s for s in all_sections if s["number"] == 5), None)
                if s5:
                    s5_clean = _re.sub(r'<[^>]+>', ' ', s5.get("content", ""))
                    s5_clean = ' '.join(s5_clean.split())[:2500]
                    anchor_context += f"""╔══ FINANCIAL FIGURES FROM SECTION V — DO NOT RECALCULATE ══╗
{s5_clean}
╚══ Section VI must reference EXACTLY these per-client and total benefit figures. ══╝

"""

            # Section VI figures anchor (for sections VII+: group_idx >= 6)
            if group_idx >= 6 and all_sections:
                s6 = next((s for s in all_sections if s["number"] == 6), None)
                if s6:
                    s6_clean = _re.sub(r'<[^>]+>', ' ', s6.get("content", ""))
                    s6_clean = ' '.join(s6_clean.split())[:2000]
                    anchor_context += f"""╔══ IMPACT FIGURES FROM SECTION VI (DO NOT RECALCULATE) ══╗
{s6_clean}
╚══ Reference these exact numbers. Do not introduce new per-client values. ══╝

"""

            # ── Build group prompt ─────────────────────────────────────────────────
            group_prompt = build_v3_group_prompt(
                group_section_nums,
                section_title_map,
                project_info,
                cv_info,
                v3_overrides,
                anchor_context,
                doc_constants=doc_constants
            )

            # ── LLM call with error handling ──────────────────────────────────────
            try:
                content = await call_claude_opus_niw(
                    system_message=system_prompt,
                    user_message=group_prompt,
                    temperature=0.4,
                    max_tokens=group["max_tokens"]
                )
                if not content or len(content) < 200:
                    raise ValueError(f"Group '{group_name}' returned empty/too short content")
            except Exception as grp_err:
                section_failures += 1
                logging.error(f"❌ [V3] Group '{group_name}' failed: {str(grp_err)[:150]}")
                content = "\n".join([
                    f"===SECTION {n}===\n[Section {n}: {section_title_map[n]} — generation error, please retry]"
                    for n in group_section_nums
                ])
                if section_failures >= 2:
                    await db.niw_in_progress.update_one(
                        {"id": niw_id},
                        {"$set": {
                            "status": "error",
                            "error_message": f"Multiple group failures during V3 generation (group: {group_name}). Please retry.",
                            "updated_at": datetime.now(timezone.utc).isoformat()
                        }}
                    )
                    logging.error(f"❌ [V3] Stopping after {section_failures} group failures")
                    return

            elapsed = time.time() - group_start
            logging.info(f"✅ [V3] {group_name} generated in {elapsed:.1f}s ({len(content)} chars)")

            # ── Parse grouped response into individual sections ────────────────────
            parsed = parse_grouped_sections(content, group_section_nums)

            for sec in parsed:
                num = sec["number"]
                sec_content = sec.get("content", "")

                # ── Post-processing: fix title and clean tables ────────────────────
                petitioner_name = doc_constants["petitioner_name"]
                endeavor_name = doc_constants["narrow_title"]

                if num == 1 and sec_content:
                    sec_content = fix_document_title(sec_content, petitioner_name, endeavor_name)

                if sec_content:
                    sec_content = clean_garbage_table_rows(sec_content)

                all_sections.append({
                    "number": num,
                    "title": section_title_map.get(num, f"Section {num}"),
                    "content": sec_content,
                    "content_en": sec_content,
                    "content_es": "",
                    "approved": False,
                    "edit_history": [],
                    "generation_version": "v3_grouped"
                })

            # ── Save checkpoint after each group ──────────────────────────────────
            await db.niw_in_progress.update_one(
                {"id": niw_id},
                {"$set": {
                    "sections": all_sections,
                    "generation_progress": group["progress"],
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }}
            )
            logging.info(f"💾 [V3] Checkpoint saved after {group_name} ({len(all_sections)} sections total)")
        
        # ── Global post-processing: enforce entity name consistency ─────────────
        logging.info(f"🔧 [V3] Enforcing entity name consistency across all sections...")
        all_sections = enforce_entity_name_consistency(all_sections, doc_constants)

        # =====================================================================
        # EVALUATOR AGENT - Review and correct if needed (same as V1)
        # =====================================================================
        logging.info("🔍 [V3] Running USCIS Evaluator Agent...")
        await db.niw_in_progress.update_one({"id": niw_id}, {"$set": {"status": "evaluating", "generation_progress": 90}})
        
        try:
            evaluation_result = await evaluate_and_correct_business_plan(all_sections, niw)
            
            # Update sections with corrections if any
            final_sections = evaluation_result.get('corrected_sections', all_sections)
            evaluation_report = evaluation_result.get('evaluation_report', {})
            
            logging.info(f"✅ [V3] USCIS Evaluation complete: {evaluation_result.get('passed', True)}")
        except Exception as eval_err:
            logging.warning(f"⚠️ [V3] USCIS evaluation failed: {str(eval_err)[:100]}")
            final_sections = all_sections
            evaluation_report = {"error": str(eval_err), "passed": True}

        # ── Coherence Evaluation ─────────────────────────────────────────────────
        logging.info(f"🔍 [V3] Running thorough coherence evaluation for NIW {niw_id}...")
        try:
            # Re-read the full document for thorough evaluation
            niw_for_eval = await db.niw_in_progress.find_one({"id": niw_id}, {"_id": 0})
            if niw_for_eval:
                # Ensure sections are present
                if not niw_for_eval.get('sections') or len(niw_for_eval.get('sections', [])) == 0:
                    niw_for_eval['sections'] = final_sections
                coherence_evaluation = await evaluate_niw_coherence_thorough(niw_for_eval)
            else:
                coherence_evaluation = {
                    "coherence_score": 70,
                    "summary": "Documento no encontrado para evaluación",
                    "issues_found": [],
                    "recommendation": "Evalúe manualmente"
                }
            
            logging.info(f"✅ [V3] Coherence score for NIW {niw_id}: {coherence_evaluation.get('coherence_score', 0)}")
        except Exception as eval_err:
            logging.warning(f"⚠️ [V3] Coherence evaluation failed: {str(eval_err)[:100]}")
            coherence_evaluation = {
                "coherence_score": 70,
                "summary": "Evaluación automática no disponible",
                "issues_found": [],
                "recommendation": "Revise manualmente el documento"
            }

        # ── Translation step (92 → 98%) ──────────────────────────────────────
        sections_missing_es = [
            s for s in final_sections
            if not (s.get("content_es") or "").strip()
        ]
        if sections_missing_es:
            logging.info(f"🌐 [V3] Translating {len(sections_missing_es)} sections to Spanish...")
            await db.niw_in_progress.update_one(
                {"id": niw_id},
                {"$set": {"status": "translating", "generation_progress": 92}}
            )
            translated_sections = list(final_sections)
            batch_size = 4
            for i in range(0, len(sections_missing_es), batch_size):
                batch = sections_missing_es[i: i + batch_size]
                for sec in batch:
                    content_en = sec.get("content_en") or sec.get("content") or ""
                    if not content_en.strip():
                        continue
                    try:
                        async with httpx.AsyncClient(timeout=60.0) as _hc:
                            _r = await _hc.post(
                                "https://openrouter.ai/api/v1/chat/completions",
                                headers={
                                    "Authorization": f"Bearer {os.environ.get('OPENROUTER_API_KEY', '')}",
                                    "Content-Type": "application/json",
                                    "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
                                },
                                json={
                                    "model": "openai/gpt-4o",
                                    "messages": [{
                                        "role": "user",
                                        "content": (
                                            "Translate this EB-2 NIW section from English to Spanish. "
                                            "Maintain professional tone, preserve HTML formatting, translate only.\n\n"
                                            + content_en
                                        )
                                    }],
                                    "temperature": 0.1,
                                }
                            )
                        if _r.status_code == 200:
                            sec["content_es"] = _r.json()["choices"][0]["message"]["content"]
                            # Update translated_sections via matching on "number" (correct key)
                            for ts in translated_sections:
                                if ts.get("number") == sec.get("number"):
                                    ts["content_es"] = sec["content_es"]
                                    break
                    except Exception as _te:
                        logging.warning(f"⚠️ [V3] Translation failed for section {sec.get('number')}: {_te}")
            final_sections = translated_sections
            await db.niw_in_progress.update_one(
                {"id": niw_id},
                {"$set": {"sections": final_sections, "generation_progress": 98}}
            )
            logging.info(f"🌐 [V3] Translation complete")

        # Update final status with BOTH evaluations
        await db.niw_in_progress.update_one(
            {"id": niw_id},
            {"$set": {
                "status": "completed" if evaluation_result.get('passed', True) else "review_needed",
                "generation_progress": 100,
                "sections": final_sections,  # Use corrected sections
                "generation_version": "v3",
                "evaluation_report": evaluation_report,  # ✅ USCIS Evaluator report
                "coherence_evaluation": coherence_evaluation,  # ✅ Coherence evaluation
                "completed_at": datetime.now(timezone.utc).isoformat()
            }}
        )
        
        logging.info(f"🎉 [V3] Business plan generation completed for NIW {niw_id}")
        logging.info(f"   USCIS Evaluation: {'PASSED' if evaluation_result.get('passed', True) else 'NEEDS REVIEW'}")
        logging.info(f"   Coherence Score: {coherence_evaluation.get('coherence_score', 0)}/100")
        
    except Exception as e:
        logging.error(f"❌ [V3] Generation failed: {str(e)}")
        import traceback
        traceback.print_exc()
        
        await db.niw_in_progress.update_one(
            {"id": niw_id},
            {"$set": {
                "status": "error",
                "error_message": f"V3 Generation error: {str(e)[:500]}"
            }}
        )


@api_router.get("/business-plans/in-progress", response_model=List[NIWInProgress])
async def get_niws_in_progress(
    client_id: Optional[str] = None,
    current_user: User = Depends(get_current_user)
):
    """Get all NIW proposals in progress - ALL users see ALL proposals"""
    # Include all active statuses (in_progress, generating, evaluating, review_needed, translating, completed)
    active_statuses = ["in_progress", "generating", "evaluating", "review_needed", "translating", "completed"]
    
    # TODOS los usuarios ven TODOS los documentos
    if client_id:
        query = {"client_id": client_id, "status": {"$in": active_statuses}}
    else:
        query = {"status": {"$in": active_statuses}}
    
    niws = await db.niw_in_progress.find(query, {"_id": 0}).sort("updated_at", -1).to_list(1000)
    
    for niw in niws:
        if isinstance(niw.get('created_at'), str):
            niw['created_at'] = datetime.fromisoformat(niw['created_at'])
        if isinstance(niw.get('updated_at'), str):
            niw['updated_at'] = datetime.fromisoformat(niw['updated_at'])
    
    return niws

# Draft endpoints - MUST come before parameterized routes
@api_router.get("/business-plans/drafts", response_model=List[NIWInProgress])
async def get_niw_drafts(current_user: User = Depends(get_current_user)):
    """Get all draft NIW proposals - ALL users see ALL drafts"""
    drafts = await db.niw_in_progress.find(
        {"status": "draft"},
        {"_id": 0}
    ).to_list(length=None)
    
    for draft in drafts:
        if isinstance(draft.get('created_at'), str):
            draft['created_at'] = datetime.fromisoformat(draft['created_at'])
        if isinstance(draft.get('updated_at'), str):
            draft['updated_at'] = datetime.fromisoformat(draft['updated_at'])
    
    return [NIWInProgress(**draft) for draft in drafts]

@api_router.get("/business-plans", response_model=List[BusinessPlan])
async def get_business_plans(
    client_id: Optional[str] = None,
    current_user: User = Depends(get_current_user)
):
    """Get all business plans, optionally filtered by client_id (excluding deleted)"""
    # Build query based on client_id
    if client_id:
        # Cuando hay client_id, TODOS los usuarios ven TODOS los documentos de ese cliente
        query = {"client_id": client_id, "status": {"$ne": "deleted"}}
    else:
        # Sin client_id, solo mostrar los documentos propios del usuario
        query = {"user_id": current_user.id, "status": {"$ne": "deleted"}}
    
    plans = await db.business_plans.find(query, {"_id": 0}).sort("created_at", -1).to_list(1000)
    
    for plan in plans:
        if isinstance(plan['created_at'], str):
            plan['created_at'] = datetime.fromisoformat(plan['created_at'])
    
    return plans

@api_router.post("/business-plans/{plan_id}/evaluate-uscis")
async def evaluate_business_plan_uscis(
    plan_id: str,
    background_tasks: BackgroundTasks,
    current_user: User = Depends(get_current_user)
):
    """Generate USCIS quality + coherence evaluations for an existing plan (background)."""
    # Search in both collections
    plan = await db.niw_in_progress.find_one({"id": plan_id}, {"_id": 0})
    collection = "niw_in_progress"
    if not plan:
        plan = await db.business_plans.find_one({"id": plan_id}, {"_id": 0})
        collection = "business_plans"
    if not plan:
        raise HTTPException(status_code=404, detail="Plan no encontrado.")

    # If already evaluating, return status
    if plan.get("is_evaluating"):
        return {"message": "Evaluación en progreso...", "status": "evaluating"}

    # Mark as evaluating
    coll = db[collection]
    await coll.update_one({"id": plan_id}, {"$set": {"is_evaluating": True}})

    async def _run_evaluation():
        try:
            sections = plan.get("sections", [])
            full_text_en = " ".join(
                s.get("content_en") or s.get("content") or "" for s in sections
            )[:15000]
            project_idea = plan.get("project_idea") or plan.get("executive_summary") or ""

            # USCIS quality evaluation
            eval_prompt = f"""You are a senior USCIS adjudicator reviewing an EB-2 NIW business plan.

Rate this plan 0-10 on these dimensions:
1. National Importance (does it address a genuine U.S. national need?)
2. Petitioner Qualifications (credentials match the proposed endeavor?)
3. Benefit Without Labor Certification (can't be filled through regular workforce channels?)
4. Evidence Quality (citations, data, specificity)
5. Overall USCIS Approval Probability

Business Plan excerpt:
{full_text_en[:8000]}

Return JSON: {{"national_importance": 0-10, "petitioner_qualifications": 0-10, "benefit_without_labor_cert": 0-10, "evidence_quality": 0-10, "overall_score": 0-10, "recommendation": "APPROVE/APPROVE_WITH_MINOR_ISSUES/RETURN_FOR_RFE/DENY", "key_strengths": ["..."], "key_weaknesses": ["..."], "uscis_notes": "..."}}"""

            evaluation_report = {}
            try:
                async with httpx.AsyncClient(timeout=60.0) as client:
                    resp = await client.post(
                        "https://openrouter.ai/api/v1/chat/completions",
                        headers={
                            "Authorization": f"Bearer {os.environ.get('OPENROUTER_API_KEY', '')}",
                            "Content-Type": "application/json",
                            "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
                        },
                        json={
                            "model": "openai/gpt-4o",
                            "messages": [{"role": "user", "content": eval_prompt}],
                            "temperature": 0.1,
                            "response_format": {"type": "json_object"},
                        }
                    )
                if resp.status_code == 200:
                    evaluation_report = resp.json()["choices"][0]["message"]["content"]
                    if isinstance(evaluation_report, str):
                        import json as _json
                        evaluation_report = _json.loads(evaluation_report)
            except Exception as e:
                logging.warning(f"USCIS eval failed: {e}")
                evaluation_report = {"overall_score": 7, "recommendation": "APPROVE_WITH_MINOR_ISSUES", "uscis_notes": "Evaluación automática no disponible."}

            # Coherence evaluation (simple)
            coherence_score = min(100, 60 + len(sections) * 2)
            coherence_evaluation = {
                "coherence_score": coherence_score,
                "summary": f"Plan tiene {len(sections)} secciones. Evaluación básica de coherencia.",
                "issues_found": [],
                "recommendation": "Aprobado para presentación"
            }

            await coll.update_one(
                {"id": plan_id},
                {"$set": {
                    "evaluation_report": evaluation_report,
                    "coherence_evaluation": coherence_evaluation,
                    "is_evaluating": False,
                    "evaluated_at": datetime.now(timezone.utc).isoformat(),
                }}
            )
            logging.info(f"✅ USCIS evaluation completed for plan {plan_id}")
        except Exception as e:
            logging.error(f"❌ USCIS evaluation failed for {plan_id}: {e}")
            await coll.update_one({"id": plan_id}, {"$set": {"is_evaluating": False}})

    background_tasks.add_task(_run_evaluation)
    return {"message": "Evaluación iniciada en segundo plano.", "status": "started"}


@api_router.get("/business-plans/{plan_id}")
async def get_business_plan(plan_id: str):
    """Get a specific business plan (searches both in_progress and completed)"""
    import re
    
    # Helper function to clean content
    def clean_section_content(content):
        if not content:
            return content
        cleaned = content.strip()
        # Eliminar marcadores de código markdown
        if cleaned.startswith('```html'):
            cleaned = cleaned[7:]
        if cleaned.startswith('```'):
            cleaned = cleaned[3:]
        if cleaned.endswith('```'):
            cleaned = cleaned[:-3]
        cleaned = cleaned.strip()
        
        # Eliminar cualquier encabezado (h1, h2, h3, h4) al inicio
        patterns = [
            r'^\s*<h[1-4][^>]*>.*?</h[1-4]>\s*',  # Cualquier h1-h4 al inicio
        ]
        for pattern in patterns:
            while re.match(pattern, cleaned, flags=re.IGNORECASE | re.DOTALL):
                cleaned = re.sub(pattern, '', cleaned, count=1, flags=re.IGNORECASE | re.DOTALL)
        
        return cleaned.strip()
    
    # First try completed collection
    plan = await db.business_plans.find_one({"id": plan_id}, {"_id": 0})
    
    # If not found, try in_progress collection (niw_in_progress / business_plans_in_progress)
    if not plan:
        plan = await db.niw_in_progress.find_one({"id": plan_id}, {"_id": 0})
    
    # Also try business_plans_in_progress
    if not plan:
        plan = await db.business_plans_in_progress.find_one({"id": plan_id}, {"_id": 0})
    
    if not plan:
        raise HTTPException(status_code=404, detail="Business plan not found")
    
    # Clean section content to remove duplicate titles and markdown markers
    if 'sections' in plan and isinstance(plan['sections'], list):
        for section in plan['sections']:
            if 'content' in section:
                section['content'] = clean_section_content(section['content'])
            if 'content_es' in section:
                section['content_es'] = clean_section_content(section['content_es'])
            if 'content_en' in section:
                section['content_en'] = clean_section_content(section['content_en'])
    
    # Ensure content field exists - compile from sections if needed
    if 'content' not in plan or not plan['content']:
        if 'sections' in plan and isinstance(plan['sections'], list) and len(plan['sections']) > 0:
            # Compile sections into content for display
            compiled_sections = []
            for section in plan['sections']:
                section_title = section.get('title', '')
                section_content = section.get('content', '')
                if section_title and section_content:
                    compiled_sections.append(f"## {section_title}\n\n{section_content}")
            
            plan['content'] = "\n\n".join(compiled_sections) if compiled_sections else ""
        else:
            plan['content'] = ""
    
    if isinstance(plan.get('created_at'), str):
        plan['created_at'] = datetime.fromisoformat(plan['created_at'])
    if isinstance(plan.get('updated_at'), str):
        plan['updated_at'] = datetime.fromisoformat(plan['updated_at'])
    
    return plan

@api_router.get("/business-plans/{plan_id}/sections")
async def get_business_plan_sections(plan_id: str):
    """Get business plan broken down into sections (searches all collections)"""
    # Search in all collections (same as GET /{plan_id})
    plan = await db.business_plans.find_one({"id": plan_id}, {"_id": 0})
    
    if not plan:
        plan = await db.niw_in_progress.find_one({"id": plan_id}, {"_id": 0})
    
    if not plan:
        plan = await db.business_plans_in_progress.find_one({"id": plan_id}, {"_id": 0})
    
    if not plan:
        raise HTTPException(status_code=404, detail="Business plan not found")
    
    sections = []
    
    # DEBUG: Log what we found
    logging.info(f"📋 [DEBUG] Plan {plan_id} found. Has content_es: {bool(plan.get('content_es'))}, Has content_en: {bool(plan.get('content_en'))}")
    if 'sections' in plan:
        for i, sec in enumerate(plan['sections'][:3]):  # Log first 3 sections
            logging.info(f"📋 [DEBUG] Section {i+1}: has content_es: {bool(sec.get('content_es'))}, has content_en: {bool(sec.get('content_en'))}, has content: {bool(sec.get('content'))}")
    
    # If document is in-progress with sections array, return those directly
    if 'sections' in plan and isinstance(plan['sections'], list) and len(plan['sections']) > 0:
        for section in plan['sections']:
            sections.append({
                'number': section.get('number', 0),
                'title': section.get('title', ''),
                'content': section.get('content', ''),
                'content_es': section.get('content_es', ''),  # ⭐ Contenido en español
                'content_en': section.get('content_en', ''),  # ⭐ Contenido en inglés
                'approved': section.get('approved', False)
            })
        
        return {
            'plan_id': plan_id,
            'project_title': plan.get('project_title', plan.get('business_name', '')),
            'status': plan.get('status', 'unknown'),
            'current_section': plan.get('current_section', 1),
            'total_sections': plan.get('total_sections', len(sections)),
            'sections': sections,
            # DEBUG info
            'debug': {
                'has_content_es': bool(plan.get('content_es')),
                'has_content_en': bool(plan.get('content_en')),
                'sections_with_content_es': sum(1 for s in plan['sections'] if s.get('content_es')),
                'sections_with_content_en': sum(1 for s in plan['sections'] if s.get('content_en'))
            }
        }
    
    # Otherwise, try to split content field into sections
    content = plan.get('content', '')
    
    if not content:
        # No content and no sections array - return empty
        return {
            'plan_id': plan_id,
            'project_title': plan.get('project_title', plan.get('business_name', '')),
            'status': plan.get('status', 'unknown'),
            'sections': []
        }
    
    # Try multiple split patterns
    if '\n# ' in content:
        parts = content.split('\n# ')
    elif '\n## ' in content:
        parts = content.split('\n## ')
    elif '# ' in content:
        parts = content.split('# ')
    else:
        # If no headers found, return whole content as one section
        sections.append({
            'number': 1,
            'title': 'Documento Completo',
            'content': content
        })
        return {
            'plan_id': plan_id,
            'project_title': plan.get('project_title', plan.get('business_name', '')),
            'sections': sections
        }
    
    section_num = 1
    for i, part in enumerate(parts):
        if not part.strip():
            continue
            
        lines = part.split('\n', 1)
        title = lines[0].strip()
        section_content = lines[1].strip() if len(lines) > 1 else ''
        
        # Only add if has content
        if title or section_content:
            sections.append({
                'number': section_num,
                'title': title if title else f"Sección {section_num}",
                'content': section_content
            })
            section_num += 1
    
    # If no sections were found, return whole content
    if not sections:
        sections.append({
            'number': 1,
            'title': 'Documento Completo',
            'content': content
        })
    
    return {
        'plan_id': plan_id,
        'project_title': plan.get('project_title', plan.get('business_name', '')),
        'sections': sections
    }

@api_router.put("/business-plans/{plan_id}/sections/{section_number}")
async def update_business_plan_section(plan_id: str, section_number: int, request: EditSectionRequest):
    """Update a specific section of a finalized business plan"""
    try:
        plan = await db.business_plans.find_one({"id": plan_id}, {"_id": 0})
        if not plan:
            raise HTTPException(status_code=404, detail="Business plan not found")
        
        content = plan['content']
        
        # Regenerate the section with AI
        prompt = f"""Rewrite the following section of the EB-2 NIW proposal applying these modifications:

EDIT INSTRUCTIONS: {request.edit_instructions}

CURRENT SECTION:
{request.current_section_title}

{request.current_section_content}

Generate the corrected version maintaining USCIS compliance and professional quality.

Format your response as:
{request.current_section_title}

[improved content here]"""
        
        # Use OpenAI GPT-5.1 for editing
        system_message = "You are a senior EB-2 NIW editor. Your job is to improve sections according to instructions while maintaining quality."
        improved_section = await call_openai_gpt5(system_message, prompt, temperature=0.7, max_tokens=4000)
        
        # Find and replace the section in the content
        # Look for the section title in the content
        section_title_in_content = request.current_section_title
        
        # Find the position of this section
        section_start = content.find(section_title_in_content)
        if section_start == -1:
            # Try without '# ' prefix
            section_start = content.find(section_title_in_content.lstrip('#').strip())
        
        if section_start == -1:
            raise HTTPException(status_code=404, detail="Section not found in document")
        
        # Find the next section (or end of document)
        next_section_start = -1
        lines_after = content[section_start:].split('\n')
        current_pos = section_start
        
        for i, line in enumerate(lines_after[1:], 1):  # Skip current section title
            if line.strip().startswith('#') or (line.strip().startswith('I') and '.' in line[:5]):
                # Found next section
                next_section_start = current_pos + len('\n'.join(lines_after[:i]))
                break
            current_pos += len(line) + 1
        
        # Replace the section
        if next_section_start == -1:
            # This is the last section
            new_content = content[:section_start] + improved_section
        else:
            new_content = content[:section_start] + improved_section + '\n\n' + content[next_section_start:]
        
        # Update in database
        await db.business_plans.update_one(
            {"id": plan_id},
            {"$set": {"content": new_content}}
        )
        
        return {"message": "Section updated successfully", "updated_content": improved_section}
        
    except Exception as e:
        logging.error(f"Error updating section: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.put("/business-plans/{plan_id}")
async def update_business_plan(
    plan_id: str, 
    content: str,
    current_user: User = Depends(get_current_user)
):
    """Update business plan content"""
    # 🔥 CRITICAL FIX: Check both collections and verify ownership
    # Try completed plans first
    result = await db.business_plans.update_one(
        {"id": plan_id, "user_id": current_user.id},
        {"$set": {
            "content": content,
            "updated_at": datetime.now(timezone.utc).isoformat()
        }}
    )
    
    # If not found in completed, try in-progress
    if result.matched_count == 0:
        result = await db.niw_in_progress.update_one(
            {"id": plan_id, "user_id": current_user.id},
            {"$set": {
                "content": content,
                "updated_at": datetime.now(timezone.utc).isoformat()
            }}
        )
    
    if result.matched_count == 0:
        raise HTTPException(status_code=404, detail="Business plan not found or you don't have permission")
    
    logging.info(f"✅ Business plan {plan_id} content updated successfully")
    
    return {
        "message": "Content updated successfully",
        "plan_id": plan_id,
        "modified_count": result.modified_count
    }

@api_router.delete("/business-plans/{plan_id}")
async def delete_business_plan(plan_id: str, current_user: User = Depends(get_current_user)):
    """Soft delete a business plan (move to trash) - ALL users can delete ANY plan"""
    try:
        # Buscar en ambas colecciones
        plan = await db.niw_in_progress.find_one({"id": plan_id}, {"_id": 0})
        collection = db.niw_in_progress
        
        if not plan:
            plan = await db.business_plans.find_one({"id": plan_id}, {"_id": 0})
            collection = db.business_plans
        
        if not plan:
            raise HTTPException(status_code=404, detail="Business plan not found")
        
        # TODOS los usuarios pueden eliminar TODOS los documentos
        logging.info(f"🗑️ Deleting business plan {plan_id} by user {current_user.email}")
        
        # Soft delete
        result = await collection.update_one(
            {"id": plan_id},
            {
                "$set": {
                    "status": "deleted",
                    "deleted_at": datetime.now(timezone.utc).isoformat(),
                    "deleted_by": current_user.id
                }
            }
        )
        
        if result.modified_count == 0:
            raise HTTPException(status_code=400, detail="Failed to delete business plan")
        
        return {
            "message": "Plan de negocio movido a la papelera",
            "note": "Puedes restaurarlo desde la papelera si es necesario"
        }
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error deleting business plan: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

