@api_router.post("/business-plans/{plan_id}/regenerate-translations")
async def regenerate_plan_translations(plan_id: str, background_tasks: BackgroundTasks, current_user: User = Depends(get_current_user)):
    """Regenerate Spanish translations for an existing business plan that only has English content"""
    import asyncio
    
    # Search in all collections
    plan = await db.business_plans.find_one({"id": plan_id}, {"_id": 0})
    collection = db.business_plans
    collection_name = "business_plans"
    
    if not plan:
        plan = await db.niw_in_progress.find_one({"id": plan_id}, {"_id": 0})
        collection = db.niw_in_progress
        collection_name = "niw_in_progress"
    
    if not plan:
        raise HTTPException(status_code=404, detail="Business plan not found")
    
    # Check if already has Spanish content
    sections = plan.get('sections', [])
    sections_with_es = sum(1 for s in sections if s.get('content_es'))
    
    if sections_with_es == len(sections) and len(sections) > 0:
        return {
            "message": "Este plan ya tiene todas las secciones traducidas al español",
            "sections_with_es": sections_with_es,
            "total_sections": len(sections)
        }
    
    # Start background translation task
    async def translate_plan_background(plan_id: str, collection_name: str):
        """Background task to translate all sections to Spanish"""
        try:
            logging.warning(f"🌐 Starting translation regeneration for plan {plan_id}")
            
            # Get the plan again (fresh copy)
            coll = db.business_plans if collection_name == "business_plans" else db.niw_in_progress
            plan_doc = await coll.find_one({"id": plan_id}, {"_id": 0})
            
            if not plan_doc:
                logging.error(f"❌ Plan {plan_id} not found for translation")
                return
            
            sections = plan_doc.get('sections', [])
            
            async def translate_single_section(content_en: str, section_title: str) -> str:
                """Translate a single section from English to Spanish"""
                if not content_en or len(content_en) < 10:
                    return content_en
                
                translation_prompt = f"""Translate the following EB-2 NIW section from English to Spanish.

CRITICAL REQUIREMENTS:
- Maintain professional, formal tone appropriate for USCIS immigration documents
- Preserve all technical terms accurately
- Keep HTML formatting intact (<h2>, <h3>, <p>, <strong>, <ul>, <li>, <table>, etc.)
- Do NOT add or remove content, only translate
- Use native Spanish that sounds natural, not machine-translated
- Preserve paragraph structure and formatting
- Keep all numbers, percentages, and data exactly as they appear

Section: {section_title}

English content to translate:

{content_en}

Provide ONLY the Spanish translation, no explanations or additional text."""

                try:
                    # Use call_openai_gpt4o which has built-in 429 retry + OpenRouter fallback
                    return await call_openai_gpt4o(
                        system_message="Eres un traductor profesional especializado en documentos legales e inmigración de EE.UU. Produces traducciones precisas, formales y naturales del inglés al español.",
                        user_message=translation_prompt,
                        temperature=0.3,
                        max_tokens=8000
                    )
                except Exception as e:
                    logging.warning(f"⚠️ Translation failed for section '{section_title}': {str(e)}")
                    return content_en
            
            # Translate sections in batches
            batch_size = 4
            for i in range(0, len(sections), batch_size):
                batch = sections[i:i+batch_size]
                logging.warning(f"🌐 Translating batch {i//batch_size + 1}/{(len(sections) + batch_size - 1)//batch_size}...")
                
                translation_tasks = []
                for sec in batch:
                    content_en = sec.get('content_en') or sec.get('content', '')
                    section_title = sec.get('title', f"Section {sec.get('number', 0)}")
                    translation_tasks.append(translate_single_section(content_en, section_title))
                
                translated_contents = await asyncio.gather(*translation_tasks)
                
                # Update each section with Spanish content
                for j, sec in enumerate(batch):
                    section_number = sec.get('number')
                    content_es = translated_contents[j]
                    
                    await coll.update_one(
                        {"id": plan_id, "sections.number": section_number},
                        {"$set": {"sections.$.content_es": content_es}}
                    )
                    logging.info(f"✅ Section {section_number} translated ({len(content_es)} chars)")
            
            # Update plan status
            await coll.update_one(
                {"id": plan_id},
                {"$set": {
                    "translations_regenerated_at": datetime.now(timezone.utc).isoformat(),
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }}
            )
            
            logging.warning(f"✅ Translation regeneration complete for plan {plan_id}")
            
        except Exception as e:
            logging.error(f"❌ Error in translation regeneration: {str(e)}")
            import traceback
            traceback.print_exc()
    
    # Add to background tasks
    background_tasks.add_task(translate_plan_background, plan_id, collection_name)
    
    return {
        "message": "Regeneración de traducciones iniciada en segundo plano",
        "plan_id": plan_id,
        "sections_to_translate": len(sections) - sections_with_es,
        "total_sections": len(sections),
        "note": "Las traducciones estarán disponibles en unos minutos. Refresca la página para ver los cambios."
    }

@api_router.post("/business-plans/{plan_id}/cleanup-titles")
async def cleanup_duplicate_titles(plan_id: str, current_user: User = Depends(get_current_user)):
    """Clean up duplicate section titles from business plan content"""
    import re
    
    # Search in all collections
    plan = await db.business_plans.find_one({"id": plan_id}, {"_id": 0})
    collection = db.business_plans
    collection_name = "business_plans"
    
    if not plan:
        plan = await db.niw_in_progress.find_one({"id": plan_id}, {"_id": 0})
        collection = db.niw_in_progress
        collection_name = "niw_in_progress"
    
    if not plan:
        raise HTTPException(status_code=404, detail="Business plan not found")
    
    sections = plan.get('sections', [])
    if not sections:
        return {"message": "No hay secciones para limpiar", "sections_cleaned": 0}
    
    def clean_content_titles(content, section_title):
        """Remove duplicate titles from content"""
        if not content:
            return content
        
        cleaned = content.strip()
        
        # Remove markdown code fences
        if cleaned.startswith('```html') or cleaned.startswith('```HTML'):
            cleaned = re.sub(r'^```html\s*\n?', '', cleaned, flags=re.IGNORECASE)
        if cleaned.startswith('```'):
            cleaned = cleaned[3:].lstrip()
        if cleaned.endswith('```'):
            cleaned = cleaned[:-3].rstrip()
        
        # Remove leading h1/h2 headers
        patterns = [
            r'^\s*<h[1-2][^>]*>.*?</h[1-2]>\s*',
            r'^\s*<strong>.*?</strong>\s*',
        ]
        for pattern in patterns:
            while re.match(pattern, cleaned, flags=re.IGNORECASE | re.DOTALL):
                cleaned = re.sub(pattern, '', cleaned, count=1, flags=re.IGNORECASE | re.DOTALL)
        
        # Remove specific section title if present in content
        if section_title:
            title_escaped = re.escape(section_title)
            title_patterns = [
                rf'<h[1-4][^>]*>\s*<strong>\s*{title_escaped}\s*</strong>\s*</h[1-4]>\s*',
                rf'<h[1-4][^>]*>\s*{title_escaped}\s*</h[1-4]>\s*',
                rf'<strong>\s*{title_escaped}\s*</strong>\s*<br\s*/?>\s*',
                rf'<strong>\s*{title_escaped}\s*</strong>\s*',
                rf'<p>\s*<strong>\s*{title_escaped}\s*</strong>\s*</p>\s*',
            ]
            for pattern in title_patterns:
                cleaned = re.sub(pattern, '', cleaned, flags=re.IGNORECASE | re.DOTALL)
        
        # Clean excessive whitespace at start
        cleaned = re.sub(r'^\s*\n+', '', cleaned)
        cleaned = re.sub(r'^\s*<br\s*/?>\s*', '', cleaned, flags=re.IGNORECASE)
        
        return cleaned.strip()
    
    sections_cleaned = 0
    for section in sections:
        section_title = section.get('title', '')
        section_number = section.get('number', 0)
        
        content_es = section.get('content_es', '')
        content_en = section.get('content_en', '')
        content = section.get('content', '')
        
        # Clean each content field
        new_content_es = clean_content_titles(content_es, section_title) if content_es else content_es
        new_content_en = clean_content_titles(content_en, section_title) if content_en else content_en
        new_content = clean_content_titles(content, section_title) if content else content
        
        # Check if anything changed
        if new_content_es != content_es or new_content_en != content_en or new_content != content:
            await collection.update_one(
                {"id": plan_id, "sections.number": section_number},
                {"$set": {
                    "sections.$.content_es": new_content_es,
                    "sections.$.content_en": new_content_en,
                    "sections.$.content": new_content
                }}
            )
            sections_cleaned += 1
            logging.info(f"✅ Limpiada sección {section_number}: {section_title}")
    
    # Update timestamp
    await collection.update_one(
        {"id": plan_id},
        {"$set": {"updated_at": datetime.now(timezone.utc).isoformat()}}
    )
    
    return {
        "message": f"Limpieza completada. {sections_cleaned} secciones actualizadas.",
        "plan_id": plan_id,
        "sections_cleaned": sections_cleaned,
        "total_sections": len(sections)
    }

@api_router.get("/business-plans/{plan_id}/download")
async def download_business_plan_pdf(plan_id: str, language: str = "es"):
    """Download business plan as PDF (searches all collections) - supports language parameter"""
    # Search in all collections (same as GET /{plan_id})
    plan = await db.business_plans.find_one({"id": plan_id}, {"_id": 0})
    
    if not plan:
        plan = await db.niw_in_progress.find_one({"id": plan_id}, {"_id": 0})
    
    if not plan:
        plan = await db.business_plans_in_progress.find_one({"id": plan_id}, {"_id": 0})
    
    if not plan:
        raise HTTPException(status_code=404, detail="Business plan not found")
    
    # Handle both old and new document formats
    title = plan.get('project_title') or plan.get('business_name', 'Business Plan')
    applicant_name = plan.get('applicant_name', '')
    
    # ✅ FIX: If applicant_name is empty, try to get it from the client collection
    if not applicant_name and plan.get('client_id'):
        client_doc = await db.clients.find_one({"id": plan['client_id']}, {"_id": 0, "name": 1})
        if client_doc:
            applicant_name = client_doc.get('name', '')
            logging.info(f"[DOWNLOAD] Retrieved client name '{applicant_name}' for business plan filename")
    
    doc_type = "EB-2 NIW Project Proposal" if plan.get('project_title') else "Business Plan"
    
    import re

    # ⭐ FOR NIW PLANS: Use project_title from DB directly — do NOT try to extract from
    # generated content (extraction is unreliable and picks up garbage headings like
    # "FLEXIBILITY TO CREATE SOLUTION" from LLM-generated section headings).
    # The project_title field in the DB is set when the user selects a suggestion and
    # is always the correct narrow title for the cover page.
    is_niw = bool(plan.get('project_title'))
    if not is_niw:
        # Non-NIW: try extraction from content for title accuracy
        import re
        def extract_title_from_en_content(content_text):
            """Extract project title from English Executive Summary"""
            if not content_text:
                return None
            match = re.search(r'develops\s+an?\s+([A-Za-z\-]+(?:\s+[A-Za-z\-]+)*\s+(?:platform|system|solution|framework))', content_text, re.IGNORECASE)
            if match:
                extracted = match.group(1).strip()
                if len(extracted) > 15:
                    return extracted.title()
            match = re.search(r'[Tt]he\s+([A-Za-z\-]+(?:\s+[A-Za-z\-]+)*\s+(?:platform|system|solution))', content_text, re.IGNORECASE)
            if match:
                extracted = match.group(1).strip()
                if len(extracted) > 15:
                    return extracted.title()
            return None
    
    # Helper function to extract title from Spanish content
    def extract_title_from_es_content(project_idea):
        """Extract project title from Spanish project_idea"""
        if not project_idea:
            return None
        
        title_patterns = [
            r'[Tt][ií]tulo del [Pp]royecto:\s*(.+?)(?:\n|$)',
            r'[Pp]roject [Tt]itle:\s*(.+?)(?:\n|$)',
            r'1\.\s*[Tt][ií]tulo.*?:\s*(.+?)(?:\n|$)',
        ]
        
        for pattern in title_patterns:
            match = re.search(pattern, project_idea, re.IGNORECASE | re.MULTILINE)
            if match:
                extracted = match.group(1).strip()
                extracted = re.sub(r'\*+', '', extracted).strip()
                if extracted and len(extracted) > 5 and len(extracted) < 200:
                    return extracted
        return None
    
    # Get sections
    sections = plan.get('sections', [])
    
    # ⭐ FOR ENGLISH: Try to extract from content_en ONLY for non-NIW documents
    if language == 'en' and not is_niw:
        for section in sections:
            section_title = section.get('title', '')
            if 'Executive Summary' in section_title or 'Resumen Ejecutivo' in section_title:
                content_en = section.get('content_en', '')
                if content_en:
                    extracted = extract_title_from_en_content(content_en)
                    if extracted:
                        print(f"[DOWNLOAD] 🎯 Extracted English project title: '{extracted}' from content_en")
                        title = extracted
                        break
    
    # ⭐ FOR SPANISH: Use project_title or extract from project_idea
    if language == 'es':
        # First try to extract from project_idea if title seems generic
        project_idea = plan.get('project_idea', '')
        extracted_es = extract_title_from_es_content(project_idea)
        if extracted_es:
            print(f"[DOWNLOAD] 🎯 Extracted Spanish project title: '{extracted_es}' from project_idea")
            title = extracted_es
    
    # ⭐ Siempre compile from sections if available (to support bilingual)
    content = ''
    
    # Helper function to clean section content - removes ALL header tags and markdown markers
    def clean_section_content_for_pdf(section_content, section_title=''):
        if not section_content:
            return ''
        cleaned = section_content.strip()
        
        # 🧹 PASO 0: CRÍTICO - Eliminar TODAS las correcciones del evaluador
        # Estas NO deben aparecer en el PDF final
        evaluator_patterns = [
            r'<p>\s*<strong>\s*\[Evaluator Correction\]:?\s*</strong>.*?</p>',  # HTML format
            r'\[Evaluator Correction\]:?[^\n]*\n?',  # Plain text format
            r'<p>\s*\[Evaluator Correction\]:?.*?</p>',  # Without strong tags
            r'\*\*\[Evaluator Correction\]\*\*:?[^\n]*\n?',  # Markdown bold format
        ]
        for pattern in evaluator_patterns:
            cleaned = re.sub(pattern, '', cleaned, flags=re.IGNORECASE | re.DOTALL)
        
        # 🧹 PASO 1: Eliminar markdown code fence (```html o ```HTML) si existe
        if cleaned.startswith('```html') or cleaned.startswith('```HTML'):
            cleaned = re.sub(r'^```html\s*\n?', '', cleaned, flags=re.IGNORECASE)
        if cleaned.startswith('```'):
            cleaned = cleaned[3:].lstrip()
        
        # También eliminar el cierre ``` si existe al final
        if cleaned.endswith('```'):
            cleaned = cleaned[:-3].rstrip()
        
        # 🧹 PASO 2: Eliminar SOLO el encabezado h1/h2 al inicio SI es el título de la sección
        # (NO eliminar subsecciones A., B., C. o numeradas como 4.1, 4.2 etc.)
        # Estrategia: verificar si el h2 inicial contiene palabras clave del título de la sección
        def _is_section_title_heading(h2_html_text, sec_title):
            """Returns True if the h2 text looks like a duplicate of the section title"""
            from bs4 import BeautifulSoup as _BS
            plain = _BS(h2_html_text, 'html.parser').get_text().strip().lower()
            if not plain:
                return False
            # Check if it's a subsection indicator: single letter + dot (A., B., C.)
            # or number + dot (4.1, 4.2) — these are subsections and should be KEPT
            if re.match(r'^[a-z]\.\s', plain) or re.match(r'^\d+\.\d+\s', plain):
                return False
            # If we have a section title, do a keyword match
            if sec_title:
                meaningful_words = [w.lower() for w in sec_title.split() if len(w) > 3
                                    and w.lower() not in ('and', 'the', 'for', 'with', 'from')]
                if meaningful_words:
                    matching = sum(1 for w in meaningful_words if w in plain)
                    if matching >= max(1, len(meaningful_words) * 0.5):
                        return True
            # Also strip if it starts with Roman numerals pattern (I., II., III., IV. etc.)
            if re.match(r'^[ivxlcdm]+\.', plain, re.IGNORECASE):
                return True
            return False

        h2_match_at_start = re.match(r'^\s*(<h[1-2][^>]*>.*?</h[1-2]>)\s*', cleaned, flags=re.IGNORECASE | re.DOTALL)
        if h2_match_at_start:
            if _is_section_title_heading(h2_match_at_start.group(1), section_title):
                cleaned = re.sub(r'^\s*<h[1-2][^>]*>.*?</h[1-2]>\s*', '', cleaned, count=1, flags=re.IGNORECASE | re.DOTALL)

        # Strip leading standalone <strong>...</strong> only if it matches section title
        strong_match = re.match(r'^\s*(<strong>.*?</strong>)\s*', cleaned, flags=re.IGNORECASE | re.DOTALL)
        if strong_match:
            if _is_section_title_heading(strong_match.group(1), section_title):
                cleaned = re.sub(r'^\s*<strong>.*?</strong>\s*', '', cleaned, count=1, flags=re.IGNORECASE | re.DOTALL)
        
        # 🧹 PASO 3: Si tenemos el título de la sección, eliminarlo si aparece en el contenido
        if section_title:
            # Eliminar variaciones del título de la sección
            # Ejemplo: "III-A. Applicant's Unique Positioning & Competitive Advantage"
            # Puede aparecer como <h2>, <h3>, <strong>, o texto plano al inicio de un párrafo
            
            # Escapar caracteres especiales en el título para usar en regex
            title_escaped = re.escape(section_title)
            
            # Patrones para diferentes formatos del título
            title_patterns = [
                rf'<h[1-4][^>]*>\s*<strong>\s*{title_escaped}\s*</strong>\s*</h[1-4]>\s*',  # <h2><strong>Title</strong></h2>
                rf'<h[1-4][^>]*>\s*{title_escaped}\s*</h[1-4]>\s*',  # <h2>Title</h2>
                rf'<strong>\s*{title_escaped}\s*</strong>\s*<br\s*/?>\s*',  # <strong>Title</strong><br>
                rf'<strong>\s*{title_escaped}\s*</strong>\s*',  # <strong>Title</strong>
                rf'<p>\s*<strong>\s*{title_escaped}\s*</strong>\s*</p>\s*',  # <p><strong>Title</strong></p>
            ]
            
            for pattern in title_patterns:
                cleaned = re.sub(pattern, '', cleaned, flags=re.IGNORECASE | re.DOTALL)
            
            # También eliminar el título si aparece como texto al inicio del párrafo
            # Buscar el título (o parte de él) al inicio de la primera línea
            lines = cleaned.split('\n')
            if lines:
                first_line = lines[0].strip()
                # Si la primera línea contiene principalmente el título, eliminarla
                title_words = section_title.lower().split()
                first_line_lower = first_line.lower()
                matching_words = sum(1 for word in title_words if word in first_line_lower)
                if matching_words >= len(title_words) * 0.7:  # 70% de las palabras coinciden
                    # La primera línea parece ser el título, eliminarla
                    lines = lines[1:]
                    cleaned = '\n'.join(lines)
        
        # 🧹 PASO 4: Limpiar espacios y líneas vacías excesivas al inicio
        cleaned = re.sub(r'^\s*\n+', '', cleaned)
        cleaned = re.sub(r'^\s*<br\s*/?>\s*', '', cleaned, flags=re.IGNORECASE)
        
        return cleaned.strip()
    
    if 'sections' in plan and isinstance(plan['sections'], list) and len(plan['sections']) > 0:
        # Verificar si las secciones tienen content_es/content_en
        has_bilingual_sections = any(
            section.get('content_es') or section.get('content_en') 
            for section in plan['sections']
        )
        
        if has_bilingual_sections:
            # Compile sections into content - bilingüe CON LIMPIEZA DE DUPLICADOS
            print(f"[DOWNLOAD] 📋 Compilando {len(plan['sections'])} secciones bilingües para plan {plan_id}, idioma: {language}")
            compiled_sections = []
            
            for section in plan['sections']:
                section_title = section.get('title', '')
                
                # ⭐ SKIP Cover Page section (Section I) - rendered as professional visual cover page
                # The visual cover page IS the Portada. In the body, numbering starts at I = Executive Summary.
                if section_title and ('Cover Page' in section_title or 'Portada' in section_title):
                    print(f"[DOWNLOAD] ⏭️ Skipping Cover Page section (front matter, not a numbered body section)")
                    continue
                
                # ⭐ Usar content_es o content_en según el idioma solicitado
                if language == 'es':
                    section_content = section.get('content_es') or section.get('content', '')
                    if not section.get('content_es'):
                        print(f"[DOWNLOAD] ⚠️ Sección '{section_title}' NO tiene content_es, usando content por defecto")
                else:
                    section_content = section.get('content_en') or section.get('content', '')
                    if not section.get('content_en'):
                        print(f"[DOWNLOAD] ⚠️ Sección '{section_title}' NO tiene content_en, usando content por defecto")
                
                if section_title and section_content:
                    # 🔄 CONVERT MARKDOWN TO HTML if content is not HTML
                    if not ('<p>' in section_content or '<h' in section_content):
                        # Content is Markdown, convert to HTML
                        import markdown
                        section_content = markdown.markdown(
                            section_content,
                            extensions=['tables', 'fenced_code', 'nl2br']
                        )
                        print(f"[DOWNLOAD] 🔄 Converted Markdown to HTML for section '{section_title}'")
                    
                    content_clean = clean_section_content_for_pdf(section_content, section_title)
                    
                    # ⭐ POST-PROCESSING: Fix missing "A." heading for existing documents
                    # When the AI generated content starting directly with B, C, D (no A. heading),
                    # we need to insert the A. heading before the first paragraph.
                    section_number = section.get('number', 0)
                    
                    # Check if this section has B./C./D. headings but no A. heading
                    # Uses h2-h5 to cover all heading levels the AI might generate (h4 is most common)
                    has_letter_b_heading = bool(re.search(r'<h[2-5][^>]*>\s*B\.\s+', content_clean, re.IGNORECASE)) or \
                                          bool(re.search(r'<p[^>]*>\s*<strong>\s*B\.\s+', content_clean, re.IGNORECASE))
                    has_letter_a_heading = bool(re.search(r'<h[2-5][^>]*>\s*A\.\s+', content_clean, re.IGNORECASE)) or \
                                          bool(re.search(r'<p[^>]*>\s*<strong>\s*A\.\s+', content_clean, re.IGNORECASE))
                    
                    if has_letter_b_heading and not has_letter_a_heading:
                        # Determine appropriate A. heading based on section number
                        a_heading_titles = {
                            2: "A. Descripción del Proyecto y Propuesta de Valor" if language == 'es' else "A. Project Description and Value Proposition",
                            3: "A. Trayectoria Profesional y Calificaciones" if language == 'es' else "A. Professional Background and Qualifications",
                            11: "A. Mérito Sustancial del Proyecto" if language == 'es' else "A. Substantial Merit of the Project",
                        }
                        a_heading = a_heading_titles.get(section_number, 
                            "A. Descripción General" if language == 'es' else "A. Overview")
                        
                        # Insert A. heading before the first paragraph or first element
                        # Use <h4> to match the heading level used by the AI for letter subsections
                        first_p = re.search(r'<p[^>]*>', content_clean, re.IGNORECASE)
                        if first_p:
                            insert_pos = first_p.start()
                            content_clean = content_clean[:insert_pos] + f'<h4>{a_heading}</h4>\n' + content_clean[insert_pos:]
                        else:
                            content_clean = f'<h4>{a_heading}</h4>\n' + content_clean
                        
                        print(f"[DOWNLOAD] 🔧 Inserted missing A. heading for section {section_number}")
                    
                    # ⭐ POST-PROCESSING: Fix wrong subsection numbering for existing documents
                    # New display numbering: section N in DB displays as (N-1)
                    # - Old docs: section 4 has "4.x" → fix to "3.x" (display III)
                    # - Older bug docs: section 3 had "4.x" → fix to "2.x" (display II)
                    if section_number >= 3:
                        display_num = section_number - 1  # e.g., DB section 4 → display "III" = 3
                        has_correct_num = bool(re.search(rf'<h[2-5][^>]*>\s*{display_num}\.\d+[\s<]', content_clean))
                        if not has_correct_num:
                            # Check for both old-style (N.x) and older-bug-style (N+1.x)
                            for old_prefix in [section_number, section_number + 1]:
                                has_old = bool(re.search(rf'<h[2-5][^>]*>\s*{old_prefix}\.\d+[\s<]', content_clean))
                                if has_old:
                                    content_clean = re.sub(
                                        rf'(<h[2-5][^>]*>)\s*{old_prefix}\.(\d+)',
                                        rf'\g<1>{display_num}.\2',
                                        content_clean,
                                        flags=re.IGNORECASE
                                    )
                                    print(f"[DOWNLOAD] 🔧 Fixed subsection numbering: {old_prefix}.x → {display_num}.x in section {section_number} (display {display_num})")
                                    break
                    
                    # ⭐ POST-PROCESSING: Fix missing X.1 subsection heading for sections 4+
                    # When section N has X.2, X.3... but NO X.1, insert the X.1 heading.
                    # Uses display_num = section_number - 1 (new numbering standard)
                    if section_number >= 4:
                        display_num = section_number - 1
                        # Default X.1 titles keyed by display_num
                        x1_titles_es = {
                            3:  "Descripción de la Crisis Nacional",        # DB section 4, display III
                            4:  "Contexto Nacional y Evidencia",            # DB section 5, display IV
                            5:  "Marco General de la Solución",             # DB section 6, display V
                            6:  "Panorama del Mercado Objetivo",            # DB section 7, display VI
                            7:  "Estructura del Plan de Implementación",    # DB section 8, display VII
                            8:  "Supuestos Financieros Clave",              # DB section 9, display VIII
                            9:  "Análisis de Creación de Empleo",           # DB section 10, display IX
                            10: "Cumplimiento de los Tres Criterios de Dhanasar",  # DB 11, display X
                            11: "Identificación y Categorización de Riesgos",      # DB 12, display XI
                            12: "Marco de Indicadores de Desempeño",       # DB 13, display XII
                            13: "Estructura de Gobernanza del Proyecto",   # DB 14, display XIII
                            14: "Sistema de Monitoreo Continuo",           # DB 15, display XIV
                            15: "Fuentes Gubernamentales y Federales",     # DB 16, display XV
                            16: "Lista de Documentos de Apoyo",            # DB 17, display XVI
                        }
                        x1_titles_en = {
                            3:  "National Crisis Description",
                            4:  "National Context and Evidence",
                            5:  "General Solution Framework",
                            6:  "Target Market Overview",
                            7:  "Implementation Plan Structure",
                            8:  "Key Financial Assumptions",
                            9:  "Job Creation Analysis",
                            10: "Compliance with the Three Dhanasar Criteria",
                            11: "Risk Identification and Categorization",
                            12: "Performance Indicators Framework",
                            13: "Project Governance Structure",
                            14: "Continuous Monitoring System",
                            15: "Government and Federal Sources",
                            16: "List of Supporting Documents",
                        }
                        # Check if display_num.2+ exists but display_num.1 is missing
                        has_x2_plus = bool(re.search(rf'<h[2-5][^>]*>\s*{display_num}\.2[\s<]', content_clean))
                        has_x1 = bool(re.search(rf'<h[2-5][^>]*>\s*{display_num}\.1[\s<]', content_clean))
                        if has_x2_plus and not has_x1:
                            if language == 'es':
                                x1_title = x1_titles_es.get(display_num, "Descripción General")
                            else:
                                x1_title = x1_titles_en.get(display_num, "General Overview")
                            x1_heading = f"{display_num}.1 {x1_title}"
                            # Insert before the first paragraph, table, or any block element
                            first_block = re.search(r'<(?:p|table|ul|ol|div)[^>]*>', content_clean, re.IGNORECASE)
                            if first_block:
                                insert_pos = first_block.start()
                                content_clean = content_clean[:insert_pos] + f'<h4>{x1_heading}</h4>\n' + content_clean[insert_pos:]
                            else:
                                content_clean = f'<h4>{x1_heading}</h4>\n' + content_clean
                            print(f"[DOWNLOAD] 🔧 Inserted missing {display_num}.1 heading for section {section_number}")
                    
                    # Display title: section_number 2 → NIW_SECTIONS_ES[0] = "I. Resumen Ejecutivo"
                    # (Cover Page / section_number=1 is skipped, so we offset by 2)
                    if language == 'es' and section_number >= 2:
                        body_index = section_number - 2  # section 2 → index 0 ("I.")
                        if body_index < len(NIW_SECTIONS_ES):
                            display_title = NIW_SECTIONS_ES[body_index]
                        else:
                            display_title = section_title
                    elif language == 'en' and section_number >= 2:
                        # For English: shift Roman numerals starting at I for Executive Summary
                        roman = ["I", "II", "III", "IV", "V", "VI", "VII", "VIII", "IX", "X",
                                 "XI", "XII", "XIII", "XIV", "XV", "XVI", "XVII", "XVIII", "XIX", "XX"]
                        body_index = section_number - 2
                        if body_index < len(roman):
                            # Extract the English part after the Roman numeral prefix if present
                            raw_title = section_title
                            clean_title = re.sub(r'^[IVX]+\.\s*', '', raw_title).strip()
                            display_title = f"{roman[body_index]}. {clean_title}"
                        else:
                            display_title = section_title
                    else:
                        display_title = section_title
                    
                    compiled_sections.append(f"<h2><strong>{display_title}</strong></h2>\n\n{content_clean}")
            
            content = "\n\n".join(compiled_sections)
            print(f"[DOWNLOAD] ✅ Contenido compilado desde secciones: {len(content)} caracteres")
        else:
            # Las secciones no tienen bilingüe - usar content_es/content_en del documento principal
            print(f"[DOWNLOAD] ⚠️ Secciones sin contenido bilingüe - usando content_{language} del documento principal")
            if language == 'es':
                content = plan.get('content_es') or plan.get('content', '')
            else:
                content = plan.get('content_en') or plan.get('content', '')
            print(f"[DOWNLOAD] ✅ Contenido desde campo principal: {len(content)} caracteres")
        
        # Add status indicator if document is in progress
        if plan.get('status') == 'in_progress':
            current = plan.get('current_section', 0)
            total = plan.get('total_sections', 0)
            status_text = f"**DOCUMENTO EN PROGRESO - {current}/{total} secciones completadas**" if language == 'es' else f"**DOCUMENT IN PROGRESS - {current}/{total} sections completed**"
            content = f"{status_text}\n\n{content}"
    
    # Fallback to content field if no sections
    if not content:
        logging.warning(f"⚠️  Plan {plan_id} no tiene sections, usando content directo")
        # Si usa el campo 'content' pre-compilado, también limpiarlo
        content_raw = plan.get('content_en' if language == 'en' else 'content_es') or plan.get('content', '')
        
        if content_raw:
            # Limpiar TODO el contenido de encabezados duplicados
            logging.info(f"🧹 Limpiando content pre-compilado ({len(content_raw)} chars)")
            
            # Dividir por secciones buscando <h2>
            # Esta es una limpieza más agresiva para contenido pre-compilado
            parts = re.split(r'(<h2[^>]*>.*?</h2>)', content_raw, flags=re.IGNORECASE | re.DOTALL)
            
            cleaned_parts = []
            last_h2 = None
            
            for part in parts:
                if re.match(r'<h2[^>]*>.*?</h2>', part, flags=re.IGNORECASE | re.DOTALL):
                    # Es un título
                    if last_h2 != part:  # Solo agregar si es diferente al anterior
                        cleaned_parts.append(part)
                        last_h2 = part
                    else:
                        logging.info(f"🗑️  Eliminado <h2> duplicado consecutivo")
                else:
                    # Es contenido - también limpiar h3, h4 al inicio
                    cleaned_content = clean_section_content_for_pdf(part)
                    if cleaned_content:
                        cleaned_parts.append(cleaned_content)
            
            content = ''.join(cleaned_parts)
            logging.info(f"✅ Content limpio: {len(content)} caracteres")
    
    if not content:
        raise HTTPException(status_code=400, detail="Document has no content to generate PDF")
    
    # 🔥 CRITICAL FIX: Replace special characters that cause black boxes in PDF
    # Replace various types of hyphens/dashes with standard ASCII hyphen
    content = content.replace('–', '-')  # en dash
    content = content.replace('—', '-')  # em dash
    content = content.replace('−', '-')  # minus sign
    content = content.replace('\u2011', '-')  # non-breaking hyphen
    content = content.replace('\u2012', '-')  # figure dash
    content = content.replace('\u2013', '-')  # en dash
    content = content.replace('\u2014', '-')  # em dash
    content = content.replace('\u2015', '-')  # horizontal bar
    
    # Also clean title and applicant name
    title = title.replace('–', '-').replace('—', '-').replace('\u2011', '-').replace('\u2013', '-').replace('\u2014', '-')
    applicant_name = applicant_name.replace('–', '-').replace('—', '-').replace('\u2011', '-').replace('\u2013', '-').replace('\u2014', '-') if applicant_name else ''
    
    pdf_bytes = create_pdf(
        title=f"{doc_type}: {title}",
        content=content,
        doc_type="business_plan",
        project_title=title,
        applicant_name=applicant_name,
        language=language
    )
    
    # Create safe filename - include applicant name if available
    safe_title = sanitize_filename(title)
    safe_applicant = sanitize_filename(applicant_name) if applicant_name else ''
    filename_suffix = "niw_proposal" if plan.get('project_title') else "business_plan"
    lang_suffix = language.upper()
    
    # Build filename: Title_ApplicantName_LANG_type.pdf or Title_LANG_type.pdf
    if safe_applicant:
        filename = f"{safe_applicant}_{safe_title}_{lang_suffix}_{filename_suffix}.pdf"
    else:
        filename = f"{safe_title}_{lang_suffix}_{filename_suffix}.pdf"
    
    return StreamingResponse(
        io.BytesIO(pdf_bytes),
        media_type="application/pdf",
        headers={'Content-Disposition': f'attachment; filename="{filename}"'}
    )

# Book Endpoints
async def evaluate_book_ideas(ideas: list, profile_summary: str, language: str) -> dict:
    """Evaluate book ideas quality using AI and recommend the best one"""
    try:
        language_instruction = "in English" if language == "en" else "en Español"
        
        eval_prompt = f"""You are a concise publishing industry expert. Evaluate the following book ideas and RECOMMEND which one the author should choose.

AUTHOR PROFILE:
{profile_summary}

BOOK IDEAS TO EVALUATE:
{chr(10).join([f'{i+1}. {idea}' for i, idea in enumerate(ideas)])}

YOUR TASK:
1. Evaluate each idea for: Marketability, Originality, Author alignment, Clarity
2. Determine which idea has the BEST potential for success
3. Provide a BRIEF and clear recommendation

**IMPORTANT STYLE GUIDELINES:**
- Keep responses SHORT and CONCISE (max 2 sentences per section)
- Use simple, direct language
- Be decisive but brief
- Focus only on the most important points

Provide your response {language_instruction} in this EXACT format:

BEST_IDEA: [1, 2, or 3]
WHY_THIS_IDEA: [1-2 short sentences explaining why - MAX 25 words total]
STRENGTHS: [2-3 bullet points with "✓" - each MAX 10 words - Example: "✓ Strong market demand"]
QUICK_TIPS: [2-3 bullet points with "→" - each MAX 10 words - Example: "→ Focus on niche audience"]

Be decisive, clear, and BRIEF."""

        eval_response = await call_cheap_evaluator(
            "You are a decisive publishing consultant who helps authors choose the best book concept.",
            eval_prompt,
            temperature=0.3,
            max_tokens=1500,
            json_mode=False,
        )
        
        # Parse evaluation
        best_idea = "1"
        why_this_idea = ""
        strengths = ""
        quick_tips = ""
        
        if "BEST_IDEA:" in eval_response:
            best_idea = eval_response.split("BEST_IDEA:")[1].split("\n")[0].strip()
        if "WHY_THIS_IDEA:" in eval_response:
            why_this_idea = eval_response.split("WHY_THIS_IDEA:")[1].split("STRENGTHS:")[0].strip()
        if "STRENGTHS:" in eval_response:
            strengths = eval_response.split("STRENGTHS:")[1].split("QUICK_TIPS:")[0].strip()
        if "QUICK_TIPS:" in eval_response:
            quick_tips = eval_response.split("QUICK_TIPS:")[1].strip()
        
        return {
            "best_idea_number": best_idea,
            "why_this_idea": why_this_idea,
            "strengths": strengths,
            "quick_tips": quick_tips,
            "quality": "Good",
            "recommendation": "Accept",
            "passed": True
        }
    except Exception as e:
        logging.error(f"Error evaluating book ideas: {str(e)}")
        return {
            "best_idea_number": "1",
            "why_this_idea": "All ideas have potential. Choose the one you're most passionate about.",
            "strengths": "",
            "quick_tips": "",
            "quality": "Good",
            "recommendation": "Accept",
            "passed": True
        }

@api_router.post("/books/suggest-ideas")
async def suggest_book_ideas(profile: ProfileSubmission, current_user: User = Depends(get_current_user)):
    """Suggest 3 book ideas based on author profile - OPTIMIZED: No evaluation loop"""
    try:
        language_instruction = "in English" if profile.language == "en" else "en Español"
        
        # Build additional context sections
        additional_context = ""
        if profile.project_description:
            additional_context += f"\n\nPROJECT CONTEXT:\n{profile.project_description}\n"
        if profile.patent_content:
            additional_context += f"\n\nPATENT INFORMATION:\n{profile.patent_content}\n"
        
        prompt = f"""Based on the following author profile, suggest 3 compelling and marketable book ideas that align with the author's expertise and interests.

AUTHOR PROFILE:
Name: {profile.author_name}

Profile Summary:
{profile.profile_summary}
{additional_context}

REQUIREMENTS:
- Suggest exactly 3 book ideas {language_instruction}
- Each idea should be unique, engaging, and marketable
- Ideas should leverage the author's background and expertise
{f"- Take into account the provided project and patent information to create relevant and innovative book concepts" if additional_context else ""}
- Include genre and brief concept (3-5 sentences each with specific details)
- Avoid generic or vague concepts
- Make each idea distinctive and commercially appealing
- Recommend which idea is BEST (add ⭐ emoji to the best one)

FORMAT YOUR RESPONSE AS:
1. [Genre]: [Detailed compelling book idea concept with hook]
2. [Genre]: [Detailed compelling book idea concept with hook]
3. ⭐ [Genre]: [Detailed compelling book idea concept with hook] (RECOMMENDED)

Only provide the 3 numbered ideas, nothing else."""

        system_message = "You are a creative literary consultant specializing in developing compelling, detailed, and marketable book concepts tailored to authors' backgrounds."
        response_text = await call_openai_gpt5(system_message, prompt, temperature=0.8)
        
        logging.info(f"📚 Book ideas generated successfully (1 call, no evaluation)")
        
        # Parse the 3 suggestions
        # Strip any HTML tags the LLM may emit (e.g. <p>) before any other processing.
        cleaned_response = re.sub(r'<[^>]+>', '', response_text)
        lines = [line.strip() for line in cleaned_response.split('\n') if line.strip() and any(c.isalnum() for c in line)]

        suggestions = []
        best_idea_index = 0
        for i, line in enumerate(lines[:3]):
            # Drop leading numbering / bullets / stars before extracting genre.
            cleaned = re.sub(r'^[\s\d.)\-•⭐*]+', '', line).strip()
            if cleaned:
                # Check if this is the recommended one
                if '⭐' in cleaned or '(RECOMMENDED)' in cleaned.upper():
                    best_idea_index = i
                    cleaned = cleaned.replace('⭐', '').strip()
                suggestions.append(cleaned)
        
        # Return simplified response without evaluation
        return {
            "suggestions": suggestions,
            "message": "Ideas generadas exitosamente",
            "evaluation": {
                "best_idea_number": str(best_idea_index + 1),
                "passed": True
            },
            "attempts": 1
        }
        
    except Exception as e:
        logging.error(f"Error generating book ideas: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

async def evaluate_book_titles(titles: list, book_idea: str, language: str) -> dict:
    """Evaluate book titles quality using AI - CONCISE style with title recommendation"""
    try:
        language_instruction = "in English" if language == "en" else "en Español"
        
        eval_prompt = f"""You are a CONCISE publishing marketing expert. Evaluate the following book titles and RECOMMEND the best one.

BOOK CONCEPT:
{book_idea}

PROPOSED TITLES:
{chr(10).join([f'{i+1}. {title}' for i, title in enumerate(titles)])}

EVALUATION CRITERIA:
1. Memorability 2. Marketability 3. Relevance 4. Uniqueness 5. Length

**IMPORTANT STYLE GUIDELINES:**
- Keep responses EXTREMELY SHORT (max 1 sentence per section)
- Use simple, direct language
- Be decisive but brief
- MUST recommend which title is best (1, 2, or 3)

Provide your evaluation {language_instruction} in this EXACT format:
BEST_TITLE: [1, 2, or 3]
WHY_THIS_TITLE: [1 SHORT sentence - MAX 20 words explaining why this title is best]
OVERALL_QUALITY: [Excellent/Good/Fair/Poor]
ISSUES: [Max 3 bullet points, each 5-8 words max - Example: "• Titles too generic"]
FEEDBACK: [1 SHORT sentence - MAX 15 words]
RECOMMENDATION: [Accept/Revise/Regenerate]

Be critical, constructive, BRIEF, and DECISIVE about which title is best."""

        eval_response = await call_cheap_evaluator(
            "You are a critical book marketing consultant who evaluates book titles.",
            eval_prompt,
            temperature=0.3,
            max_tokens=1500,
            json_mode=False,
        )
        
        # Parse evaluation
        best_title = "1"
        why_this_title = ""
        overall_quality = "Good"
        issues = []
        feedback = ""
        recommendation = "Accept"
        
        if "BEST_TITLE:" in eval_response:
            best_title = eval_response.split("BEST_TITLE:")[1].split("\n")[0].strip()
        if "WHY_THIS_TITLE:" in eval_response:
            why_this_title = eval_response.split("WHY_THIS_TITLE:")[1].split("OVERALL_QUALITY:")[0].strip()
        if "OVERALL_QUALITY:" in eval_response:
            overall_quality = eval_response.split("OVERALL_QUALITY:")[1].split("\n")[0].strip()
        if "ISSUES:" in eval_response:
            issues_text = eval_response.split("ISSUES:")[1].split("FEEDBACK:")[0].strip()
            issues = [i.strip() for i in issues_text.split("\n") if i.strip()]
        if "FEEDBACK:" in eval_response:
            feedback = eval_response.split("FEEDBACK:")[1].split("RECOMMENDATION:")[0].strip()
        if "RECOMMENDATION:" in eval_response:
            recommendation = eval_response.split("RECOMMENDATION:")[1].strip()
        
        return {
            "best_title_number": best_title,
            "why_this_title": why_this_title,
            "quality": overall_quality,
            "issues": issues,
            "feedback": feedback,
            "recommendation": recommendation,
            "passed": recommendation.lower() in ["accept", "aceptar"]
        }
    except Exception as e:
        logging.error(f"Error evaluating book titles: {str(e)}")
        return {"quality": "Unknown", "issues": [], "feedback": "", "recommendation": "Accept", "passed": True}

@api_router.post("/books/suggest-titles")
async def suggest_book_titles(idea: BookIdeaSelection, current_user: User = Depends(get_current_user)):
    """Suggest 3 book titles based on selected idea - OPTIMIZED: No evaluation loop"""
    try:
        # Adjust prompt based on whether it's a custom idea or AI-suggested
        idea_context = "CUSTOM BOOK IDEA FROM USER:" if idea.is_custom_idea else "BOOK IDEA:"
        
        prompt = f"""Based on the following book idea, suggest 3 compelling and marketable book titles.

{idea_context}
{idea.selected_idea}

AUTHOR BACKGROUND:
{idea.profile_summary}

REQUIREMENTS:
- Suggest exactly 3 book titles
- Titles should be catchy, memorable, and marketable
- Titles should accurately reflect the book concept
- Consider current market trends
- Titles should be concise (2-6 words ideally)
- Make titles unique and attention-grabbing
- Avoid generic or cliché titles
- Mark the BEST title with ⭐ emoji
{"- The user already has a clear idea, so titles should closely match their vision" if idea.is_custom_idea else ""}

FORMAT YOUR RESPONSE AS:
1. [Title 1]
2. ⭐ [Title 2] (RECOMMENDED)
3. [Title 3]

Only provide the 3 numbered titles, nothing else."""

        system_message = "You are a publishing industry expert specializing in creating compelling, marketable, and memorable book titles that sell."
        response_text = await call_openai_gpt5(system_message, prompt, temperature=0.9)
        
        logging.info(f"📖 Book titles generated successfully (1 call, is_custom: {idea.is_custom_idea})")
        
        # Parse the 3 suggestions
        lines = [line.strip() for line in response_text.split('\n') if line.strip() and any(c.isalnum() for c in line)]
        suggestions = []
        best_title_index = 0
        for i, line in enumerate(lines[:3]):
            cleaned = line.lstrip('0123456789.)-• ').strip()
            if cleaned:
                # Check if this is the recommended one
                if '⭐' in cleaned:
                    best_title_index = i
                    cleaned = cleaned.replace('⭐', '').strip()
                # ✅ FIX: Remove "(RECOMMENDED)" text from title
                if '(RECOMMENDED)' in cleaned:
                    cleaned = cleaned.replace('(RECOMMENDED)', '').strip()
                if '(recommended)' in cleaned:
                    cleaned = cleaned.replace('(recommended)', '').strip()
                suggestions.append(cleaned)
        
        # Return simplified response without evaluation
        return {
            "suggestions": suggestions,
            "message": "Títulos generados exitosamente",
            "evaluation": {
                "best_title_number": str(best_title_index + 1),
                "passed": True
            },
            "attempts": 1,
            "is_custom_idea": idea.is_custom_idea
        }
        
    except Exception as e:
        logging.error(f"Error generating book titles: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

