@api_router.post("/books/finalize/{book_id}", response_model=Book)
async def finalize_book(book_id: str, current_user: User = Depends(get_current_user)):
    """Finalize a book and move to completed books"""
    try:
        book_in_progress = await db.books_in_progress.find_one({"id": book_id}, {"_id": 0})
        if not book_in_progress:
            raise HTTPException(status_code=404, detail="Book not found")
        
        # Combine chapters content
        content = "\n\n".join([
            chapter.get('content_es', chapter.get('content', ''))
            for chapter in book_in_progress['chapters']
            if chapter.get('approved', False)
        ])
        
        # ⭐ Generate additional sections (About Author, Conclusion, Appendix)
        logging.info("📚 Generating additional book sections...")
        
        # 1. About the Author (500-800 words)
        logging.info("   ✍️ Generating 'About the Author' section...")
        about_author_prompt = f"""Write an "About the Author" introduction section for this book in ENGLISH.

**Book Title:** {book_in_progress['title']}
**Genre:** {book_in_progress['genre']}
**Author Profile:** {book_in_progress.get('author_profile', {}).get('profile_summary', 'Professional in the field')}

**Requirements:**
- Length: 500-800 words
- Include: Who is the author, explicit credentials, why they wrote this book
- Tone: Professional, authoritative, first-person when appropriate
- Format: Use <h2>About the Author</h2> as header, then <p> tags for paragraphs

Write the complete "About the Author" section now in English."""

        about_author_en = await call_openai_gpt5(
            "You are a professional book editor specializing in author biographies.",
            about_author_prompt,
            temperature=0.7,
            max_tokens=1500
        )
        
        # Translate to Spanish
        about_author_es = await call_openai_gpt5(
            "You are a professional translator. Translate accurately while maintaining tone.",
            f"Translate the following 'About the Author' section to Spanish:\n\n{about_author_en}",
            temperature=0.3,
            max_tokens=1500
        )
        
        logging.info(f"   ✅ About the Author generated: {len(about_author_es)} chars")
        
        # 2. Conclusion (400-600 words)
        logging.info("   🎯 Generating 'Conclusion' section...")
        conclusion_prompt = f"""Write a powerful conclusion for this book in ENGLISH.

**Book Title:** {book_in_progress['title']}
**Genre:** {book_in_progress['genre']}
**Synopsis:** {book_in_progress['synopsis']}
**Number of Chapters:** {book_in_progress['num_chapters']}

**Requirements:**
- Length: 400-600 words
- Include: 
  * Summary of key insights from the book
  * Call to action for readers
  * Vision for the future in this field
- Tone: Inspiring, actionable, forward-looking
- Format: Use <h2>Conclusion</h2> as header, then <p> tags for paragraphs

Write the complete conclusion now in English."""

        conclusion_en = await call_openai_gpt5(
            "You are a professional book editor specializing in powerful conclusions.",
            conclusion_prompt,
            temperature=0.7,
            max_tokens=1200
        )
        
        # Translate to Spanish
        conclusion_es = await call_openai_gpt5(
            "You are a professional translator. Translate accurately while maintaining inspirational tone.",
            f"Translate the following conclusion to Spanish:\n\n{conclusion_en}",
            temperature=0.3,
            max_tokens=1200
        )
        
        logging.info(f"   ✅ Conclusion generated: {len(conclusion_es)} chars")
        
        # 3. Appendix (300-500 words)
        logging.info("   📎 Generating 'Appendix' section...")
        appendix_prompt = f"""Write an appendix section for this book in ENGLISH.

**Book Title:** {book_in_progress['title']}
**Genre:** {book_in_progress['genre']}

**Requirements:**
- Length: 300-500 words
- Include:
  * Recommended resources (books, websites, tools)
  * Complete references cited in the book
  * Tools and platforms mentioned
- Format: Use <h2>Appendix</h2> as header, then organized lists with <h3> subsections
- Structure:
  * <h3>Recommended Resources</h3>
  * <h3>References</h3>
  * <h3>Tools & Platforms</h3>

Write the complete appendix now in English."""

        appendix_en = await call_openai_gpt5(
            "You are a professional book editor specializing in appendices and references.",
            appendix_prompt,
            temperature=0.7,
            max_tokens=1000
        )
        
        # Translate to Spanish
        appendix_es = await call_openai_gpt5(
            "You are a professional translator. Translate accurately, keeping resource names in English when appropriate.",
            f"Translate the following appendix to Spanish:\n\n{appendix_en}",
            temperature=0.3,
            max_tokens=1000
        )
        
        logging.info(f"   ✅ Appendix generated: {len(appendix_es)} chars")
        
        # Combine all sections: About Author + Chapters + Conclusion + Appendix
        full_content_es = f"{about_author_es}\n\n{content}\n\n{conclusion_es}\n\n{appendix_es}"
        full_content_en = f"{about_author_en}\n\n" + "\n\n".join([
            chapter.get('content_en', chapter.get('content', ''))
            for chapter in book_in_progress['chapters']
            if chapter.get('approved', False)
        ]) + f"\n\n{conclusion_en}\n\n{appendix_en}"
        
        logging.info(f"📚 Book finalization complete with all sections")
        
        book = Book(
            id=book_in_progress['id'],
            user_id=book_in_progress['user_id'],
            client_id=book_in_progress.get('client_id'),
            title=book_in_progress['title'],
            genre=book_in_progress['genre'],
            synopsis=book_in_progress['synopsis'],
            num_chapters=book_in_progress['num_chapters'],
            writing_style=book_in_progress['writing_style'],
            content=full_content_es,  # Spanish version with all sections
            language=book_in_progress['language'],
            has_graphic_design=book_in_progress['has_graphic_design'],
            design_description=book_in_progress.get('design_description', '')
        )
        
        doc = book.model_dump()
        doc['created_at'] = doc['created_at'].isoformat()
        
        # ⭐ FIX: Preserve chapters array for bilingual PDF generation
        chapters_with_sections = book_in_progress.get('chapters', []).copy()
        
        # Add special sections as "chapters" for PDF generation
        chapters_with_sections.insert(0, {
            "number": 0,
            "title": "About the Author",
            "content": about_author_es,
            "content_en": about_author_en,
            "content_es": about_author_es,
            "approved": True,
            "edit_history": []
        })
        
        chapters_with_sections.append({
            "number": len(book_in_progress.get('chapters', [])) + 1,
            "title": "Conclusion",
            "content": conclusion_es,
            "content_en": conclusion_en,
            "content_es": conclusion_es,
            "approved": True,
            "edit_history": []
        })
        
        chapters_with_sections.append({
            "number": len(book_in_progress.get('chapters', [])) + 2,
            "title": "Appendix",
            "content": appendix_es,
            "content_en": appendix_en,
            "content_es": appendix_es,
            "approved": True,
            "edit_history": []
        })
        
        doc['chapters'] = chapters_with_sections
        
        await db.books.insert_one(doc)
        
        # Apply Gamma if requested
        if book_in_progress['has_graphic_design'] and book_in_progress.get('design_description'):
            try:
                gamma_result = await generate_with_gamma(
                    content=content,
                    title=book_in_progress['title'],
                    design_description=book_in_progress['design_description']
                )
                
                if gamma_result.get('gamma_url'):
                    await db.books.update_one(
                        {"id": book.id},
                        {"$set": {
                            "gamma_url": gamma_result.get('gamma_url'),
                            "gamma_pdf_url": gamma_result.get('pdf_url')
                        }}
                    )
                    book.gamma_url = gamma_result.get('gamma_url')
                    book.gamma_pdf_url = gamma_result.get('pdf_url')
                    
                logging.info(f"Gamma design applied to book {book.id}")
            except Exception as gamma_error:
                logging.error(f"Gamma processing failed (non-critical): {str(gamma_error)}")
        
        # Delete in-progress book (move completely to books collection)
        await db.books_in_progress.delete_one(
            {"id": book_id, "user_id": current_user.id}
        )
        
        # Auto-save version for finalization
        await auto_save_version(
            document_id=book_id,
            document_type='book',
            user_id=current_user.id,
            change_description="Libro finalizado",
            change_type='finalize'
        )
        
        # Save to Supabase if client has supabase_id
        if book.client_id:
            try:
                client_doc = await db.clients.find_one({"id": book.client_id}, {"_id": 0})
                if client_doc and client_doc.get('supabase_id'):
                    document_data = {
                        "id": book.id,
                        "title": book.title,
                        "genre": book.genre,
                        "synopsis": book.synopsis,
                        "content": content,
                        "num_chapters": book.num_chapters,
                        "language": book.language,
                        "created_at": doc['created_at'],
                        "status": "completed"
                    }
                    await save_document_to_supabase(
                        cliente_supabase_id=client_doc['supabase_id'],
                        cliente_nombre=client_doc.get('name', 'Unknown'),
                        tipo="Book",
                        document_data=document_data
                    )
            except Exception as supabase_error:
                logging.error(f"Error saving to Supabase (non-critical): {str(supabase_error)}")
        
        return book
        
    except Exception as e:
        logging.error(f"Error finalizing book: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

