@api_router.get("/books/in-progress/{book_id}", response_model=BookInProgress)
async def get_book_in_progress(book_id: str, current_user: User = Depends(get_current_user)):
    """Get book in progress — checks both books_in_progress and books collections"""
    book = await db.books_in_progress.find_one({"id": book_id}, {"_id": 0})
    if not book:
        # Also check completed books collection (needed for translation status polling)
        book = await db.books.find_one({"id": book_id}, {"_id": 0})
    
    if not book:
        raise HTTPException(status_code=404, detail="Book not found")
    
    if isinstance(book.get('created_at'), str):
        book['created_at'] = datetime.fromisoformat(book['created_at'])
    if isinstance(book.get('updated_at'), str):
        book['updated_at'] = datetime.fromisoformat(book['updated_at'])
    
    return book


@api_router.post("/books/{book_id}/regenerate-chapter/{chapter_number}")
async def regenerate_chapter(
    book_id: str, 
    chapter_number: int,
    feedback: dict = None,
    current_user: User = Depends(get_current_user)
):
    """Regenerate a specific chapter with optional user feedback"""
    try:
        book = await db.books_in_progress.find_one({"id": book_id}, {"_id": 0})
        if not book:
            raise HTTPException(status_code=404, detail="Book not found")
        
        # Get user feedback/evaluation if provided
        user_feedback = feedback.get('feedback', '') if feedback else ''
        user_issues = feedback.get('issues', []) if feedback else []
        
        # Build previous chapters context
        previous_chapters = [ch for ch in book.get('chapters', []) if ch['number'] < chapter_number]
        previous_content = "\n\n".join([
            f"Capítulo {ch['number']}: {ch['title']}\n{ch.get('content_es', ch.get('content', ''))}"
            for ch in previous_chapters
        ])
        
        # Enhanced prompt with user feedback
        author_name = book.get('author_name', 'El Autor')
        profile_summary = book.get('profile_summary', 'Profesional con experiencia')
        
        feedback_section = ""
        if user_feedback or user_issues:
            feedback_section = f"""

**⚠️ REGENERACIÓN SOLICITADA POR EL USUARIO**

**Retroalimentación del usuario:**
{user_feedback}

**Problemas específicos a corregir:**
{chr(10).join(['- ' + issue for issue in user_issues])}

**IMPORTANTE:** Atiende específicamente estos comentarios y problemas en la regeneración."""
        
        prompt = f"""Eres un escritor experto especializado en libros para casos de inmigración USCIS. Escribe el Capítulo {chapter_number} de {book['num_chapters']} para "{book['title']}".

**📋 CREDENCIALES DEL AUTOR:**
- Autor: {author_name}
- Background: {profile_summary[:300]}...
- Especialización: {book['genre']}

**📚 CONTEXTO DEL LIBRO:**
Título: {book['title']}
Género: {book['genre']}
Sinopsis: {book['synopsis']}

{("**CONTEXTO DE CAPÍTULOS ANTERIORES:**" + chr(10) + previous_content) if previous_content else "**Este es el Capítulo 1. Establece credibilidad fuerte.**"}

{feedback_section}

**🎯 REQUISITOS CRÍTICOS USCIS:**

1. **ESTABLECER AUTORIDAD (OBLIGATORIO):**
   - Voz en primera persona: "En mis X años de experiencia..."
   - Referencias específicas: "Trabajando con [empresas/clientes], descubrí..."
   - Mínimo 3-4 declaraciones expertas en primera persona por capítulo

2. **INCLUIR DATOS Y ESTADÍSTICAS (OBLIGATORIO):**
   - Mínimo 2-3 puntos de datos por capítulo
   - Estadísticas de la industria relevantes
   - Hallazgos de investigación o estudios
   - Resultados cuantificables del trabajo del autor
   - Ejemplo: "Los estudios muestran que el 73% de profesionales en [campo]..."

3. **PRESENTAR FRAMEWORKS ORIGINALES (OBLIGATORIO):**
   - Crear y NOMBRAR al menos 1 metodología original por capítulo
   - Formato: "El Sistema/Marco [Apellido del Autor] de [Concepto]"
   - Ejemplo: "El Sistema {author_name.split()[0] if ' ' in author_name else author_name} de [Tema]"
   - Explicar cómo se desarrolló y sus resultados medibles

4. **VOZ EXPERTA PROFESIONAL:**
   - Balance entre insights personales y contenido instructivo
   - Mostrar conocimiento profundo, no solo narrativa
   - Incluir aplicación práctica y análisis

**📏 REQUISITO DE LONGITUD:**
**El capítulo DEBE tener entre 8,000 y 15,000 caracteres (óptimo: 10,000-12,000)**

**ESTRUCTURA (6 secciones - SIN transición final):**
1. Gancho Inicial (500-800 chars) - Establece relevancia del tema
2. Insight Profesional del Autor (1,500-2,500 chars) - Autoridad en primera persona
3. Datos e Investigación (1,500-2,500 chars) - Estadísticas y hallazgos
4. Framework/Metodología Original (2,500-3,500 chars) - Sistema nombrado y explicado
5. Aplicación Práctica (2,500-3,500 chars) - Ejemplos del mundo real con detalles
6. Análisis Profundo (1,500-2,500 chars) - Insights de nivel experto

**🚨 EL CAPÍTULO DEBE TERMINAR EN LA SECCIÓN 6 (Análisis Profundo)**
- Termina con un insight específico, dato puntual, o ejemplo concreto
- NO agregues una sección 7 de "transición"
- NO resumas lo que acabas de decir
- NO menciones "el siguiente capítulo" o "próximo paso"
- El último párrafo debe ser contenido sustancial, no un puente

**FORMATO HTML:**
- <h2> para título del capítulo
- <h3> para secciones principales (2-3 por capítulo)
- <h4> para nombres de frameworks y subsecciones
- <p> para todos los párrafos
- <blockquote> para estadísticas clave o insights
- <strong> para énfasis
- <ul>/<li> para componentes de frameworks

**🚫 ESTRICTAMENTE PROHIBIDO:**

1. ❌ **SIN CONCLUSIONES NI TRANSICIONES AL FINAL:**
   - "En conclusión...", "Para finalizar...", "En resumen...", "Finalmente..."
   - "El siguiente paso es...", "En el próximo capítulo...", "A continuación veremos..."
   - NO crear sección de "Transición Natural"
   - NO resumir puntos principales
   - NO mencionar el siguiente capítulo

2. ✅ **TERMINA CON CONTENIDO SUSTANCIAL:**
   - Ejemplo específico, dato impactante, pregunta reflexiva, o insight profundo
   - El último párrafo debe ser contenido, no puente

3. ❌ Declaraciones genéricas sin respaldo de datos
4. ❌ Afirmaciones sin sustento
5. ❌ Repetición de capítulos anteriores

Escribe el Capítulo {chapter_number} ahora siguiendo TODOS los requisitos anteriores."""

        system_message = f"""Eres un escritor experto especializado en libros para casos de inmigración USCIS del género {book['genre']}.

Tu escritura demuestra:
- Expertise profesional profundo con autoridad en primera persona
- Argumentos basados en evidencia con datos y estadísticas
- Frameworks y metodologías originales con nombres profesionales
- Voz experta profesional (no solo narrativa)
- Contenido sustancial optimizado para casos de habilidad extraordinaria USCIS

SIEMPRE creas capítulos entre 8,000-15,000 caracteres con autoridad, datos y frameworks nombrados.
Escribes directamente en español con calidad profesional de nivel experto."""

        # Generate chapter
        logging.info(f"🔄 Regenerating chapter {chapter_number} for book {book_id}")
        
        # Use call_openai_gpt5 which has built-in OpenRouter fallback (Claude Opus / Gemini Pro)
        chapter_content = await call_openai_gpt5(
            system_message=system_message,
            user_message=prompt,
            temperature=0.7,
            max_tokens=8000
        )
        
        if not chapter_content or len(chapter_content.strip()) < 100:
            logging.error(f"   ❌ Regenerated content is empty: {len(chapter_content) if chapter_content else 0} chars")
            raise HTTPException(
                status_code=500,
                detail="El capítulo regenerado está vacío. Por favor, intenta nuevamente."
            )
        
        # Parse title
        import re
        title_match = re.search(r'<h2>(.*?)</h2>', chapter_content, re.IGNORECASE)
        chapter_title = title_match.group(1).strip() if title_match else f"Capítulo {chapter_number}"
        
        # Create new chapter
        new_chapter = {
            "number": chapter_number,
            "title": chapter_title,
            "content": clean_content(chapter_content),
            "content_es": clean_content(chapter_content),
            "content_en": None,
            "approved": False,
            "edit_history": []
        }
        
        # Update in database - replace the specific chapter
        await db.books_in_progress.update_one(
            {"id": book_id, "chapters.number": chapter_number},
            {"$set": {
                "chapters.$": new_chapter,
                "updated_at": datetime.now(timezone.utc).isoformat()
            }}
        )
        
        return {
            "success": True,
            "chapter": new_chapter,
            "message": "Capítulo regenerado exitosamente con el prompt mejorado"
        }
        
    except Exception as e:
        logging.error(f"Error regenerating chapter: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.get("/books/in-progress", response_model=List[BookInProgress])
async def get_books_in_progress(
    client_id: Optional[str] = None,
    current_user: User = Depends(get_current_user)
):
    """Get all books in progress - ALL users see ALL books"""
    try:
        # TODOS los usuarios ven TODOS los documentos
        if client_id:
            query = {"client_id": client_id, "status": {"$ne": "deleted"}}
        else:
            query = {"status": {"$ne": "deleted"}}
        
        logging.info(f"📚 Getting books in progress - client_id: {client_id}, query: {query}")
        
        books_raw = await db.books_in_progress.find(query, {"_id": 0}).sort("updated_at", -1).to_list(1000)
        
        logging.info(f"📚 Found {len(books_raw)} raw books in progress from DB")
        
        # Process and sanitize books data
        valid_books = []
        for idx, book in enumerate(books_raw):
            try:
                # Ensure required fields have defaults
                book.setdefault('title', '')
                book.setdefault('genre', '')
                book.setdefault('synopsis', '')
                book.setdefault('num_chapters', 0)
                book.setdefault('writing_style', '')
                book.setdefault('chapters', [])
                book.setdefault('language', 'es')
                book.setdefault('status', 'in_progress')
                book.setdefault('current_chapter', 1)
                
                # Fix datetime fields
                if isinstance(book.get('created_at'), str):
                    book['created_at'] = datetime.fromisoformat(book['created_at'].replace('Z', '+00:00'))
                elif book.get('created_at') is None:
                    book['created_at'] = datetime.now(timezone.utc)
                    
                if isinstance(book.get('updated_at'), str):
                    book['updated_at'] = datetime.fromisoformat(book['updated_at'].replace('Z', '+00:00'))
                elif book.get('updated_at') is None:
                    book['updated_at'] = book.get('created_at', datetime.now(timezone.utc))
                
                valid_books.append(book)
            except Exception as e:
                logging.error(f"📚 Error processing book in progress {idx} (id={book.get('id', 'unknown')}): {str(e)}")
                # Still try to include the book with minimal data
                try:
                    safe_book = {
                        'id': book.get('id', str(uuid.uuid4())),
                        'title': book.get('title', 'Sin título'),
                        'genre': book.get('genre', ''),
                        'synopsis': book.get('synopsis', ''),
                        'num_chapters': book.get('num_chapters', 0),
                        'writing_style': book.get('writing_style', ''),
                        'chapters': [],
                        'language': book.get('language', 'es'),
                        'status': book.get('status', 'in_progress'),
                        'current_chapter': 1,
                        'client_id': book.get('client_id'),
                        'user_id': book.get('user_id'),
                        'created_at': datetime.now(timezone.utc),
                        'updated_at': datetime.now(timezone.utc)
                    }
                    valid_books.append(safe_book)
                except Exception as e2:
                    logging.error(f"📚 Could not recover book in progress {idx}: {str(e2)}")
        
        logging.info(f"📚 Returning {len(valid_books)} valid books in progress")
        return valid_books
    except Exception as e:
        logging.error(f"📚 Error in get_books_in_progress endpoint: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error al cargar borradores de libros: {str(e)}")
    
    return books

