@api_router.post("/books/{book_id}/generate-cover-image")
async def generate_book_cover_image(
    book_id: str,
    background_tasks: BackgroundTasks,
    current_user: User = Depends(get_current_user)
):
    """Start generating a book cover image using Gemini Nano Banana (async)"""
    import os
    
    # Get book info
    book = await db.books.find_one({"id": book_id}, {"_id": 0})
    if not book:
        book = await db.books_in_progress.find_one({"id": book_id}, {"_id": 0})
    
    if not book:
        raise HTTPException(status_code=404, detail="Book not found")
    
    # Mark as generating
    await db.books_in_progress.update_one(
        {"id": book_id},
        {"$set": {"cover_status": "generating", "cover_started_at": datetime.now(timezone.utc).isoformat()}}
    )
    await db.books.update_one(
        {"id": book_id},
        {"$set": {"cover_status": "generating", "cover_started_at": datetime.now(timezone.utc).isoformat()}}
    )
    
    # Start background task
    async def generate_cover_async():
        import base64
        import uuid
        import httpx
        from pathlib import Path
        
        try:
            # Use English title if available, otherwise translate
            title_en = book.get('title_en', '').strip()
            title_es = book.get('title', 'Untitled Book').replace('(RECOMMENDED)', '').strip()
            
            if not title_en:
                try:
                    # Use call_openai_gpt4o which has built-in 429 retry + OpenRouter fallback
                    title_en = (await call_openai_gpt4o(
                        system_message="Translate the following book title from Spanish to English. Return ONLY the translated title, nothing else.",
                        user_message=title_es,
                        temperature=0.3,
                        max_tokens=200
                    )).strip()
                except Exception as e:
                    title_en = title_es
            
            title = title_en
            
            # Get author name
            client_doc = await db.clients.find_one({"id": book.get('client_id')}, {"_id": 0, "name": 1})
            author_name = client_doc['name'].title() if client_doc else "Author"
            
            cover_prompt = f"""Create a visually rich and illustrated book cover with:
- Title "{title}" prominently displayed in bold, stylized text with artistic typography
- Author name "{author_name}" at the bottom in elegant font
- Rich illustrated artwork that represents the book's theme
- Include detailed illustrations, symbolic imagery, and visual metaphors
- Use vibrant colors with depth and dimension
- Add decorative elements like ornamental borders, flourishes, or thematic icons
- Include relevant imagery such as: landscapes, figures, objects, or abstract artistic elements
- Create a sense of depth with layered visual elements
- Professional quality with attention to artistic detail
- Vertical book cover format (portrait orientation)
- The illustration should be the main focus, with the title integrated artistically"""

            logging.warning(f"🎨 [ASYNC] Generating cover with OpenRouter Gemini 2.5 Flash Image")
            logging.warning(f"   Title: {title}")
            logging.warning(f"   Author: {author_name}")
            
            # Use OpenRouter directly with google/gemini-2.5-flash-image (Nano Banana)
            openrouter_key = os.environ.get('OPENROUTER_API_KEY')
            
            async with httpx.AsyncClient(timeout=180.0) as http_client:
                response = await http_client.post(
                    "https://openrouter.ai/api/v1/chat/completions",
                    headers={
                        "Authorization": f"Bearer {openrouter_key}",
                        "Content-Type": "application/json",
                        "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
                        "X-Title": "Monica Book Cover Generator"
                    },
                    json={
                        "model": "google/gemini-2.5-flash-image",
                        "modalities": ["text", "image"],
                        "messages": [
                            {
                                "role": "user",
                                "content": [
                                    {"type": "text", "text": cover_prompt}
                                ]
                            }
                        ]
                    }
                )
                
                if response.status_code != 200:
                    raise Exception(f"OpenRouter error: {response.status_code} - {response.text[:500]}")
                
                result = response.json()
                logging.warning(f"   OpenRouter response received. Keys: {result.keys()}")
                
                # Extract image from response
                image_data = None
                if result.get('choices') and len(result['choices']) > 0:
                    message = result['choices'][0].get('message', {})
                    content = message.get('content', [])
                    
                    # Content can be a list of parts or a string
                    if isinstance(content, list):
                        for part in content:
                            if isinstance(part, dict):
                                # Check for inline_data (base64 image)
                                if part.get('type') == 'image_url':
                                    image_url_obj = part.get('image_url', {})
                                    url = image_url_obj.get('url', '')
                                    if url.startswith('data:image'):
                                        image_data = url.split('base64,')[1] if 'base64,' in url else None
                                elif part.get('inline_data'):
                                    image_data = part['inline_data'].get('data')
                    
                    # Also check for images array in message (OpenRouter format)
                    if not image_data and message.get('images'):
                        images = message.get('images', [])
                        if images and len(images) > 0:
                            first_img = images[0]
                            if isinstance(first_img, dict):
                                url = first_img.get('url', '') or first_img.get('image_url', {}).get('url', '')
                                if url and 'base64,' in url:
                                    image_data = url.split('base64,')[1]
                                elif first_img.get('data'):
                                    image_data = first_img.get('data')
                
                logging.warning(f"   Image data found: {bool(image_data)}")
                
                if image_data:
                    # Decode base64 data
                    image_bytes = base64.b64decode(image_data)
                    
                    static_dir = Path("/app/backend/static/covers")
                    static_dir.mkdir(parents=True, exist_ok=True)
                    
                    image_filename = f"cover_{book_id}_{uuid.uuid4().hex[:8]}.png"
                    image_path = static_dir / image_filename
                    
                    with open(image_path, "wb") as f:
                        f.write(image_bytes)
                    
                    image_url = f"/static/covers/{image_filename}"
                    
                    await db.books.update_one(
                        {"id": book_id},
                        {"$set": {
                            "cover_image_url": image_url, 
                            "cover_status": "completed",
                            "cover_completed_at": datetime.now(timezone.utc).isoformat()
                        }}
                    )
                    await db.books_in_progress.update_one(
                        {"id": book_id},
                        {"$set": {
                            "cover_image_url": image_url, 
                            "cover_status": "completed",
                            "cover_completed_at": datetime.now(timezone.utc).isoformat()
                        }}
                    )
                    
                    logging.warning(f"✅ [ASYNC] Cover image generated: {image_url}")
                    return
                
                # Log full response for debugging if no image found
                logging.warning(f"   Full response structure: {str(result)[:1000]}")
                raise Exception("No image found in OpenRouter response")
                
        except Exception as e:
            logging.error(f"❌ [ASYNC] Error generating cover image: {e}")
            await db.books_in_progress.update_one(
                {"id": book_id},
                {"$set": {"cover_status": "error", "cover_error": str(e)}}
            )
            await db.books.update_one(
                {"id": book_id},
                {"$set": {"cover_status": "error", "cover_error": str(e)}}
            )
    
    background_tasks.add_task(generate_cover_async)
    
    return {
        "success": True,
        "message": "Cover generation started. Check status endpoint for progress.",
        "status": "generating",
        "book_id": book_id
    }


@api_router.get("/books/{book_id}/cover-status")
async def get_book_cover_status(
    book_id: str,
    current_user: User = Depends(get_current_user)
):
    """Get the status of book cover generation"""
    book = await db.books.find_one({"id": book_id}, {"_id": 0, "cover_status": 1, "cover_image_url": 1, "cover_error": 1})
    if not book:
        book = await db.books_in_progress.find_one({"id": book_id}, {"_id": 0, "cover_status": 1, "cover_image_url": 1, "cover_error": 1})
    
    if not book:
        raise HTTPException(status_code=404, detail="Book not found")
    
    status = book.get('cover_status', 'not_started')
    
    return {
        "book_id": book_id,
        "status": status,
        "image_url": book.get('cover_image_url') if status == 'completed' else None,
        "error": book.get('cover_error') if status == 'error' else None
    }


@api_router.get("/books/{book_id}/cover-image")
async def get_book_cover_image(book_id: str):
    """Get the cover image URL for a book if it exists"""
    book = await db.books.find_one({"id": book_id}, {"_id": 0, "cover_image_url": 1, "title": 1})
    if not book:
        book = await db.books_in_progress.find_one({"id": book_id}, {"_id": 0, "cover_image_url": 1, "title": 1})
    
    if not book:
        raise HTTPException(status_code=404, detail="Book not found")
    
    cover_url = book.get('cover_image_url')
    if not cover_url:
        return {"has_cover": False, "message": "No cover image generated yet"}
    
    return {
        "has_cover": True,
        "image_url": cover_url,
        "title": book.get('title', 'Untitled')
    }


@api_router.get("/books/{book_id}/download-cover")
async def download_book_cover(book_id: str):
    """Download the cover image file directly"""
    from fastapi.responses import FileResponse
    from pathlib import Path
    
    book = await db.books.find_one({"id": book_id}, {"_id": 0, "cover_image_url": 1, "title": 1})
    if not book:
        book = await db.books_in_progress.find_one({"id": book_id}, {"_id": 0, "cover_image_url": 1, "title": 1})
    
    if not book:
        raise HTTPException(status_code=404, detail="Book not found")
    
    cover_url = book.get('cover_image_url')
    if not cover_url:
        raise HTTPException(status_code=404, detail="No cover image generated yet")
    
    # Convert URL path to file path
    # cover_url is like: /static/covers/cover_xxx.png
    file_path = Path("/app/backend") / cover_url.lstrip('/')
    
    if not file_path.exists():
        raise HTTPException(status_code=404, detail="Cover image file not found")
    
    # Clean title for filename
    title = book.get('title', 'portada').replace(' ', '_').replace('/', '-')[:50]
    filename = f"portada_{title}.png"
    
    return FileResponse(
        path=str(file_path),
        media_type="image/png",
        filename=filename,
        headers={"Content-Disposition": f"attachment; filename={filename}"}
    )



