def generate_fallback_patent_section(
    section_number: int,
    section_title: str,
    patent_title: str,
    technical_field: str,
    description: str,
    language: str
) -> tuple:
    """
    Generate fallback patent content when AI generation fails.
    Returns (content_es, content_en) tuple with substantial technical content.
    """
    
    # Section-specific templates
