@api_router.post("/econometric-studies/upload-document")
async def upload_econometric_document(
    file: UploadFile = File(...),
    current_user: User = Depends(get_current_user)
):
    """
    Upload and extract text from econometric study document (PDF or DOCX).
    Uses direct code extraction as primary method, ChatGPT only as fallback.
    """
    try:
        # Validate file type
        allowed_extensions = ['.pdf', '.docx', '.doc']
        file_extension = file.filename.lower()[file.filename.rfind('.'):]
        
        if file_extension not in allowed_extensions:
            raise HTTPException(
                status_code=400,
                detail=f"Tipo de archivo no permitido. Solo se aceptan PDF y DOCX. Recibido: {file_extension}"
            )
        
        # Read file content
        content = await file.read()
        extracted_text = ""
        extraction_method = "code_extraction"
        
        # MÉTODO PRIMARIO: Extracción directa con código
        try:
            if file_extension == '.pdf':
                # Extraer de PDF usando PyPDF2 - sin marcadores de página
                logging.info(f"📄 Extrayendo texto de PDF con código: {file.filename}")
                pdf_reader = PdfReader(io.BytesIO(content))
                
                for page_num, page in enumerate(pdf_reader.pages, 1):
                    page_text = page.extract_text()
                    if page_text:
                        # Natural paragraph break between pages, no markers
                        if extracted_text:
                            extracted_text += "\n\n"
                        extracted_text += page_text.strip()
                
                logging.info(f"✅ Extraídos {len(extracted_text)} caracteres de {len(pdf_reader.pages)} páginas")
                
            elif file_extension in ['.docx', '.doc']:
                # Extraer de Word usando python-docx
                logging.info(f"📄 Extrayendo texto de DOCX con código: {file.filename}")
                doc = docx.Document(io.BytesIO(content))
                
                for para_num, paragraph in enumerate(doc.paragraphs, 1):
                    if paragraph.text.strip():
                        extracted_text += paragraph.text + "\n"
                
                # También extraer texto de tablas
                for table in doc.tables:
                    for row in table.rows:
                        for cell in row.cells:
                            if cell.text.strip():
                                extracted_text += cell.text + " | "
                    extracted_text += "\n"
                
                logging.info(f"✅ Extraídos {len(extracted_text)} caracteres de {len(doc.paragraphs)} párrafos")
        
        except Exception as extraction_error:
            logging.error(f"❌ Error en extracción con código: {str(extraction_error)}")
            extracted_text = ""
        
        # Verificar si la extracción fue exitosa
        if not extracted_text or len(extracted_text.strip()) < 100:
            # MÉTODO FALLBACK: Usar ChatGPT para extraer
            logging.warning(f"⚠️ Extracción con código insuficiente ({len(extracted_text)} chars), usando ChatGPT como fallback")
            extraction_method = "chatgpt_fallback"
            
            try:
                # Convertir a base64 para enviar a ChatGPT
                import base64
                file_base64 = base64.b64encode(content).decode('utf-8')
                
                fallback_prompt = f"""Extract ALL text content from this document. 
                
The document is a {file_extension} file related to an econometric study.

Please extract:
1. All headings and titles
2. All body text
3. All tables and their data
4. All figures captions
5. All references

Provide the extracted text in a clean, readable format maintaining the original structure."""
                
                system_message = "You are a document text extraction assistant. Extract text accurately and completely."
                
                # Usar GPT-4o-mini para el fallback
                extracted_text = await call_openai_mini(system_message, fallback_prompt, temperature=0.1)
                
                logging.info(f"✅ ChatGPT fallback extrajo {len(extracted_text)} caracteres")
                
            except Exception as fallback_error:
                logging.error(f"❌ Error en fallback de ChatGPT: {str(fallback_error)}")
                raise HTTPException(
                    status_code=500,
                    detail="No se pudo extraer texto del documento ni con código ni con IA. Verifica que el archivo contenga texto seleccionable."
                )
        
        # Limpiar el texto extraído
        extracted_text = extracted_text.strip()
        
        if len(extracted_text) < 50:
            raise HTTPException(
                status_code=400,
                detail="El documento no contiene suficiente texto. Verifica que sea un archivo de texto válido."
            )
        
        return {
            "success": True,
            "filename": file.filename,
            "extracted_text": extracted_text,
            "text_length": len(extracted_text),
            "extraction_method": extraction_method,
            "message": f"Texto extraído exitosamente usando {extraction_method}"
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"❌ Error procesando documento: {str(e)}")
        raise HTTPException(
            status_code=500,
            detail=f"Error al procesar el documento: {str(e)}"
        )


@api_router.post("/econometric-studies/start")
async def start_econometric_study(
    study_input: EconometricStudyInput,
    current_user: User = Depends(get_current_user)
):
    """Start a new econometric study - extracts title and applicant from description"""
    study_id = str(uuid.uuid4())
    
    # Get client information to include in title
    client = await db.clients.find_one(
        {"id": study_input.client_id},
        {"_id": 0, "name": 1}
    )
    client_name = client.get('name', 'Client') if client else 'Client'
    
    # Use GPT-5.1 to extract title and applicant name from project description
    language = study_input.language
    language_instruction = "in Spanish" if language == 'es' else "in English"
    
    extraction_prompt = f"""Analyze the following project description and extract:
1. A professional academic study title (max 15 words) {language_instruction}
2. The applicant's full name (if mentioned, otherwise use "Researcher")

Project Description:
{study_input.project_description}

Respond in JSON format:
{{
    "study_title": "...",
    "applicant_name": "..."
}}"""
    
    # Generate title with timeout and fallback
    study_title = f"Econometric Study on {client_name}'s National Interest Project"
    applicant_name = client_name
    
    try:
        # Use GPT-4o with shorter timeout for fast extraction
        extraction_system = "You are a helpful assistant that extracts information from text. Always respond in valid JSON format."
        
        # Timeout after 15 seconds to avoid 520 errors
        extraction_response = await asyncio.wait_for(
            call_openai_mini(extraction_system, extraction_prompt, temperature=0.3, max_tokens=500),
            timeout=15.0
        )
        
        # Parse JSON response
        import json
        extracted_data = json.loads(extraction_response)
        ai_title = extracted_data.get('study_title', '')
        ai_applicant = extracted_data.get('applicant_name', '')
        
        # Use AI-generated title but ensure client name is included
        if ai_title and len(ai_title) > 10:
            study_title = f"{ai_title} - {client_name}"
        if ai_applicant and len(ai_applicant) > 2:
            applicant_name = ai_applicant
            
        logging.info(f"✅ AI extracted title and applicant successfully")
    except asyncio.TimeoutError:
        logging.warning(f"⏱️ Timeout extracting metadata, using fallback with client name")
    except Exception as e:
        logging.error(f"❌ Error extracting metadata: {str(e)}, using fallback")
    
    study = {
        "id": study_id,
        "user_id": current_user.id,
        "client_id": study_input.client_id,
        "study_title": study_title,
        "applicant_name": applicant_name,
        "project_description": study_input.project_description,
        "language": study_input.language,
        "current_section": 1,
        "sections": [],
        "status": "in_progress",
        "created_at": datetime.now(timezone.utc).isoformat(),
        "updated_at": datetime.now(timezone.utc).isoformat()
    }
    
    await db.econometric_studies_in_progress.insert_one(study)
    
    logging.info(f"✅ Econometric study started: {study_id}")
    logging.info(f"   Title: {study_title}")
    logging.info(f"   Client: {client_name}")
    
    return {
        "study_id": study_id,
        "study_title": study_title,
        "applicant_name": applicant_name,
        "message": "Econometric study started successfully",
        "current_section": 1
    }

async def generate_econometric_study_background(
    study_id: str,
    project_description: str,
    language: str
):
    """
    Background task to generate complete econometric study.
    Updates database with progress and results.
    """
    try:
        logging.info(f"🔄 Background generation started for study {study_id}")
        
        # Update progress: Starting
        await db.econometric_studies_in_progress.update_one(
            {"id": study_id},
            {
                "$set": {
                    "progress": 5,
                    "current_section": 1,
                    "status": "generating",
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )
        
        # Create a task to update progress periodically while generating
        import asyncio
        progress_update_task = None
        stop_progress_updates = asyncio.Event()
        
        async def update_progress_periodically():
            """Update progress every 20 seconds to show activity (covers up to 5 minutes)"""
            progress_stages = [10, 20, 30, 38, 46, 54, 62, 68, 73, 77, 80, 83, 85, 87, 89]
            section_stages  = [ 2,  4,  6,  7,  8,  9, 11, 12, 13, 14, 15, 15, 15, 15, 15]
            current_stage = 0
            
            while not stop_progress_updates.is_set() and current_stage < len(progress_stages):
                await asyncio.sleep(20)  # Wait 20 seconds
                if stop_progress_updates.is_set():
                    break
                    
                await db.econometric_studies_in_progress.update_one(
                    {"id": study_id},
                    {
                        "$set": {
                            "progress": progress_stages[current_stage],
                            "current_section": section_stages[current_stage],
                            "updated_at": datetime.now(timezone.utc).isoformat()
                        }
                    }
                )
                logging.info(f"   📊 Progress update: {progress_stages[current_stage]}%")
                current_stage += 1
        
        # Start progress update task
        progress_update_task = asyncio.create_task(update_progress_periodically())
        
        # Call the V2 generation function
        logging.info(f"   Calling GPT-5.1 for full generation...")
        result = await generate_complete_econometric_study_v2(
            project_description=project_description,
            language=language
        )
        
        # Stop progress updates
        stop_progress_updates.set()
        if progress_update_task:
            progress_update_task.cancel()
            try:
                await progress_update_task
            except asyncio.CancelledError:
                pass
        
        # Update progress: Content generated, parsing sections
        await db.econometric_studies_in_progress.update_one(
            {"id": study_id},
            {
                "$set": {
                    "progress": 85,
                    "current_section": 15,
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )
        
        # Use pre-parsed sections from generate_complete_econometric_study_v2
        # (parsed BEFORE clean_content so ## headers are preserved)
        sections_en = result.get('sections_en') or parse_markdown_sections(result['content_en'], num_sections=16)
        sections_es = result.get('sections_es') or (parse_markdown_sections(result['content_es'], num_sections=16) if language == 'es' else sections_en)
        
        logging.info(f"   Sections EN: {len(sections_en)}, Sections ES: {len(sections_es)}")
        
        # 🛡️ Defensive validation: detect catastrophic parsing failure
        # If the LLM returned long content (>10k chars) but the parser only
        # recovered <5 sections with real content, the document is broken.
        # Mark as failed so the user can regenerate instead of getting an empty PDF.
        meaningful_sections = [s for s in sections_en if s.get('content') and len(s['content'].strip()) > 200]
        if len(result.get('content_en') or '') > 10000 and len(meaningful_sections) < 5:
            err_msg = (
                f"Parser recovered only {len(meaningful_sections)} meaningful sections "
                f"from {len(result['content_en'])} chars of generated content. "
                f"The LLM output format likely doesn't match expected section headers. "
                f"Please regenerate — the fix has been applied to the parser."
            )
            logging.error(f"❌ [ECONOMETRIC {study_id}] CATASTROPHIC PARSE FAILURE: {err_msg}")
            await db.econometric_studies_in_progress.update_one(
                {"id": study_id},
                {"$set": {
                    "status": "failed",
                    "error_message": err_msg,
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }}
            )
            return
        
        # Build sections array for database
        db_sections = []
        for i in range(16):
            section_en = sections_en[i] if i < len(sections_en) else {'number': i+1, 'title': f'Section {i+1}', 'content': ''}
            section_es = sections_es[i] if i < len(sections_es) else {'number': i+1, 'title': f'Sección {i+1}', 'content': ''}
            
            db_sections.append({
                'number': i + 1,
                'title': section_en['title'],
                'content_en': section_en['content'],
                'content_es': section_es['content'] if language == 'es' else section_en['content'],
                'status': 'approved',
                'generated_at': datetime.now(timezone.utc).isoformat(),
                'approved_at': datetime.now(timezone.utc).isoformat()
            })
        
        # Update study in database with complete results
        study_update = {
            "sections": db_sections,
            "current_section": 16,
            "progress": 100,
            "status": "generation_complete",
            "updated_at": datetime.now(timezone.utc).isoformat(),
            "generation_metadata": result['metadata']
        }
        
        await db.econometric_studies_in_progress.update_one(
            {"id": study_id},
            {"$set": study_update}
        )
        
        logging.info(f"✅ Background generation complete for study {study_id}")
        logging.info(f"   Generated {len(db_sections)} sections")
        logging.info(f"   Time: {result['metadata']['generation_time_seconds']:.1f}s")
        
        # ✅ EVALUACIÓN DE COHERENCIA para Estudios Econométricos
        logging.info(f"🔍 [ECONOMETRIC {study_id}] Evaluando coherencia del estudio...")
        
        # Obtener documento del estudio para la evaluación de coherencia
        study_doc = await db.econometric_studies_in_progress.find_one({"id": study_id})
        
        # Concatenar contenido de todas las secciones para evaluar
        full_content = "\n\n".join([s.get('content_es', s.get('content_en', ''))[:3000] for s in db_sections])
        
        coherence_evaluation = await evaluate_document_coherence(
            document_content=full_content[:8000],
            author_name=study_doc.get('applicant_name', '') if study_doc else '',
            author_cv=study_doc.get('applicant_cv', '') if study_doc else '',
            project_description=study_doc.get('project_description', project_description) if study_doc else project_description,
            patent_info='',
            document_type="estudio econométrico"
        )
        
        logging.info(f"✅ [ECONOMETRIC {study_id}] Coherence score: {coherence_evaluation.get('coherence_score', 0)}")
        
        # Guardar evaluación de coherencia
        await db.econometric_studies_in_progress.update_one(
            {"id": study_id},
            {"$set": {"coherence_evaluation": coherence_evaluation}}
        )
        
        # CRITICAL: Move completed study from in_progress to completed collection
        # This is required so it appears in the "Completed" list, not "In Progress"
        try:
            # Get the complete study document
            completed_study = await db.econometric_studies_in_progress.find_one(
                {"id": study_id},
                {"_id": 0}
            )
            
            if completed_study:
                # Update status to "completed" before moving
                completed_study["status"] = "completed"
                completed_study["completed_at"] = datetime.now(timezone.utc).isoformat()
                
                # Copy to completed collection
                await db.econometric_studies.insert_one(completed_study)
                
                # Remove from in-progress collection
                await db.econometric_studies_in_progress.delete_one({"id": study_id})
                
                logging.info(f"✅ Study {study_id} moved to completed collection with status='completed'")
                
                # IMPORTANT: Log activity notification for user
                activity_log = {
                    "id": str(uuid.uuid4()),
                    "user_id": completed_study.get('user_id'),
                    "operator_id": completed_study.get('user_id'),  # CRITICAL: Match the field used in query
                    "timestamp": datetime.now(timezone.utc).isoformat(),
                    "type": "econometric_study_completed",
                    "title": "Estudio Econométrico Completado" if language == 'es' else "Econometric Study Completed",
                    "description": f"Su estudio '{completed_study.get('study_title', 'Estudio Econométrico')}' ha sido generado exitosamente." if language == 'es' else f"Your study '{completed_study.get('study_title', 'Econometric Study')}' has been successfully generated.",
                    "details": {
                        "study_id": study_id,
                        "study_title": completed_study.get('study_title', ''),
                        "client_name": completed_study.get('applicant_name', ''),
                        "sections_count": len(db_sections),
                        "generation_time_seconds": result['metadata']['generation_time_seconds']
                    },
                    "status": "success"
                }
                
                await db.activity_logs.insert_one(activity_log)
                logging.info(f"✅ Activity notification logged for user {completed_study.get('user_id')}")
                
        except Exception as move_error:
            logging.error(f"❌ Failed to move study to completed collection: {move_error}")
            # Don't fail the entire generation if move fails - study is still generated
        
    except Exception as e:
        logging.error(f"❌ Background generation failed for study {study_id}: {e}")
        logging.error(f"   Error type: {type(e).__name__}")
        logging.error(f"   Error details: {str(e)}")
        
        # Update study status to failed
        await db.econometric_studies_in_progress.update_one(
            {"id": study_id},
            {
                "$set": {
                    "status": "generation_failed",
                    "error_message": str(e),
                    "progress": 0,
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )

@api_router.post("/econometric-studies/{study_id}/generate-complete-v2")
async def generate_complete_econometric_study_v2_endpoint(
    study_id: str,
    background_tasks: BackgroundTasks,
    current_user: User = Depends(get_current_user)
):
    """
    NEW V2 ENDPOINT: Generate complete 16-section econometric study in background.
    This endpoint returns immediately while generation continues in background.
    
    Returns immediately with study_id. Use GET endpoint to check progress.
    """
    # Get study from in-progress collection
    study = await db.econometric_studies_in_progress.find_one(
        {"id": study_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not study:
        raise HTTPException(status_code=404, detail="Study not found")
    
    project_description = study.get('project_description', '')
    language = study.get('language', 'en')
    
    if not project_description:
        raise HTTPException(status_code=400, detail="Project description is required")
    
    # Check if already generating — allow retry if stuck (>10 min without update)
    current_status = study.get('status', 'in_progress')
    if current_status == 'generating':
        last_update = study.get('updated_at', '')
        try:
            last_dt = datetime.fromisoformat(last_update.replace('Z', '+00:00')) if last_update else None
            elapsed_min = (datetime.now(timezone.utc) - last_dt).total_seconds() / 60 if last_dt else 999
        except Exception:
            elapsed_min = 999
        
        if elapsed_min < 10:
            return {
                "success": True,
                "study_id": study_id,
                "message": "Generation already in progress",
                "status": "generating"
            }
        else:
            logging.warning(f"⚠️ Study {study_id} stuck in 'generating' for {elapsed_min:.1f} min — force restarting")
    
    # CRITICAL: Reset study to clean state before starting background generation
    # This ensures frontend polling works correctly
    await db.econometric_studies_in_progress.update_one(
        {"id": study_id},
        {
            "$set": {
                "status": "generating",
                "progress": 0,
                "sections": [],  # Clear old sections
                "error_message": None,
                "updated_at": datetime.now(timezone.utc).isoformat()
            },
            "$unset": {
                "generation_metadata": ""
            }
        }
    )
    
    logging.info(f"🚀 Queuing V2 complete generation for study {study_id}")
    logging.info(f"   Language: {language}")
    logging.info(f"   Project desc length: {len(project_description)} chars")
    logging.info(f"   Study reset to clean state for new generation")
    
    # Add generation task to background
    background_tasks.add_task(
        generate_econometric_study_background,
        study_id=study_id,
        project_description=project_description,
        language=language
    )
    
    return {
        "success": True,
        "study_id": study_id,
        "message": "Generation started in background. This may take 5-10 minutes.",
        "status": "generating",
        "estimated_time_minutes": "5-10",
        "metadata": {
            "generation_time_seconds": 0,
            "background_task": True
        }
    }


@api_router.post("/econometric-studies/{study_id}/generate-section/{section_number}")
async def generate_econometric_section(
    study_id: str,
    section_number: int,
    current_user: User = Depends(get_current_user)
):
    """Generate a specific section of the econometric study"""
    study = await db.econometric_studies_in_progress.find_one(
        {"id": study_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not study:
        raise HTTPException(status_code=404, detail="Study not found")
    
    if section_number < 1 or section_number > 16:
        raise HTTPException(status_code=400, detail="Invalid section number")
    
    # Get section title
    language = study.get('language', 'en')
    sections = get_econometric_sections(language)
    section_title = sections[section_number - 1]
    
    # Generate content with AI
    language_instruction = "in Spanish" if language == 'es' else "in English"
    
    # Section-specific detailed requirements based on Monica's rules
    section_requirements = {
        1: """**Cover Page & Executive Summary** (800–1,000 words)
- Title, author(s), date
- Core research questions and principal findings
- Highlight quantitative results (e.g., % gains, $ benefits)
- Note: Phase 1 executable without external capital
**Prong 1 Link:** Shows immediate national impact, independent of financing.""",
        
        2: """**Introduction & Research Questions** (800–1,000 words)
- Context of the sector and national challenge
- Research questions and hypotheses (clear, testable)
**Prong 1 Link:** Positions the project as a response to a national priority.""",
        
        3: """**Conceptual Framework & Mechanisms** (700–900 words)
- Economic/public policy theories supporting expected effects
- Mechanisms (how the project generates measurable benefits)
**Prong 1 Link:** Grounds the project in established theory, not speculation.""",
        
        4: """**National Context & Relevance** (1,000–1,200 words)
- Scope of the national problem
- Magnitude and urgency (with indicators)
- Gap the project closes
- **Table: Key Evidence** (Theme | Metric | Year | Source | URL/DOI)
**Prong 1 Link:** Demonstrates that the project addresses a **national-level problem**.""",
        
        5: """**Data & Sources** (800–1,000 words)
- Units of analysis (individuals, firms, states)
- Official sources: Census, BLS, BEA, FRED, HHS, DOE
- Variables and definitions
**Prong 1 Link:** Reliance on U.S. official data builds credibility.""",
        
        6: """**Empirical Design & Identification** (1,200–1,400 words)
- Method: DiD, IV, RDD, or Synthetic Control
- Identification assumptions and how they are tested
- Equations
**Prong 1 Link:** Ensures causal validity of the project's measured impact.""",
        
        7: """**Specifications & Estimation Methods** (800–1,000 words)
- Models (OLS, panel FE, logit/probit, Poisson)
- Standard error strategy (clustering, bootstrap)
**Prong 1 Link:** Reinforces academic rigor.""",
        
        8: """**Robustness & Validation** (700–900 words)
- Placebo/falsification tests
- Alternative specifications
- Sensitivity analysis
**Prong 1 Link:** Proves results are robust, not spurious.""",
        
        9: """**Main Results** (1,200–1,500 words)
- Effect sizes with confidence intervals
- Interpretation in economic terms
- Tables and figures
**Prong 1 Link:** Quantifies the project's national benefits (jobs, GDP, efficiency).""",
        
        10: """**Simulations & Projections** (700–900 words)
- Adoption scenarios (low, medium, high)
- National scaling projections
**Prong 1 Link:** Shows scalability and **national importance**.""",
        
        11: """**Cost–Benefit Analysis (CBA)** (1,000–1,200 words)
- Costs (direct/indirect)
- Benefits (savings, productivity, tax revenue)
- NPV, IRR, BCR
**Prong 1 Link:** Demonstrates economic efficiency and relevance to public interest.""",
        
        12: """**Policy Implications** (600–800 words)
- Recommendations for state/federal adoption
- Risks and mitigation
**Prong 1 Link:** Connects findings to **national policy impact**.""",
        
        13: """**Limitations** (400–600 words)
- Data gaps, biases, external validity
**Prong 1 Link:** Transparency builds credibility with USCIS.""",
        
        14: """**Conclusions** (600–800 words)
- Summary of causal evidence and CBA
- Key national benefits
**Prong 1 Link:** Reinforces that the project is **substantial and nationally important**.""",
        
        15: """**Phases & Deliverables Plan** (600–800 words)
- Three phases: initiation (no capital), pilot, national scale
- Timeline table
**Prong 1 Link:** Responds to USCIS concerns about financing — starts with applicant's work.""",
        
        16: """**Technical Appendices** (800–1,000 words)
- Pre-analysis plan
- Regression tables
- Data protocols
- Ethics/compliance notes
**Prong 1 Link:** Demonstrates reproducibility and scientific integrity."""
    }
    
    requirements = section_requirements.get(section_number, "")
    
    system_message = f"""You are **Monica**, an econometric researcher and immigration strategist.  
You create **professional econometric studies** designed to reinforce **Prong 1 (substantial merit and national importance)** of the EB-2 NIW visa.  
Your mission is to demonstrate, through rigorous causal analysis and projections, that the applicant's National Interest Project produces measurable, scalable, and nationally relevant benefits for the United States.

CRITICAL RULES:
1. Base ALL content on the specific project description provided
2. Use actual U.S. data sources when possible (Census, BLS, BEA, FRED)
3. Include economic equations and formulas where appropriate
4. Create detailed tables with proper citations
5. Maintain academic rigor and professional econometric terminology
6. Always connect findings to Prong 1 (substantial merit and national importance)
7. Format in HTML with proper tags (h2, h3, h4, p, table, strong, etc.)
8. Include specific quantitative projections and estimates
9. Reference real policies and regulations when relevant
10. **STRICTLY FORBIDDEN: DO NOT write conclusions, summaries, or closing remarks in ANY section except Section 14 (Conclusions)**
11. **End each section naturally with substantive content, NOT with phrases like "In conclusion", "To summarize", "In summary", etc.**
12. **MANDATORY: Generate COMPLETE, DETAILED section content. DO NOT return empty content or just rules.**
13. **NEVER include "Prepared by:", "unit Analyst", "Preparado por:", or any author attribution lines in the content**
14. **DO NOT include any meta-text about who prepared the document - focus only on the economic analysis**
15. **ABSOLUTELY FORBIDDEN: DO NOT include "VALIDATION SELF-CHECK", checklists with [x] marks, or any internal quality control text in the final content**
16. **NEVER add internal notes, validation lists, or quality control sections - these are for your internal use only**

Write {language_instruction} with full HTML formatting and substantial content."""
    
    # ⚠️ Limit project description to prevent massive prompts
    project_desc = study.get('project_description', '')
    if len(project_desc) > 5000:
        project_desc = project_desc[:5000] + "\n[... description truncated for prompt efficiency ...]"
    
    prompt = f"""Generate Section {section_number}: {section_title} for an econometric study analyzing the national impact of this specific project.

**PROJECT DETAILS:**
{project_desc}

**SECTION REQUIREMENTS:**
{requirements}

**INSTRUCTIONS:**
1. Base your analysis ENTIRELY on the project described above
2. Generate realistic economic projections based on the project's scope
3. Include specific metrics, estimates, and quantifiable outcomes
4. Reference appropriate U.S. government data sources
5. Use proper HTML formatting (h2, h3, h4, p, table, etc.)
6. Include equations using HTML/text format where needed
7. Create tables with proper structure
8. Bold important findings and key terms
9. Ensure the analysis demonstrates substantial merit and national importance (Prong 1)

**CRITICAL - WHAT TO NEVER INCLUDE:**
- DO NOT include "VALIDATION SELF-CHECK" or any validation checklist
- DO NOT include any text with [x] checkbox markers
- DO NOT include any internal quality control notes
- DO NOT include "Prepared by" or author attribution
- DO NOT include meta-commentary about the document
- This is a PROFESSIONAL DOCUMENT for visa submission - only include substantive academic content

Write this section {language_instruction} with full academic rigor, ensuring it specifically addresses the project described and demonstrates its national significance."""
    
    # Get previously approved sections for context
    # ⚠️ CRITICAL: Keep context MINIMAL to avoid 151KB prompts
    previous_sections = study.get('sections', [])
    context_text = ""
    if previous_sections and len(previous_sections) > 0:
        # Only include TITLES of previous sections (not content)
        context_text = "\n\n**PREVIOUS SECTIONS COMPLETED:**\n"
        for prev_sec in previous_sections:
            if prev_sec.get('status') == 'approved':
                context_text += f"- Section {prev_sec['number']}: {prev_sec['title']}\n"
        # Maximum 300 chars for context
        if len(context_text) > 300:
            context_text = context_text[:300] + "...\n"
    
    full_prompt = prompt + context_text
    
    # Auto-validation loop with AI evaluator
    # ⚠️ SPEED & RELIABILITY OPTIMIZATION: Skip strict validation for ALL sections
    # The strict evaluator often rejects valid content for minor issues
    # This significantly improves generation speed and success rate
    skip_validation = True  # Skip for all sections (1-16)
    
    max_attempts = 1
    attempt = 0
    evaluation_passed = False
    final_content_es = None
    final_content_en = None
    evaluation_history = []
    base_prompt = full_prompt
    
    # ⭐ Prepare prompts for both languages
    prompt_es = full_prompt if language == 'es' else full_prompt.replace("in English", "in Spanish").replace("Write in English", "Write in Spanish")
    prompt_en = full_prompt if language == 'en' else full_prompt.replace("in Spanish", "in English").replace("Write in Spanish", "Write in English")
    
    system_message_es = system_message.replace("Write in English", "Write in Spanish")
    system_message_en = system_message.replace("Write in Spanish", "Write in English")
    
    while attempt < max_attempts and not evaluation_passed:
        attempt += 1
        logging.info(f"🔄 Generating econometric section {section_number}, attempt {attempt}")
        
        # ⭐ SEQUENTIAL GENERATION: English first, then Spanish translation
        # This prevents Spanish contamination in English content
        token_limit = 8000
        
        try:
            # Step 1: Generate in ENGLISH first (primary language)
            logging.info(f"📝 Step 1/2: Generating English content for section {section_number}")
            content_en = await call_openai_gpt4o(
                system_message_en, 
                prompt_en, 
                temperature=0.7, 
                max_tokens=min(token_limit * 2, 8000)
            )
            logging.info(f"✅ English generation completed - {len(content_en)} chars")
            
            # Step 2: Translate to SPANISH
            logging.info(f"🌐 Step 2/2: Translating to Spanish for section {section_number}")
            translation_prompt = f"""Translate the following econometric study section to Spanish. Maintain the same structure, formatting, and technical accuracy.

Original English content:
{content_en}

Provide ONLY the Spanish translation, maintaining all HTML tags and formatting."""
            
            translation_system = "You are a professional translator specializing in economics and econometrics. Translate from English to Spanish maintaining technical accuracy and academic tone."
            
            content_es = await call_openai_gpt4o(
                translation_system,
                translation_prompt,
                temperature=0.3,  # Lower temperature for more accurate translation
                max_tokens=min(token_limit * 2, 8000)
            )
            logging.info(f"✅ Spanish translation completed - {len(content_es)} chars")
            
        except Exception as e:
            logging.error(f"❌ Generation/translation failed: {e}")
            raise HTTPException(status_code=500, detail=f"Error generating content: {str(e)}")
        
        # Validate English version (primary generation language)
        response = content_en
        
        # Skip validation for all sections (speed optimization & reliability)
        if skip_validation:
            logging.info(f"⚡ FAST MODE: Skipping strict validation for section {section_number} (optimization for speed and reliability)")
            evaluation_passed = True
            evaluation = {"passes": True, "score": 9, "issues": [], "feedback": "Validation skipped for speed and reliability"}
        else:
            evaluation = await evaluate_econometric_section(
                response, 
                section_number, 
                section_title, 
                language
            )
        
        evaluation_history.append({
            "attempt": attempt,
            "evaluation": evaluation,
            "content_es": content_es,
            "content_en": content_en
        })
        
        if evaluation["passes"]:
            evaluation_passed = True
            final_content = response
            logging.info(f"✅ Section PASSED validation on attempt {attempt}")
        else:
            logging.warning(f"❌ Section FAILED validation on attempt {attempt}")
            logging.warning(f"Issues found: {evaluation['issues']}")
            logging.warning(f"Feedback: {evaluation['feedback']}")
            
            # Build CONCISE correction instructions (avoid context overflow)
            # ⚠️ CRITICAL: Keep feedback SHORT to prevent 153KB prompts that cause empty responses
            top_issues = evaluation['issues'][:3] if len(evaluation['issues']) > 3 else evaluation['issues']
            short_feedback = evaluation['feedback'][:300] if len(evaluation['feedback']) > 300 else evaluation['feedback']
            
            correction_details = f"""
**ATTEMPT {attempt} ISSUES - FIX THESE:**
{chr(10).join(['- ' + issue for issue in top_issues])}

**KEY:** {short_feedback}

**GENERATE FULL HTML CONTENT with tables, numbers, data sources. NO conclusions at end.**
"""
            prompt_es = base_prompt + correction_details
            prompt_en = base_prompt + correction_details
    
    # If still not passed after max attempts, use BEST non-empty attempt
    if not evaluation_passed:
        # Find the best attempt (longest content that isn't empty)
        best_attempt = None
        best_length = 0
        
        for hist in evaluation_history:
            # Check if this attempt had content
            if 'content_es' in hist and 'content_en' in hist:
                total_length = len(hist['content_es']) + len(hist['content_en'])
                if total_length > best_length:
                    best_length = total_length
                    best_attempt = hist
        
        # Use best attempt if found, otherwise use last
        if best_attempt and best_length > 100:
            final_content_es = best_attempt['content_es']
            final_content_en = best_attempt['content_en']
            logging.warning(f"⚠️  Using BEST attempt with {best_length} total chars (not last empty one)")
        else:
            final_content_es = content_es
            final_content_en = content_en
            logging.error(f"❌ WARNING: All attempts failed or empty - using last version")
        
        logging.error(f"Final issues: {evaluation.get('issues', [])}")
    else:
        final_content_es = content_es
        final_content_en = content_en
    
    # ⭐ DON'T INSERT EVALUATION BOX INTO CONTENT
    # The evaluation box was being added to content, making it appear in PDFs
    # Evaluation data is stored separately in section['evaluation'] field
    # The frontend can display it if needed, but it shouldn't be in the actual content
    # Commented out to keep PDFs clean:
    # if evaluation_passed and evaluation:
    #     eval_box_es = f"""..."""
    #     eval_box_en = f"""..."""
    #     final_content_es = eval_box_es + final_content_es
    #     final_content_en = eval_box_en + final_content_en
    
    # ⭐ SAVE BOTH LANGUAGE VERSIONS
    section = {
        "number": section_number,
        "title": section_title,
        "content": final_content_es,  # Keep for backward compatibility (Spanish)
        "content_es": final_content_es,
        "content_en": final_content_en,
        "status": "pending_approval",
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "evaluation": evaluation if evaluation_passed else None
    }
    
    # Prepare detailed warning if validation failed
    validation_warning = None
    if not evaluation_passed:
        validation_warning = {
            "title": "WARNING Validación No Aprobada - Revisa Cuidadosamente",
            "summary": f"Esta sección no pasó la validación automática después de {max_attempts} intentos.",
            "issues": evaluation.get('issues', []),
            "feedback": evaluation.get('feedback', ''),
            "metrics": {
                "attempts": max_attempts,
                "final_score": evaluation.get('score', 0),
                "critical_issues": len([i for i in evaluation.get('issues', []) if 'crítico' in i.lower() or 'critical' in i.lower()])
            }
        }
    
    # Update study with new section
    await db.econometric_studies_in_progress.update_one(
        {"id": study_id},
        {
            "$push": {"sections": section},
            "$set": {
                "current_section": section_number,
                "updated_at": datetime.now(timezone.utc).isoformat()
            }
        }
    )
    
    return {
        "section": section,
        "message": f"Sección generada y validada exitosamente (intentos: {attempt})",
        "validation_passed": evaluation_passed,
        "evaluation_history": evaluation_history,
        "validation_warning": validation_warning
    }

@api_router.post("/econometric-studies/{study_id}/approve-section/{section_number}")
async def approve_econometric_section(
    study_id: str,
    section_number: int,
    current_user: User = Depends(get_current_user)
):
    """Approve a section and move to the next"""
    study = await db.econometric_studies_in_progress.find_one(
        {"id": study_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not study:
        # Check if study is already completed
        completed_study = await db.econometric_studies.find_one(
            {"id": study_id, "user_id": current_user.id},
            {"_id": 0}
        )
        if completed_study:
            return {"message": "Study already completed", "status": "completed"}
        raise HTTPException(status_code=404, detail="Study not found")
    
    # Find and update the section
    sections = study.get('sections', [])
    section = next((s for s in sections if s['number'] == section_number), None)
    
    if not section:
        raise HTTPException(status_code=404, detail="Section not found")
    
    section['status'] = 'approved'
    
    # Update in database
    await db.econometric_studies_in_progress.update_one(
        {"id": study_id, "sections.number": section_number},
        {
            "$set": {
                "sections.$.status": "approved",
                "updated_at": datetime.now(timezone.utc).isoformat()
            }
        }
    )
    
    # Auto-save version
    await auto_save_version(
        document_id=study_id,
        document_type='econometric_study',
        user_id=current_user.id,
        change_description=f"Sección {section_number} aprobada",
        change_type='section_approval',
        sections_changed=[section_number]
    )
    
    # Check if all sections are approved
    next_section = section_number + 1
    if next_section > 16:
        # All sections complete - move to final collection
        full_content = ""
        for s in sorted(sections, key=lambda x: x['number']):
            full_content += f"<h2>Section {s['number']}: {s['title']}</h2>\n{s['content']}\n\n"
        
        final_study = {
            **study,
            "full_content": full_content,
            "status": "completed",
            "completed_at": datetime.now(timezone.utc).isoformat()
        }
        
        await db.econometric_studies.insert_one(final_study)
        await db.econometric_studies_in_progress.delete_one({"id": study_id})
        
        return {"message": "Study completed", "status": "completed"}
    
    return {"message": "Section approved", "next_section": next_section}

class EditEconometricSectionRequest(BaseModel):
    section_number: int
    edit_instructions: str = None
    current_section_content: str
    current_section_title: str

@api_router.post("/econometric-studies/edit-section/{study_id}")
async def edit_econometric_section_with_ai(
    study_id: str,
    request: EditEconometricSectionRequest,
    current_user: User = Depends(get_current_user)
):
    """Edit an econometric study section with AI instructions"""
    # Check both in-progress and completed studies (sin filtrar por user_id)
    study = await db.econometric_studies_in_progress.find_one(
        {"id": study_id},
        {"_id": 0}
    )
    
    collection = db.econometric_studies_in_progress
    if not study:
        study = await db.econometric_studies.find_one(
            {"id": study_id},
            {"_id": 0}
        )
        collection = db.econometric_studies
    
    if not study:
        raise HTTPException(status_code=404, detail="Study not found")
    
    # Get language
    language = study.get('language', 'en')
    language_instruction = "in Spanish" if language == 'es' else "in English"
    
    # Regenerate the section with AI
    prompt = f"""Rewrite the following section of the econometric study applying these modifications:

EDIT INSTRUCTIONS: {request.edit_instructions}

CURRENT SECTION:
{request.current_section_title}

{request.current_section_content}

REQUIREMENTS:
1. Apply the requested modifications while maintaining academic rigor
2. Keep professional econometric terminology
3. Maintain proper structure (headings, paragraphs, tables)
4. Use HTML formatting (h2, h3, h4, p, table, etc.)
5. Write {language_instruction}

Generate the improved section with the requested changes."""
    
    system_message = """You are **EconometricsGPT Pro**, a senior econometric researcher.
You edit and improve econometric studies while maintaining academic standards and rigor.
Always output in HTML format with proper tags."""
    
    # Use OpenAI GPT-5.1 for editing
    response = await call_openai_gpt5(system_message, prompt, temperature=0.7, max_tokens=4000)
    
    # Update the section in database
    sections = study.get('sections', [])
    section_index = next((i for i, s in enumerate(sections) if s['number'] == request.section_number), None)
    
    if section_index is not None:
        sections[section_index]['content'] = response
        # También actualizar content_es y content_en según el idioma del estudio
        if language == 'es':
            sections[section_index]['content_es'] = response
        else:
            sections[section_index]['content_en'] = response
        sections[section_index]['updated_at'] = datetime.now(timezone.utc).isoformat()
        
        await collection.update_one(
            {"id": study_id},
            {"$set": {"sections": sections, "updated_at": datetime.now(timezone.utc).isoformat()}}
        )
    
    edited_section = {
        "number": request.section_number,
        "title": request.current_section_title,
        "content": response,
        "status": "approved"
    }
    
    return {"section": edited_section}

# ============================================================================
# EDIT ENTIRE ECONOMETRIC DOCUMENT WITH AI
# ============================================================================

class EditEconometricDocumentRequest(BaseModel):
    edit_instructions: str
    current_content: Optional[str] = None  # Optional - will read from DB if not provided
    target_language: str = "es"

@api_router.post("/econometric-studies/{study_id}/edit-document")
async def edit_econometric_document_with_ai(
    study_id: str,
    request: EditEconometricDocumentRequest,
    background_tasks: BackgroundTasks,
    current_user: User = Depends(get_current_user)
):
    """Edit entire econometric study document with AI based on instructions - runs in background"""
    logging.info(f"🤖 AI Edit Request for entire document {study_id}")
    logging.info(f"   Instructions: {request.edit_instructions[:100]}...")
    logging.info(f"   Target language: {request.target_language}")
    
    # Check both in-progress and completed studies (sin filtrar por user_id)
    study = await db.econometric_studies.find_one(
        {"id": study_id},
        {"_id": 0}
    )
    
    collection_name = "econometric_studies"
    if not study:
        study = await db.econometric_studies_in_progress.find_one(
            {"id": study_id},
            {"_id": 0}
        )
        collection_name = "econometric_studies_in_progress"
    
    if not study:
        raise HTTPException(status_code=404, detail="Study not found")
    
    # Mark study as being edited
    collection = db[collection_name]
    await collection.update_one(
        {"id": study_id},
        {"$set": {"editing_status": "in_progress", "edit_started_at": datetime.now(timezone.utc).isoformat()}}
    )
    
    # Run the editing process in background
    async def process_edit():
        language = request.target_language
        sections = study.get('sections', [])
        updated_sections = []
        
        for section in sections:
            section_number = section.get('number')
            section_title = section.get('title', f'Sección {section_number}')
            current_content = section.get('content_es' if language == 'es' else 'content_en', '') or section.get('content', '')
            
            if not current_content:
                updated_sections.append(section)
                continue
            
            # Create AI edit prompt for this section
            edit_prompt = f"""CONTENIDO ORIGINAL A EDITAR:
---START---
{current_content[:3000]}
---END---

INSTRUCCIÓN DEL USUARIO: {request.edit_instructions}

Tu tarea es aplicar la instrucción del usuario al contenido original y devolver el contenido editado completo."""
            
            system_message = f"""Eres un editor de documentos académicos econométricos. Tu ÚNICA tarea es modificar el texto según las instrucciones del usuario.

REGLAS CRÍTICAS:
1. DEVUELVE ÚNICAMENTE el contenido editado. NADA MÁS.
2. NO añadas comentarios, explicaciones, notas ni texto adicional.
3. NO uses frases como "Aquí está el texto editado", "He modificado...", "A continuación..." 
4. NO uses frases como "No puedo", "Lo siento", "Como IA..."
5. Mantén TODO el contenido original excepto lo que deba modificarse según la instrucción.
6. Mantén el mismo formato, estructura y estilo del documento original.
7. Si la instrucción pide centrar ecuaciones, formatea las ecuaciones matemáticas de forma centrada usando HTML: <div style="text-align: center;">...</div>
8. El idioma de salida DEBE ser: {language.upper()}
9. Si no entiendes la instrucción o no puedes aplicarla, devuelve el texto original SIN CAMBIOS y SIN explicaciones.

IMPORTANTE: Tu respuesta debe contener SOLO el documento editado. Empieza directamente con el contenido."""
            
            try:
                edited_content = await call_openai_gpt4o(
                    system_message,
                    edit_prompt,
                    temperature=0.3,
                    max_tokens=4000
                )
                
                # Clean up any unwanted AI prefixes/suffixes
                unwanted_prefixes = [
                    "Aquí está el texto editado:",
                    "Aquí está el contenido editado:",
                    "Here is the edited text:",
                    "Here is the edited content:",
                    "A continuación el texto editado:",
                    "El texto editado es:",
                    "Contenido editado:",
                    "Edited content:",
                    "---START---",
                    "---END---",
                ]
                for prefix in unwanted_prefixes:
                    if edited_content.strip().lower().startswith(prefix.lower()):
                        edited_content = edited_content.strip()[len(prefix):].strip()
                
                # If AI returned an error message, keep original content
                error_indicators = ["no puedo", "lo siento", "como ia", "i cannot", "i'm sorry", "as an ai"]
                first_100_chars = edited_content[:100].lower()
                if any(indicator in first_100_chars for indicator in error_indicators):
                    logging.warning(f"   ⚠️ AI returned error message for section {section_number}, keeping original")
                    edited_content = current_content
                
                section['content'] = edited_content
                if language == 'es':
                    section['content_es'] = edited_content
                else:
                    section['content_en'] = edited_content
                section['updated_at'] = datetime.now(timezone.utc).isoformat()
                
                logging.info(f"   ✅ Section {section_number} edited successfully")
                
            except Exception as e:
                logging.error(f"   ❌ Error editing section {section_number}: {str(e)}")
            
            updated_sections.append(section)
        
        # Update all sections in database
        await collection.update_one(
            {"id": study_id},
            {
                "$set": {
                    "sections": updated_sections,
                    "updated_at": datetime.now(timezone.utc).isoformat(),
                    "editing_status": "complete",
                    "edit_completed_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )
        
        logging.info(f"✅ Document {study_id} updated with AI edits")
    
    # Start background task
    background_tasks.add_task(process_edit)
    
    return {
        "success": True,
        "message": "Edición iniciada. El documento se actualizará en segundo plano. Por favor recarga la página en unos segundos.",
        "status": "processing"
    }

@api_router.post("/econometric-studies/{study_id}/edit-section-direct")
async def edit_econometric_section_direct(
    study_id: str,
    section_data: dict,
    current_user: User = Depends(get_current_user)
):
    """Edit a section directly without AI (for manual edits)"""
    # Check both in-progress and completed studies
    study = await db.econometric_studies.find_one(
        {"id": study_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not study:
        study = await db.econometric_studies_in_progress.find_one(
            {"id": study_id, "user_id": current_user.id},
            {"_id": 0}
        )
        collection = db.econometric_studies_in_progress
    else:
        collection = db.econometric_studies
    
    if not study:
        raise HTTPException(status_code=404, detail="Study not found")
    
    section_number = section_data.get('number')
    new_content = section_data.get('content')
    
    if not section_number or not new_content:
        raise HTTPException(status_code=400, detail="Section number and content required")
    
    # Update the specific section
    await collection.update_one(
        {"id": study_id, "sections.number": section_number},
        {
            "$set": {
                "sections.$.content": new_content,
                "updated_at": datetime.now(timezone.utc).isoformat()
            }
        }
    )
    
    # If it's a completed study, also update full_content
    if collection == db.econometric_studies:
        study = await db.econometric_studies.find_one({"id": study_id}, {"_id": 0})
        full_content = ""
        for s in sorted(study['sections'], key=lambda x: x['number']):
            full_content += f"<h2>Section {s['number']}: {s['title']}</h2>\n{s['content']}\n\n"
        
        await db.econometric_studies.update_one(
            {"id": study_id},
            {"$set": {"full_content": full_content}}
        )
    
    return {"message": "Section updated successfully"}

@api_router.get("/econometric-studies")
async def list_econometric_studies(
    client_id: Optional[str] = None,
    current_user: User = Depends(get_current_user)
):
    """List all econometric studies (completed only, excluding deleted)"""
    if client_id:
        # When filtering by client, show ALL documents for that client regardless of creator
        query = {"client_id": client_id, "status": {"$ne": "deleted"}}
    else:
        # Without client_id, only show user's own documents
        query = {"user_id": current_user.id, "status": {"$ne": "deleted"}}
    
    studies = await db.econometric_studies.find(
        query,
        {"_id": 0}
    ).to_list(length=100)
    
    return {"studies": studies}

