@api_router.get("/econometric-studies/{study_id}")
async def get_econometric_study(
    study_id: str,
    current_user: User = Depends(get_current_user)
):
    """Get a specific econometric study (completed or in progress)"""
    # 🔧 FIX: Permitir que cualquier usuario vea cualquier documento por ID
    # Try completed studies first
    study = await db.econometric_studies.find_one(
        {"id": study_id},
        {"_id": 0}
    )
    
    # If not found, try in-progress studies
    if not study:
        study = await db.econometric_studies_in_progress.find_one(
            {"id": study_id},
            {"_id": 0}
        )
    
    if not study:
        raise HTTPException(status_code=404, detail="Study not found")
    
    # Add 'content' field to each section based on study language for frontend compatibility
    study_language = study.get('language', 'es')
    sections = study.get('sections', [])
    
    for section in sections:
        # Choose content based on study language
        if study_language == 'en':
            section['content'] = section.get('content_en', section.get('content', ''))
        else:
            section['content'] = section.get('content_es', section.get('content', ''))
        
        # If content is still empty, try the other language as fallback
        if not section['content']:
            if study_language == 'en':
                section['content'] = section.get('content_es', '')
            else:
                section['content'] = section.get('content_en', '')
    
    return study

@api_router.get("/econometric-studies/{study_id}/download")
async def download_econometric_study(
    study_id: str,
    language: str = "es",
    current_user: User = Depends(get_current_user)
):
    """Download econometric study as PDF in specified language (es or en)"""
    logging.info(f"[DOWNLOAD] Econometric study {study_id} requested in language: {language}")
    
    # 🔧 FIX: Permitir descargar cualquier documento por ID
    # Check in completed studies first
    study = await db.econometric_studies.find_one(
        {"id": study_id},
        {"_id": 0}
    )
    
    # If not found, check in-progress studies
    if not study:
        study = await db.econometric_studies_in_progress.find_one(
            {"id": study_id},
            {"_id": 0}
        )
    
    if not study:
        logging.error(f"[DOWNLOAD] Study {study_id} not found")
        raise HTTPException(status_code=404, detail="Study not found")
    
    logging.info(f"[DOWNLOAD] Study found: {study.get('study_title', 'N/A')}, sections: {len(study.get('sections', []))}")
    
    # Build content from sections in the specified language
    sections = study.get('sections', [])
    compiled_content = ""
    
    # Get section titles in the correct language
    section_titles = get_econometric_sections(language)
    
    for section in sorted(sections, key=lambda x: x['number']):
        section_number = section['number']
        
        # Get title in the correct language (section numbers are 1-indexed)
        section_title = section_titles[section_number - 1] if section_number <= len(section_titles) else section.get('title', '')
        
        # Use content_es or content_en based on language parameter
        if language == "en" and 'content_en' in section:
            section_content = section['content_en']
        elif language == "es" and 'content_es' in section:
            section_content = section['content_es']
        else:
            # Fallback to 'content' field for backward compatibility
            section_content = section.get('content', '')
        
        # Additional fallback: if Spanish content is empty, use English or general content
        if not section_content or section_content.strip() == '':
            logging.warning(f"Section {section_number}: Empty content for language={language}, trying fallback")
            if 'content_en' in section and section['content_en']:
                section_content = section['content_en']
                logging.info(f"Section {section_number}: Using English content as fallback")
            elif 'content' in section and section['content']:
                section_content = section['content']
                logging.info(f"Section {section_number}: Using generic content as fallback")
            else:
                logging.error(f"Section {section_number}: No content available in any language!")
                # Use a section-specific, actionable placeholder instead of the
                # generic "Content not available for this section." string.
                # The auto-recovery step in generate_complete_econometric_study_v2
                # should have filled every section — if we still hit this branch
                # something went badly wrong upstream and the user needs to know.
                _sec_title = section.get('title', '') or f'Section {section_number}'
                if language == 'es':
                    section_content = (
                        f'<p><strong>⚠️ Esta sección no pudo generarse automáticamente.</strong></p>'
                        f'<p>Por favor regenere el estudio econométrico desde el dashboard — '
                        f'el sistema de auto-recuperación intentará completar la sección "{_sec_title}" '
                        f'en el siguiente intento. Si el problema persiste, contacte a soporte.</p>'
                    )
                else:
                    section_content = (
                        f'<p><strong>⚠️ This section could not be generated automatically.</strong></p>'
                        f'<p>Please regenerate the econometric study from the dashboard — '
                        f'the auto-recovery system will attempt to complete the "{_sec_title}" '
                        f'section on the next attempt. If the issue persists, contact support.</p>'
                    )
        
        # Clean up unwanted evaluation text and formatting
        import re
        
        # Apply centralized Unicode cleaning to section content
        section_content = clean_content(section_content)
        
        # Log for debugging
        has_eval_before = 'Quality Evaluation' in section_content
        
        # Remove entire quality evaluation box (HTML div with all its content)
        section_content = re.sub(
            r'<div[^>]*background:\s*#e8f5e9[^>]*>.*?</div>\s*',
            '',
            section_content,
            flags=re.DOTALL | re.IGNORECASE
        )
        
        has_eval_after = 'Quality Evaluation' in section_content
        if has_eval_before:
            logging.info(f"Section {section_number}: Eval text found. Removed: {not has_eval_after}")
        
        # Remove quality evaluation headers if still present
        section_content = re.sub(r'Quality Evaluation.*?Section Approved', '', section_content, flags=re.DOTALL | re.IGNORECASE)
        section_content = re.sub(r'Evaluación de Calidad.*?Sección Aprobada', '', section_content, flags=re.DOTALL | re.IGNORECASE)
        
        # Remove any h3 tags with evaluation text
        section_content = re.sub(r'<h3[^>]*>.*?(Quality Evaluation|Evaluación de Calidad).*?</h3>', '', section_content, flags=re.IGNORECASE)
        
        # Remove duplicated section title lines at the beginning (Spanish titles after English ones)
        # Pattern: English title followed by Spanish translation on next line
        section_content = re.sub(r'(Cover Page & Executive Summary|Introduction & Research Questions|Conceptual Framework & Mechanisms|National Context & Relevance|Data & Sources|Empirical Design & Identification|Specifications & Estimation Methods|Robustness & Validation|Main Results|Simulations & Projections|Cost–Benefit Analysis|Policy Implications|Limitations|Conclusions|Phases & Deliverables|Technical Appendices)\s*\n\s*(Portada y Resumen Ejecutivo|Introducción y Preguntas de Investigación|Fundamento Conceptual y Mecanismos|Contexto Nacional y Relevancia|Datos y Fuentes|Diseño Empírico e Identificación|Especificaciones y Métodos de Estimación|Robustez y Validación|Resultados Principales|Simulaciones y Proyecciones|Análisis Costo-Beneficio|Implicaciones de Política|Limitaciones|Conclusiones|Fases y Entregables|Apéndices Técnicos)', r'\1', section_content, flags=re.IGNORECASE)
        
        # Remove standalone Spanish section titles
        section_content = re.sub(r'^(Portada y Resumen Ejecutivo|Introducción y Preguntas de Investigación|Fundamento Conceptual y Mecanismos|Contexto Nacional y Relevancia|Datos y Fuentes|Diseño Empírico e Identificación|Especificaciones y Métodos de Estimación|Robustez y Validación|Resultados Principales|Simulaciones y Proyecciones|Análisis Costo-Beneficio|Implicaciones de Política|Limitaciones|Conclusiones|Fases y Entregables|Apéndices Técnicos)\s*\n', '', section_content, flags=re.MULTILINE | re.IGNORECASE)
        
        # Remove "Prepared by: ... Analyst" lines (including variations with brackets)
        section_content = re.sub(r'Prepared\s+by:\s*[\[\(]?[^\n\]]*(?:Analyst|Analysis Unit)[^\n\]]*[\]\)]?\s*\n?', '', section_content, flags=re.IGNORECASE)
        section_content = re.sub(r'Preparado\s+por:\s*[\[\(]?[^\n\]]*(?:Analista|Unidad de Análisis)[^\n\]]*[\]\)]?\s*\n?', '', section_content, flags=re.IGNORECASE)
        
        # ⭐ NEW: Remove "Prepared For:" headers with their content
        section_content = re.sub(r'Prepared\s+For:.*?(?=<h[1-6]|$)', '', section_content, flags=re.DOTALL | re.IGNORECASE)
        section_content = re.sub(r'Preparado\s+para:.*?(?=<h[1-6]|$)', '', section_content, flags=re.DOTALL | re.IGNORECASE)
        # Also remove in plain text (without HTML)
        section_content = re.sub(r'Prepared\s+For:[^\n]{0,200}\n(?:[^\n]{0,200}\n){0,3}', '', section_content, flags=re.IGNORECASE)
        section_content = re.sub(r'Preparado\s+para:[^\n]{0,200}\n(?:[^\n]{0,200}\n){0,3}', '', section_content, flags=re.IGNORECASE)
        
        # Remove specific placeholder variations commonly found
        section_content = re.sub(r'\[?Econometric Analysis Unit[^\]]*\]?\s*\n?', '', section_content, flags=re.IGNORECASE)
        section_content = re.sub(r'\[?Mental Health & Public Policy\]?\s*\n?', '', section_content, flags=re.IGNORECASE)
        section_content = re.sub(r'\[?Unidad de Análisis Econométrico[^\]]*\]?\s*\n?', '', section_content, flags=re.IGNORECASE)
        
        # Remove VALIDATION SELF-CHECK sections (internal quality control text that shouldn't be in final doc)
        # This is EXTREMELY AGGRESSIVE to catch all variations including HTML-formatted text
        
        # First pass: Remove the header and EVERYTHING after it (most aggressive)
        section_content = re.sub(
            r'(?:<[^>]*>)?(?:■\s*|▪\s*)?VALIDATION\s+SELF[-\s]?CHECK\s*:?(?:</[^>]*>)?.*',
            '',
            section_content,
            flags=re.DOTALL | re.IGNORECASE
        )
        
        # Second pass: Remove paragraphs or sections containing validation keywords
        # Uses negative lookahead to ensure we match ONE <p>…</p>, not jump across many.
        section_content = re.sub(
            r'<p[^>]*>(?:(?!</p>).)*?(?:VALIDATION|SELF-CHECK)(?:(?!</p>).)*?</p>',
            '',
            section_content,
            flags=re.DOTALL | re.IGNORECASE
        )
        
        # Third pass: Remove any line that starts with bullet + [x] (plain text or HTML)
        section_content = re.sub(
            r'(?:<[^>]*>)?[\s•■▪▫◾◽●○-]*\[x\].*?(?:</[^>]*>)?$',
            '',
            section_content,
            flags=re.MULTILINE | re.IGNORECASE
        )
        
        # Fourth pass: Remove list items with [x]
        section_content = re.sub(
            r'<li[^>]*>.*?\[x\].*?</li>',
            '',
            section_content,
            flags=re.DOTALL | re.IGNORECASE
        )
        
        # Fifth pass: Remove any standalone [x] checklist items
        section_content = re.sub(
            r'[\s•■▪-]*\[x\][^\n<]*(?:<br\s*/?>\s*|\n)?',
            '',
            section_content,
            flags=re.IGNORECASE
        )
        
        # Sixth pass: Remove unordered lists containing [x] items
        section_content = re.sub(
            r'<ul[^>]*>(?:(?!</ul>).)*\[x\](?:(?!</ul>).)*</ul>',
            '',
            section_content,
            flags=re.DOTALL | re.IGNORECASE
        )
        
        # Seventh pass: Nuclear option - remove common validation phrases anywhere
        validation_phrases = [
            r'All\s+projections\s+<[^>]*>\$500M',
            r'All\s+projections\s+have\s+ranges',
            r'All\s+citations\s+complete',
            r'All\s+equation\s+variables\s+defined',
            r'Job\s+numbers\s+consistent',
            r'Economic\s+benefits\s+consistent',
            r'Federal\s+programs\s+consistent',
            r'Primary\s+data\s+sources\s+consistent',
            r'100%\s+English\s+language'
        ]
        for phrase in validation_phrases:
            section_content = re.sub(phrase, '', section_content, flags=re.IGNORECASE)
        
        # Final cleanup: Remove empty paragraphs or list items left behind
        section_content = re.sub(r'<p[^>]*>\s*</p>', '', section_content)
        section_content = re.sub(r'<li[^>]*>\s*</li>', '', section_content)
        section_content = re.sub(r'<ul[^>]*>\s*</ul>', '', section_content)
        
        # NUCLEAR OPTION: Remove ALL occurrences of black squares and orphaned symbols
        # These are artifacts from the validation checklist that MUST be removed
        
        # Remove paragraphs containing ONLY bullets/asterisks
        section_content = re.sub(r'<p[^>]*>\s*[■▪▫◾◽●○•\*\s]+\s*</p>', '', section_content, flags=re.IGNORECASE)
        
        # Remove the black square symbol ANYWHERE in the content (not just at end)
        section_content = section_content.replace('■', '')
        section_content = section_content.replace('▪', '')
        section_content = section_content.replace('▫', '')
        section_content = section_content.replace('◾', '')
        section_content = section_content.replace('◽', '')
        
        # Remove orphaned symbols at the end with aggressive loop
        while True:
            original = section_content
            # Remove trailing bullets, asterisks, whitespace, newlines
            section_content = re.sub(r'[■▪▫◾◽●○•\*\s\n]+$', '', section_content)
            if section_content == original:
                break  # No more changes, exit loop
        
        # Remove trailing <br> tags that might be left
        section_content = re.sub(r'(<br\s*/?>\s*)+$', '', section_content, flags=re.IGNORECASE)
        
        # Strip internal self-check / auto-validation blocks inserted by the LLM
        # These are QA artifacts and must NEVER appear in the final document
        # ⚠️  IMPORTANT: the lookahead `(?:(?!</p>).)` prevents `.*?` from spanning
        # across multiple paragraphs (the original `<p>.*?VALIDACIÓN.*?</p>` with
        # DOTALL was greedy enough to match from the first <p> in the section all
        # the way to the VALIDACIÓN paragraph — silently deleting all references).
        section_content = re.sub(
            r'<p[^>]*>(?:(?!</p>).)*?(?:VALIDACI[ÓO]N\s+AUTO[- ]?CHEQUEO|SELF[- ]?CHECK\s+VALIDATION|AUTO[- ]?CHECK)(?:(?!</p>).)*?</p>',
            '', section_content, flags=re.IGNORECASE | re.DOTALL
        )
        # Also strip the entire checklist block (everything from the ✅ marker to end of content)
        section_content = re.sub(
            r'(?:<p[^>]*>)?\s*✅\s*<strong>\s*(?:VALIDACI[ÓO]N|SELF[- ]?CHECK|AUTO[- ]?CHECK).*',
            '', section_content, flags=re.IGNORECASE | re.DOTALL
        )
        # Markdown format version: ## ✅ VALIDACIÓN AUTO-CHEQUEO: ...
        section_content = re.sub(
            r'\n\s*(?:#{1,4}\s*)?✅\s*(?:VALIDACI[ÓO]N|SELF[- ]?CHECK|AUTO[- ]?CHECK).*',
            '', section_content, flags=re.IGNORECASE | re.DOTALL
        )
        # Also strip [x] checklist lines
        section_content = re.sub(r'<p[^>]*>\s*-?\s*\[x\].*?</p>', '', section_content, flags=re.IGNORECASE | re.DOTALL)

        # 🔥 NUCLEAR: strip the ENTIRE auto-self-check block when it starts with the ✅ marker
        # (HTML form emitted after markdown.markdown() conversion):
        #   <p>✅ <strong>VALIDACIÓN AUTO-CHEQUEO:</strong></p>
        #   <p>- [x] ...</p>
        #   <p>- [x] ...</p>
        # Captures from the ✅ marker to the end of the section content.
        section_content = re.sub(
            r'(?:<p[^>]*>\s*)?✅\s*(?:<strong>\s*)?(?:VALIDACI[ÓO]N|SELF[- ]?CHECK|AUTO[- ]?CHECK|VALIDATION)[\s\S]*$',
            '', section_content, flags=re.IGNORECASE
        )
        # Also kill any trailing <p>- [x] ...</p> lines that survived without the ✅ header
        section_content = re.sub(
            r'(?:\s*<p[^>]*>\s*-?\s*\[x\][\s\S]*?</p>\s*)+$',
            '', section_content, flags=re.IGNORECASE
        )

        # Final trim
        section_content = section_content.rstrip()
        
        # Remove common Spanish headings found in the content
        spanish_headings = [
            r'Plan de Pre-análisis',
            r'Tablas de Regresión',
            r'Protocolos de Datos',
            r'Notas de Ética y Cumplimiento',
            r'Proyecciones Económicas',
            r'Main Results \(Resultados Principales\)',
            r'Resultados Principales'
        ]
        for heading in spanish_headings:
            section_content = re.sub(heading, '', section_content, flags=re.IGNORECASE)
        
        # Remove any section number headers that might be duplicated
        section_content = re.sub(r'<h2[^>]*>(Section|Sección)\s+\d+:.*?</h2>', '', section_content, flags=re.IGNORECASE)
        section_content = re.sub(r'^(Section|Sección)\s+\d+:\s*[^\n]+\n', '', section_content, flags=re.MULTILINE)
        
        # 🔥 STRIP CODE-FENCE WRAPPERS that the LLM emits around entire sections.
        # Claude Opus frequently wraps whole sections in ```markdown … ``` or
        # ```plaintext … ``` blocks. If left in place, markdown.markdown() treats
        # everything inside as a <pre><code> block — so the literal backticks
        # appear in the PDF and all inline formatting (bold, headings, tables) is
        # rendered as monospaced plain text. We strip ONLY the fence markers and
        # preserve inner content so markdown processes it normally.
        # Opening fence with optional language tag (markdown, plaintext, text, html, json, ``)
        section_content = re.sub(
            r'^[ \t]*```[a-zA-Z]*[ \t]*\n',
            '',
            section_content,
            flags=re.MULTILINE
        )
        # Closing fence (```) on its own line
        section_content = re.sub(
            r'^[ \t]*```[ \t]*$',
            '',
            section_content,
            flags=re.MULTILINE
        )
        # Also strip any lingering ``` sequences that didn't sit on their own line
        section_content = re.sub(r'```[a-zA-Z]*', '', section_content)
        section_content = section_content.replace('```', '')
        
        # 🔥 STRIP LATEX MATH DELIMITERS — Claude emits \[ … \] and \( … \)
        # which don't render in ReportLab; keep the math expression as plain text.
        section_content = re.sub(r'\\\[\s*', '', section_content)
        section_content = re.sub(r'\s*\\\]', '', section_content)
        section_content = re.sub(r'\\\(\s*', '', section_content)
        section_content = re.sub(r'\s*\\\)', '', section_content)
        # Convert common LaTeX commands to readable plain text/Unicode
        _latex_replacements = [
            (r'\\frac\{([^{}]+)\}\{([^{}]+)\}', r'(\1)/(\2)'),      # \frac{a}{b} → (a)/(b)
            (r'\\sqrt\{([^{}]+)\}', r'√(\1)'),                       # \sqrt{x} → √(x)
            (r'\\sum_\{([^{}]+)\}\^\{([^{}]+)\}', r'Σ(\1 to \2)'),  # \sum_{i=1}^{n}
            (r'\\sum_\{([^{}]+)\}', r'Σ(\1)'),
            (r'\\sum\b', 'Σ'),
            (r'\\int\b', '∫'),
            (r'\\infty\b', '∞'),
            (r'\\cdot\b', '·'),
            (r'\\times\b', '×'),
            (r'\\alpha\b', 'α'),
            (r'\\beta\b', 'β'),
            (r'\\gamma\b', 'γ'),
            (r'\\delta\b', 'δ'),
            (r'\\theta\b', 'θ'),
            (r'\\lambda\b', 'λ'),
            (r'\\mu\b', 'μ'),
            (r'\\sigma\b', 'σ'),
            (r'\\epsilon\b', 'ε'),
            (r'\\pi\b', 'π'),
            (r'\\rho\b', 'ρ'),
            (r'\\leq\b', '≤'),
            (r'\\geq\b', '≥'),
            (r'\\neq\b', '≠'),
            (r'\\approx\b', '≈'),
            (r'\\pm\b', '±'),
            (r'\\ldots\b', '...'),
            (r'\\dots\b', '...'),
            (r'\\,', ' '),   # thin space
            (r'\\;', ' '),
            (r'\\:', ' '),
            (r'\\\\', '<br/>'),  # LaTeX line break → HTML line break
        ]
        for _pat, _rep in _latex_replacements:
            section_content = re.sub(_pat, _rep, section_content)
        # Subscripts/superscripts in LaTeX: _{text} and ^{text}
        section_content = re.sub(r'_\{([^{}]+?)\}', r'<sub>\1</sub>', section_content)
        section_content = re.sub(r'\^\{([^{}]+?)\}', r'<sup>\1</sup>', section_content)
        # Simple sub/sup: _x and ^x (single token)
        section_content = re.sub(r'(?<=[A-Za-z0-9\)])_([A-Za-z0-9])(?=[^A-Za-z0-9]|$)',
                                  r'<sub>\1</sub>', section_content)
        section_content = re.sub(r'(?<=[A-Za-z0-9\)])\^([A-Za-z0-9])(?=[^A-Za-z0-9]|$)',
                                  r'<sup>\1</sup>', section_content)

        # 🔥 STRIP UNICODE BOX-DRAWING / BLOCK / ARROW CHARACTERS — LLMs sometimes draw
        # ASCII-art separator bars (── ━━ ══ ██ ▀▀ ▄▄) or flowchart arrows (↓ ↑ → ← ⇒).
        # These render as black squares/bars in Helvetica/Times because the fonts
        # lack those glyphs, and they leave behind broken bracketed fragments.
        # Replace U+2190–U+21FF (arrows) + U+2500–U+259F (box-drawing/block).
        section_content = re.sub(r'[\u2190-\u21FF\u2500-\u259F]+', '', section_content)
        # Also remove paragraphs that became empty after arrow/box removal
        section_content = re.sub(r'<p[^>]*>\s*</p>', '', section_content)
        
        # 🔥 STRIP ASCII-FLOWCHART BROKEN FRAGMENTS.
        # When Claude Opus draws a conceptual flowchart with bracket labels
        # ([Input: X] → [Process] → [Output]) and arrows, the PDF renderer cannot
        # reproduce the 2-D layout. What remains after stripping arrows is a series
        # of short paragraphs with orphaned square brackets that look like empty
        # placeholders. Detect and delete clusters of 3+ consecutive short (<120c)
        # paragraphs that together contain ≥3 square brackets — that signature is
        # unique to broken flowcharts and never matches legitimate prose.
        def _strip_ascii_flowchart_blocks(content):
            para_re = re.compile(r'<p[^>]*>([^<]*)</p>', re.DOTALL)
            parts = []
            pos = 0
            for m in para_re.finditer(content):
                if m.start() > pos:
                    parts.append(('other', content[pos:m.start()], content[pos:m.start()]))
                parts.append(('p', m.group(1), m.group(0)))
                pos = m.end()
            if pos < len(content):
                parts.append(('other', content[pos:], content[pos:]))
            
            def _is_fragment(text):
                t = text.strip()
                if len(t) == 0:
                    return True
                if len(t) >= 120:
                    return False
                if '[' in t or ']' in t:
                    return True
                # Very short label-like paragraphs without a terminal punctuation
                if len(t) <= 25 and not t.endswith(('.', ',', ':', ';', '?', '!')):
                    return True
                return False
            
            out = []
            i = 0
            while i < len(parts):
                part = parts[i]
                if part[0] != 'p':
                    out.append(part[1])
                    i += 1
                    continue
                j = i
                frag_indices = []
                bracket_count = 0
                while j < len(parts):
                    p = parts[j]
                    if p[0] == 'other':
                        if p[1].strip() == '':
                            j += 1
                            continue
                        break
                    if p[0] == 'p':
                        if _is_fragment(p[1]):
                            frag_indices.append(j)
                            bracket_count += p[1].count('[') + p[1].count(']')
                            j += 1
                            continue
                        break
                if len(frag_indices) >= 3 and bracket_count >= 3:
                    i = j  # skip the whole cluster
                else:
                    out.append(part[2])
                    i += 1
            return ''.join(out)
        
        section_content = _strip_ascii_flowchart_blocks(section_content)
        
        # Remove legacy narrow pattern: bare ```html leftovers (kept for safety)
        section_content = re.sub(r'```html\s*', '', section_content)
        
        # ⭐ Remove markdown horizontal rules (--- *** === ___) that appear as literal text in PDF
        # Pattern 1: standalone line --- (raw markdown, not in HTML tags)
        section_content = re.sub(r'^\s*[-\*=_]{3,}\s*$', '', section_content, flags=re.MULTILINE)
        # Pattern 2: <p>---</p> — LLM wraps horizontal rules in <p> tags
        section_content = re.sub(r'<p[^>]*>\s*[-\*=_]{3,}\s*</p>', '', section_content, flags=re.IGNORECASE)
        # Pattern 3: --- inside any other tag or at end of paragraph
        section_content = re.sub(r'\s*[-\*=_]{3,}\s*(?=<(?:h[1-6]|p|ul|li|div|br))', '', section_content, flags=re.IGNORECASE)
        # Pattern 4: Remove <hr> tags (produced by markdown converter from ---)
        section_content = re.sub(r'<hr\s*/?>', '', section_content, flags=re.IGNORECASE)
        # NOTE: We intentionally DO NOT pre-convert ### headings here. Doing so used to
        # trick the "is this HTML?" check below into skipping markdown.markdown(), which
        # left bullet lists under each subsection (6.1, 6.2, 15.1, 15.2, …) un-rendered
        # as plain text — so the PDF showed only the subsection titles with no content.
        # The has_md detection + markdown.markdown() call below handles this correctly.
        
        # WARNING: If content_en is mostly Spanish, this is a generation issue
        # For now, if language is 'en' and we detect significant Spanish content, log it
        if language == "en":
            spanish_indicators = ['basándose', 'análisis', 'según', 'través', 'además', 'económicas', 'métodos']
            spanish_count = sum(1 for indicator in spanish_indicators if indicator.lower() in section_content.lower())
            if spanish_count >= 3:
                logging.warning(f"Section {section_number}: content_en contains significant Spanish text (indicators: {spanish_count})")
        
        # Convert markdown to HTML if needed — detect markdown constructs even when
        # the content is partially HTML (LLMs routinely mix <p> paragraphs with
        # `### Subsection` headings and `- bullet` lists in the same section).
        import markdown
        from pdf_utils import preprocess_markdown_latex, preprocess_html_latex

        has_md_heading = bool(re.search(r'(?m)^\s*#{1,6}\s+\S', section_content))
        has_md_bullet  = bool(re.search(r'(?m)^\s*[-\*]\s+\S', section_content))
        has_md_numlist = bool(re.search(r'(?m)^\s*\d+\.\s+\S', section_content))
        has_md_bold_it = bool(re.search(r'\*\*[^*]+\*\*|(?<!\*)\*[^*\s][^*]*\*(?!\*)', section_content))
        # Detect pipe-style tables (| col1 | col2 |) so we run markdown conversion
        # even when the section is mostly prose+table.
        has_md_table = bool(re.search(r'(?m)^\s*\|.+\|.+\|\s*$', section_content))
        # Detect PRE-BROKEN tables (legacy content where rows were pre-wrapped in <p>)
        has_broken_table = bool(re.search(r'<p[^>]*>\s*\|[^<\n]+\|\s*</p>', section_content))
        # Detect pre-converted HTML headings that we want to demote (e.g., <h2><strong>5.1 ...</strong></h2>)
        has_html_heading = bool(re.search(r'<h2[^>]*>\s*<strong>', section_content))
        is_mixed_or_markdown = (has_md_heading or has_md_bullet or has_md_numlist or 
                                has_md_bold_it or has_md_table or has_broken_table or has_html_heading)

        # ─── 🛡️ SAFETY NET: orphan pipe-row AFTER a real <table> ─────
        # Defined at the section level so BOTH the markdown path and the
        # pure-HTML path can run it.  Claude Opus (and Gemini 3) sometimes
        # emit a proper HTML <table>…</table> with the first N rows, then
        # a SINGLE bare-pipe row `|Small (<50 emp.) | 7.1 | 4.2 | 40.8% |`
        # survives as a <p> sibling.  `_salvage_failed_tables` requires
        # 2+ rows in a cluster so it skips single orphans.  This pass
        # walks every <p>|…|</p> sibling of a </table> and injects it as
        # a new <tr> INSIDE that table — keeping the user-visible result
        # as ONE cohesive table.
        def _merge_orphan_pipe_rows_into_tables(html: str) -> str:
            orphan_re = re.compile(
                r'(</table>)(\s*)'
                r'<p[^>]*>\s*(\|[^<\n]+\|)\s*</p>',
                flags=re.IGNORECASE,
            )

            def _inject(match):
                end_tag = match.group(1)
                gap = match.group(2)
                pipe_row = match.group(3).strip()
                # Skip markdown separator rows (---|---|---).
                if re.match(r'^\|[\s\-:|]+\|$', pipe_row):
                    return end_tag + gap
                cells = re.split(r'(?<!\\)\|', pipe_row)
                if cells and cells[0].strip() == '':
                    cells = cells[1:]
                if cells and cells[-1].strip() == '':
                    cells = cells[:-1]
                cells = [c.strip().replace(r'\|', '|') for c in cells]
                if not cells:
                    return end_tag + gap
                tr_html = '<tr>' + ''.join(
                    f'<td>{c}</td>' for c in cells
                ) + '</tr>'
                return f'__ORPHAN_TR__{tr_html}__ORPHAN_TR__{end_tag}{gap}'

            # Iterate until fixed-point (an orphan <p> may follow
            # another orphan <p> so we keep consuming one at a time).
            prev, max_iter = None, 10
            while prev != html and max_iter > 0:
                prev = html
                html = orphan_re.sub(_inject, html, count=1)
                max_iter -= 1

            # Collapse the markers into the preceding </table>.
            html = re.sub(
                r'__ORPHAN_TR__(<tr>.*?</tr>)__ORPHAN_TR__</table>',
                lambda m: m.group(1) + '</table>',
                html,
                flags=re.DOTALL | re.IGNORECASE,
            )
            # If there's a </tbody> right before </table>, move the
            # injected <tr> INSIDE </tbody>.
            html = re.sub(
                r'(</tbody>)(\s*<tr>.*?</tr>)(\s*</table>)',
                r'\2\1\3',
                html,
                flags=re.DOTALL | re.IGNORECASE,
            )

            # Merge consecutive <table>…</table><table>…</table> blocks
            # when they have matching column counts.  This catches the
            # case where the LLM emits a real HTML <table> followed by
            # 2+ orphan pipe-rows that the pre-tokenizer turns into a
            # separate <table> — semantically they are ONE table.
            def _count_first_row_cells(table_html: str) -> int:
                """Count <th>/<td> in the first <tr> of the snippet."""
                m = re.search(r'<tr[^>]*>(.*?)</tr>', table_html, flags=re.DOTALL | re.IGNORECASE)
                if not m:
                    return 0
                inner = m.group(1)
                return len(re.findall(r'<t[hd]\b', inner, flags=re.IGNORECASE))

            def _merge_consecutive(match):
                first = match.group(1)         # <table>…</table>
                gap = match.group(2)           # whitespace
                second = match.group(3)        # <table>…</table>
                first_cols = _count_first_row_cells(first)
                second_cols = _count_first_row_cells(second)
                if first_cols == 0 or first_cols != second_cols:
                    return match.group(0)  # leave as-is
                # Extract every <tr>…</tr> from the second table EXCEPT
                # treat its first row as data (not a header) — strip the
                # <thead>…</thead> wrapper if present.
                second_body = re.sub(
                    r'<thead[^>]*>(.*?)</thead>', r'\1',
                    second, flags=re.DOTALL | re.IGNORECASE,
                )
                second_rows = re.findall(
                    r'<tr[^>]*>.*?</tr>',
                    second_body, flags=re.DOTALL | re.IGNORECASE,
                )
                # Replace any <th> in those rows with <td> so they
                # render as data, not as another header band.
                second_rows = [
                    re.sub(r'<(/?)th\b', r'<\1td', r, flags=re.IGNORECASE)
                    for r in second_rows
                ]
                rows_html = ''.join(second_rows)
                # Insert before the closing </table> of the first table.
                if '</tbody>' in first.lower():
                    merged = re.sub(
                        r'(</tbody>\s*</table>)',
                        rows_html + r'\1',
                        first,
                        count=1,
                        flags=re.IGNORECASE,
                    )
                else:
                    merged = re.sub(
                        r'(\s*</table>)',
                        rows_html + r'\1',
                        first,
                        count=1,
                        flags=re.IGNORECASE,
                    )
                return merged

            consec_re = re.compile(
                r'(<table\b[^>]*>.*?</table>)(\s*)(<table\b[^>]*>.*?</table>)',
                flags=re.DOTALL | re.IGNORECASE,
            )
            prev, max_iter = None, 10
            while prev != html and max_iter > 0:
                prev = html
                html = consec_re.sub(_merge_consecutive, html, count=1)
                max_iter -= 1
            return html

        if is_mixed_or_markdown:
            logging.info(f"Section {section_number}: Converting markdown (or mixed markdown+HTML) to HTML "
                         f"[h={has_md_heading} b={has_md_bullet} n={has_md_numlist} bi={has_md_bold_it}]")
            section_content = preprocess_markdown_latex(section_content)
            # 🔧 UNWRAP PRE-BROKEN TABLES: Some previously-saved content has tables
            # already converted to HTML with each row wrapped as <p>| cell | cell |</p>.
            # We must FIRST convert inner <strong>/<em> tags to Markdown bold/italic,
            # THEN unwrap the <p>...</p> around pipe rows, so the `tables` extension
            # can re-convert them into proper HTML tables.
            
            # Convert <strong>...</strong> → **text** (needed BEFORE unwrap so the
            # row-unwrap regex doesn't choke on angle brackets inside cells)
            section_content = re.sub(
                r'<strong>\s*(.+?)\s*</strong>',
                r'**\1**',
                section_content,
                flags=re.DOTALL
            )
            # Convert <em>...</em> → *text*
            section_content = re.sub(
                r'<em>\s*(.+?)\s*</em>',
                r'*\1*',
                section_content,
                flags=re.DOTALL
            )
            # Now unwrap <p>| ... |</p> pipe rows → plain markdown table rows.
            # Allow ** and any other characters inside cells (no angle brackets left).
            section_content = re.sub(
                r'<p[^>]*>\s*(\|[^<\n]+\|)\s*</p>',
                r'\1',
                section_content
            )
            # CRITICAL: python-markdown's `tables` extension requires a BLANK LINE
            # both BEFORE and AFTER the table block. Without a terminating blank
            # line, the extension greedily swallows subsequent non-pipe lines
            # (bold summaries, headings, paragraphs) as extra single-cell rows.
            # Insert a blank line BEFORE the first pipe row AND AFTER the last
            # pipe row of each contiguous table block.
            _lines = section_content.split('\n')
            _fixed = []
            _prev_was_pipe = False
            for _i, _ln in enumerate(_lines):
                _stripped = _ln.strip()
                _is_pipe = _stripped.startswith('|') and _stripped.endswith('|')
                # Entering a table (previous was not pipe, current is pipe)
                if _is_pipe and not _prev_was_pipe and _i > 0:
                    _prev = _lines[_i - 1].strip()
                    if _prev != '':
                        _fixed.append('')  # inject blank line BEFORE table
                # Exiting a table (previous was pipe, current is NOT pipe and NOT blank)
                if _prev_was_pipe and not _is_pipe and _stripped != '':
                    _fixed.append('')  # inject blank line AFTER table
                _fixed.append(_ln)
                _prev_was_pipe = _is_pipe
            section_content = '\n'.join(_fixed)
            
            # 🔧 AUTO-INJECT SEPARATOR ROWS for tables that lack `|---|---|`.
            # python-markdown's `tables` extension SILENTLY FAILS to render
            # tables that lack a header-separator row, leaving literal `|`
            # characters visible in the PDF. Claude Opus often emits 2-column
            # key-value "tables" (e.g. `| Label | Value |`) without a separator.
            # Detect contiguous pipe-row blocks with NO separator and inject one
            # after the first row.
            _lines_sep = section_content.split('\n')
            _out_sep = []
            _k = 0
            while _k < len(_lines_sep):
                _s = _lines_sep[_k].strip()
                _is_p = _s.startswith('|') and _s.endswith('|')
                if _is_p:
                    # Collect contiguous pipe rows
                    _m = _k
                    while _m < len(_lines_sep):
                        _ss = _lines_sep[_m].strip()
                        if _ss.startswith('|') and _ss.endswith('|'):
                            _m += 1
                        else:
                            break
                    _block = _lines_sep[_k:_m]
                    _has_sep = any(
                        re.match(r'^\s*\|[\s\-:|]+\|\s*$', _l) and _l.count('-') >= 2
                        for _l in _block
                    )
                    _out_sep.append(_block[0])
                    if not _has_sep and len(_block) >= 1:
                        _first = _block[0].strip()
                        _cols = _first.count('|') - 1
                        if _cols >= 1:
                            _sep_row = '|' + '|'.join(['---'] * _cols) + '|'
                            _out_sep.append(_sep_row)
                    _out_sep.extend(_block[1:])
                    _k = _m
                else:
                    _out_sep.append(_lines_sep[_k])
                    _k += 1
            section_content = '\n'.join(_out_sep)

            # ═══ 🚀 ROBUST TABLE PRE-TOKENIZER ═══════════════════════════════
            # python-markdown's `tables` extension is fragile: it silently
            # fails on column-count mismatches, ragged rows, or pipes inside
            # cells, leaving rows as literal `|cell|cell|` text in the PDF.
            # Case studies and policy papers DON'T hit this because they
            # parse pipe rows directly into ReportLab Tables. We do the
            # equivalent here: convert every contiguous bare pipe-row
            # cluster into a real <table>…</table> BEFORE markdown sees it.
            # Markdown leaves block-level HTML alone, so the table is
            # rendered exactly as we built it — no parsing surprises, no
            # silent failures, no orphan rows.
            def _pretokenize_pipe_tables_to_html(text: str) -> str:
                lines = text.split('\n')
                out, j = [], 0
                while j < len(lines):
                    s = lines[j].strip()
                    is_pipe = s.startswith('|') and s.endswith('|') and len(s) > 2
                    if not is_pipe:
                        out.append(lines[j])
                        j += 1
                        continue

                    # Collect the contiguous cluster.
                    cluster_start = j
                    while j < len(lines):
                        ss = lines[j].strip()
                        if ss.startswith('|') and ss.endswith('|') and len(ss) > 2:
                            j += 1
                        else:
                            break
                    cluster = lines[cluster_start:j]

                    # Parse rows; drop separator rows (---|---).
                    parsed_rows = []
                    for row_line in cluster:
                        rs = row_line.strip()
                        if re.match(r'^\|[\s\-:|]+\|$', rs) and rs.count('-') >= 2:
                            continue
                        # Split on un-escaped pipes; drop leading/trailing
                        # empty cells caused by the leading/trailing `|`.
                        cells = re.split(r'(?<!\\)\|', rs)
                        if cells and cells[0].strip() == '':
                            cells = cells[1:]
                        if cells and cells[-1].strip() == '':
                            cells = cells[:-1]
                        cells = [c.strip().replace(r'\|', '|') for c in cells]
                        if cells:
                            parsed_rows.append(cells)

                    # Need at least 2 rows (header + 1 body) to form a table.
                    if len(parsed_rows) < 2:
                        out.extend(cluster)
                        continue

                    # Pad ragged rows to the max column count so ReportLab
                    # doesn't render a broken / clipped table.
                    n_cols = max(len(r) for r in parsed_rows)
                    for r in parsed_rows:
                        while len(r) < n_cols:
                            r.append('')

                    # Build the table HTML. We escape only the basic
                    # entities needed for safety; inline markdown like
                    # **bold** and *italic* is converted post-markdown.
                    def _esc(t: str) -> str:
                        return (t.replace('&', '&amp;')
                                 .replace('<', '&lt;')
                                 .replace('>', '&gt;'))
                    header = parsed_rows[0]
                    body = parsed_rows[1:]
                    html_parts = ['<table>', '<thead><tr>']
                    for h in header:
                        html_parts.append(f'<th>{_esc(h)}</th>')
                    html_parts.append('</tr></thead>')
                    if body:
                        html_parts.append('<tbody>')
                        for r in body:
                            html_parts.append('<tr>')
                            for c in r:
                                html_parts.append(f'<td>{_esc(c)}</td>')
                            html_parts.append('</tr>')
                        html_parts.append('</tbody>')
                    html_parts.append('</table>')
                    table_html = ''.join(html_parts)

                    # Surround with blank lines so markdown treats it as a
                    # block-level HTML island (and won't wrap it in <p>).
                    out.append('')
                    out.append(table_html)
                    out.append('')

                return '\n'.join(out)

            section_content = _pretokenize_pipe_tables_to_html(section_content)

            # Demote HTML sub-section headings (e.g., <h2>5.1 METHODOLOGY</h2>) to
            # Markdown ### which markdown.markdown() re-renders as proper h3.
            section_content = re.sub(
                r'<h2[^>]*>\s*\*\*\s*(\d+(?:\.\d+)+)\s+([^*<]+?)\s*\*\*\s*</h2>',
                r'### \1 \2',
                section_content
            )
            section_content = re.sub(
                r'<h2[^>]*>\s*(\d+(?:\.\d+)+)\s+([^<]+?)\s*</h2>',
                r'### \1 \2',
                section_content
            )
            # Main h2 with bold marker → ## markdown (will stay h2 after conversion)
            section_content = re.sub(
                r'<h2[^>]*>\s*\*\*\s*([^*<]+?)\s*\*\*\s*</h2>',
                r'## \1',
                section_content
            )
            section_content = re.sub(
                r'<h2[^>]*>\s*([^<]+?)\s*</h2>',
                r'## \1',
                section_content
            )
            
            # 🔧 DEMOTE SUB-SECTION HEADINGS (## 7.1, ## 8.3, ## 10.1, etc.)
            # Claude Opus emits sub-sections at the same heading level as main sections,
            # which makes them render as giant h2 titles in the middle of content.
            # Demote them to h3/h4 so they appear as normal sub-headings.
            # Pattern: "## <num>.<num>" or "## <num>.<num>.<num>" → one more # per dot.
            def _demote_subsections(match):
                hashes = match.group(1)
                number = match.group(2)  # e.g., "7.1" or "5.2.1"
                rest = match.group(3)
                depth = number.count('.')  # 1 = sub, 2 = sub-sub
                new_hashes = hashes + ('#' * depth)
                # Clamp to max 6 hashes
                if len(new_hashes) > 6:
                    new_hashes = '######'
                return f'{new_hashes} {number}{rest}'
            section_content = re.sub(
                r'^(#{1,4})\s+(\d+(?:\.\d+)+)([.:]?\s+.+)$',
                _demote_subsections,
                section_content,
                flags=re.MULTILINE
            )
            
            # 🔧 COLLAPSE BLANK LINES INSIDE MARKDOWN TABLES
            # python-markdown's table extension requires table rows to be CONSECUTIVE
            # (no blank lines between rows). Claude/Gemini often emit tables with a
            # blank line between each row, which makes markdown render them as 
            # literal text (| col1 | col2 |) instead of real HTML tables.
            lines_tbl = section_content.split('\n')
            out_lines = []
            in_table = False
            for idx, ln in enumerate(lines_tbl):
                stripped = ln.strip()
                is_table_row = stripped.startswith('|') and stripped.endswith('|')
                if is_table_row:
                    in_table = True
                    out_lines.append(ln)
                elif in_table and stripped == '':
                    # Look ahead: if next non-blank line is also a table row, skip this blank
                    j = idx + 1
                    while j < len(lines_tbl) and lines_tbl[j].strip() == '':
                        j += 1
                    if j < len(lines_tbl):
                        next_stripped = lines_tbl[j].strip()
                        if next_stripped.startswith('|') and next_stripped.endswith('|'):
                            # Skip blank line inside table
                            continue
                    # Not followed by another row → end of table
                    in_table = False
                    out_lines.append(ln)
                else:
                    in_table = False
                    out_lines.append(ln)
            section_content = '\n'.join(out_lines)
            
            section_content = markdown.markdown(
                section_content,
                extensions=['tables', 'fenced_code', 'nl2br']
            )

            # ─── 🛡️ SAFETY NET: salvage failed markdown tables ────────────────
            # python-markdown's `tables` extension can SILENTLY FAIL on edge cases
            # (mismatched column counts between header and rows, malformed
            # separator alignment markers like `:---`, exotic whitespace, etc.).
            # When that happens the pipe rows survive as literal `|` text in
            # <p> tags, ruining the PDF. We detect any surviving pipe-row
            # cluster and manually convert it to a proper <table> as a fallback.
            def _salvage_failed_tables(html: str) -> str:
                # Find clusters of consecutive <p>| ... |</p> blocks that survived.
                # Pattern: 2+ consecutive paragraphs whose stripped content starts
                # AND ends with a pipe character.
                def _flush_block(block_paragraphs):
                    """Convert a cluster of pipe-rows into a real <table>."""
                    if len(block_paragraphs) < 2:
                        return ''.join(block_paragraphs)
                    rows = []
                    for p in block_paragraphs:
                        # Strip <p ...> wrapper
                        inner = re.sub(r'^<p[^>]*>\s*', '', p)
                        inner = re.sub(r'\s*</p>\s*$', '', inner)
                        inner = inner.strip()
                        # Skip the markdown separator row (---|---|--- etc.)
                        if re.match(r'^\|[\s\-:|]+\|$', inner):
                            continue
                        # Split on unescaped pipes; drop the leading/trailing empty
                        # cells caused by the leading and trailing `|`.
                        cells = re.split(r'(?<!\\)\|', inner)
                        if cells and cells[0].strip() == '':
                            cells = cells[1:]
                        if cells and cells[-1].strip() == '':
                            cells = cells[:-1]
                        cells = [c.strip().replace(r'\|', '|') for c in cells]
                        rows.append(cells)
                    if not rows:
                        return ''
                    # First row is treated as the header.
                    header = rows[0]
                    body_rows = rows[1:] if len(rows) > 1 else []
                    out = ['<table>', '<thead><tr>']
                    for h in header:
                        out.append(f'<th>{h}</th>')
                    out.append('</tr></thead>')
                    if body_rows:
                        out.append('<tbody>')
                        for r in body_rows:
                            out.append('<tr>')
                            for c in r:
                                out.append(f'<td>{c}</td>')
                            out.append('</tr>')
                        out.append('</tbody>')
                    out.append('</table>')
                    return ''.join(out)

                # Scan paragraph-by-paragraph and identify pipe-row clusters.
                # We work line-by-line — the HTML produced by python-markdown
                # places each <p> on roughly its own line, but to be safe we
                # also handle the case of multiple <p> on one line.
                # First, normalize so each <p>...</p> is on its own line.
                normalized = re.sub(r'(</p>)\s*(<p)', r'\1\n\2', html)
                lines = normalized.split('\n')
                out_lines = []
                i = 0
                while i < len(lines):
                    line = lines[i]
                    # Detect a <p> whose inner content is a pipe-row.
                    m = re.match(
                        r'^\s*<p[^>]*>\s*(\|[^<\n]*\|)\s*</p>\s*$',
                        line,
                    )
                    if m:
                        # Collect the contiguous cluster.
                        cluster = []
                        while i < len(lines):
                            ln = lines[i]
                            mm = re.match(
                                r'^\s*<p[^>]*>\s*(\|[^<\n]*\|)\s*</p>\s*$',
                                ln,
                            )
                            if mm:
                                cluster.append(ln)
                                i += 1
                            else:
                                break
                        if len(cluster) >= 2:
                            logging.warning(
                                f"🛡️ [TABLE_SALVAGE] Section {section_number}: "
                                f"recovered {len(cluster)} surviving pipe-rows "
                                f"into a <table> (markdown.tables extension failed)"
                            )
                            out_lines.append(_flush_block(cluster))
                        else:
                            out_lines.extend(cluster)
                    else:
                        out_lines.append(line)
                        i += 1
                return '\n'.join(out_lines)

            section_content = _salvage_failed_tables(section_content)
            section_content = _merge_orphan_pipe_rows_into_tables(section_content)
        else:
            logging.info(f"Section {section_number}: Content already pure HTML")
            section_content = preprocess_html_latex(section_content)
            # Orphan pipe-rows after a real <table> can also leak here
            # when the LLM emitted a mostly-HTML document with a trailing
            # markdown row.  Apply the SAME merge pass.
            section_content = _merge_orphan_pipe_rows_into_tables(section_content)

        # 🔥 POST-MARKDOWN: Convert any lingering inline markdown bold/italic to HTML
        # (happens when Claude Opus emits <table> HTML directly with **bold** inside
        # <td> — python-markdown does NOT process inline markdown inside raw HTML
        # block elements, so the asterisks leak into the final PDF as literal text).
        # Safe to run after markdown.markdown() because the converter has already
        # consumed all legitimate markdown in non-HTML regions.
        # Bold: **text** → <strong>text</strong>  (also handles __text__)
        section_content = re.sub(r'\*\*([^\*\n]+?)\*\*', r'<strong>\1</strong>', section_content)
        section_content = re.sub(r'(?<![_\w])__([^_\n]+?)__(?!\w)', r'<strong>\1</strong>', section_content)
        # Italic: *text* → <i>text</i>  (only when not adjacent to another * — avoids eating <strong>)
        section_content = re.sub(r'(?<![\*\w])\*([^\*\n]+?)\*(?!\*)', r'<i>\1</i>', section_content)
        # 🧹 Strip any remaining ORPHAN `**` (unbalanced markers emitted by the LLM
        # when it forgets the opening or closing pair). These would otherwise
        # appear as literal asterisks in the PDF.
        section_content = section_content.replace('**', '')

        # 🔥 POST-MARKDOWN: Strip literal `####` / `###` / `##` markdown heading
        # markers that survive INSIDE raw HTML blocks (e.g. table cells, list items).
        # python-markdown does not process markdown inside block-level HTML, so any
        # `#### 11.4 NPV Analysis` left inside a <td> appears in the PDF as the
        # literal hashes. Convert them to <strong> so the header text still stands
        # out without showing the raw markdown.
        section_content = re.sub(
            r'(<t[dh][^>]*>[^<]*?)#{2,6}\s+',
            r'\1',
            section_content,
            flags=re.IGNORECASE
        )
        section_content = re.sub(
            r'(<li[^>]*>[^<]*?)#{2,6}\s+',
            r'\1',
            section_content,
            flags=re.IGNORECASE
        )
        # As a final safety net, strip any `####` that appear at the very start of
        # a line (these only reach here when they were inside a raw HTML block).
        section_content = re.sub(r'(?m)^\s*#{2,6}\s+', '', section_content)

        # 🔥 POST-MARKDOWN cleanup: remove the VALIDATION / AUTO-CHEQUEO block
        # that the LLM sometimes appends — after markdown conversion it looks like:
        #   <p>✅ <strong>VALIDACIÓN AUTO-CHEQUEO:</strong></p>
        #   <p>- [x] ...</p><p>- [x] ...</p>
        section_content = re.sub(
            r'(?:<p[^>]*>\s*)?✅\s*(?:<strong>\s*)?(?:VALIDACI[ÓO]N|SELF[- ]?CHECK|AUTO[- ]?CHECK|VALIDATION)[\s\S]*$',
            '', section_content, flags=re.IGNORECASE
        )
        section_content = re.sub(
            r'(?:\s*<p[^>]*>\s*-?\s*\[x\][\s\S]*?</p>\s*)+',
            '', section_content, flags=re.IGNORECASE
        )
        # Also kill <ul>/<ol> lists whose items are all [x] checkboxes
        section_content = re.sub(
            r'<(ul|ol)[^>]*>(?:\s*<li[^>]*>\s*\[x\][\s\S]*?</li>\s*)+</\1>',
            '', section_content, flags=re.IGNORECASE
        )
        # Remove any orphan trailing <hr> or empty <p>
        section_content = re.sub(r'(?:\s*<hr\s*/?>)+\s*$', '', section_content, flags=re.IGNORECASE)
        section_content = re.sub(r'(?:\s*<p[^>]*>\s*</p>\s*)+$', '', section_content, flags=re.IGNORECASE)
        
        compiled_content += f"<h2>{section_number}. {section_title}</h2>\n{section_content}\n\n"
    
    # CRITICAL: Apply comprehensive Unicode cleaning using the centralized clean_content function
    # This removes all black box characters and special Unicode that render incorrectly in PDFs
    compiled_content = clean_content(compiled_content)
    
    # ⭐ NUCLEAR CLEANUP: Remove ALL black square symbols from entire compiled content
    # This is a final safety net to catch any symbols that made it through earlier cleaning
    compiled_content = compiled_content.replace('■', '')
    compiled_content = compiled_content.replace('▪', '')
    compiled_content = compiled_content.replace('▫', '')
    compiled_content = compiled_content.replace('◾', '')
    compiled_content = compiled_content.replace('◽', '')
    
    # 🔣 Unicode subscripts (₀-₉, etc.) — these render as BLACK SQUARES in PDF fonts
    # (Helvetica/Times). Replace with ASCII equivalents so equations like β₁·S + β₂·X
    # render correctly. The slight loss in visual math typography is much better than
    # having ■ placeholders.
    _unicode_subs = {
        '₀':'0','₁':'1','₂':'2','₃':'3','₄':'4','₅':'5','₆':'6','₇':'7','₈':'8','₉':'9',
        '₊':'+','₋':'-','₌':'=','₍':'(','₎':')','ₐ':'a','ₑ':'e','ₒ':'o','ₓ':'x',
        'ₕ':'h','ₖ':'k','ₗ':'l','ₘ':'m','ₙ':'n','ₚ':'p','ₛ':'s','ₜ':'t',
    }
    _unicode_sups = {
        '⁰':'0','¹':'1','²':'2','³':'3','⁴':'4','⁵':'5','⁶':'6','⁷':'7','⁸':'8','⁹':'9',
        '⁺':'+','⁻':'-','⁼':'=','⁽':'(','⁾':')',
        'ᵃ':'a','ᵇ':'b','ᶜ':'c','ᵈ':'d','ᵉ':'e','ᶠ':'f','ᵍ':'g','ʰ':'h','ⁱ':'i',
        'ʲ':'j','ᵏ':'k','ˡ':'l','ᵐ':'m','ⁿ':'n','ᵒ':'o','ᵖ':'p','ʳ':'r','ˢ':'s',
        'ᵗ':'t','ᵘ':'u','ᵛ':'v','ʷ':'w','ˣ':'x','ʸ':'y','ᶻ':'z',
    }
    # Collapse runs of consecutive subscripts into a single <sub>N</sub> tag
    # (reportlab Paragraph understands <sub> and <sup> when rendering the final PDF).
    def _wrap_subs(match):
        return '<sub>' + ''.join(_unicode_subs.get(c, c) for c in match.group(0)) + '</sub>'
    def _wrap_sups(match):
        return '<sup>' + ''.join(_unicode_sups.get(c, c) for c in match.group(0)) + '</sup>'
    compiled_content = re.sub('[' + ''.join(re.escape(c) for c in _unicode_subs.keys()) + ']+',
                               _wrap_subs, compiled_content)
    compiled_content = re.sub('[' + ''.join(re.escape(c) for c in _unicode_sups.keys()) + ']+',
                               _wrap_sups, compiled_content)
    
    # Also remove any standalone black squares in their own paragraph
    import re
    compiled_content = re.sub(r'<p[^>]*>\s*[■▪▫◾◽]\s*</p>', '', compiled_content, flags=re.IGNORECASE)
    compiled_content = re.sub(r'^■\s*$', '', compiled_content, flags=re.MULTILINE)
    
    logging.info(f"[PDF_CLEANUP] Applied clean_content() + nuclear ■ cleanup to compiled content before PDF generation")
    
    # Extract author information from study
    author_name = study.get('applicant_name', 'Economic Research Team')
    # Try to infer institutional affiliation from project description if available
    project_desc = study.get('project_description', '')
    author_affiliation = None
    
    # Simple heuristic to extract institution from project description
    institution_keywords = ['University', 'Instituto', 'Institute', 'College', 'Research Center', 
                           'Brookings', 'RAND', 'Department', 'Laboratory', 'Center for']
    for keyword in institution_keywords:
        if keyword in project_desc:
            # Extract sentence containing the keyword
            sentences = project_desc.split('.')
            for sent in sentences:
                if keyword in sent:
                    # Clean and use first 100 chars
                    author_affiliation = sent.strip()[:100]
                    break
            if author_affiliation:
                break
    
    if not author_affiliation:
        author_affiliation = "Independent Economic Research"
    
    logging.info(f"[PDF_AUTHOR] Using author: {author_name}, affiliation: {author_affiliation}")
    
    # 🔥🔥🔥 FINAL NUCLEAR CLEANUP - Last chance to remove black squares
    # This is executed RIGHT BEFORE creating the PDF
    logging.info(f"[FINAL_CLEANUP] Content length before final cleanup: {len(compiled_content)}")
    logging.info(f"[FINAL_CLEANUP] Checking for black square symbol...")
    
    if '■' in compiled_content:
        logging.warning(f"[FINAL_CLEANUP] ⚠️ Found black square (■) in compiled content! Removing...")
        count_before = compiled_content.count('■')
        compiled_content = compiled_content.replace('■', '')
        logging.info(f"[FINAL_CLEANUP] Removed {count_before} instances of ■")
    else:
        logging.info(f"[FINAL_CLEANUP] ✅ No black squares found")
    
    # Remove all variations of bullets
    for bullet in ['▪', '▫', '◾', '◽', '●', '○', '•']:
        compiled_content = compiled_content.replace(bullet, '')
    
    # Remove any paragraphs that contain only whitespace or bullets
    import re
    compiled_content = re.sub(r'<p[^>]*>\s*</p>', '', compiled_content, flags=re.IGNORECASE)
    
    # Remove trailing whitespace and empty lines at the end
    compiled_content = compiled_content.rstrip()
    
    logging.info(f"[FINAL_CLEANUP] Content length after final cleanup: {len(compiled_content)}")
    logging.info(f"[FINAL_CLEANUP] Final check - contains ■?: {'YES ❌' if '■' in compiled_content else 'NO ✅'}")
    
    pdf_bytes = create_pdf(
        title=study['study_title'],
        content=compiled_content,
        doc_type="econometric_study",
        author_name=author_name,
        author_affiliation=author_affiliation,
        language=language
    )
    
    lang_suffix = "_EN" if language == "en" else "_ES"
    filename = f"{study['study_title']}{lang_suffix}_econometric_study.pdf"
    
    return StreamingResponse(
        io.BytesIO(pdf_bytes),
        media_type="application/pdf",
        headers={"Content-Disposition": f'attachment; filename="{filename}"'}
    )

@api_router.put("/econometric-studies/{study_id}/sections/{section_number}")
async def update_econometric_section_manual(
    study_id: str,
    section_number: int,
    content_es: str = "",
    content_en: str = "",
    current_user: User = Depends(get_current_user)
):
    """Manually update a section's content in both languages"""
    # Check in-progress first
    study = await db.econometric_studies_in_progress.find_one(
        {"id": study_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    collection = db.econometric_studies_in_progress
    
    if not study:
        # Check completed studies
        study = await db.econometric_studies.find_one(
            {"id": study_id, "user_id": current_user.id},
            {"_id": 0}
        )
        collection = db.econometric_studies
    
    if not study:
        raise HTTPException(status_code=404, detail="Study not found")
    
    # Update the section content
    await collection.update_one(
        {"id": study_id, "sections.number": section_number},
        {
            "$set": {
                "sections.$.content": content_es,  # For backward compatibility
                "sections.$.content_es": content_es,
                "sections.$.content_en": content_en,
                "updated_at": datetime.now(timezone.utc).isoformat()
            }
        }
    )
    
    return {"message": "Section updated successfully"}


@api_router.post("/econometric-studies/{study_id}/retry-generation")
async def retry_econometric_study_generation(
    study_id: str,
    current_user: User = Depends(get_current_user)
):
    """
    Retry/continue generation of an econometric study that failed or got stuck.
    Continues from where it left off based on sections already generated.
    """
    # Find the study in either collection
    study = await db.econometric_studies_in_progress.find_one({"id": study_id})
    
    if not study:
        study = await db.econometric_studies.find_one({"id": study_id})
        if study:
            # Study is already complete
            return {
                "message": "Study is already completed",
                "study_id": study_id,
                "status": "completed"
            }
    
    if not study:
        raise HTTPException(status_code=404, detail="Study not found")
    
    # Check if study already has all 16 sections - if so, mark as complete
    sections = study.get("sections", [])
    if len(sections) >= 9:
        print(f"✅ Study {study_id} already has {len(sections)} sections - marking as completed")
        
        # Update status to completed and move to completed collection
        study_copy = {k: v for k, v in study.items() if k != '_id'}
        study_copy["status"] = "completed"
        study_copy["progress"] = 100
        study_copy["completed_at"] = datetime.now(timezone.utc).isoformat()
        
        # Check if already in completed collection
        existing = await db.econometric_studies.find_one({"id": study_id})
        if not existing:
            await db.econometric_studies.insert_one(study_copy)
        else:
            await db.econometric_studies.update_one(
                {"id": study_id},
                {"$set": {"status": "completed", "progress": 100, "completed_at": study_copy["completed_at"]}}
            )
        
        # Remove from in-progress
        await db.econometric_studies_in_progress.delete_one({"id": study_id})
        
        return {
            "message": "Study marked as completed (all sections present)",
            "study_id": study_id,
            "status": "completed",
            "sections_count": len(sections)
        }
    
    # Update status to generating
    await db.econometric_studies_in_progress.update_one(
        {"id": study_id},
        {
            "$set": {
                "status": "generating",
                "updated_at": datetime.now(timezone.utc).isoformat()
            }
        }
    )
    
    # Start background generation
    print(f"🔄 Creating background task for study {study_id}")
    try:
        asyncio.create_task(generate_econometric_study_background(
            study_id,
            study.get("project_description", ""),
            study.get("language", "es")
        ))
        print(f"✅ Background task created successfully for study {study_id}")
    except Exception as e:
        print(f"❌ Failed to create background task: {e}")
        raise HTTPException(status_code=500, detail=f"Failed to start generation: {str(e)}")
    
    print(f"🔄 Retry generation started for econometric study {study_id} by {current_user.email}")
    
    return {
        "message": "Generation retry started",
        "study_id": study_id,
        "status": "generating"
    }



@api_router.delete("/econometric-studies/{study_id}")
async def delete_econometric_study(
    study_id: str,
    current_user: User = Depends(get_current_user)
):
    """Soft delete an econometric study (move to trash) - ALL users can delete"""
    try:
        # Buscar en ambas colecciones
        study = await db.econometric_studies.find_one({"id": study_id}, {"_id": 0})
        collection = db.econometric_studies
        
        if not study:
            study = await db.econometric_studies_in_progress.find_one({"id": study_id}, {"_id": 0})
            collection = db.econometric_studies_in_progress
        
        if not study:
            raise HTTPException(status_code=404, detail="Study not found")
        
        # TODOS los usuarios pueden eliminar TODOS los documentos
        logging.info(f"🗑️ Deleting econometric study {study_id} by user {current_user.email}")
        
        # Soft delete - mover a papelera
        result = await collection.update_one(
            {"id": study_id},
            {
                "$set": {
                    "status": "deleted",
                    "deleted_at": datetime.now(timezone.utc).isoformat(),
                    "deleted_by": current_user.id
                }
            }
        )
        
        if result.modified_count == 0:
            raise HTTPException(status_code=400, detail="Failed to delete study")
        
        return {
            "message": "Estudio econométrico movido a la papelera",
            "note": "Puedes restaurarlo desde la papelera si es necesario"
        }
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error deleting econometric study: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))


@api_router.post("/econometric-studies/finalize/{study_id}")
async def finalize_econometric_study(study_id: str, current_user: User = Depends(get_current_user)):
    """Finalize the econometric study"""
    study = await db.econometric_studies_in_progress.find_one(
        {"id": study_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not study:
        raise HTTPException(status_code=404, detail="Econometric study not found")
    
    sections = study.get('sections', [])
    if not sections:
        raise HTTPException(status_code=400, detail="No sections found to finalize")
    
    # Compile all sections into final content
    compiled_content = f"# {study['study_title']}\n\n"
    compiled_content += f"**Applicant:** {study['applicant_name']}\n"
    compiled_content += f"**Field of Study:** {study.get('field_of_study', 'N/A')}\n\n"
    compiled_content += "---\n\n"
    
    for section in sorted(sections, key=lambda x: x['number']):
        compiled_content += f"## Section {section['number']} — {section['title']}\n\n"
        compiled_content += section['content'] + "\n\n"
        compiled_content += "---\n\n"
    
    # Create final econometric study
    final_study = {
        "id": study['id'],
        "user_id": current_user.id,
        "client_id": study.get('client_id'),
        "study_title": study['study_title'],
        "applicant_name": study['applicant_name'],
        "field_of_study": study.get('field_of_study'),
        "project_description": study['project_description'],
        "language": study['language'],
        "content": compiled_content,
        "sections": sections,
        "status": "completed",
        "created_at": study.get('created_at', datetime.now(timezone.utc).isoformat()),
        "updated_at": datetime.now(timezone.utc).isoformat()
    }
    
    # Save final econometric study
    await db.econometric_studies.insert_one(final_study)
    
    # Save to Supabase if client has supabase_id
    if final_study.get('client_id'):
        try:
            client_doc = await db.clients.find_one({"id": final_study['client_id']}, {"_id": 0})
            if client_doc and client_doc.get('supabase_id'):
                document_data = {
                    "id": final_study['id'],
                    "title": final_study['study_title'],
                    "applicant_name": final_study['applicant_name'],
                    "field_of_study": final_study.get('field_of_study', 'N/A'),
                    "content": compiled_content,
                    "language": final_study['language'],
                    "created_at": datetime.now(timezone.utc).isoformat(),
                    "status": "completed"
                }
                await save_document_to_supabase(
                    cliente_supabase_id=client_doc['supabase_id'],
                    cliente_nombre=client_doc.get('name', 'Unknown'),
                    tipo="Econometric Study",
                    document_data=document_data
                )
        except Exception as supabase_error:
            logging.error(f"Error saving to Supabase (non-critical): {str(supabase_error)}")
    
    # Remove from in-progress
    await db.econometric_studies_in_progress.delete_one({"id": study_id})
    
    return {
        "message": "Econometric study finalized successfully",
        "id": final_study['id'],
        "success": True
    }


# CV Upload and Analysis Endpoint
@api_router.post("/upload-cv")
async def upload_cv_pdf(
    file: UploadFile = File(...),
    current_user: User = Depends(get_current_user)
):
    """Upload and extract text from CV PDF or Word document.

    Stage-tracked: cada fase (read, extract, ai_analysis, address_extraction)
    se etiqueta para que un 500 nos diga exactamente cuál falló. Antes el
    `except Exception` final tragaba el detalle y el cliente solo veía
    "Error al procesar el PDF: <repr>" sin pista de la fase. Esto es lo
    que rompió "leer CV" en producción sin traceback en el log."""
    fname = (file.filename or "").lower()
    stage = "init"
    logging.info(f"📄 [upload-cv] user={current_user.email} file={file.filename!r} content_type={file.content_type!r}")
    try:
        # Phase 1: read bytes from the upload
        stage = "read"
        content = await file.read()
        logging.info(f"📄 [upload-cv] stage={stage} bytes={len(content)}")
        if not content:
            raise HTTPException(status_code=400, detail="El archivo está vacío.")

        extracted_text = ""
        extraction_method = "none"

        # Phase 2: text extraction (PDF or DOCX)
        stage = "extract"
        if fname.endswith('.pdf'):
            extracted_text, extraction_method = await extract_text_from_pdf_robust(content, file.filename)

        elif fname.endswith(('.doc', '.docx')):
            doc = docx.Document(io.BytesIO(content))
            for paragraph in doc.paragraphs:
                if paragraph.text.strip():
                    extracted_text += paragraph.text + "\n"
            for table in doc.tables:
                for row in table.rows:
                    for cell in row.cells:
                        if cell.text.strip():
                            extracted_text += cell.text + "\n"
            extraction_method = "docx"
        else:
            raise HTTPException(
                status_code=400,
                detail=f"Solo se permiten archivos PDF, DOC o DOCX (recibido: {file.filename!r})",
            )
        
        # Clean up the text
        stage = "post_extract"
        extracted_text = extracted_text.strip()

        if not extracted_text or len(extracted_text) < 50:
            raise HTTPException(
                status_code=400,
                detail=(
                    "No se pudo extraer texto del archivo. "
                    "El CV puede estar dañado o ser una imagen escaneada sin texto reconocible. "
                    f"Método usado: {extraction_method}, caracteres extraídos: {len(extracted_text)}."
                ),
            )

        logging.info(f"✅ [upload-cv] extraction OK: {len(extracted_text)} chars via {extraction_method}")
        
        # Analyze the CV with AI to extract structured information
        system_message = """Eres un experto en análisis de hojas de vida (CVs).
Tu tarea es analizar el CV proporcionado y extraer información clave de manera estructurada y organizada.

Organiza la información en las siguientes categorías:
1. Información Personal (nombre, título profesional)
2. Datos de Contacto (dirección física completa, ciudad, estado/provincia, país, código postal, email, teléfono)
3. Educación (grados académicos, instituciones, años)
4. Experiencia Profesional (puestos, empresas, responsabilidades clave)
5. Publicaciones y Investigación (si aplica)
6. Premios y Reconocimientos
7. Certificaciones y Habilidades Técnicas
8. Áreas de Especialización

Proporciona un resumen bien estructurado y profesional que pueda ser usado en una propuesta EB-2 NIW o una patente provisional USPTO."""

        prompt = f"""Analiza la siguiente hoja de vida y extrae la información clave de manera estructurada:

{extracted_text}

Proporciona un resumen profesional y bien organizado con las categorías mencionadas. Para la sección "Datos de Contacto" incluye TODO lo que encuentres en el CV (dirección completa, email, teléfono) — si algún campo no aparece en el CV, escribe "no especificado" en esa línea."""

        stage = "ai_analysis"
        try:
            # Use GPT-4o-mini for faster CV analysis (10-20x faster than GPT-5)
            analyzed_cv = await call_openai_mini(
                system_message,
                prompt,
                temperature=0.3,  # More deterministic = faster
                max_tokens=2500   # Slightly higher to accommodate the contact section
            )

            # If AI analysis fails or returns empty, use the raw text
            if not analyzed_cv or len(analyzed_cv.strip()) < 50:
                logging.warning("WARNING AI analysis returned empty or too short, using raw extracted text")
                analyzed_cv = extracted_text
        except Exception as ai_error:
            # Non-fatal: si el LLM falla por timeout/billing/rate-limit/etc.,
            # devolvemos el texto crudo del CV. El operador puede seguir adelante
            # con el flujo de generación; perdimos la versión "linda" del resumen
            # pero NO bloqueamos al usuario por un problema upstream.
            logging.warning(f"⚠️ [upload-cv] AI análisis falló ({type(ai_error).__name__}: {ai_error}); usando texto crudo")
            analyzed_cv = extracted_text

        # Second call: structured address extraction (JSON). Keeps the markdown
        # analysis intact for display and adds machine-readable fields that
        # downstream features (patents, intent letters, etc.) can use directly
        # without re-parsing markdown.
        extracted_address = {
            "street_address": "",
            "city": "",
            "state": "",
            "postal_code": "",
            "country": "",
            "email": "",
            "phone": "",
        }
        try:
            address_system = (
                "You extract structured contact information from CV text. "
                "Return ONLY valid JSON matching the requested schema. "
                "If a field is genuinely not present in the CV, return an empty string for it — never invent values."
            )
            address_user = f"""Extract the following contact fields from this CV. Return JSON only, no commentary.

CV TEXT:
{extracted_text[:12000]}

Required JSON schema (every key must be present, use empty string for missing):
{{
  "street_address": "street number + street name only, no city/state/postal",
  "city": "city or town",
  "state": "state, province, region — empty string if not in CV",
  "postal_code": "postal/zip code — empty string if not in CV",
  "country": "country name (English or Spanish, as written in CV)",
  "email": "email address",
  "phone": "phone number with any country code shown"
}}"""
            addr_resp = await asyncio.wait_for(
                openai_client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": address_system},
                        {"role": "user", "content": address_user},
                    ],
                    temperature=0.0,
                    max_tokens=400,
                    response_format={"type": "json_object"},
                ),
                timeout=30.0,
            )
            parsed = json.loads(addr_resp.choices[0].message.content)
            for k in extracted_address:
                v = parsed.get(k)
                if isinstance(v, str):
                    extracted_address[k] = v.strip()
        except Exception as addr_err:
            logging.warning(f"CV address extraction failed (non-fatal): {type(addr_err).__name__}: {addr_err}")

        return {
            "success": True,
            "filename": file.filename,
            "raw_text": extracted_text,
            "analyzed_cv": analyzed_cv,
            "extracted_address": extracted_address,
            "text_length": len(extracted_text),
            "used_ocr": extraction_method == "ocr" or extraction_method == "gpt4o_vision"
        }
        
    except HTTPException:
        raise
    except Exception as e:
        # Stage-aware error: dice EXACTAMENTE en qué fase explotó (read /
        # extract / post_extract / ai_analysis / address). Sin esto el cliente
        # solo ve "Error al procesar el PDF" y no podemos debuggear.
        import traceback as _tb
        tb_str = _tb.format_exc()
        logging.error(f"❌ [upload-cv] FAIL stage={stage} file={file.filename!r}: {type(e).__name__}: {e}")
        logging.error(f"❌ [upload-cv] traceback:\n{tb_str}")
        raise HTTPException(
            status_code=500,
            detail=f"Error al procesar el CV (fase: {stage}): {type(e).__name__}: {str(e)[:300]}",
        )


@api_router.post("/upload-project")
async def upload_project_document(
    file: UploadFile = File(...),
    current_user: User = Depends(get_current_user)
):
    """Upload and extract text from project document (PDF, Word, or TXT)"""
    try:
        # Read file content
        content = await file.read()
        extracted_text = ""
        
        # Extract text based on file type
        if file.filename.endswith('.pdf'):
            # Extract from PDF
            pdf_reader = PdfReader(io.BytesIO(content))
            for page in pdf_reader.pages:
                extracted_text += page.extract_text() + "\n"
        elif file.filename.endswith(('.doc', '.docx')):
            # Extract from Word (including tables)
            doc = docx.Document(io.BytesIO(content))
            # Extract from paragraphs
            for paragraph in doc.paragraphs:
                if paragraph.text.strip():
                    extracted_text += paragraph.text + "\n"
            # Extract from tables (many CVs use tables for layout)
            for table in doc.tables:
                for row in table.rows:
                    for cell in row.cells:
                        if cell.text.strip():
                            extracted_text += cell.text + "\n"
        elif file.filename.endswith('.txt'):
            # Extract from TXT
            extracted_text = content.decode('utf-8', errors='ignore')
        else:
            raise HTTPException(
                status_code=400, 
                detail="Solo se permiten archivos PDF, DOC, DOCX o TXT"
            )
        
        # Clean up the text
        extracted_text = extracted_text.strip()
        
        if not extracted_text or len(extracted_text) < 50:
            raise HTTPException(
                status_code=400, 
                detail="No se pudo extraer texto del documento. Asegúrate de que contenga texto."
            )
        
        # Analyze the project with AI to extract key information
        system_message = """Eres un experto en análisis de proyectos técnicos. 
Tu tarea es analizar el documento del proyecto y extraer información clave de manera estructurada.

Organiza la información en las siguientes categorías:
1. Título/Nombre del Proyecto
2. Objetivo Principal
3. Problema que Resuelve
4. Solución Propuesta
5. Tecnologías o Metodologías Clave
6. Resultados Esperados o Logros
7. Impacto o Beneficios

Proporciona un resumen estructurado y conciso del proyecto."""
        
        prompt = f"""Analiza el siguiente documento de proyecto y extrae la información clave:

{extracted_text[:15000]}

Proporciona un resumen profesional y bien organizado con las categorías mencionadas."""
        
        try:
            analyzed_content = await call_openai_mini(
                system_message, 
                prompt,
                temperature=0.3,
                max_tokens=2000
            )
            
            if not analyzed_content or len(analyzed_content.strip()) < 50:
                analyzed_content = extracted_text[:5000]
        except Exception as ai_error:
            logging.error(f"❌ Error analyzing project with AI: {str(ai_error)}")
            analyzed_content = extracted_text[:5000]
        
        return {
            "success": True,
            "filename": file.filename,
            "raw_text": extracted_text,
            "analyzed_content": analyzed_content,
            "text_length": len(extracted_text)
        }
    
    except Exception as e:
        logging.error(f"Error processing project document: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))


