@api_router.post("/whitepapers/extract-cv-info")
async def extract_cv_info(file: UploadFile = File(...), background_tasks: BackgroundTasks = None, current_user: User = Depends(get_current_user)):
    """Extract comprehensive author information from CV file - runs AI extraction in background"""
    
    try:
        # Read file content (fast)
        content = await file.read()
        file_extension = file.filename.split('.')[-1].lower()
        
        # Extract text based on file type (fast - no AI)
        if file_extension == 'pdf':
            import PyPDF2
            from io import BytesIO
            pdf_reader = PyPDF2.PdfReader(BytesIO(content))
            text = ""
            for page in pdf_reader.pages:
                text += page.extract_text()
        elif file_extension in ['doc', 'docx']:
            from docx import Document
            from io import BytesIO
            doc = Document(BytesIO(content))
            text = "\n".join([paragraph.text for paragraph in doc.paragraphs])
        elif file_extension == 'txt':
            text = content.decode('utf-8')
        else:
            raise HTTPException(status_code=400, detail="Unsupported file format. Please upload PDF, DOC, DOCX, or TXT")
        
        logging.info(f"📄 CV text extracted: {len(text)} characters")
        
        # Create extraction task
        task_id = str(uuid.uuid4())
        await db.extraction_tasks.insert_one({
            "id": task_id,
            "type": "cv",
            "user_id": current_user.id,
            "status": "processing",
            "text": text[:12000],
            "result": None,
            "error": None,
            "created_at": datetime.now(timezone.utc).isoformat()
        })
        
        # Start background extraction
        background_tasks.add_task(_extract_cv_background, task_id, text)
        
        return {"task_id": task_id, "status": "processing"}
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error extracting CV info: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error processing CV: {str(e)}")


async def _extract_cv_background(task_id: str, text: str):
    """Background task for CV extraction with AI"""
    try:
        extraction_prompt = f"""You are extracting information from a CV/Resume for an EB-2 NIW (National Interest Waiver) petition white paper.

EXTRACT ALL AVAILABLE INFORMATION - do not summarize or omit details.

CV Content:
{text[:12000]}

Extract and return a JSON object with ALL of the following:

{{
  "author_name": "Full name of the person",
  "author_credentials": "ALL degrees, certifications, licenses",
  "technical_domain": "Main technical areas/expertise",
  "years_of_experience": "Total years if mentioned, or 'Not specified'",
  "employment_history": [
    {{
      "company": "Company name",
      "location": "City, Country",
      "role": "Job title",
      "dates": "Start - End dates",
      "duration_months": "Duration in months if calculable",
      "responsibilities": ["Key responsibility 1"],
      "achievements": ["Achievement with numbers if any"],
      "metrics": ["Any quantified results"]
    }}
  ],
  "education": [
    {{
      "degree": "Degree name",
      "institution": "University/School name",
      "year": "Graduation year",
      "field": "Field of study",
      "honors": "Any honors or distinctions"
    }}
  ],
  "certifications": [
    {{
      "name": "Certification name",
      "issuer": "Issuing organization",
      "year": "Year obtained",
      "id": "Certification ID if shown"
    }}
  ],
  "skills": ["Skill 1", "Skill 2"],
  "languages": ["Language 1 (level)"],
  "publications": ["Publication 1 if any"],
  "awards": ["Award 1 if any"],
  "professional_affiliations": ["Affiliation 1 if any"],
  "key_achievements_summary": "2-3 sentence summary of most impressive quantified achievements"
}}

IMPORTANT: Extract EXACTLY what is in the CV - do not invent. If information is not present, use empty string or empty array. Return ONLY valid JSON."""

        response = await call_openai_gpt4o(
            "You are an expert at extracting professional information from CVs for immigration petitions. Extract ALL details exactly as written. Return only valid JSON.",
            extraction_prompt,
            temperature=0.2,
            max_tokens=4000
        )
        
        import json
        import re
        
        cleaned = response.strip()
        if cleaned.startswith("```json"):
            cleaned = cleaned[7:]
        elif cleaned.startswith("```"):
            cleaned = cleaned[3:]
        if cleaned.endswith("```"):
            cleaned = cleaned[:-3]
        cleaned = cleaned.strip()
        
        json_match = re.search(r'\{.*\}', cleaned, re.DOTALL)
        if json_match:
            cleaned = json_match.group(0)
        
        extracted_data = json.loads(cleaned)

        # Defensive coercion: some LLMs (esp. OpenRouter fallbacks) may return
        # fields as arrays instead of strings. Normalize to plain strings to
        # prevent "sequence item 0: expected str instance, list found" errors
        # during the "; ".join(credentials_parts) below.
        def _to_str(v):
            if v is None:
                return ""
            if isinstance(v, list):
                return "; ".join(str(x) for x in v if x)
            if isinstance(v, dict):
                return "; ".join(f"{k}: {vv}" for k, vv in v.items() if vv)
            return str(v)

        for _k in ("author_name", "author_credentials", "technical_domain",
                   "years_of_experience", "key_achievements_summary"):
            if _k in extracted_data:
                extracted_data[_k] = _to_str(extracted_data[_k])

        # Build comprehensive author_credentials string
        credentials_parts = []
        if extracted_data.get("author_credentials"):
            credentials_parts.append(str(extracted_data["author_credentials"]))
        for edu in extracted_data.get("education", []):
            if edu.get("degree") and edu.get("institution"):
                edu_str = f"{edu['degree']} from {edu['institution']}"
                if edu.get("year"):
                    edu_str += f" ({edu['year']})"
                credentials_parts.append(edu_str)
        for cert in extracted_data.get("certifications", []):
            if cert.get("name"):
                cert_str = cert["name"]
                if cert.get("issuer"):
                    cert_str += f" ({cert['issuer']})"
                credentials_parts.append(cert_str)
        
        employment_summary = []
        for job in extracted_data.get("employment_history", []):
            job_parts = []
            if job.get("role"):
                job_parts.append(job["role"])
            if job.get("company"):
                job_parts.append(f"at {job['company']}")
            if job.get("dates"):
                job_parts.append(f"({job['dates']})")
            job_str = " ".join(job_parts)
            metrics = job.get("metrics", []) + job.get("achievements", [])
            if metrics:
                job_str += ": " + "; ".join(metrics[:3])
            if job_str:
                employment_summary.append(job_str)
        
        comprehensive_credentials = "; ".join(credentials_parts) if credentials_parts else extracted_data.get("author_credentials", "")
        if extracted_data.get("key_achievements_summary"):
            comprehensive_credentials += f". Key achievements: {extracted_data['key_achievements_summary']}"
        
        # 🛟 Fallback: if the LLM produced empty/too-short credentials, use the raw
        # CV text (trimmed) so downstream white-paper generation has something
        # concrete to work from. Without this, the user sees "CV Subido
        # Exitosamente" but the generate-whitepaper call receives empty credentials
        # and the frontend validator then blocks the request.
        if not comprehensive_credentials or len(comprehensive_credentials.strip()) < 30:
            logging.warning(
                f"⚠️ CV extraction returned empty/short credentials "
                f"(len={len(comprehensive_credentials or '')}); falling back to raw CV text"
            )
            # Use up to 8000 chars of the raw CV as credentials
            raw_fallback = (text or "").strip()
            if raw_fallback:
                comprehensive_credentials = raw_fallback[:8000]
        
        result = {
            "author_name": extracted_data.get("author_name", ""),
            "author_credentials": comprehensive_credentials,
            "technical_domain": extracted_data.get("technical_domain", ""),
            "years_of_experience": extracted_data.get("years_of_experience", ""),
            "full_cv_data": {
                "employment_history": extracted_data.get("employment_history", []),
                "education": extracted_data.get("education", []),
                "certifications": extracted_data.get("certifications", []),
                "skills": extracted_data.get("skills", []),
                "languages": extracted_data.get("languages", []),
                "publications": extracted_data.get("publications", []),
                "awards": extracted_data.get("awards", []),
                "professional_affiliations": extracted_data.get("professional_affiliations", [])
            },
            "employment_summary": employment_summary
        }
        
        await db.extraction_tasks.update_one(
            {"id": task_id},
            {"$set": {"status": "completed", "result": result}}
        )
        logging.info(f"✅ CV extraction task {task_id} completed")
        
    except Exception as e:
        logging.error(f"❌ CV extraction task {task_id} failed: {str(e)}")
        await db.extraction_tasks.update_one(
            {"id": task_id},
            {"$set": {"status": "failed", "error": str(e)}}
        )


@api_router.post("/whitepapers/extract-project-info")
async def extract_project_info(file: UploadFile = File(...), background_tasks: BackgroundTasks = None, current_user: User = Depends(get_current_user)):
    """Extract project information from project document - runs AI extraction in background"""
    
    try:
        # Read file content (fast)
        content = await file.read()
        file_extension = file.filename.split('.')[-1].lower()
        
        # Extract text based on file type (fast - no AI)
        if file_extension == 'pdf':
            import PyPDF2
            from io import BytesIO
            pdf_reader = PyPDF2.PdfReader(BytesIO(content))
            text = ""
            for page in pdf_reader.pages:
                text += page.extract_text()
        elif file_extension in ['doc', 'docx']:
            from docx import Document
            from io import BytesIO
            doc = Document(BytesIO(content))
            text = "\n".join([paragraph.text for paragraph in doc.paragraphs])
        elif file_extension == 'txt':
            text = content.decode('utf-8')
        else:
            raise HTTPException(status_code=400, detail="Unsupported file format. Please upload PDF, DOC, DOCX, or TXT")
        
        # Create extraction task
        task_id = str(uuid.uuid4())
        await db.extraction_tasks.insert_one({
            "id": task_id,
            "type": "project",
            "user_id": current_user.id,
            "status": "processing",
            "text": text[:12000],
            "result": None,
            "error": None,
            "created_at": datetime.now(timezone.utc).isoformat()
        })
        
        # Start background extraction
        background_tasks.add_task(_extract_project_background, task_id, text)
        
        return {"task_id": task_id, "status": "processing"}
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error extracting project info: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error processing project document: {str(e)}")


async def _extract_project_background(task_id: str, text: str):
    """Background task for project extraction with AI — uses fast model with 45s timeout.
    Falls back to raw text if AI call times out or fails."""
    try:
        extraction_prompt = f"""Extract the following information from this project document:

Document Content:
{text[:8000]}

Extract:
1. Project title (short, descriptive, max 10 words)
2. Project description (objectives, methodology, expected results - 150-300 words)
3. Target audience (who will read/use this white paper)

Return ONLY a JSON object:
{{
  "project_title": "AI System for Medical Diagnosis",
  "project_description": "Detailed description...",
  "target_audience": "ML Engineers, Healthcare Researchers"
}}"""

        try:
            response = await call_openai_mini(
                "You are an expert at extracting technical project information. Return ONLY valid JSON, nothing else.",
                extraction_prompt,
                temperature=0.2,
                max_tokens=600,
                timeout=45
            )
        except Exception as ai_err:
            # AI call failed or timed out — use raw text directly as fallback
            logging.warning(f"⚠️ AI extraction timed out/failed for task {task_id}: {ai_err}. Using raw text fallback.")
            first_line = text.split('\n')[0].strip()[:80] if text else "Project Document"
            await db.extraction_tasks.update_one(
                {"id": task_id},
                {"$set": {
                    "status": "completed",
                    "result": {
                        "project_title": first_line,
                        "project_description": text[:3000].strip(),
                        "target_audience": ""
                    }
                }}
            )
            return
        
        import json
        import re
        
        cleaned = response.strip()
        if cleaned.startswith("```json"):
            cleaned = cleaned[7:]
        elif cleaned.startswith("```"):
            cleaned = cleaned[3:]
        if cleaned.endswith("```"):
            cleaned = cleaned[:-3]
        cleaned = cleaned.strip()
        
        json_match = re.search(r'\{[^{}]*(?:\{[^{}]*\}[^{}]*)*\}', cleaned, re.DOTALL)
        if json_match:
            cleaned = json_match.group(0)
        
        # Try to parse JSON, fall back to raw text if parsing fails
        extracted_data = {}
        try:
            extracted_data = json.loads(cleaned)
        except json.JSONDecodeError as je:
            logging.warning(f"⚠️ JSON parse failed for task {task_id}: {str(je)}, using raw text as fallback")
        
        # Use raw text as fallback if AI extraction returns empty description
        extracted_desc = extracted_data.get("project_description", "")
        if not extracted_desc or len(extracted_desc.strip()) < 50:
            logging.warning(f"⚠️ AI extraction returned empty/short description for task {task_id}, using raw text as fallback")
            extracted_desc = text[:3000].strip()
        
        result = {
            "project_title": extracted_data.get("project_title", ""),
            "project_description": extracted_desc,
            "target_audience": extracted_data.get("target_audience", "")
        }
        
        await db.extraction_tasks.update_one(
            {"id": task_id},
            {"$set": {"status": "completed", "result": result}}
        )
        logging.info(f"✅ Project extraction task {task_id} completed with {len(extracted_desc)} chars description")
        
    except Exception as e:
        logging.error(f"❌ Project extraction task {task_id} failed: {str(e)}")
        await db.extraction_tasks.update_one(
            {"id": task_id},
            {"$set": {"status": "failed", "error": str(e)}}
        )


@api_router.get("/whitepapers/extraction-status/{task_id}")
async def get_extraction_status(task_id: str, current_user: User = Depends(get_current_user)):
    """Get status of an extraction task (CV or project)"""
    task = await db.extraction_tasks.find_one({"id": task_id}, {"_id": 0})
    if not task:
        raise HTTPException(status_code=404, detail="Extraction task not found")
    return {
        "task_id": task.get("id"),
        "type": task.get("type"),
        "status": task.get("status"),
        "result": task.get("result"),
        "error": task.get("error")
    }





async def generate_single_whitepaper_section(
    section_number: int,
    section_title: str,
    project_title: str,
    author_name: str,
    author_credentials: str,
    project_description: str,
    target_audience: str,
    technical_domain: str,
    previous_context: str,
    full_cv_data: dict = None,  # Enhanced CV data
    employment_summary: list = None  # Key employment with metrics
) -> str:
    """
    Generate a single whitepaper section using Claude Opus 4 with USCIS EB-2 NIW evaluator-compliant prompts.
    
    NEW STRUCTURE (17 sections including Part 2.5):
    - Part 1: Executive Summary
    - Part 2: Context and Problem
    - Part 2.5: Evidence of Exceptional Ability (CRITICAL - 10-12 pages)
    - Parts 3-16: Standard sections
    
    All prompts follow the 15 corrections from USCIS evaluator guidelines:
    1. Part 2.5 as independent section
    2. Evidence references mandatory (Exhibit X, page Y)
    3. Specific numbers, not generic
    4. Scarcity with 3 formal methods
    5. Historical benchmarking with actual numbers
    6. Methodologies with quantified results
    7. Track record with evidence basis
    8. Federal citations with USC/CFR
    9. Page count requirements
    10. Scarcity as percentile/number
    11. Tables with Evidence column
    12. Mitigation with historical solutions
    13. References with Specific Citation
    14. Verifiable industry averages
    15. Conservative projection methodology
    """
    
    # Build enhanced credentials string if full CV data is available
    enhanced_credentials = author_credentials
    
    if full_cv_data:
        credentials_parts = [author_credentials]
        
        # Add employment history with metrics
        employment_history = full_cv_data.get('employment_history', [])
        if employment_history:
            credentials_parts.append("\n\nEMPLOYMENT HISTORY:")
            for job in employment_history:
                job_line = f"- {job.get('role', '')} at {job.get('company', '')} ({job.get('dates', '')})"
                if job.get('metrics'):
                    job_line += f": {'; '.join(job['metrics'][:3])}"
                elif job.get('achievements'):
                    job_line += f": {'; '.join(job['achievements'][:3])}"
                credentials_parts.append(job_line)
        
        # Add education
        education = full_cv_data.get('education', [])
        if education:
            credentials_parts.append("\n\nEDUCATION:")
            for edu in education:
                edu_line = f"- {edu.get('degree', '')} in {edu.get('field', '')} from {edu.get('institution', '')}"
                if edu.get('year'):
                    edu_line += f" ({edu['year']})"
                credentials_parts.append(edu_line)
        
        # Add certifications
        certifications = full_cv_data.get('certifications', [])
        if certifications:
            credentials_parts.append("\n\nCERTIFICATIONS:")
            for cert in certifications:
                cert_line = f"- {cert.get('name', '')}"
                if cert.get('issuer'):
                    cert_line += f" ({cert['issuer']})"
                if cert.get('year'):
                    cert_line += f" - {cert['year']}"
                credentials_parts.append(cert_line)
        
        # Add languages
        languages = full_cv_data.get('languages', [])
        if languages:
            credentials_parts.append(f"\n\nLANGUAGES: {', '.join(languages)}")
        
        # Add skills
        skills = full_cv_data.get('skills', [])
        if skills:
            credentials_parts.append(f"\n\nSKILLS: {', '.join(skills[:15])}")
        
        enhanced_credentials = "\n".join(credentials_parts)
        logging.info(f"📋 Enhanced credentials built: {len(enhanced_credentials)} chars")
    
    # Import the new EB-2 NIW compliant prompts
    from whitepaper_prompts_eb2_niw import (
        get_section_prompts_eb2_niw,
        get_eb2_niw_system_message,
        SECTION_TITLES_17,
        SECTION_DISPLAY_NUMBERS
    )
    
    # Get all section prompts with enhanced credentials
    section_prompts = get_section_prompts_eb2_niw(
        project_title=project_title,
        author_name=author_name,
        author_credentials=enhanced_credentials,  # Use enhanced credentials
        project_description=project_description,
        target_audience=target_audience,
        technical_domain=technical_domain
    )
    
    # Get the prompt for this section
    prompt = section_prompts.get(section_number, f"Generate section {section_number}: {section_title}")
    
    # Get the USCIS-compliant system message with enhanced credentials
    system_message = get_eb2_niw_system_message(
        author_name=author_name,
        author_credentials=enhanced_credentials,  # Use enhanced credentials
        technical_domain=technical_domain,
        project_title=project_title,
        project_description=project_description,
        target_audience=target_audience
    )
    
    # Determine max tokens based on section criticality
    # Reduced tokens to speed up generation (was causing timeouts)
    if section_number == 3:  # Part 2.5: Evidence of Exceptional Ability
        max_tokens = 6000  # Reduced from 10000
        logging.info(f"📝 [WHITEPAPER] Generating Part 2.5 (max_tokens={max_tokens})")
    elif section_number == 8:  # Part 7: Implementation Methodology
        max_tokens = 6000  # Reduced from 10000
        logging.info(f"📝 [WHITEPAPER] Generating Part 7 (max_tokens={max_tokens})")
    else:
        max_tokens = 4000  # Reduced from 6000 for faster generation
    
    # Build user message with context
    user_message = f"""{prompt}

---
**PREVIOUS SECTIONS CONTEXT** (for consistency):
{previous_context if previous_context else 'This is the first section.'}

---
**CRITICAL REMINDERS FOR THIS SECTION:**
1. Use ONLY the author credentials provided - DO NOT invent achievements
2. Every metric needs evidence reference: (Document type, Exhibit [#], page [#]) OR [NEEDED: description]
3. All numbers must be specific, not generic descriptions
4. Industry averages must cite verifiable sources with page numbers
5. NO placeholders for data that IS provided in credentials
6. Write in ENGLISH only
7. Use proper Markdown formatting with tables where indicated"""

    # Use Claude Opus 4 (same as business plans module - proven reliable)
    display_num = SECTION_DISPLAY_NUMBERS.get(section_number, str(section_number))
    logging.info(f"📝 [WHITEPAPER] Generating Part {display_num} ({section_title}) with Claude Opus 4 (max_tokens={max_tokens})...")
    
    import time
    start_time = time.time()
    
    try:
        content = await call_claude_opus_niw(
            system_message=system_message,
            user_message=user_message,
            temperature=0.3,
            max_tokens=max_tokens
        )
        elapsed = time.time() - start_time
        logging.info(f"✅ [WHITEPAPER] Part {display_num} completed in {elapsed:.1f}s ({len(content)} chars)")
        print(f"✅ Part {display_num} generated in {elapsed:.1f}s ({len(content)} chars)")
        return content
    except Exception as e:
        elapsed = time.time() - start_time
        logging.error(f"❌ [WHITEPAPER] Claude Opus 4 failed for Part {display_num} after {elapsed:.1f}s: {str(e)[:200]}")
        print(f"❌ Part {display_num} FAILED after {elapsed:.1f}s: {str(e)[:100]}")
        raise Exception(f"Claude Opus 4 failed for Part {display_num}: {str(e)[:100]}")



async def translate_text_to_spanish(text: str) -> str:
    """
    Translate English text to Spanish using GPT-4o.
    Handles large content by splitting into chunks at paragraph boundaries.
    Max 12,000 chars per chunk to stay safely within GPT-4o output token limits.
    """
    system_message = """You are a professional technical translator specializing in immigration and technical documents.

CRITICAL RULES:
1. Translate from English to Spanish
2. Maintain ALL technical terms, formatting, tables, and structure
3. Keep technical jargon accurate (EB-2 NIW, USCIS terms stay in English)
4. Provide ONLY the translation, no explanations
5. Preserve markdown and HTML formatting exactly"""
    
    MAX_CHUNK = 12000  # chars — safely within GPT-4o output limits
    
    async def _translate_chunk(chunk: str) -> str:
        # Use call_openai_gpt4o which has built-in 429 retry + OpenRouter fallback
        return await call_openai_gpt4o(
            system_message=system_message,
            user_message=chunk,
            temperature=0.2,
            max_tokens=4096
        )
    
    if len(text) <= MAX_CHUNK:
        return await _translate_chunk(text)
    
    # Split at paragraph/section boundaries to avoid cutting mid-sentence
    # Try splitting at double-newlines first (markdown paragraph breaks)
    import asyncio
    chunks = []
    current = ""
    for block in text.split('\n\n'):
        block_with_sep = block + '\n\n'
        if len(current) + len(block_with_sep) <= MAX_CHUNK:
            current += block_with_sep
        else:
            if current:
                chunks.append(current.strip())
            current = block_with_sep
    if current.strip():
        chunks.append(current.strip())
    
    if not chunks:
        chunks = [text]
    
    logging.info(f"🌐 Translating large content in {len(chunks)} chunks ({len(text)} total chars)")
    
    # Translate all chunks concurrently
    results = await asyncio.gather(*[_translate_chunk(c) for c in chunks], return_exceptions=True)
    
    translated_parts = []
    for i, r in enumerate(results):
        if isinstance(r, Exception):
            logging.warning(f"⚠️ Chunk {i+1} translation failed: {r} — keeping English")
            translated_parts.append(chunks[i])  # fallback to original chunk (same language)
        else:
            translated_parts.append(r)
    
    return '\n\n'.join(translated_parts)


async def generate_whitepaper_background_thread(
    db,  # Thread-local database connection
    whitepaper_id: str,
    project_title: str,
    author_name: str,
    author_credentials: str,
    project_description: str,
    target_audience: str,
    technical_domain: str,
    language: str
):
    """
    Background task to generate complete EB-2 NIW whitepaper following strict evaluator guidelines.
    
    Uses Claude Opus 4 with 4 sequential batches:
    - Batch 1: Executive Summary + Part 1 + Part 2.5 (CRITICAL - 10-12 pages)
    - Batch 2: Parts 2-6 (Qualifications through Technical Framework)
    - Batch 3: Part 7 (Proven Methodologies) + Parts 8-9
    - Batch 4: Parts 10-14 + Evidence Checklist
    """
    import sys
    import time
    import asyncio
    import re
    
    print(f"🚀🚀🚀 BACKGROUND TASK STARTED for whitepaper {whitepaper_id}")
    sys.stdout.flush()
    
    start_time = time.time()
    
    async def update_progress(progress: int, message: str):
        """Helper to update progress in database"""
        try:
            await db.whitepapers_in_progress.update_one(
                {"id": whitepaper_id},
                {"$set": {
                    "progress": progress,
                    "progress_message": message,
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }}
            )
            print(f"   📊 Progress: {progress}% - {message}")
            sys.stdout.flush()
        except Exception as e:
            print(f"   ⚠️ Failed to update progress: {str(e)[:50]}")
    
    try:
        print(f"   Project: {project_title}")
        print(f"   Author: {author_name}")
        print(f"   Language: {language}")
        sys.stdout.flush()
        
        await update_progress(5, "Iniciando generación con directrices EB-2 NIW...")
        
        # Import strict EB-2 NIW guidelines
        from whitepaper_eb2_niw_strict import (
            SECTION_TITLES_EB2_NIW,
            SECTION_DISPLAY_NUMBERS,
            get_master_system_prompt,
            get_section_0_prompt,
            get_section_2_5_prompt,
            get_section_7_prompt,
            get_section_8_kpi_benchmark_prompt,
            get_section_12_risk_mitigation_prompt,
            get_evidence_checklist_prompt,
        )
        
        section_titles = SECTION_TITLES_EB2_NIW
        total_sections = len(section_titles)
        
        # Get enhanced CV data if available
        whitepaper = await db.whitepapers_in_progress.find_one(
            {"id": whitepaper_id},
            {"_id": 0, "full_cv_data": 1, "employment_summary": 1, "sections": 1}
        )
        
        full_cv_data = whitepaper.get('full_cv_data') if whitepaper else None
        
        # Generate master system prompt with all CV data
        system_message = get_master_system_prompt(
            author_name=author_name,
            author_credentials=author_credentials,
            project_title=project_title,
            project_description=project_description,
            full_cv_data=full_cv_data
        )
        
        print(f"📋 Starting 3-BATCH generation with NIW Dhanasar legal structure...")
        sys.stdout.flush()

        # ── RESUME SUPPORT ──────────────────────────────────────────────────
        # If the whitepaper already has sections (e.g. a retry after a crash or
        # timeout), seed `all_sections` with them and skip batches whose every
        # section number is already covered. Avoids paying the multi-minute LLM
        # cost for work already done.
        existing_sections = whitepaper.get('sections', []) if whitepaper else []
        all_sections = list(existing_sections) if existing_sections else []
        completed_section_numbers = {s.get('number') for s in all_sections if s.get('content') or s.get('content_en')}
        if completed_section_numbers:
            print(f"🔁 Resume mode: {len(completed_section_numbers)} sections already present — will skip complete batches")
            sys.stdout.flush()

        # Import new batch structure
        from whitepaper_eb2_niw_strict import GENERATION_BATCHES

        for batch in GENERATION_BATCHES:
            batch_name = batch["name"]
            batch_sections = batch["sections"]
            batch_display = batch["display_nums"]
            batch_titles = batch["titles"]
            batch_prompts = batch["prompts"]
            progress_start, progress_end = batch["progress_range"]

            # Skip batch if every section in it is already generated
            if completed_section_numbers and all(n in completed_section_numbers for n in batch_sections):
                print(f"   ⏭️  Skipping {batch_name} — all {len(batch_sections)} sections already present")
                sys.stdout.flush()
                await update_progress(progress_end, f"Saltando {batch_name} (ya generado)")
                continue

            # Remove any partial sections of this batch before regenerating so
            # we don't end up with duplicates in `all_sections`.
            if completed_section_numbers:
                all_sections = [s for s in all_sections if s.get('number') not in batch_sections]

            batch_start_t = time.time()
            await update_progress(progress_start, f"Generando {batch_name}...")
            print(f"\n   🔄 {batch_name} ({len(batch_sections)} sections)")
            sys.stdout.flush()
            
            # Build combined prompt for this batch
            batch_prompt_parts = []
            for i, (display_num, title, prompt_fn) in enumerate(zip(batch_display, batch_titles, batch_prompts)):
                batch_prompt_parts.append(f"===SECTION {display_num}===")
                batch_prompt_parts.append(prompt_fn())
                batch_prompt_parts.append("")
            
            combined_batch_prompt = f"""Generate the following sections for an EB-2 NIW whitepaper.
Use the EXACT section delimiters shown below so content can be parsed.

{chr(10).join(batch_prompt_parts)}

CRITICAL OUTPUT FORMAT:
- Start each section with its exact delimiter: ===SECTION [N]===
- Write [NEEDED: description] for any missing CV data — do NOT invent it
- All credentials cite their Exhibit (A, B, C, D...)
- Temperature is LOW — do not invent achievements, metrics, or statistics
- Write ENTIRELY IN ENGLISH — translate any Spanish credentials before use

🔒 ANTI-HALLUCINATION CONTRACT (system prompt above is binding):
- Every university, employer, degree, license, or date about the petitioner
  MUST appear verbatim in the CV_GROUND_TRUTH block of the system prompt.
- If a fact is not there, emit [NEEDED: <gap>] and continue. Do NOT guess.
- Do NOT write "Stanford", "MIT", "Harvard", "Ph.D.", "Electrical Engineer",
  "CDS license", or any specific credential unless it appears verbatim in the CV.
- If the CV is sparse, keep Prong 2 (petitioner background) SHORT and expand
  Prong 1 (national importance) instead. Never pad with invented credentials."""
            
            try:
                # Upgraded to Opus 4.6 (was Sonnet 4.6) + temperature 0.1 to
                # eliminate biographical hallucinations reported by clients
                # (e.g. invented "Electrical Engineer / PhD Stanford / CDS license"
                # on petitioners who never held those credentials).
                content = await call_claude_opus_niw(
                    system_message=system_message,
                    user_message=combined_batch_prompt,
                    temperature=0.1,
                    max_tokens=16000
                )
                elapsed = time.time() - batch_start_t
                print(f"   ✅ {batch_name} done in {elapsed:.1f}s ({len(content) if content else 0} chars)")
                sys.stdout.flush()
                
                if content:
                    for i, (sec_num, display_num, title) in enumerate(zip(batch_sections, batch_display, batch_titles)):
                        section_content = None
                        
                        # Try delimiter extraction first
                        delimiter = f"===SECTION {display_num}==="
                        start_idx = content.find(delimiter)
                        if start_idx != -1:
                            start_idx += len(delimiter)
                            # Find next delimiter or end
                            end_idx = len(content)
                            for other_num in batch_display:
                                next_marker = f"===SECTION {other_num}==="
                                next_idx = content.find(next_marker, start_idx)
                                if next_idx != -1 and next_idx < end_idx:
                                    end_idx = next_idx
                            section_content = content[start_idx:end_idx].strip()
                            print(f"   ✅ Section {display_num} ({title[:40]}): {len(section_content)} chars")
                        
                        # Fallback: extract by section heading
                        if not section_content or len(section_content) < 300:
                            pattern = rf"(?:#{1,2}\s*(?:SECTION\s*{re.escape(display_num)}[:\.]?|PRONG\s*{re.escape(display_num[0] if display_num else '0')})[^\n]*\n)(.*?)(?=#{1,2}\s*(?:SECTION|PRONG)|===|$)"
                            match = re.search(pattern, content, re.DOTALL | re.IGNORECASE)
                            if match:
                                section_content = match.group(1).strip()
                                print(f"   ✅ Section {display_num} via regex: {len(section_content)} chars")
                        
                        if not section_content or len(section_content) < 300:
                            section_content = f"## {title}\n\n[Section content extraction failed — please regenerate this section]\n"
                            print(f"   ⚠️ Could not extract Section {display_num}")
                        
                        # Translate to Spanish if needed — no char limit, use chunked translation
                        section_es = ""
                        if language == 'es' and section_content:
                            try:
                                section_es = await translate_text_to_spanish(section_content)
                                if not section_es or len(section_es.strip()) < 50:
                                    logging.warning(f"   ⚠️ Empty translation for Section {display_num} — will store empty")
                                    section_es = ""
                            except Exception as te:
                                logging.warning(f"   ⚠️ Translation failed for Section {display_num}: {te} — storing empty (NOT English fallback)")
                                section_es = ""  # Empty is better than English stored in content_es
                        
                        all_sections.append({
                            "number": sec_num,
                            "display_number": display_num,
                            "title": title,
                            "content": section_es if section_es else section_content,
                            "content_en": section_content,
                            "content_es": section_es,
                            "approved": True,
                            "edit_history": [],
                            "validation_warning": None,
                            "evaluation_history": []
                        })
                    
                    await db.whitepapers_in_progress.update_one(
                        {"id": whitepaper_id},
                        {"$set": {"sections": all_sections, "progress": progress_end}}
                    )
                    
            except Exception as e:
                print(f"   ❌ {batch_name} failed: {str(e)[:100]}")
                import traceback
                traceback.print_exc()
        
        # Coherence evaluation
        # Coherence evaluation
        await update_progress(92, "Evaluando coherencia...")
        print(f"📊 Running coherence evaluation...")
        sys.stdout.flush()
        
        coherence_evaluation = {"coherence_score": 0, "summary": "Evaluación pendiente"}
        try:
            if all_sections:
                full_content = "\n\n".join([s.get('content_en', '')[:3000] for s in all_sections])
                coherence_evaluation = await evaluate_document_coherence(
                    document_content=full_content[:12000],
                    author_name=author_name,
                    author_cv=author_credentials,
                    project_description=project_description,
                    document_type="white paper técnico EB-2 NIW"
                )
                print(f"   ✅ Coherence score: {coherence_evaluation.get('coherence_score', 'N/A')}")
        except Exception as ce:
            coherence_evaluation = {"coherence_score": 0, "summary": f"Error: {str(ce)[:100]}", "error": str(ce)}
            print(f"   ⚠️ Coherence evaluation failed: {str(ce)[:100]}")
        
        # ── PLACEHOLDER CLEANUP (Firecrawl + bracket strip) ────────────────
        # The generation prompt instructs the LLM to write `[NEEDED: …]` when CV
        # data is missing. Before persisting as `completed`, resolve what we
        # can via Firecrawl and strip any leftover bracketed placeholder so
        # the reader never sees raw `[NEEDED]`, `[Organization]`, etc. We also
        # normalize markdown `**bold**` / `####` residuals by letting the
        # frontend render with `react-markdown`; the raw text is preserved so
        # the PDF generator's markdown→HTML step still works.
        await update_progress(95, "Limpiando placeholders y resolviendo datos con Firecrawl...")
        try:
            for _sec in all_sections:
                for _fld in ("content_en", "content_es", "content"):
                    _val = _sec.get(_fld)
                    if not _val or not isinstance(_val, str) or "[" not in _val:
                        continue
                    try:
                        _sec[_fld] = await resolve_placeholders_with_firecrawl(_val)
                    except Exception as _resolve_err:
                        logging.warning(
                            f"⚠️ [CLEANUP] Section {_sec.get('display_number','?')} {_fld} "
                            f"resolve failed: {str(_resolve_err)[:120]} — applying strip only"
                        )
                        # Hard-fail safe: strip brackets even if Firecrawl blew up
                        try:
                            _sec[_fld] = _strip_unresolved_brackets(_val)
                        except Exception:
                            pass
            logging.info("✅ [CLEANUP] Placeholder cleanup done for all sections")
        except Exception as _cl_err:
            logging.warning(f"⚠️ [CLEANUP] Global placeholder cleanup failed: {str(_cl_err)[:160]}")

        # Mark complete
        total_elapsed = time.time() - start_time
        await db.whitepapers_in_progress.update_one(
            {"id": whitepaper_id},
            {
                "$set": {
                    "status": "completed",
                    "progress": 100,
                    "progress_message": "Completado",
                    "current_section": total_sections,
                    "total_sections": total_sections,
                    "sections": all_sections,
                    "coherence_evaluation": coherence_evaluation,
                    "completed_at": datetime.now(timezone.utc).isoformat(),
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )
        
        print(f"\n🎉 Whitepaper completed in {total_elapsed:.1f}s ({len(all_sections)} sections)")
        sys.stdout.flush()
        logging.info(f"🎉 Whitepaper {whitepaper_id} completed in {total_elapsed:.1f}s")
        
    except Exception as e:
        import traceback
        traceback.print_exc()
        logging.error(f"❌ Whitepaper generation failed: {str(e)}")
        print(f"❌ Generation failed: {str(e)[:200]}")
        sys.stdout.flush()
        
        await db.whitepapers_in_progress.update_one(
            {"id": whitepaper_id},
            {"$set": {"status": "error", "error_message": str(e)[:500], "progress_message": "Error en generación"}}
        )





@api_router.post("/whitepapers/start-interactive", response_model=dict)
async def start_whitepaper_interactive(whitepaper_input: WhitepaperInput, current_user: User = Depends(get_current_user)):
    """Start creating a technical white paper interactively"""
    
    # Check for recent duplicates (within last 5 seconds with same title and client)
    from datetime import datetime, timedelta, timezone
    five_seconds_ago = datetime.now(timezone.utc) - timedelta(seconds=5)

    # Prepend client name to project_title (same behaviour as Policy Papers)
    client_name_prefix = whitepaper_input.author_name.strip() if whitepaper_input.author_name else ""
    raw_title = whitepaper_input.project_title.strip() if whitepaper_input.project_title else "Technical White Paper"
    if client_name_prefix and not raw_title.startswith(client_name_prefix):
        display_title = f"{client_name_prefix} - {raw_title}"
    else:
        display_title = raw_title
    
    # Search using datetime object (MongoDB stores it as datetime, not string)
    existing = await db.whitepapers_in_progress.find_one({
        "client_id": whitepaper_input.client_id,
        "project_title": display_title,
        "created_at": {"$gte": five_seconds_ago},
        "status": {"$in": ["in_progress", "generating"]}
    }, {"_id": 0})
    
    if existing:
        logging.warning(f"⚠️ Duplicate whitepaper creation prevented for: {display_title}")
        return {
            "whitepaper_id": existing.get('id'),
            "message": "Technical white paper already exists (duplicate prevented)",
            "current_section": existing.get('current_section', 1),
            "total_sections": 16,
            "duplicate_prevented": True
        }
    
    whitepaper = WhitepaperInProgress(
        user_id=current_user.id,
        client_id=whitepaper_input.client_id,
        project_title=display_title,
        author_name=whitepaper_input.author_name,
        author_credentials=whitepaper_input.author_credentials,
        project_description=whitepaper_input.project_description,
        target_audience=whitepaper_input.target_audience,
        technical_domain=whitepaper_input.technical_domain,
        language=whitepaper_input.language,
        sections=[],
        current_section=1,
        status="in_progress",
        # Enhanced CV data
        full_cv_data=whitepaper_input.full_cv_data,
        employment_summary=whitepaper_input.employment_summary,
        years_of_experience=whitepaper_input.years_of_experience
    )
    
    # Insert into database
    await db.whitepapers_in_progress.insert_one(whitepaper.model_dump())
    
    logging.info(f"✅ New whitepaper created: {whitepaper.id} - {display_title}")
    
    return {
        "whitepaper_id": whitepaper.id,
        "message": "Technical white paper started successfully",
        "current_section": 1,
        "total_sections": 16
    }


@api_router.post("/whitepapers/{whitepaper_id}/generate-complete")
async def generate_complete_whitepaper_endpoint(
    whitepaper_id: str,
    background_tasks: BackgroundTasks,
    current_user: User = Depends(get_current_user)
):
    """
    NEW V2 ENDPOINT: Generate complete 16-section whitepaper in background.
    This endpoint returns immediately while generation continues in background.
    
    Returns immediately with whitepaper_id. Use GET endpoint to check progress.
    """
    # Get whitepaper from in-progress collection (no user_id filter to support panel integrations)
    whitepaper = await db.whitepapers_in_progress.find_one(
        {"id": whitepaper_id},
        {"_id": 0}
    )
    
    if not whitepaper:
        raise HTTPException(status_code=404, detail="Whitepaper not found")
    
    project_title = whitepaper.get('project_title', '')
    author_name = whitepaper.get('author_name', '')
    author_credentials = whitepaper.get('author_credentials', '')
    project_description = whitepaper.get('project_description', '')
    target_audience = whitepaper.get('target_audience', '')
    technical_domain = whitepaper.get('technical_domain', '')
    language = whitepaper.get('language', 'en')
    
    if not project_description:
        raise HTTPException(status_code=400, detail="Project description is required")

    # Block generation when the CV is too sparse to ground the biography.
    # Without enough source text the LLM fills gaps with plausible-sounding but
    # fabricated credentials (e.g. "PhD Stanford", "CDS license"). 200 chars is
    # roughly one short paragraph — anything below that cannot anchor a 35k-word
    # whitepaper.
    full_cv_data = whitepaper.get('full_cv_data') or {}
    cv_text_len = len((author_credentials or '').strip())
    has_structured_cv = bool(
        full_cv_data.get('employment_history')
        or full_cv_data.get('education')
        or full_cv_data.get('certifications')
    )
    if cv_text_len < 200 and not has_structured_cv:
        raise HTTPException(
            status_code=400,
            detail=(
                "El CV / credenciales del autor es demasiado corto para generar "
                "el whitepaper sin riesgo de invención. Sube un CV completo o "
                "pega al menos 200 caracteres con educación, experiencia y "
                "certificaciones reales antes de continuar."
            )
        )

    # Check if already generating
    current_status = whitepaper.get('status', 'in_progress')
    if current_status == 'generating':
        return {
            "success": True,
            "whitepaper_id": whitepaper_id,
            "message": "Generation already in progress",
            "status": "generating"
        }
    
    # Reset whitepaper to clean state before starting background generation
    print(f"DEBUG: About to update whitepaper {whitepaper_id} status to generating")
    logging.info(f"[WHITEPAPER] About to update whitepaper {whitepaper_id} status to generating")
    
    await db.whitepapers_in_progress.update_one(
        {"id": whitepaper_id},
        {
            "$set": {
                "status": "generating",
                "progress": 0,
                "sections": [],  # Clear old sections
                "error_message": None,
                "updated_at": datetime.now(timezone.utc).isoformat()
            },
            "$unset": {
                "generation_metadata": ""
            }
        }
    )
    
    print(f"DEBUG: Whitepaper {whitepaper_id} status updated to generating")
    logging.info(f"[WHITEPAPER] Whitepaper {whitepaper_id} status updated to generating")
    print(f"DEBUG: Queuing V2 complete generation for whitepaper {whitepaper_id}")
    logging.info(f"[WHITEPAPER] Queuing V2 complete generation for whitepaper {whitepaper_id}")
    logging.info(f"   Project: {project_title}")
    logging.info(f"   Language: {language}")
    logging.info(f"   Whitepaper reset to clean state for new generation")
    
    # Use threading instead of BackgroundTasks for long-running operations
    # This ensures the task continues even if the HTTP response completes
    import threading
    
    def run_generation_in_thread():
        """Wrapper to run async function in a thread with its own event loop and DB facade."""
        import asyncio
        from db.mongo_compat import get_mongo_compat_db

        loop = asyncio.new_event_loop()
        asyncio.set_event_loop(loop)

        try:
            thread_db = get_mongo_compat_db()
            logging.info("[THREAD] DB facade ready")
            
            # Run generation with thread-local database connection
            loop.run_until_complete(
                generate_whitepaper_background_thread(
                    db=thread_db,
                    whitepaper_id=whitepaper_id,
                    project_title=project_title,
                    author_name=author_name,
                    author_credentials=author_credentials,
                    project_description=project_description,
                    target_audience=target_audience,
                    technical_domain=technical_domain,
                    language=language
                )
            )
            
            # Close MongoDB connection
            client.close()
            logging.info(f"[THREAD] Generation completed for {whitepaper_id}")
        except Exception as e:
            logging.error(f"[THREAD] Error in generation thread: {str(e)}")
            import traceback
            traceback.print_exc()
        finally:
            loop.close()
    
    # Start generation in background thread
    thread = threading.Thread(target=run_generation_in_thread, daemon=True)
    thread.start()
    logging.info(f"✅ Background thread started for whitepaper {whitepaper_id}")
    
    return {
        "success": True,
        "whitepaper_id": whitepaper_id,
        "message": "Generation started in background. This may take 5-10 minutes.",
        "status": "generating",
        "estimated_time_minutes": "5-10",
        "metadata": {
            "generation_time_seconds": 0,
            "background_task": True
        }
    }

@api_router.post("/whitepapers/generate-section/{whitepaper_id}")
async def generate_whitepaper_section(whitepaper_id: str, current_user: User = Depends(get_current_user)):
    """Generate a section for the technical white paper with AI evaluation"""
    
    whitepaper = await db.whitepapers_in_progress.find_one(
        {"id": whitepaper_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not whitepaper:
        raise HTTPException(status_code=404, detail="Whitepaper not found")
    
    section_number = whitepaper.get('current_section', 1)
    
    # Define the 16 sections for technical white papers
    section_titles = [
        "Executive Summary", "Context and Problem", "Target Audience and Use Cases", 
        "State of the Art and Gap Analysis", "Requirements and Assumptions", 
        "Architecture / Solution Design", "Implementation Methodology", 
        "Evaluation and Metrics", "Results and Analysis", 
        "Security, Privacy and Compliance", "Reliability, Scalability and Costs",
        "Risks, Limitations and Mitigation", "Roadmap", 
        "Conclusions and Recommendations", "References", "Appendices"
    ]
    
    # Validate section number is within bounds
    if section_number > len(section_titles):
        raise HTTPException(
            status_code=400, 
            detail=f"All 16 sections have been generated. Cannot generate section {section_number}."
        )
    
    section_title = section_titles[section_number - 1]
    
    # Get previous sections for context
    existing_sections = whitepaper.get('sections', [])
    previous_context = ""
    if existing_sections:
        previous_context = "\n\n".join([f"## {s['title']}\n{s['content']}" for s in existing_sections])
    
    # Create detailed prompt based on your specification - ALL IN ENGLISH to ensure English generation
    section_prompts = {
        1: f"""**Part 1. Executive Summary**\nCreate a rigorous executive summary that includes:

**Project Overview:**
- Identified problem with specific metrics
- Detailed technical proposal
- 3-5 quantifiable benefits
- Project scope and boundaries

**About the Author:**
Expand this into a comprehensive professional biography for {whitepaper['author_name']} that includes:
- Professional title/role and current position
- Years of experience in {whitepaper['technical_domain']}
- Key projects led or contributed to (use realistic examples based on the technical domain)
- Technical certifications or credentials: {whitepaper['author_credentials']}
- Areas of expertise and specialization
- Notable achievements or contributions to the field

**Project Details:**
- Project: {whitepaper['project_title']}
- Description: {whitepaper['project_description']}
- Technical Domain: {whitepaper['technical_domain']}
- Target Audience: {whitepaper['target_audience']}

Use professional, precise, and technical tone. Include concrete examples and realistic metrics. NO PLACEHOLDERS.""",
        
        2: f"**Part 2. Context and Problem**\nDevelop the context and problem with:\n- Technical background of the domain\n- Relevant national/international metrics\n- Quantifiable impact if not resolved\n- Current state of the art\n\nProject: {whitepaper['project_title']}\nDomain: {whitepaper['technical_domain']}\nTarget Audience: {whitepaper['target_audience']}\n\nInclude data tables when appropriate and technical references.",
        
        3: f"**Part 3. Target Audience and Use Cases**\nDefine audience and use cases:\n- Detailed technical user profiles\n- Prioritization matrix (impact vs ease)\n- Specific use stories\n- Requirements by user type\n\nAudience: {whitepaper['target_audience']}\nDomain: {whitepaper['technical_domain']}\n\nUse table format for use cases: | Case | User | Impact | Ease | Priority |",
        
        4: f"**Part 4. State of the Art and Gap Analysis**\nAnalyze the state of the art:\n- Current approaches in {whitepaper['technical_domain']}\n- Comparative table of existing solutions\n- Technical gap analysis\n- Differential advantage of the proposal\n\nUse format: | Criterion | Approach A | Approach B | Our Proposal | Notes |",
        
        5: f"**Part 5. Requirements and Assumptions**\nSpecify technical requirements:\n- Detailed functional requirements\n- Non-functional requirements (SLOs)\n- Technical and business assumptions\n- System constraints\n\nInclude SLOs table: | Service | SLO | Threshold | Measurement | Frequency |",
        
        6: f"**Part 6. Architecture / Solution Design**\nDesign the architecture:\n- System overview\n- Main components and responsibilities\n- Data flows and communication\n- Technical design decisions\n\nProject: {whitepaper['project_title']}\nDomain: {whitepaper['technical_domain']}",
        
        7: f"**Part 7. Implementation Methodology**\nDefine implementation methodology:\n- Phases: MVP → pilot → production\n- Quality assurance processes\n- Detailed schedule\n- Required resources\n\nInclude specific milestones and acceptance criteria.",
        
        8: f"**Part 8. Evaluation and Metrics**\nDesign evaluation and metrics:\n- Experimental design\n- KPIs with specific formulas\n- Measurable success criteria\n- Robustness methodology\n\nUse format: | KPI | Definition | Formula | Baseline | Target | Verification |",
        
        9: f"**Part 9. Results and Analysis**\nPresent results and analysis:\n- Key project findings\n- Comparison with baseline\n- Technical discussion of results\n- Metrics interpretation\n\nInclude statistical analysis and technical significance.",
        
        10: f"**Part 10. Security, Privacy and Compliance**\nAddress security and compliance:\n- Specific threat model\n- Technical security controls\n- Applicable regulatory frameworks\n- Data privacy policies\n\nDomain: {whitepaper['technical_domain']}",
        
        11: f"**Part 11. Reliability, Scalability and Costs**\nAnalyze reliability and costs:\n- Reliability analysis (MTTR, MTBF)\n- Scaling strategies\n- TCO (Total Cost of Ownership)\n- Estimated ROI with formulas\n\nInclude technical financial projections.",
        
        12: f"**Part 12. Risks, Limitations and Mitigation**\nRisk management:\n- Complete technical risk register\n- Known system limitations\n- Detailed mitigation plan\n- Technical contingencies\n\nUse format: | Risk | Probability | Impact | Mitigation | Trigger |",
        
        13: f"**Part 13. Roadmap**\nDetailed roadmap:\n- Milestones at 30/60/90 days\n- 12-month planning\n- Critical dependencies\n- Resources and budget\n\nInclude specific technical timeline.",
        
        14: f"**Part 14. Conclusions and Recommendations**\nTechnical conclusions:\n- Hypothesis validation\n- Specific recommendations\n- Technical next steps\n- Expected impact\n\nSummarize technical and commercial value of the project.",
        
        15: f"**Part 15. References**\nTechnical bibliography:\n- References in IEEE/APA format\n- DOI/URL when possible\n- Cited technical standards\n- Data sources used\n\nMinimum 10 relevant technical references to {whitepaper['technical_domain']}.",
        
        16: f"**Part 16. Appendices**\nTechnical appendices:\n- Glossary of technical terms\n- Detailed protocols\n- Algorithm pseudocode\n- APIs and specifications\n- Extended data tables\n\nInclude detailed supplementary technical information."
    }
    
    prompt = section_prompts.get(section_number, f"Generate section {section_number}: {section_title}")
    
    system_message = f"""You are Monica, a senior technical writer and strategist specialized in creating rigorous, well-structured technical white papers.

CRITICAL INSTRUCTION: You MUST write EXCLUSIVELY in ENGLISH. Do NOT write in Spanish or any other language.

You create expert-level content with:
- Professional, precise, technical tone
- Tables, formulas, and procedures where appropriate
- **Use in-text citations (e.g., "according to Smith et al., 2023") when referencing sources, but DO NOT include a References section at the end of this part**
- **CRITICAL: NEVER use placeholders like <TO_BE_SUPPLIED>. Always use concrete examples, realistic data, or omit the section if information is truly unavailable**
- When specific metrics are unknown, provide realistic industry-standard examples or benchmarks
- Use actual technology names (e.g., "Kubernetes, Docker, PostgreSQL" instead of "<CONTAINER_PLATFORM>")
- Structured markdown format with proper headers (###), bold (**text**), and tables
- **IMPORTANT: Do NOT add a "References" subsection at the end. All references will be consolidated in Part 15 at the end of the document**

CONTEXT OF PREVIOUS SECTIONS:
{previous_context}

Create a comprehensive section with technical depth appropriate for experts in {whitepaper['technical_domain']}.

REMINDER: Write ONLY in ENGLISH. The content will be translated to Spanish later. NO PLACEHOLDERS - use concrete examples. DO NOT add a References section at the end of this part."""
    
    # Auto-validation loop with AI evaluator
    max_attempts = 3
    attempt = 0
    evaluation_passed = False
    final_content_en = None
    final_content_es = None
    validation_warning = None
    evaluation_history = []
    base_prompt = prompt
    current_max_tokens = 10000  # Increased from 8000 to 10000 to prevent truncation
    
    while attempt < max_attempts and not evaluation_passed:
        attempt += 1
        logging.info(f"📝 Generating Whitepaper section {section_number} in ENGLISH - Attempt {attempt}/{max_attempts}")
        logging.info(f"   Using max_tokens: {current_max_tokens}")
        
        # STEP 1: Generate content in ENGLISH using OpenAI GPT-5.1
        content_en = await call_openai_gpt5(system_message, prompt, temperature=0.7, max_tokens=current_max_tokens)
        
        # LOG RAW CONTENT TO VERIFY LANGUAGE - Critical debugging for data corruption issue
        logging.info(f"   🔍 RAW ENGLISH CONTENT (first 500 chars): {content_en[:500] if content_en else 'EMPTY'}")
        
        # Check if content is empty or too short
        if not content_en or len(content_en.strip()) < 100:
            logging.error(f"   ❌ Empty or insufficient content generated (length: {len(content_en) if content_en else 0})")
            
            if attempt < max_attempts:
                logging.warning(f"   🔄 Retrying with adjusted parameters...")
                # Reduce prompt complexity for retry - MUST BE IN ENGLISH
                simplified_prompt = f"""Write a comprehensive {section_title} section for this technical white paper.

Technical Domain: {whitepaper['technical_domain']}
Target Audience: {whitepaper['target_audience']}

Requirements:
- Minimum 2000 characters
- Professional technical tone
- Include specific examples, metrics, and technical details
- Use proper markdown formatting (### headers, **bold**, tables)
- WRITE ONLY IN ENGLISH

Create the section now with rich technical content IN ENGLISH."""
                prompt = simplified_prompt
                continue  # Skip to next attempt
            else:
                logging.error(f"   ❌ Failed to generate content after {max_attempts} attempts")
                raise HTTPException(
                    status_code=500,
                    detail=f"Failed to generate content for section {section_number} after {max_attempts} attempts. Please try again."
                )
        
        logging.info(f"   ✅ English content generated, length: {len(content_en)} characters")
        
        # Evaluate with AI (whitepaper-specific evaluator) - evaluate English content
        logging.info(f"   🔍 Starting AI evaluation for attempt {attempt}...")
        evaluation = await evaluate_whitepaper_section_quality(
            content=content_en,
            section_type=section_title,
            previous_content=previous_context
        )
        
        evaluation_history.append({
            "attempt": attempt,
            "evaluation": evaluation,
            "content_length": len(content_en)
        })
        
        if evaluation["passes"]:
            evaluation_passed = True
            final_content_en = content_en
            logging.info(f"   ✅ Whitepaper Section PASSED validation on attempt {attempt}")
        else:
            logging.warning(f"   ❌ Whitepaper Section FAILED validation on attempt {attempt}")
            logging.warning(f"   Issues found: {evaluation.get('issues', [])}")
            logging.warning(f"   Feedback: {evaluation.get('feedback', '')}")
            
            # Build specific correction instructions
            correction_details = f"""
**PREVIOUS ATTEMPT FAILED VALIDATION - ATTEMPT {attempt}**

**SPECIFIC PROBLEMS DETECTED BY TECHNICAL EVALUATOR:**
{chr(10).join(['- ' + str(issue) for issue in evaluation.get('issues', [])])}

**DETAILED FEEDBACK:**
{evaluation.get('feedback', '')}

**TECHNICAL METRICS:**
- Character Count: {evaluation.get('character_count', len(content_en))} (Required: minimum 1500)
- Technical Depth: {'❌ INSUFFICIENT' if not evaluation.get('has_technical_depth') else '✅ Adequate'}
- Proper Structure: {'❌ NEEDS IMPROVEMENT' if not evaluation.get('has_proper_structure') else '✅ Good'}
- Evidence-Based: {'❌ MISSING' if not evaluation.get('has_evidence') else '✅ Present'}

**CRITICAL INSTRUCTIONS FOR REGENERATION:**
1. Address EACH technical issue listed above
2. Ensure minimum 1500 characters with technical depth
3. Include specific methodologies, metrics, and technical details
4. Add evidence-based content (data, standards, references)
5. Follow professional white paper structure
6. Use technical language appropriate for experts

Please regenerate the section now, addressing ALL these technical requirements."""

            # Update prompt with specific corrections
            prompt = base_prompt + correction_details
    
    # STEP 2: Translate to Spanish if generation passed
    if evaluation_passed and final_content_en:
        logging.info(f"   🌍 Translating section {section_number} to SPANISH...")
        try:
            translation_system = """You are a professional technical translator. Translate technical white papers accurately while maintaining:
- Technical terminology precision
- Professional academic tone
- Markdown formatting (###, **, tables)
- IEEE/APA citation formats
- Technical depth and rigor"""
            
            translation_prompt = f"""Translate the following technical white paper section from English to Spanish. Maintain all markdown formatting, technical precision, and professional tone.

SECTION TITLE: {section_title}
TECHNICAL DOMAIN: {whitepaper['technical_domain']}

ENGLISH CONTENT:
{final_content_en}

Provide ONLY the translated Spanish content, maintaining all markdown formatting."""
            
            final_content_es = await call_openai_gpt4o(
                translation_system,
                translation_prompt,
                temperature=0.3,
                max_tokens=8000  # Increased from 4000 to 8000 to handle long content
            )
            
            logging.info(f"   ✅ Spanish translation completed: {len(final_content_es)} characters")
            
            # LOG TRANSLATED CONTENT TO VERIFY LANGUAGE - Critical debugging
            logging.info(f"   🔍 RAW SPANISH CONTENT (first 500 chars): {final_content_es[:500] if final_content_es else 'EMPTY'}")
            
        except Exception as trans_error:
            logging.error(f"   ❌ Translation error: {str(trans_error)}")
            final_content_es = final_content_en  # Fallback to English if translation fails
    
    # STEP 3: Convert Markdown to HTML
    import markdown
    import re
    
    # Clean excessive line breaks from markdown before converting to HTML
    def clean_markdown_linebreaks(text):
        """Remove excessive line breaks from markdown while preserving intentional spacing"""
        if not text:
            return text
        
        # Replace 4+ consecutive newlines with just 2 (paragraph break)
        text = re.sub(r'\n{4,}', '\n\n', text)
        
        # Replace 3 consecutive newlines with 2
        text = re.sub(r'\n{3}', '\n\n', text)
        
        # Clean up spaces before newlines
        text = re.sub(r' +\n', '\n', text)
        
        # Clean up multiple spaces
        text = re.sub(r'  +', ' ', text)
        
        # Remove trailing whitespace from lines
        lines = text.split('\n')
        lines = [line.rstrip() for line in lines]
        text = '\n'.join(lines)
        
        # Remove empty lines between list items
        text = re.sub(r'(\n- [^\n]+)\n\n(\n- )', r'\1\n\2', text)
        
        return text
    
    def post_process_html(html_content):
        """Clean up HTML to remove excessive spacing"""
        if not html_content:
            return html_content
        
        # Remove multiple consecutive <br> tags
        html_content = re.sub(r'(<br\s*/?>){3,}', '<br/><br/>', html_content)
        
        # Remove <br> before closing paragraph tags
        html_content = re.sub(r'<br\s*/?>\s*</p>', '</p>', html_content)
        
        # Remove <br> after opening paragraph tags
        html_content = re.sub(r'<p>\s*<br\s*/?>', '<p>', html_content)
        
        # Remove excessive empty paragraphs
        html_content = re.sub(r'(<p>\s*</p>\s*){2,}', '<p></p>', html_content)
        
        # Remove completely empty paragraphs
        html_content = re.sub(r'<p>\s*</p>', '', html_content)
        
        return html_content
    
    if final_content_en:
        logging.info(f"   🔄 Converting Markdown to HTML...")
        # Clean excessive linebreaks before conversion
        final_content_en_cleaned = clean_markdown_linebreaks(final_content_en)
        # Don't use nl2br extension - it converts ALL newlines to <br>
        final_content_en_html = markdown.markdown(final_content_en_cleaned, extensions=['tables', 'fenced_code'])
        # Post-process HTML to remove excessive spacing
        final_content_en_html = post_process_html(final_content_en_html)
        logging.info(f"   ✅ English HTML conversion complete")
    else:
        final_content_en_html = content_en if 'content_en' in locals() else ""
        
    if final_content_es:
        # Clean excessive linebreaks before conversion
        final_content_es_cleaned = clean_markdown_linebreaks(final_content_es)
        # Don't use nl2br extension
        final_content_es_html = markdown.markdown(final_content_es_cleaned, extensions=['tables', 'fenced_code'])
        # Post-process HTML to remove excessive spacing
        final_content_es_html = post_process_html(final_content_es_html)
        logging.info(f"   ✅ Spanish HTML conversion complete")
    else:
        final_content_es_html = final_content_en_html
    
    # Create validation warning if failed
    if not evaluation_passed:
        final_content_en = content_en if 'content_en' in locals() else ""
        # BUG FIX: Do NOT copy English content to Spanish field - generate proper translation
        # This was causing data corruption where content_es contained English text
        logging.warning(f"⚠️ Section failed validation - generating translation anyway to prevent data corruption")
        
        # Generate Spanish translation even if evaluation failed
        try:
            translation_system = """You are a professional technical translator. Translate technical white papers accurately while maintaining:
- Technical terminology precision
- Professional academic tone
- Markdown formatting (###, **, tables)
- IEEE/APA citation formats
- Technical depth and rigor"""
            
            translation_prompt = f"""Translate the following technical white paper section from English to Spanish. Maintain all markdown formatting, technical precision, and professional tone.

SECTION TITLE: {section_title}
TECHNICAL DOMAIN: {whitepaper['technical_domain']}

ENGLISH CONTENT:
{final_content_en}

Provide ONLY the translated Spanish content, maintaining all markdown formatting."""
            
            final_content_es = await call_openai_gpt4o(
                translation_system,
                translation_prompt,
                temperature=0.3,
                max_tokens=8000
            )
            logging.info(f"   ✅ Spanish translation completed for failed section: {len(final_content_es)} characters")
        except Exception as trans_error:
            logging.error(f"   ❌ Translation error on failed section: {str(trans_error)}")
            final_content_es = final_content_en  # Only fallback on translation error
        
        final_content_en_html = final_content_en
        final_content_es_html = final_content_es
        logging.error(f"WARNING Whitepaper Section did not pass validation after {max_attempts} attempts")
        
        validation_warning = {
            "title": "Sección técnica requiere mejoras",
            "summary": "El evaluador IA detectó deficiencias técnicas que comprometen la calidad del white paper.",
            "issues": evaluation.get('issues', []),
            "feedback": evaluation.get('feedback', ''),
            "recommendation": "Revise la sección para incluir mayor profundidad técnica, métricas específicas y evidencia antes de continuar.",
            "metrics": {
                "character_count": evaluation.get('character_count', len(final_content_en)),
                "required_range": "mínimo 1500 caracteres técnicos",
                "has_technical_depth": evaluation.get('has_technical_depth', False),
                "has_proper_structure": evaluation.get('has_proper_structure', True),
                "has_evidence": evaluation.get('has_evidence', False)
            }
        }
    
    section = {
        "number": section_number,
        "title": section_title,
        "content": final_content_es_html,  # Default to Spanish HTML for display
        "content_en": final_content_en_html,  # English HTML
        "content_es": final_content_es_html,  # Spanish HTML
        "approved": False,
        "edit_history": [],
        "validation_warning": validation_warning,
        "evaluation_history": evaluation_history
    }
    
    # LOG FINAL DATA BEFORE SAVING - Critical for debugging data corruption
    logging.info(f"   💾 FINAL DATA BEFORE DB SAVE:")
    logging.info(f"      content_en (first 300 chars): {final_content_en_html[:300] if final_content_en_html else 'EMPTY'}")
    logging.info(f"      content_es (first 300 chars): {final_content_es_html[:300] if final_content_es_html else 'EMPTY'}")
    
    
    # Auto-save section if it passed evaluation
    if evaluation_passed:
        whitepaper_sections = whitepaper.get('sections', [])
        section_exists = False
        
        # Update or add section
        for i, s in enumerate(whitepaper_sections):
            if s['number'] == section_number:
                whitepaper_sections[i] = section
                section_exists = True
                break
        
        if not section_exists:
            whitepaper_sections.append(section)
        
        # Update whitepaper in database
        await db.whitepapers_in_progress.update_one(
            {"id": whitepaper_id},
            {
                "$set": {
                    "sections": whitepaper_sections,
                    # DO NOT increment current_section here - will be incremented on approval
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )
        
        logging.info(f"✅ Whitepaper section {section_number} automatically saved after passing evaluation")
    
    return {"section": section}

@api_router.post("/whitepapers/approve-section/{whitepaper_id}")
async def approve_whitepaper_section(
    whitepaper_id: str, 
    section_data: dict = None,
    current_user: User = Depends(get_current_user)
):
    """Approve current section and move to next. Auto-finalizes on section 16."""
    logging.info(f"📋 Approve section request for whitepaper {whitepaper_id}")
    logging.info(f"   Section data: {section_data.get('number') if section_data else 'None'}")
    
    whitepaper = await db.whitepapers_in_progress.find_one(
        {"id": whitepaper_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not whitepaper:
        logging.error(f"   ❌ Whitepaper not found: {whitepaper_id}")
        raise HTTPException(status_code=404, detail="Whitepaper not found")
    
    # Get section number from the provided section data or use current_section
    if section_data and 'number' in section_data:
        current_section_number = section_data['number']
    else:
        current_section_number = whitepaper.get('current_section', 1)
    
    logging.info(f"   Approving section {current_section_number}")
    
    sections = whitepaper.get('sections', [])
    
    # Find and approve current section
    section_found = False
    for section in sections:
        if section['number'] == current_section_number:
            section['approved'] = True
            section_found = True
            break
    
    if not section_found:
        logging.warning(f"Section {current_section_number} not found in whitepaper {whitepaper_id}")
    
    # Update whitepaper - cap next_section at 17 (after completing section 16)
    next_section = min(current_section_number + 1, 17)
    await db.whitepapers_in_progress.update_one(
        {"id": whitepaper_id},
        {
            "$set": {
                "sections": sections,
                "current_section": next_section,
                "updated_at": datetime.now(timezone.utc).isoformat()
            }
        }
    )
    
    # AUTO-FINALIZE if section 16 was just approved
    if current_section_number == 16:
        logging.info(f"🎯 Section 16 approved - AUTO-FINALIZING whitepaper")
        
        # Call the finalize logic inline
        try:
            # Finalize the whitepaper
            finalized_id = await finalize_whitepaper_inline(whitepaper_id, current_user)
            
            logging.info(f"✅ Whitepaper auto-finalized successfully with ID: {finalized_id}")
            
            return {
                "message": "Section 16 approved and whitepaper finalized successfully",
                "current_section": 17,
                "total_sections": 16,
                "finalized": True,
                "finalized_id": finalized_id
            }
        except Exception as e:
            logging.error(f"❌ Error auto-finalizing whitepaper: {str(e)}")
            # Return normal response even if finalization fails
            return {
                "message": "Section approved successfully",
                "current_section": next_section,
                "total_sections": 16,
                "finalized": False,
                "error": str(e)
            }
    
    return {
        "message": "Section approved successfully",
        "current_section": next_section,
        "total_sections": 16
    }

# Helper function for inline finalization
async def finalize_whitepaper_inline(whitepaper_id: str, current_user: User):
    """Internal helper to finalize whitepaper"""
    whitepaper = await db.whitepapers_in_progress.find_one(
        {"id": whitepaper_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not whitepaper:
        raise Exception("Whitepaper not found")
    
    sections = whitepaper.get('sections', [])
    if not sections:
        raise Exception("No sections found")
    
    # Sort sections by number
    sections_sorted = sorted(sections, key=lambda x: x.get('number', 0))
    
    # Compile content
    compiled_content = f"# {whitepaper['project_title']}\n\n"
    compiled_content += f"**Author:** {whitepaper['author_name']}\n"
    compiled_content += f"**Credentials:** {whitepaper['author_credentials']}\n"
    compiled_content += f"**Technical Domain:** {whitepaper['technical_domain']}\n\n"
    
    for section in sections_sorted:
        compiled_content += f"\n## {section['number']}. {section['title']}\n\n"
        compiled_content += section.get('content_es', section.get('content', ''))
        compiled_content += "\n\n"
    
    # 🔍 FIRECRAWL-BACKED PLACEHOLDER RESOLUTION
    # Walk every section and resolve any `[pending information]`, `[NEEDED: …]`,
    # `[TBD: …]`, `[to be determined: …]` placeholder by querying Firecrawl
    # against government / academic sources and replacing them inline. This
    # runs BEFORE persisting the final document so the stored content is
    # already clean — no placeholders ever reach the PDF.
    try:
        logging.info(f"🔍 [FIRECRAWL] Resolving placeholders in {len(sections)} sections (whitepaper {whitepaper_id})")
        for _sec in sections:
            for _fld in ("content_en", "content_es", "content"):
                _val = _sec.get(_fld)
                if not _val or not isinstance(_val, str):
                    continue
                if "[" not in _val:
                    continue  # skip fast when no brackets at all
                try:
                    _sec[_fld] = await resolve_placeholders_with_firecrawl(_val)
                except Exception as _resolve_err:
                    logging.warning(
                        f"⚠️  [FIRECRAWL] Section {_sec.get('number','?')} {_fld} "
                        f"resolution failed: {str(_resolve_err)[:120]}"
                    )
        # Recompile `compiled_content` from the now-resolved sections so the
        # `content` field saved at the top level reflects the Firecrawl-resolved
        # text (without it the stored `content` would still have placeholders,
        # even though the per-section content_en/content_es are clean).
        _recompiled = ""
        for _sec in sections_sorted:
            _recompiled += f"\n## {_sec['number']}. {_sec['title']}\n\n"
            _recompiled += _sec.get('content_es', _sec.get('content', ''))
            _recompiled += "\n\n"
        compiled_content = _recompiled
        logging.info("✅ [FIRECRAWL] Placeholder resolution completed")
    except Exception as _fc_err:
        logging.warning(f"⚠️  [FIRECRAWL] Placeholder resolution failed globally: {str(_fc_err)[:160]}")

    # Create final whitepaper
    final_whitepaper = Whitepaper(
        user_id=current_user.id,
        client_id=whitepaper.get('client_id'),
        project_title=whitepaper['project_title'],
        author_name=whitepaper['author_name'],
        author_credentials=whitepaper['author_credentials'],
        project_description=whitepaper['project_description'],
        target_audience=whitepaper['target_audience'],
        technical_domain=whitepaper['technical_domain'],
        language=whitepaper['language'],
        content=compiled_content,
        status="completed"
    )
    
    # Save final whitepaper with sections
    whitepaper_dict = final_whitepaper.model_dump()
    whitepaper_dict['sections'] = sections  # Preserve individual sections for viewing
    whitepaper_dict['finalized_at'] = datetime.now(timezone.utc).isoformat()
    # ✅ Copiar coherence_evaluation desde whitepapers_in_progress
    if whitepaper.get('coherence_evaluation'):
        whitepaper_dict['coherence_evaluation'] = whitepaper['coherence_evaluation']
    await db.whitepapers.insert_one(whitepaper_dict)
    
    # Delete from in-progress
    await db.whitepapers_in_progress.delete_one({"id": whitepaper_id})
    
    return final_whitepaper.id

@api_router.post("/whitepapers/regenerate-section/{whitepaper_id}")
async def regenerate_whitepaper_section(
    whitepaper_id: str,
    request: dict,
    current_user: User = Depends(get_current_user)
):
    """Regenerate a whitepaper section, using evaluation feedback to improve quality"""
    
    whitepaper = await db.whitepapers_in_progress.find_one(
        {"id": whitepaper_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not whitepaper:
        raise HTTPException(status_code=404, detail="Whitepaper not found")
    
    section_number = request.get('section_number')
    previous_evaluation = request.get('previous_evaluation', [])
    
    if not section_number:
        raise HTTPException(status_code=400, detail="section_number is required")
    
    # Define the 16 sections for technical white papers
    section_titles = [
        "Executive Summary", "Context and Problem", "Target Audience and Use Cases", 
        "State of the Art and Gap Analysis", "Requirements and Assumptions", 
        "Architecture / Solution Design", "Implementation Methodology", 
        "Evaluation and Metrics", "Results and Analysis", 
        "Security, Privacy and Compliance", "Reliability, Scalability and Costs",
        "Risks, Limitations and Mitigation", "Roadmap", 
        "Conclusions and Recommendations", "References", "Appendices"
    ]
    
    if section_number < 1 or section_number > 16:
        raise HTTPException(status_code=400, detail="Invalid section number")
    
    section_title = section_titles[section_number - 1]
    
