@api_router.post("/recommendation-letters/generate")
async def generate_recommendation_letter(
    background_tasks: BackgroundTasks,
    candidate_cv: UploadFile = File(..., description="CV del Candidato (obligatorio)"),
    project_info: UploadFile = File(..., description="Información del Proyecto (obligatorio)"),
    recommender_cv: UploadFile = File(..., description="CV del Firmante (obligatorio)"),
    client_id: Optional[str] = Form(None),
    # Texto libre que escribe el operador con el contexto de la relación entre
    # el firmante (recommender) y el candidato. Mejora dramáticamente la calidad
    # del párrafo 3 ("Professional Relationship") y la verificación de logros,
    # porque el LLM ya no tiene que inferirlo desde el CV — recibe la versión
    # textual de cómo se conocen, hace cuánto, en qué proyectos colaboraron, etc.
    relationship_context: Optional[str] = Form(""),
    current_user: User = Depends(get_current_user)
):
    """
    Generate a complete professional recommendation letter for EB-2 NIW from 3 required documents.
    Returns immediately with letter_id and status='generating'. Poll GET /recommendation-letters/{id}.
    """
    letter_id = str(uuid.uuid4())

    # Read file contents NOW — UploadFile cannot be used after request context closes
    candidate_cv_bytes = await candidate_cv.read()
    project_info_bytes = await project_info.read()
    recommender_cv_bytes = await recommender_cv.read()

    # Create letter document immediately
    from letter_format_profiles import pick_random_profile
    from datetime import datetime as dt
    format_profile = pick_random_profile()
    today_str = dt.now().strftime("%B %d, %Y")

    relationship_context = (relationship_context or "").strip()

    letter_doc = {
        "id": letter_id,
        "user_id": current_user.id,
        "client_id": client_id,
        "candidate_name": "",
        "candidate_field": "",
        "recommender_name": "",
        "recommender_organization": "",
        "project_title": "",
        "visa_type": "EB-2 NIW",
        "content_en": "",
        "content_es": "",
        "current_language": "en",
        "status": "generating",
        "format_profile_id": format_profile["id"],
        "progress_percentage": 5,
        "progress_message": "Extrayendo texto de los documentos...",
        "relationship_context": relationship_context,  # auditoría
        "created_at": datetime.now(timezone.utc).isoformat(),
        "updated_at": datetime.now(timezone.utc).isoformat()
    }
    await db.recommendation_letters.insert_one(letter_doc)

    background_tasks.add_task(
        _generate_recommendation_letter_background,
        letter_id, candidate_cv_bytes, candidate_cv.filename,
        project_info_bytes, project_info.filename,
        recommender_cv_bytes, recommender_cv.filename,
        format_profile, today_str, client_id, current_user.id,
        relationship_context,
    )

    return {"letter_id": letter_id, "status": "generating", "message": "Generación iniciada en segundo plano"}


async def _generate_recommendation_letter_background(
    letter_id: str,
    candidate_cv_bytes: bytes, candidate_cv_filename: str,
    project_info_bytes: bytes, project_info_filename: str,
    recommender_cv_bytes: bytes, recommender_cv_filename: str,
    format_profile: dict, today_str: str, client_id: str, user_id: str,
    relationship_context: str = "",
):
    """Background task: runs the AI calls and updates recommendation letter document."""

    async def _update(pct: int, msg: str, extra: dict = None):
        upd = {"progress_percentage": pct, "progress_message": msg, "updated_at": datetime.now(timezone.utc).isoformat()}
        if extra:
            upd.update(extra)
        await db.recommendation_letters.update_one({"id": letter_id}, {"$set": upd})

    try:
        from recommendation_letter_endpoints import RECOMMENDATION_ANTI_PLACEHOLDER_RULE
        import io as _io

        def _extract_bytes(content: bytes, filename: str) -> str:
            if filename.lower().endswith('.pdf'):
                reader = PdfReader(_io.BytesIO(content))
                return "\n".join(p.extract_text() or "" for p in reader.pages)
            elif filename.lower().endswith('.docx'):
                doc = docx.Document(_io.BytesIO(content))
                return "\n".join(p.text for p in doc.paragraphs)
            else:
                return content.decode('utf-8', errors='ignore')

        await _update(15, "Extrayendo texto de los documentos...")
        candidate_cv_text = _extract_bytes(candidate_cv_bytes, candidate_cv_filename)
        project_info_text = _extract_bytes(project_info_bytes, project_info_filename)
        recommender_cv_text = _extract_bytes(recommender_cv_bytes, recommender_cv_filename)

        await _update(30, "Analizando documentos con IA...")

        # Bloque opcional con contexto operador-provisto sobre la relación
        # firmante↔candidato. Se incluye SOLO si el operador escribió algo;
        # cuando está vacío no agregamos sección en blanco para no enseñarle al
        # LLM a inventarse contexto cuando no lo tiene.
        relationship_block_analysis = (
            f"\n\n**OPERATOR-PROVIDED RELATIONSHIP CONTEXT (firmante ↔ candidato):**\n"
            f"This is direct information from the URPE IS team about how the recommender knows "
            f"the candidate. Treat it as authoritative when extracting `recommender_relationship`. "
            f"If it conflicts with the CVs, the operator context wins.\n\n"
            f"{relationship_context[:3000]}"
        ) if relationship_context else ""

        analysis_prompt = f"""You are analyzing three documents for generating a professional EB-2 NIW recommendation letter aligned with Matter of Dhanasar, 26 I&N Dec. 884 (AAO 2016).

**DOCUMENT 1 - CANDIDATE'S CV:**
{candidate_cv_text[:8000]}

**DOCUMENT 2 - PROJECT INFORMATION:**
{project_info_text[:8000]}

**DOCUMENT 3 - RECOMMENDER'S CV:**
{recommender_cv_text[:6000]}{relationship_block_analysis}

Extract and return ONLY a JSON object with this structure:
{{
  "candidate_name": "Full name from candidate CV",
  "candidate_field": "Specific field of expertise (be precise, e.g., 'Healthcare AI and Clinical Decision Support')",
  "candidate_position": "Current position and organization",
  "candidate_achievements": "Key publications, patents, awards, specific accomplishments with numbers",
  "candidate_unique_skills": "3-4 unique skills or skill combinations that are rare in the U.S. workforce",
  "project_title": "Title/name of the project from project document",
  "project_description": "Detailed description of what the project is about and how it works",
  "project_national_importance": "Why this project matters to the U.S. at a national level (not just local)",
  "project_technical_details": "Technical specifics: methodologies, technologies, innovations",
  "project_geographic_reach": "Number of states, organizations, or people affected by this project",
  "project_economic_impact": "Economic value, cost savings, revenue, or jobs created/supported",
  "project_federal_alignment": "Which federal laws or policies this project aligns with",
  "recommender_name": "Full name from recommender CV",
  "recommender_title": "Professional title/position",
  "recommender_organization": "Current institution/organization",
  "recommender_credentials": "Key qualifications, publications, years of experience, awards",
  "recommender_relationship": "How the recommender knows the candidate, duration, nature of collaboration",
  "recommender_email": "Email if available",
  "recommender_phone": "Phone if available"
}}
IMPORTANT: Extract real, specific information from all three documents. Be thorough and precise."""

        analysis_raw = await asyncio.wait_for(
            call_openai_gpt4o("You are an expert at analyzing documents. Return only valid JSON.", analysis_prompt, temperature=0.3, max_tokens=2000),
            timeout=90.0
        )
        analysis_raw = analysis_raw.strip()
        if analysis_raw.startswith('```'):
            analysis_raw = analysis_raw.split('```')[1]
            if analysis_raw.startswith('json'):
                analysis_raw = analysis_raw[4:]
        extracted_data = json.loads(analysis_raw.strip())

        # Select profile based on recommender's credentials.
        # 60/40 weighted picker: usually the voice that matches the recommender's
        # background, but 40% of the time a random voice so two letters by the
        # same recommender don't come out identical.
        from letter_format_profiles import (
            pick_profile_for_signer,
            pick_sign_off,
            make_style_salt,
            pick_temperature,
        )
        rec_title = extracted_data.get('recommender_title', '')
        rec_creds = extracted_data.get('recommender_credentials', '')
        rec_org   = extracted_data.get('recommender_organization', '')
        format_profile = pick_profile_for_signer(
            f"{rec_title} {rec_creds} {rec_org}",
            random_ratio=0.4,
        )

        chosen_sign_off = pick_sign_off(format_profile)
        style_salt = make_style_salt()
        gen_temperature = pick_temperature()

        # Precomputed para inyectar limpio en la f-string del generation_prompt.
        # Python < 3.12 no permite backslashes (`\n`) en expresiones `{...}`
        # dentro de f-strings — por eso construimos el bloque acá y solo
        # interpolamos la variable (sin expresiones complejas) más abajo.
        relationship_block_generation = (
            "\n## OPERATOR-PROVIDED RELATIONSHIP CONTEXT (firmante ↔ candidato):\n"
            "This is verified context from the URPE IS team about how the recommender "
            "and the candidate know each other (duration, nature of collaboration, projects together, "
            "what the recommender directly observed). Use it as the SOURCE OF TRUTH for Paragraph 3 "
            "(Professional Relationship), Paragraphs 7-9 (Three Achievement Paragraphs — verified events), "
            "and Paragraph 13 (Comparative Exceptionality). Quote concrete details (dates, project names, "
            "specific events) from this context — they are real, not invented.\n\n"
            f"{relationship_context}\n"
        ) if relationship_context else ""

        generation_prompt = f"""Generate a professional EB-2 NIW recommendation letter following the Dhanasar 3-Prong NIW structure.

{style_salt}

**CURRENT DATE: {today_str}** — Use this exact date on the letter. Never invent a different date.

{format_profile['prompt_instructions']}

---
## CANDIDATE (PETITIONER) INFORMATION:
- Full Name: {extracted_data['candidate_name']}
- Field: {extracted_data['candidate_field']}
- Current Position: {extracted_data['candidate_position']}
- Key Achievements & Credentials: {extracted_data['candidate_achievements']}

## PROJECT / PROPOSED ENDEAVOR:
- Title: {extracted_data.get('project_title', 'N/A')}
- Description: {extracted_data.get('project_description', 'N/A')}
- National Importance: {extracted_data.get('project_national_importance', 'N/A')}
- Technical Details: {extracted_data.get('project_technical_details', 'N/A')}

## RECOMMENDER (LETTER SIGNER) INFORMATION:
- Full Name: {extracted_data['recommender_name']}
- Title: {extracted_data['recommender_title']}
- Organization: {extracted_data['recommender_organization']}
- Credentials & Expertise: {extracted_data['recommender_credentials']}
- Email: {extracted_data.get('recommender_email', '')}
- Phone: {extracted_data.get('recommender_phone', '')}
{relationship_block_generation}
---
## MANDATORY FORMAT — Flowing Professional Letter (NO section headers):

CRITICAL FORMAT RULES:
- Write as a continuous professional letter with 12-14 flowing paragraphs.
- DO NOT use section titles, section numbers, or heading-style text of any kind.
- DO NOT label sections as "SECTION 1", "SECTION 2:", "PRONG 1:", "I.", "II.", "CONCLUSION:", or similar.
- DO NOT use <h1>, <h2>, <h3>, <h4>, or any HTML heading tags.
- Use ONLY <p> tags for all paragraph content.
- Use <strong> only for metrics or key terms WITHIN a paragraph, never as a standalone title.
- Do NOT insert empty <p> or <br> tags between paragraphs.
- The letter reads as a traditional professional narrative — identical in style to a formal reference letter.

LETTER CONTENT (one paragraph per item — no titles, no labels):

Paragraph 1 (Header + Opening): Write date ({today_str}), USCIS address block, and "Re: Letter of Recommendation — {extracted_data['candidate_name']}, EB-2 National Interest Waiver" as plain text. Salutation: "Dear USCIS Adjudicating Officer:". Then recommender introduces themselves: full name, title, institution, years of experience, how long and in what capacity they have known {extracted_data['candidate_name']}. Purpose: to recommend {extracted_data['candidate_name']} for the EB-2 NIW.

Paragraph 2 (Recommender Credentials): Recommender's key qualifications, publications, awards, projects. Establishes authority and why they are credible to evaluate this field.

Paragraph 3 (Professional Relationship): Specific nature, duration, and depth of professional collaboration with {extracted_data['candidate_name']}. Frequency and type of interaction. Specific aspects of the candidate's work the recommender personally witnessed.

Paragraph 4 (National Gap — Government Source): Cite a REAL government statistic (BLS, NIH, NSF, DOE, USDA, HUD, DOT, SBA, CMS, or EPA) to document the national gap in the field "{extracted_data['candidate_field']}". Recommender's firsthand professional perspective on why this gap is critical.

Paragraph 5 (Proposed Endeavor + Substantial Merit): Describe the proposed endeavor in specific technical terms as the recommender understands it from direct collaboration. What it is, how it works, why it has substantial merit. Invoke Matter of Dhanasar, 26 I&N Dec. 884 (AAO 2016).

Paragraph 6 (National Importance + Federal Alignment + Prong 1): Why this work matters at the NATIONAL level. Connect to specific U.S. federal laws or programs (full names with H.R./P.L. numbers). Recommender's personal testimony about the national scale. Close with professional opinion that Prong 1 is satisfied.

Paragraphs 7-9 (Three Achievement Paragraphs — Well Positioned): Three separate paragraphs, each presenting one specific achievement of {extracted_data['candidate_name']} that the recommender PERSONALLY OBSERVED. Each paragraph: what was accomplished + [baseline] → [result] ([X%] change) over [period] across [N cases] + how the recommender verified it ("which I personally monitored...", "as I observed through...").

Paragraph 10 (Unique Skill Combination + Prong 2 Conclusion): Why {extracted_data['candidate_name']}'s specific combination of skills is exceptional and rare in the U.S. workforce, from the recommender's perspective. Close with professional opinion that Prong 2 of Matter of Dhanasar is satisfied.

Paragraph 11 (Time-Sensitive National Need): The national need is urgent. Labor certification delays of 12-18 months would cost the U.S. [specific consequence]. From recommender's professional perspective, the standard process cannot identify a U.S. worker with this exact combination.

Paragraph 12 (Economic Multiplier + Prong 3 Conclusion): Quantify the economic value of this candidate's work: direct impact ($), jobs supported, beneficiaries, 3-year projection. Close with professional opinion that Prong 3 of Matter of Dhanasar is satisfied.

Paragraph 13 (Comparative Exceptionality): In the recommender's years working with professionals in this field, what makes {extracted_data['candidate_name']} genuinely exceptional. Why the combination of skills is rare.

Paragraph 14 (Conclusion + Strongest Recommendation): Summarize satisfaction of all 3 Dhanasar prongs in flowing prose (not a checklist). Provide strongest professional recommendation for the NIW petition without reservation. State availability for follow-up.

After paragraph 14, close with:
"{chosen_sign_off}"
[Recommender's full name, complete professional title, organization, email, phone]

---
## CRITICAL REQUIREMENTS:
1. DO NOT invent specific statistics — use real government agency ranges for the relevant field.
2. All metrics MUST have: baseline + result + % change + time period + sample size + recommender's verification method.
3. Cite "Matter of Dhanasar, 26 I&N Dec. 884 (AAO 2016)" explicitly.
4. Use {today_str} as the letter date.
5. Replace ALL placeholder text with real extracted data — NO bracket placeholders in output.
6. Length: 2,500-3,500 words.
7. Visa type: EB-2 NIW.
8. OUTPUT FORMAT: ONLY <p> tags. NEVER use <h1>, <h2>, <h3>, <h4>. No HTML heading tags whatsoever."""

        from llm_fallback import call_llm_with_fallback
        letter_content_en = await call_llm_with_fallback(
            system_prompt=RECOMMENDATION_LETTER_SYSTEM_PROMPT + RECOMMENDATION_ANTI_PLACEHOLDER_RULE,
            user_prompt=generation_prompt,
            primary_gemini_fn=call_gemini_flash_lite,
            # OpenAI-directo como último escalón cuando OpenRouter está caído.
            openai_gpt4o_fn=call_openai_gpt4o,
            temperature=gen_temperature,
            max_tokens=8000,
            min_chars=500,
            label=f"recommendation-letter/{letter_id[:8]}",
            timeout_secs=150.0,
        )
        logging.info(
            f"🎨 recommendation letter generated | profile={format_profile['id']} "
            f"sign_off={chosen_sign_off!r} temp={gen_temperature}"
        )

        await _update(80, "Traduciendo al español...")

        translation_prompt = f"""Translate this professional EB-2 NIW recommendation letter from English to Spanish.
Rules: maintain professional legal tone, keep proper nouns in English, formal Spanish (usted form).

ENGLISH LETTER:
{letter_content_en}

Provide ONLY the Spanish translation."""

        letter_content_es = await asyncio.wait_for(
            call_openai_gpt4o("You are an expert legal translator. Translate with precision.", translation_prompt, temperature=0.2, max_tokens=6000),
            timeout=120.0
        )

        import re as _re
        def _clean(txt):
            """Aggressively remove ALL [PLACEHOLDER] patterns from generated letters."""
            if not txt:
                return txt
            # Strip markdown code fences — plain AND wrapped in <p> tags
            txt = txt.strip()
            txt = _re.sub(r'^```(?:html|markdown)?\s*\n?', '', txt)
            txt = _re.sub(r'\n?```\s*$', '', txt.strip())
            txt = _re.sub(r'<p>\s*```+\s*(?:html|markdown)?\s*</p>\s*', '', txt, flags=_re.IGNORECASE)
            # Replace date placeholders
            for dp in [r'\[DATE\]', r'\[TODAY\]', r'\[CURRENT\s+DATE\]', r'\[Month,?\s*Year\]',
                       r'\[Month\s+DD,?\s*YYYY\]', r'\[Month\s+\w+,?\s*\d{4}\]']:
                txt = _re.sub(dp, today_str, txt, flags=_re.IGNORECASE)
            # Remove entire lines that are solely a placeholder
            lines = [ln for ln in txt.split('\n') if not _re.match(r'^\s*\[[^\[\]]+\]\s*$', ln)]
            txt = '\n'.join(lines)
            # Remove ALL remaining [bracket content] — any length, any case
            txt = _re.sub(r'\[[^\[\]]+\]', lambda m: m.group(0) if _re.match(r'^\[\d\]$', m.group(0)) else '', txt)
            # Remove empty <p> tags
            txt = _re.sub(r'<p>\s*</p>', '', txt)
            # Fix sentence artifacts from removed placeholders
            txt = _re.sub(r'  +', ' ', txt)
            txt = _re.sub(r' ([,.:;])', r'\1', txt)
            txt = _re.sub(r',\s*,', ',', txt)
            txt = _re.sub(r'\(\s*\)', '', txt)
            txt = _re.sub(r'\n{3,}', '\n\n', txt)
            txt = _re.sub(r'including\s*[,.]', 'including relevant professional associations.', txt, flags=_re.IGNORECASE)
            txt = _re.sub(r'member of\s*[,.]', 'member of several professional organizations.', txt, flags=_re.IGNORECASE)
            return txt
        letter_content_en = _clean(letter_content_en)
        letter_content_es = _clean(letter_content_es or letter_content_en)

        # Sanitiza placeholders del LLM ("Not provided", "N/A", …) ANTES de
        # guardar, para que el bloque de firma del PDF/Word no muestre basura
        # cuando la extracción del CV falla parcialmente. El bloque de firma
        # filtra otra vez en render (defense in depth), pero limpiar acá deja
        # la BD coherente para listados, búsquedas y auditoría.
        await _update(100, "Carta generada exitosamente", {
            "status": "completed",
            "candidate_name": _clean_recommender_field(extracted_data.get('candidate_name')),
            "candidate_field": _clean_recommender_field(extracted_data.get('candidate_field')),
            "recommender_name": _clean_recommender_field(extracted_data.get('recommender_name')),
            "recommender_title": _clean_recommender_field(extracted_data.get('recommender_title')),
            "recommender_organization": _clean_recommender_field(extracted_data.get('recommender_organization')),
            "recommender_email": _clean_recommender_field(extracted_data.get('recommender_email')),
            "recommender_phone": _clean_recommender_field(extracted_data.get('recommender_phone')),
            "project_title": _clean_recommender_field(extracted_data.get('project_title')),
            "content_en": letter_content_en,
            "content_es": letter_content_es,
            "extracted_data": extracted_data,
        })
        logging.info(f"✅ Recommendation letter {letter_id} completed")

    except Exception as e:
        logging.error(f"❌ Recommendation letter background failed {letter_id}: {str(e)}")
        import traceback; logging.error(traceback.format_exc())
        await db.recommendation_letters.update_one(
            {"id": letter_id},
            {"$set": {"status": "error", "error_message": str(e), "updated_at": datetime.now(timezone.utc).isoformat()}}
        )


@api_router.get("/recommendation-letters")
async def get_recommendation_letters(
    client_id: Optional[str] = None,
    current_user: User = Depends(get_current_user)
):
    """Get all recommendation letters (excluding deleted) - ALL users see ALL letters"""
    try:
        # Construir query - SIN filtrar por user_id
        query = {"status": {"$ne": "deleted"}}
        if client_id:
            query["client_id"] = client_id
        
        letters = await db.recommendation_letters.find(
            query,
            {"_id": 0}
        ).sort("created_at", -1).to_list(100)
        
        logging.info(f"📋 Retrieved {len(letters)} recommendation letters")
        
        return {"letters": letters, "count": len(letters)}
    except Exception as e:
        logging.error(f"❌ Error retrieving recommendation letters: {str(e)}")
        raise HTTPException(status_code=500, detail="Error retrieving letters")


@api_router.get("/recommendation-letters/{letter_id}")
async def get_recommendation_letter(
    letter_id: str,
    current_user: User = Depends(get_current_user)
):
    """Get a specific recommendation letter — content is cleaned on-the-fly for display"""
    try:
        letter = await db.recommendation_letters.find_one(
            {"id": letter_id},
            {"_id": 0}
        )
        
        if not letter:
            raise HTTPException(status_code=404, detail="Recommendation letter not found")
        
        # Clean content on-the-fly so old letters also display without placeholders/code fences
        import re as _r
        def _clean_for_display(txt):
            if not txt:
                return txt
            txt = txt.strip()
            # Remove code fences (plain or inside <p> tags)
            txt = _r.sub(r'^```(?:html|markdown)?\s*\n?', '', txt)
            txt = _r.sub(r'\n?```\s*$', '', txt.strip())
            txt = _r.sub(r'<p>\s*`{1,3}\s*(?:html|markdown)?\s*</p>\s*', '', txt, flags=_r.IGNORECASE)
            # Remove ALL [bracket placeholders]
            txt = _r.sub(r'\[[^\[\]]+\]', lambda m: m.group(0) if _r.match(r'^\[\d\]$', m.group(0)) else '', txt)
            # Remove empty <p> tags
            txt = _r.sub(r'<p>\s*</p>', '', txt)
            # Fix artifacts
            txt = _r.sub(r'  +', ' ', txt)
            txt = _r.sub(r' ([,.:;])', r'\1', txt)
            return txt
        
        if letter.get('content_en'):
            letter['content_en'] = _clean_for_display(letter['content_en'])
        if letter.get('content_es'):
            letter['content_es'] = _clean_for_display(letter['content_es'])
        
        logging.info(f"📄 Retrieved letter {letter_id}")
        return letter
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"❌ Error retrieving letter {letter_id}: {str(e)}")
        raise HTTPException(status_code=500, detail="Error retrieving letter")


@api_router.post("/recommendation-letters/{letter_id}/translate")
async def translate_recommendation_letter(
    letter_id: str,
    current_user: User = Depends(get_current_user)
):
    """Translate recommendation letter to Spanish (if not already translated)"""
    try:
        letter = await db.recommendation_letters.find_one(
            {"id": letter_id, "user_id": current_user.id},
            {"_id": 0}
        )
        
        if not letter:
            raise HTTPException(status_code=404, detail="Letter not found")
        
        # Check if Spanish version already exists
        if letter.get("content_es"):
            logging.info(f"📝 Spanish version already exists for letter {letter_id}")
            return {
                "content_es": letter["content_es"],
                "message": "Spanish version already exists"
            }
        
        # Get English content (handle both old and new format)
        content_en = letter.get("content_en") or letter.get("content", "")
        
        if not content_en:
            raise HTTPException(status_code=400, detail="No English content found")
        
        logging.info(f"🌐 Translating letter {letter_id} to Spanish...")
        
        # Translation prompt - direct and clear
        translation_prompt = f"""Translate this entire recommendation letter from English to Spanish. Maintain ALL formatting exactly:

{content_en}

RULES:
- Keep [ON ... LETTERHEAD] format
- Keep section numbers I., II., III., etc.
- Keep **bold markers**
- Keep proper nouns in English (Matter of Dhanasar, institution names)
- Use Spanish date format: "10 de diciembre de 2025"
- Translate everything else to professional Spanish

Provide ONLY the translated letter, no explanations."""

        # Use Gemini Flash Lite for fast and accurate translation
        content_es = await call_gemini_flash_lite(
            "You are a professional translator specializing in legal and immigration documents. You maintain formatting and professional tone while translating accurately.",
            translation_prompt,
            temperature=0.3,
            max_tokens=6000
        )
        
        if not content_es:
            raise HTTPException(status_code=500, detail="Translation failed")
        
        # Update database with Spanish version
        await db.recommendation_letters.update_one(
            {"id": letter_id, "user_id": current_user.id},
            {
                "$set": {
                    "content_es": content_es,
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )
        
        logging.info(f"✅ Letter {letter_id} translated to Spanish successfully")
        
        return {
            "content_es": content_es,
            "message": "Letter translated to Spanish successfully"
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"❌ Error translating letter {letter_id}: {str(e)}")
        import traceback
        logging.error(traceback.format_exc())
        raise HTTPException(status_code=500, detail=f"Error translating letter: {str(e)}")


