async def edit_recommendation_letter(
    letter_id: str,
    edit_request: dict,
    current_user: User = Depends(get_current_user)
):
    """Edit a specific section or part of the recommendation letter"""
    try:
        letter = await db.recommendation_letters.find_one(
            {"id": letter_id, "user_id": current_user.id},
            {"_id": 0}
        )
        
        if not letter:
            raise HTTPException(status_code=404, detail="Recommendation letter not found")
        
        edit_instructions = edit_request.get("instructions", "")
        if not edit_instructions:
            raise HTTPException(status_code=400, detail="Edit instructions are required")
        
        current_content = letter.get("content_en") or letter.get("content", "")
        
        logging.info(f"✏️ Editing letter {letter_id} with instructions: {edit_instructions[:100]}...")
        
        # Create edit prompt
        edit_prompt = f"""You are editing a professional recommendation letter.

**CURRENT LETTER CONTENT:**
{current_content}

**EDIT INSTRUCTIONS:**
{edit_instructions}

Please provide the complete revised letter incorporating these changes while maintaining:
- Professional tone and format
- Specific examples and evidence
- Credibility and authenticity
- Proper letter structure
- Evidence architecture (Fact → Consequence → Criterion → Conclusion)

Generate the revised letter in English."""
        
        # Use Gemini Flash Lite for editing
        revised_content = await call_gemini_flash_lite(
            RECOMMENDATION_LETTER_SYSTEM_PROMPT + RECOMMENDATION_ANTI_PLACEHOLDER_RULE,
            edit_prompt,
            temperature=0.7,
            max_tokens=6000
        )
        
        if not revised_content:
            raise HTTPException(status_code=500, detail="Edit failed")
        
        # Update in database (update English version, clear Spanish)
        await db.recommendation_letters.update_one(
            {"id": letter_id, "user_id": current_user.id},
            {
                "$set": {
                    "content_en": revised_content,
                    "content_es": None,  # Clear Spanish version after edit
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }
            }
        )
        
        logging.info(f"✅ Letter {letter_id} edited successfully")
        
        return {
            "content": revised_content,
            "message": "Letter edited successfully"
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"❌ Error editing letter {letter_id}: {str(e)}")
        import traceback
        logging.error(traceback.format_exc())
        raise HTTPException(status_code=500, detail=f"Error editing letter: {str(e)}")


@api_router.delete("/recommendation-letters/{letter_id}")
async def delete_recommendation_letter(
    letter_id: str,
    current_user: User = Depends(get_current_user)
):
    """Soft delete a recommendation letter (move to trash) - ALL users can delete"""
    try:
        letter = await db.recommendation_letters.find_one({"id": letter_id}, {"_id": 0})
        
        if not letter:
            raise HTTPException(status_code=404, detail="Letter not found")
        
        # TODOS los usuarios pueden eliminar TODOS los documentos
        
        # Soft delete
        result = await db.recommendation_letters.update_one(
            {"id": letter_id},
            {
                "$set": {
                    "status": "deleted",
                    "deleted_at": datetime.now(timezone.utc).isoformat(),
                    "deleted_by": current_user.id
                }
            }
        )
        
        if result.modified_count == 0:
            raise HTTPException(status_code=400, detail="Failed to delete letter")
        
        logging.info(f"🗑️ Letter {letter_id} moved to trash by {current_user.email}")
        
        return {
            "message": "Carta de recomendación movida a la papelera",
            "note": "Puedes restaurarla desde la papelera si es necesario"
        }
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"❌ Error deleting letter {letter_id}: {str(e)}")
        raise HTTPException(status_code=500, detail="Error deleting letter")


def _clean_recommender_field(value) -> str:
    """Sanitiza placeholders que el LLM extractor a veces escribe cuando no
    puede leer un campo del CV (CV escaneado, formato ambiguo, etc.).

    Antes el PDF mostraba `Not provided` en el bloque de firma porque
    `letter_doc['recommender_name']` venía con ese string literal — el LLM
    extrajo el JSON con "Not provided" como nombre y se guardó tal cual.
    Esto devuelve "" cuando el valor es uno de esos placeholders, para que
    el caller pueda condicionar el render (no escribir la línea vs escribirla).
    """
    if not value:
        return ""
    v = str(value).strip()
    if not v:
        return ""
    placeholders = {
        "not provided", "no proporcionado", "n/a", "na", "none", "null",
        "unknown", "tbd", "to be determined", "placeholder",
        "recommender", "candidate", "applicant",
        "[name]", "[recommender name]", "[full name]",
    }
    if v.lower() in placeholders:
        return ""
    return v


@api_router.get("/recommendation-letters/{letter_id}/download")
async def download_recommendation_letter(
    letter_id: str,
    language: str = "en",
    current_user: User = Depends(get_current_user)
):
    """Download recommendation letter as PDF with Markdown formatting in specified language"""
    try:
        # 🔧 FIX: Permitir descargar cualquier documento por ID
        letter_doc = await db.recommendation_letters.find_one(
            {"id": letter_id},
            {"_id": 0}
        )
        
        if not letter_doc:
            raise HTTPException(status_code=404, detail="Letter not found")
        
        logging.info(f"📥 Generating PDF for letter {letter_id} in language: {language}")
        
        # Get format profile for this letter
        from letter_format_profiles import get_profile
        from pdf_letter_utils import prepare_pdf_settings
        profile = get_profile(letter_doc.get('format_profile_id', 'classic_legal'))
        # Resolve fonts via the registry (EB Garamond, Lato, etc. when available;
        # falls back to Times/Helvetica when the TTFs aren't installed).
        p = prepare_pdf_settings(profile)

        # Get candidate and recommender names for metadata. Sanitize placeholder
        # values like "Not provided" that the LLM extractor sometimes emits when
        # it can't read a field from the CV — we don't want those leaking into
        # the PDF signature block (which is what the user saw in production).
        candidate_name = _clean_recommender_field(letter_doc.get('candidate_name')) or 'Candidate'
        recommender_name_clean = _clean_recommender_field(letter_doc.get('recommender_name'))
        recommender_name = recommender_name_clean or 'Recommender'
        recommender_title_clean = _clean_recommender_field(letter_doc.get('recommender_title'))
        recommender_org_clean = _clean_recommender_field(letter_doc.get('recommender_organization'))
        recommender_email_clean = _clean_recommender_field(letter_doc.get('recommender_email'))
        lang_text = "Español" if language == "es" else "English"
        
        # Create PDF with profile settings
        buffer = io.BytesIO()
        doc = SimpleDocTemplate(
            buffer, 
            pagesize=A4, 
            topMargin=p["top_margin"],
            bottomMargin=p["bottom_margin"],
            leftMargin=p["left_margin"],
            rightMargin=p["right_margin"],
            title=f"Recommendation Letter for {candidate_name}",
            author=recommender_name,
            subject=f"EB-2 NIW Recommendation Letter for {candidate_name}",
            creator="Monica NIW System",
        )
        
        # Define custom styles - OPTIMIZED for compact layout, BLACK AND WHITE
        styles = getSampleStyleSheet()
        
        # Styles driven by format profile
        h1_style = ParagraphStyle(
            'Heading1Custom', fontSize=p["font_size_section"] + 1,
            textColor=colors.black, spaceAfter=6, spaceBefore=p["space_before_section"],
            fontName=p["font_bold"]
        )
        h2_style = ParagraphStyle(
            'Heading2Custom', fontSize=p["font_size_section"],
            textColor=colors.black, spaceAfter=4, spaceBefore=p["space_before_section"] - 4,
            fontName=p["font_bold"]
        )
        body_style = ParagraphStyle(
            'BodyCustom', fontSize=p["font_size_body"], leading=p["leading"],
            alignment=TA_JUSTIFY, spaceAfter=p["space_after_para"],
            fontName=p["font_body"], textColor=colors.black
        )
        
        # Build content
        content = []
        
        # Get letter text based on requested language
        if language == "es":
            letter_text = letter_doc.get('content_es')
            if not letter_text:
                # If Spanish version doesn't exist, use English
                letter_text = letter_doc.get('content_en') or letter_doc.get('content', '')
                if letter_text:
                    logging.warning(f"Spanish version not available for letter {letter_id}, using English")
        else:
            # Default to English
            letter_text = letter_doc.get('content_en') or letter_doc.get('content', '')
        
        if not letter_text:
            raise HTTPException(status_code=400, detail="No content found in letter")

        # ── Clean content before PDF generation ────────────────────────────────
        import re as _r
        # Remove code fences (plain or inside <p> tags)
        letter_text = letter_text.strip()
        letter_text = _r.sub(r'^```(?:html|markdown)?\s*\n?', '', letter_text)
        letter_text = _r.sub(r'\n?```\s*$', '', letter_text.strip())
        letter_text = _r.sub(r'<p>\s*`{1,3}\s*(?:html|markdown)?\s*</p>\s*', '', letter_text, flags=_r.IGNORECASE)
        # Remove ALL [bracket placeholders]
        letter_text = _r.sub(r'\[[^\[\]]+\]', lambda m: m.group(0) if _r.match(r'^\[\d\]$', m.group(0)) else '', letter_text)
        # Fix artifacts
        letter_text = _r.sub(r'<p>\s*</p>', '', letter_text)
        letter_text = _r.sub(r'<p>\s*[,.:;]\s*</p>', '', letter_text)
        letter_text = _r.sub(r'  +', ' ', letter_text)
        letter_text = _r.sub(r' ([,.:;])', r'\1', letter_text)

        # Convertir markdown inline ANTES del parseo HTML para que `**bold**` dentro
        # de tags se convierta a <b>, y eliminar runs de `***`/`****` (separadores
        # no-estándar puestos por el LLM que quedaban literales en el PDF).
        from pdf_utils import md_inline_to_rl as _md_inline
        letter_text = _md_inline(letter_text)

        # ── HTML-aware content builder ─────────────────────────────────────────
        # If content has <p> tags (HTML format), use BeautifulSoup
        # Otherwise fall back to line-by-line plain-text parsing
        from bs4 import BeautifulSoup as _BS

        def _rl_inline(tag):
            """Convert a BeautifulSoup tag's children to ReportLab inline XML."""
            parts = []
            for child in tag.children:
                if hasattr(child, 'name') and child.name:
                    txt = child.get_text()
                    if child.name in ('strong', 'b'):
                        parts.append(f'<b>{txt}</b>')
                    elif child.name in ('em', 'i'):
                        parts.append(f'<i>{txt}</i>')
                    else:
                        parts.append(txt)
                else:
                    parts.append(str(child))
            return ''.join(parts).strip()

        if '<p' in letter_text or '<div' in letter_text:
            # HTML path — parse with BeautifulSoup
            soup = _BS(letter_text, 'html.parser')
            for tag in soup.find_all(['p', 'h1', 'h2', 'h3', 'h4', 'div']):
                if tag.name in ('h1', 'h2', 'h3', 'h4'):
                    txt = tag.get_text().strip()
                    if txt:
                        content.append(Paragraph(txt, h2_style))
                elif tag.name in ('p', 'div'):
                    if tag.find(['p', 'div']):
                        continue  # skip wrapper divs that contain child p/div elements
                    inline = _rl_inline(tag)
                    if inline:
                        try:
                            content.append(Paragraph(inline, body_style))
                        except Exception:
                            content.append(Paragraph(tag.get_text().strip(), body_style))
        else:
            # Plain-text / Markdown path (legacy fallback)
            def _convert_bold(text):
                while '**' in text:
                    parts = text.split('**', 2)
                    if len(parts) >= 3:
                        text = parts[0] + '<b>' + parts[1] + '</b>' + parts[2]
                    else:
                        break
                return text

            letter_text = _r.sub(r'<b>([^<]*)<b>', r'<b>\1</b>', letter_text)
            letter_text = _convert_bold(letter_text)
            lines = letter_text.split('\n')
            current_paragraph = []

            for line in lines:
                line = line.strip()
                if not line:
                    if current_paragraph:
                        content.append(Paragraph(' '.join(current_paragraph), body_style))
                        current_paragraph = []
                    continue
                if line.startswith('[') and line.endswith(']'):
                    if current_paragraph:
                        content.append(Paragraph(' '.join(current_paragraph), body_style))
                        current_paragraph = []
                    continue  # skip remaining bracket lines
                if (line.isupper() and len(line.split()) <= 8) or re.match(r'^[IVX]+\.\s+[A-Z]', line):
                    if current_paragraph:
                        content.append(Paragraph(' '.join(current_paragraph), body_style))
                        current_paragraph = []
                    content.append(Paragraph(line, h1_style))
                    continue
                if line.startswith(('───', '---')):
                    if current_paragraph:
                        content.append(Paragraph(' '.join(current_paragraph), body_style))
                        current_paragraph = []
                    content.append(Spacer(1, 0.15 * inch))
                    continue
                if line.startswith(('Re:', 'Attn:', 'Dear', 'Sincerely', 'Respectfully')):
                    if current_paragraph:
                        content.append(Paragraph(' '.join(current_paragraph), body_style))
                        current_paragraph = []
                    content.append(Paragraph(line, body_style))
                    continue
                current_paragraph.append(line)

            if current_paragraph:
                content.append(Paragraph(' '.join(current_paragraph), body_style))
        
        # ✅ FIX: Add signature space at the end of the letter
        signature_style = ParagraphStyle(
            'SignatureCustom', fontSize=p["font_size_body"], leading=p["leading"],
            alignment=TA_LEFT, spaceAfter=2,
            fontName=p["font_body"], textColor=colors.black
        )
        signature_bold_style = ParagraphStyle(
            'SignatureBold', fontSize=p["font_size_body"], leading=p["leading"],
            alignment=TA_LEFT, spaceAfter=2,
            fontName=p["font_bold"], textColor=colors.black
        )
        
        content.append(Spacer(1, 0.4*inch))

        # Signature line — siempre se renderiza para dejar espacio físico para
        # la firma manuscrita. Los campos textuales debajo solo aparecen si
        # tienen valor real (no placeholders del LLM como "Not provided").
        content.append(Paragraph("_" * 40, signature_style))
        content.append(Spacer(1, 0.05*inch))
        if recommender_name_clean:
            content.append(Paragraph(f"<b>{recommender_name_clean}</b>", signature_bold_style))
        if recommender_title_clean:
            content.append(Paragraph(recommender_title_clean, signature_style))
        if recommender_org_clean:
            content.append(Paragraph(recommender_org_clean, signature_style))
        if recommender_email_clean:
            content.append(Paragraph(recommender_email_clean, signature_style))

        content.append(Spacer(1, 0.15*inch))
        date_str = datetime.now().strftime("%B %d, %Y") if language == "en" else (lambda n: f"{n.day} de {['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'][n.month-1]} de {n.year}")(datetime.now())
        content.append(Paragraph(f"Date / Fecha: {date_str}", signature_style))

        # Leave ~1 inch of vertical whitespace right after the sign-off so the
        # recommender has physical room for a handwritten signature.
        from pdf_letter_utils import inject_signature_spacer
        inject_signature_spacer(content, height=70)

        # Build PDF
        doc.build(content)
        buffer.seek(0)
        
        # Prepare filename with candidate and recommender names
        candidate_name = letter_doc.get('candidate_name', 'Candidate').replace(' ', '_')
        recommender_name = letter_doc.get('recommender_name', 'Recommender').replace(' ', '_')
        lang_suffix = "ES" if language == "es" else "EN"
        filename = f"Carta_Recomendacion_{candidate_name}_firmada_por_{recommender_name}_{lang_suffix}.pdf"
        
        logging.info(f"✅ PDF generated successfully: {filename}")
        
        # Return as streaming response
        return StreamingResponse(
            io.BytesIO(buffer.read()),
            media_type="application/pdf",
            headers={
                "Content-Disposition": f"attachment; filename={filename}"
            }
        )
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"❌ Error generating PDF for letter {letter_id}: {str(e)}")
        import traceback
        logging.error(traceback.format_exc())
        raise HTTPException(status_code=500, detail=f"Error generating PDF: {str(e)}")


