@api_router.get("/self-petition-letters")
async def get_self_petition_letters(
    client_id: Optional[str] = Query(None),
    current_user: User = Depends(get_current_user)
):
    """Get all self-petition letters (V1 and V2) for current user (excluding deleted)"""
    # Build query filter
    if client_id:
        # Si se proporciona client_id, buscar por client_id solamente
        query_filter = {"client_id": client_id, "status": {"$ne": "deleted"}}
        logging.info(f"🔍 Fetching letters for client {client_id}")
    else:
        # Si NO se proporciona client_id, buscar por user_id del operador
        query_filter = {"user_id": current_user.id, "status": {"$ne": "deleted"}}
        logging.info(f"🔍 Fetching all letters for user {current_user.id}")
    
    logging.info(f"📊 Query filter: {query_filter}")
    
    # Get V1 letters
    letters_v1 = await db.self_petition_letters.find(
        query_filter,
        {"_id": 0}
    ).to_list(1000)
    
    # Add version marker to V1 letters
    for letter in letters_v1:
        letter['version'] = 'v1'
    
    # Get V2 letters
    letters_v2 = await db.self_petition_v2_letters.find(
        query_filter,
        {"_id": 0}
    ).to_list(1000)
    
    # Add version marker to V2 letters
    for letter in letters_v2:
        letter['version'] = 'v2'
    
    # Combine both lists
    all_letters = letters_v1 + letters_v2
    
    # Sort by created_at descending (handle both str and datetime values)
    def _sort_key(x):
        v = x.get('created_at', '')
        if hasattr(v, 'isoformat'):
            return v.isoformat()
        return str(v) if v else ''
    all_letters.sort(key=_sort_key, reverse=True)
    
    logging.info(f"✅ Found {len(letters_v1)} V1 letters and {len(letters_v2)} V2 letters = {len(all_letters)} total")
    
    return {"letters": all_letters}

@api_router.get("/self-petition-letters/{letter_id}")
async def get_self_petition_letter(letter_id: str, current_user: User = Depends(get_current_user)):
    """Get specific self-petition letter (V1 or V2)"""
    # Try V1 first
    letter = await db.self_petition_letters.find_one(
        {"id": letter_id},
        {"_id": 0}
    )
    
    if letter:
        letter['version'] = 'v1'
        return letter
    
    # Try V2
    letter = await db.self_petition_v2_letters.find_one(
        {"id": letter_id},
        {"_id": 0}
    )
    
    if letter:
        letter['version'] = 'v2'
        return letter
    
    raise HTTPException(status_code=404, detail="Letter not found")

@api_router.put("/self-petition-letters/{letter_id}")
async def update_self_petition_letter(
    letter_id: str,
    update_data: dict,
    current_user: User = Depends(get_current_user)
):
    """Update self-petition letter content (for editing)"""
    letter = await db.self_petition_letters.find_one({"id": letter_id, "user_id": current_user.id})
    if not letter:
        raise HTTPException(status_code=404, detail="Letter not found")
    
    # Update allowed fields
    update_fields = {}
    if "content_en" in update_data:
        update_fields["content_en"] = update_data["content_en"]
    if "content_es" in update_data:
        update_fields["content_es"] = update_data["content_es"]
    if "current_language" in update_data:
        update_fields["current_language"] = update_data["current_language"]
    
    if update_fields:
        update_fields["updated_at"] = datetime.now(timezone.utc).isoformat()
        await db.self_petition_letters.update_one(
            {"id": letter_id},
            {"$set": update_fields}
        )
    
    return {"message": "Letter updated successfully", "letter_id": letter_id}

@api_router.get("/self-petition-letters/{letter_id}/download")
async def download_self_petition_letter_pdf(
    letter_id: str,
    language: str = Query("en", regex="^(en|es)$"),
    current_user: User = Depends(get_current_user)
):
    """Download self-petition letter as PDF (V1 or V2)"""
    # Try V1 first
    letter = await db.self_petition_letters.find_one(
        {"id": letter_id},
        {"_id": 0}
    )
    
    # If not found in V1, try V2
    if not letter:
        letter = await db.self_petition_v2_letters.find_one(
            {"id": letter_id},
            {"_id": 0}
        )
    
    if not letter:
        raise HTTPException(status_code=404, detail="Letter not found")
    
    # Use Spanish or English content
    content = letter.get('content_es') if language == 'es' else letter.get('content_en')
    
    if not content:
        raise HTTPException(status_code=404, detail=f"Content in {language} not available")
    
    # Generate PDF with proper formatting
    from io import BytesIO
    from reportlab.lib.pagesizes import letter as letter_size
    from reportlab.lib.units import inch
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.platypus import Paragraph, Spacer, PageBreak
    from reportlab.lib.enums import TA_LEFT, TA_CENTER, TA_JUSTIFY
    from reportlab.lib import colors
    import re
    
    buffer = BytesIO()
    
    # Get beneficiary/applicant name for title (the person the petition is FOR)
    # V1 uses beneficiary_name, V2 uses applicant_name
    beneficiary_name = letter.get('beneficiary_name') or letter.get('applicant_name') or 'Beneficiary'
    client_name = letter.get('client_name', '')
    
    # Set PDF title - use beneficiary name (the subject of the petition)
    pdf_title = f"EB-2 NIW Self-Petition Letter - {beneficiary_name}"
    
    doc = SimpleDocTemplate(
        buffer, 
        pagesize=letter_size, 
        topMargin=0.75*inch, 
        bottomMargin=72,  # igual al superior
        leftMargin=1*inch,
        rightMargin=1*inch,
        title=pdf_title,  # PDF metadata title - use beneficiary
        author=beneficiary_name,  # PDF metadata author
        subject="Form I-140 EB-2 NIW Petition"
    )
    
    styles = getSampleStyleSheet()
    
    # Custom styles for the petition letter
    title_style = ParagraphStyle(
        'CustomTitle',
        parent=styles['Heading1'],
        fontSize=16,
        textColor=colors.HexColor('#1a1a1a'),
        spaceAfter=12,
        spaceBefore=12,
        alignment=TA_CENTER,
        fontName='Helvetica-Bold'
    )
    
    heading_style = ParagraphStyle(
        'CustomHeading',
        parent=styles['Heading2'],
        fontSize=13,
        textColor=colors.HexColor('#2c3e50'),
        spaceAfter=10,
        spaceBefore=14,
        fontName='Helvetica-Bold',
        borderWidth=0,
        borderColor=colors.HexColor('#3498db'),
        borderPadding=0
    )
    
    subheading_style = ParagraphStyle(
        'CustomSubheading',
        parent=styles['Heading3'],
        fontSize=11,
        textColor=colors.HexColor('#34495e'),
        spaceAfter=8,
        spaceBefore=10,
        fontName='Helvetica-Bold'
    )
    
    body_style = ParagraphStyle(
        'CustomBody',
        parent=styles['BodyText'],
        fontSize=10,
        leading=14,
        alignment=TA_JUSTIFY,
        spaceAfter=6,
        fontName='Helvetica'
    )
    
    story = []
    
    # Add title/header to the PDF using beneficiary name
    beneficiary_name_display = letter.get('beneficiary_name', 'Beneficiary')
    
    title_text = f"EB-2 NIW Self-Petition Letter<br/>{beneficiary_name_display}"
    
    story.append(Paragraph(title_text, title_style))
    story.append(Spacer(1, 0.3*inch))
    
    # Clean markdown artifacts from content
    content = re.sub(r'```markdown\s*', '', content)  # Remove ```markdown
    content = re.sub(r'```\s*', '', content)  # Remove closing ```

    # ── Helper: convert HTML element inner markup to ReportLab-safe string ──────
    def _to_rl_safe(element):
        """Strip all HTML except b/i/u/br/ — the only tags ReportLab's Paragraph supports."""
        html = element.decode_contents()
        html = re.sub(r'<strong\b[^>]*>(.*?)</strong>', r'<b>\1</b>', html, flags=re.DOTALL|re.IGNORECASE)
        html = re.sub(r'<em\b[^>]*>(.*?)</em>',         r'<i>\1</i>', html, flags=re.DOTALL|re.IGNORECASE)
        html = re.sub(r'<b\b[^>]*>(.*?)</b>',           r'<b>\1</b>', html, flags=re.DOTALL|re.IGNORECASE)
        html = re.sub(r'<i\b[^>]*>(.*?)</i>',           r'<i>\1</i>', html, flags=re.DOTALL|re.IGNORECASE)
        html = re.sub(r'<br\s*/?>', '<br/>', html, flags=re.IGNORECASE)
        # Remove all remaining HTML tags (not supported by RL Paragraph XML parser)
        html = re.sub(r'<(?!/?b>|/?i>|/?u>|br/>)[^>]+>', '', html)
        # Escape bare ampersands so ReportLab XML parser doesn't choke
        html = re.sub(r'&(?!amp;|lt;|gt;|quot;|#\d+;)', '&amp;', html)
        return html.strip()

    def _safe_para(text_or_html, style, plain_fallback=""):
        """Create a Paragraph, falling back to plain text if parse fails."""
        try:
            p = Paragraph(text_or_html, style)
            return p
        except Exception:
            safe = plain_fallback or re.sub(r'<[^>]+>', '', text_or_html)
            try:
                return Paragraph(safe, style)
            except Exception:
                return None

    # ── Detect HTML vs Markdown content ─────────────────────────────────────────
    is_html = bool(re.search(r'<\s*(?:h[1-6]|p|ul|ol|li|div)\b', content, re.IGNORECASE))

    if is_html:
        from bs4 import BeautifulSoup

        soup = BeautifulSoup(content, 'html.parser')

        def _add_element(el):
            if not hasattr(el, 'name') or not el.name:
                return  # skip NavigableString nodes
            tag = el.name.lower()
            plain = el.get_text(separator=' ', strip=True)
            if not plain:
                return

            if tag == 'h1':
                story.append(Spacer(1, 0.2*inch))
                p = _safe_para(_to_rl_safe(el), title_style, plain)
                if p: story.append(p)
            elif tag == 'h2':
                story.append(Spacer(1, 0.15*inch))
                p = _safe_para(_to_rl_safe(el), heading_style, plain)
                if p: story.append(p)
            elif tag in ('h3', 'h4', 'h5', 'h6'):
                story.append(Spacer(1, 0.1*inch))
                p = _safe_para(_to_rl_safe(el), subheading_style, plain)
                if p: story.append(p)
            elif tag == 'p':
                p = _safe_para(_to_rl_safe(el), body_style, plain)
                if p:
                    story.append(p)
                    story.append(Spacer(1, 0.04*inch))
            elif tag in ('ul', 'ol'):
                for li in el.find_all('li', recursive=False):
                    li_plain = li.get_text(strip=True)
                    if li_plain:
                        p = _safe_para(f'• {_to_rl_safe(li)}', body_style, f'• {li_plain}')
                        if p: story.append(p)
            elif tag in ('div', 'section', 'article', 'main', 'body'):
                for child in el.children:
                    _add_element(child)
            else:
                # Any other block tag — treat as body paragraph
                p = _safe_para(_to_rl_safe(el), body_style, plain)
                if p: story.append(p)

        for el in soup.children:
            _add_element(el)

    else:
        # ── Fallback: original Markdown line-by-line processing (V1 letters) ────
        lines = content.split('\n')
        for line in lines:
            stripped = line.strip()
            if not stripped:
                story.append(Spacer(1, 0.1*inch))
                continue
            # Roman numeral headings: "II. **Title**"
            if re.match(r'^[IVX]+\.\s+\*\*.*\*\*', stripped):
                heading_text = re.sub(r'\*\*', '', stripped)
                story.append(Spacer(1, 0.15*inch))
                story.append(Paragraph(heading_text, heading_style))
                continue
            # **Bold** standalone headings
            if stripped.startswith('**') and stripped.endswith('**'):
                heading_text = stripped.strip('*')
                story.append(Spacer(1, 0.12*inch))
                story.append(Paragraph(heading_text, subheading_style))
                continue
            # Markdown # headers
            if stripped.startswith('#'):
                heading_text = stripped.lstrip('#').strip()
                level = len(stripped) - len(stripped.lstrip('#'))
                if level == 1:
                    story.append(Spacer(1, 0.2*inch))
                    story.append(Paragraph(heading_text, title_style))
                elif level == 2:
                    story.append(Spacer(1, 0.15*inch))
                    story.append(Paragraph(heading_text, heading_style))
                else:
                    story.append(Spacer(1, 0.1*inch))
                    story.append(Paragraph(heading_text, subheading_style))
                continue
            # Inline formatting
            formatted = re.sub(r'\*\*(.*?)\*\*', r'<b>\1</b>', stripped)
            formatted = re.sub(r'\*(.*?)\*',     r'<i>\1</i>', formatted)
            formatted = re.sub(r'__(.*?)__',     r'<u>\1</u>', formatted)
            p = _safe_para(formatted, body_style, stripped)
            if p: story.append(p)

    doc.build(story)
    buffer.seek(0)
    
    # Generate filename with beneficiary name (the person petition is FOR)
    lang_suffix = "ES" if language == "es" else "EN"
    beneficiary_name_raw = letter.get('beneficiary_name', 'Beneficiary')
    client_name_raw = letter.get('client_name', '')
    
    # Clean beneficiary name for filename (remove spaces, special chars)
    beneficiary_name = beneficiary_name_raw.replace(' ', '_') if beneficiary_name_raw else 'Beneficiary'
    beneficiary_name = re.sub(r'[^\w\-_]', '', beneficiary_name)  # Remove special characters
    
    # Use beneficiary name in filename (the subject of the petition)
    if beneficiary_name and beneficiary_name != 'Beneficiary':
        filename = f"Self_Petition_{beneficiary_name}_{lang_suffix}.pdf"
    elif client_name_raw:
        client_name_clean = client_name_raw.replace(' ', '_')
        client_name_clean = re.sub(r'[^\w\-_]', '', client_name_clean)
        filename = f"Self_Petition_{client_name_clean}_{lang_suffix}.pdf"
    else:
        filename = f"Self_Petition_Letter_{lang_suffix}.pdf"
    
    return Response(
        content=buffer.getvalue(),
        media_type="application/pdf",
        headers={"Content-Disposition": f'attachment; filename="{filename}"'}
    )

@api_router.delete("/self-petition-letters/{letter_id}")
async def delete_self_petition_letter(letter_id: str, current_user: User = Depends(get_current_user)):
    """Soft delete self-petition letter (V1 or V2) - move to trash"""
    try:
        # Try V1 first
        letter = await db.self_petition_letters.find_one({"id": letter_id}, {"_id": 0})
        
        if letter:
            logging.info(f"🗑️ Deleting V1 self-petition letter {letter_id} by user {current_user.email}")
            result = await db.self_petition_letters.update_one(
                {"id": letter_id},
                {
                    "$set": {
                        "status": "deleted",
                        "deleted_at": datetime.now(timezone.utc).isoformat(),
                        "deleted_by": current_user.id
                    }
                }
            )
            if result.modified_count > 0:
                return {
                    "message": "Carta de autopetición movida a la papelera",
                    "note": "Puedes restaurarla desde la papelera si es necesario"
                }
        
        # Try V2
        letter = await db.self_petition_v2_letters.find_one({"id": letter_id}, {"_id": 0})
        
        if letter:
            logging.info(f"🗑️ Deleting V2 self-petition letter {letter_id} by user {current_user.email}")
            result = await db.self_petition_v2_letters.update_one(
                {"id": letter_id},
                {
                    "$set": {
                        "status": "deleted",
                        "deleted_at": datetime.now(timezone.utc).isoformat(),
                        "deleted_by": current_user.id
                    }
                }
            )
            if result.modified_count > 0:
                return {
                    "message": "Carta de autopetición V2 movida a la papelera",
                    "note": "Puedes restaurarla desde la papelera si es necesario"
                }
        
        raise HTTPException(status_code=404, detail="Letter not found")
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error deleting self-petition letter: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

