@api_router.post("/chat/conversations/{conversation_id}/messages")
async def send_message_to_conversation(
    conversation_id: str,
    message: str = Form(...),
    file: UploadFile = File(None),
    credentials: HTTPAuthorizationCredentials = Depends(security)
):
    """Enviar mensaje a una conversación específica con soporte para archivos adjuntos (PDF, Word)"""
    try:
        # Verify token
        user_email = verify_token(credentials.credentials)
        if not user_email:
            raise HTTPException(status_code=401, detail="Invalid token")
        
        user = await db.users.find_one({"email": user_email}, {"_id": 0})
        if not user:
            raise HTTPException(status_code=404, detail="User not found")
        
        user_id = user["id"]
        
        # Verify conversation belongs to user
        conversation = await db.chat_conversations.find_one(
            {"id": conversation_id, "user_id": user_id},
            {"_id": 0}
        )
        
        if not conversation:
            raise HTTPException(status_code=404, detail="Conversation not found")
        
        # Process attached file if present
        extracted_text = ""
        file_info = None
        if file:
            logging.info(f"📎 Processing attached file: {file.filename}")
            
            # Validate file type
            allowed_extensions = ['.pdf', '.docx', '.doc']
            file_ext = os.path.splitext(file.filename)[1].lower()
            
            if file_ext not in allowed_extensions:
                raise HTTPException(
                    status_code=400, 
                    detail=f"File type not supported. Allowed: {', '.join(allowed_extensions)}"
                )
            
            # Read file content
            file_content = await file.read()
            
            # Extract text based on file type
            try:
                if file_ext == '.pdf':
                    # Extract text from PDF - preserving original structure without page markers
                    from PyPDF2 import PdfReader
                    import io
                    
                    pdf_file = io.BytesIO(file_content)
                    reader = PdfReader(pdf_file)
                    
                    extracted_text = ""
                    for page_num, page in enumerate(reader.pages):
                        page_text = page.extract_text()
                        if page_text:
                            # Add natural paragraph break between pages, not markers
                            if extracted_text:
                                extracted_text += "\n\n"
                            extracted_text += page_text.strip()
                    
                    logging.info(f"✅ Extracted {len(extracted_text)} characters from PDF")
                    
                elif file_ext in ['.docx', '.doc']:
                    # Extract text from Word document
                    import docx
                    import io
                    
                    doc_file = io.BytesIO(file_content)
                    doc = docx.Document(doc_file)
                    
                    extracted_text = ""
                    for para in doc.paragraphs:
                        if para.text.strip():
                            extracted_text += para.text + "\n"
                    
                    logging.info(f"✅ Extracted {len(extracted_text)} characters from Word document")
                
                file_info = {
                    "filename": file.filename,
                    "size": len(file_content),
                    "type": file_ext,
                    "extracted_length": len(extracted_text)
                }
                
            except Exception as e:
                logging.error(f"Error extracting text from file: {str(e)}")
                raise HTTPException(status_code=500, detail=f"Error processing file: {str(e)}")

        # ─── 📚 PLAN A: Persist extracted document into conversation context ───
        # Previously: the file's extracted text was sent ONCE in `full_message` to
        # the LLM and then forgotten. Subsequent turns relied on whatever the
        # assistant happened to mention in its first reply — so deep follow-up
        # questions about parts of the document the assistant never touched in
        # turn 1 would fail (or force the user to re-attach the file).
        #
        # Now: we save the extracted text into
        # `chat_conversations.attached_documents` (a list, capped to the 3 most
        # recent docs to bound context size). Every subsequent turn re-injects
        # that text as part of the system message so the assistant has full
        # access to the document content for the entire conversation lifetime.
        if file and extracted_text:
            MAX_PER_DOC_CHARS = 60000  # ≈15k tokens, well within model context.
            stored_text = extracted_text[:MAX_PER_DOC_CHARS]
            doc_record = {
                "filename": file.filename,
                "type": file_ext,
                "size": len(file_content),
                "extracted_length": len(extracted_text),
                "stored_length": len(stored_text),
                "uploaded_at": datetime.now(timezone.utc).isoformat(),
                "content": stored_text,
                "truncated": len(extracted_text) > MAX_PER_DOC_CHARS,
            }
            # Keep only the 3 most recent docs (FIFO) to bound context.
            existing = (conversation.get("attached_documents") or [])[-2:]
            existing.append(doc_record)
            await db.chat_conversations.update_one(
                {"id": conversation_id},
                {"$set": {
                    "attached_documents": existing,
                    "updated_at": datetime.now(timezone.utc).isoformat(),
                }},
            )
            # Refresh local copy so the rest of the function sees the update.
            conversation["attached_documents"] = existing

        # Combine user message with extracted text
        full_message = message
        document_summary = ""
        web_search_results = ""
        
        # 🔍 DETECT WEB SEARCH REQUEST
        search_keywords = [
            'busca', 'buscar', 'búsqueda', 'search', 'encuentra', 
            'noticias', 'news', 'actualidad', 'información actual', 
            'current information', 'latest', 'reciente', 'recent',
            'hoy', 'today', 'qué pasó', 'what happened',
            'investiga', 'investigate', 'consulta', 'lookup'
        ]
        
        message_lower = message.lower()
        needs_web_search = any(keyword in message_lower for keyword in search_keywords)
        
        # Perform web search if detected
        if needs_web_search and not file:  # Don't search if user uploaded a file
            try:
                logging.info(f"🌐 Web search detected in message: {message[:100]}")
                
                from firecrawl import AsyncFirecrawl
                firecrawl_api_key = os.environ.get('FIRECRAWL_API_KEY')
                
                if firecrawl_api_key:
                    firecrawl = AsyncFirecrawl(api_key=firecrawl_api_key)
                    
                    # Extract search query from message (simple heuristic)
                    # Remove search keywords to get the actual query
                    search_query = message_lower
                    for kw in search_keywords:
                        search_query = search_query.replace(kw, '')
                    search_query = search_query.strip()
                    
                    # If query is too short, use full message
                    if len(search_query) < 3:
                        search_query = message
                    
                    logging.info(f"🔎 Searching web for: {search_query}")
                    
                    # Perform search with Firecrawl
                    search_results = await firecrawl.search(
                        query=search_query,
                        limit=5  # Get top 5 results
                    )
                    
                    logging.info(f"📊 Search results type: {type(search_results)}")
                    logging.info(f"📊 Search results: {search_results}")
                    
                    # Extract relevant information from results
                    # Firecrawl returns an object with .web attribute containing SearchResultWeb objects
                    web_results = None
                    if hasattr(search_results, 'web') and search_results.web:
                        web_results = search_results.web
                    elif isinstance(search_results, dict) and 'web' in search_results:
                        web_results = search_results['web']
                    elif isinstance(search_results, dict) and 'data' in search_results:
                        web_results = search_results['data']
                    
                    if web_results and len(web_results) > 0:
                        web_search_results = "\n\n--- RESULTADOS DE BÚSQUEDA EN INTERNET ---\n"
                        
                        for idx, result in enumerate(web_results[:5], 1):
                            # Handle both dict and object attributes
                            if hasattr(result, 'title'):
                                title = result.title or 'Sin título'
                                url = result.url or ''
                                description = result.description or ''
                            else:
                                title = result.get('title', 'Sin título')
                                url = result.get('url', '')
                                description = result.get('description', '')
                            
                            # Use description as content preview
                            content_preview = description if description else "Sin descripción disponible"
                            
                            web_search_results += f"\n{idx}. **{title}**\n"
                            web_search_results += f"   URL: {url}\n"
                            web_search_results += f"   Resumen: {content_preview}\n\n"
                        
                        web_search_results += "\n[INSTRUCCIÓN PARA MÓNICA: Usa esta información actual de internet para responder la pregunta del usuario. Cita las fuentes cuando sea relevante. Proporciona una respuesta completa y útil basada en estos resultados.]\n"
                        
                        logging.info(f"✅ Found {len(web_results)} web results")
                    else:
                        logging.warning("⚠️ No web results found")
                        web_search_results = "\n\n[Búsqueda en internet realizada pero no se encontraron resultados relevantes.]\n"
                else:
                    logging.warning("⚠️ FIRECRAWL_API_KEY not configured")
                    
            except Exception as e:
                logging.error(f"❌ Web search failed: {str(e)}")
                # Continue without web search - don't fail the entire request
                web_search_results = ""
        
        if extracted_text:
            # Create document summary for context retention
            document_summary = f"Archivo adjunto: {file.filename} ({len(extracted_text)} caracteres extraídos)"
            full_message = f"{message}\n\n--- CONTENIDO DEL DOCUMENTO ADJUNTO ({file.filename}) ---\n{extracted_text}\n\n[INSTRUCCIÓN PARA MÓNICA: Este documento ha sido compartido en esta conversación. Recuerda su contenido para responder preguntas posteriores sobre él. El usuario puede referirse a este documento como 'el documento', 'el libro', 'el archivo' o por su nombre en mensajes futuros.]"
        elif web_search_results:
            # Add web search results to message
            full_message = f"{message}\n{web_search_results}"
        
        # Create user message
        user_message = {
            "id": str(uuid.uuid4()),
            "conversation_id": conversation_id,
            "user_id": user_id,
            "role": "user",
            "content": message,  # Original message without file content
            "timestamp": datetime.now(timezone.utc).isoformat()
        }
        
        # Add file info if present
        if file_info:
            user_message["file"] = file_info
            # Add visual indicator in content
            user_message["content"] = f"{message}\n📎 {file.filename} ({file_info['extracted_length']} caracteres procesados)"
        elif web_search_results:
            # Add visual indicator for web search
            user_message["content"] = f"{message}\n🌐 Búsqueda en internet realizada"
        
        # Save user message
        await db.chat_messages.insert_one(user_message.copy())
        
        # Update conversation title if it's the first message
        message_count = await db.chat_messages.count_documents({"conversation_id": conversation_id})
        if message_count == 1:
            # Generate title from first message (first 50 chars)
            title = message[:50] + "..." if len(message) > 50 else message
            await db.chat_conversations.update_one(
                {"id": conversation_id},
                {"$set": {"title": title, "updated_at": datetime.now(timezone.utc).isoformat()}}
            )
        else:
            # Just update timestamp
            await db.chat_conversations.update_one(
                {"id": conversation_id},
                {"$set": {"updated_at": datetime.now(timezone.utc).isoformat()}}
            )
        
        # Initialize Gemini chat
        gemini_api_key = os.environ.get('GEMINI_API_KEY')
        session_id = f"monica_chat_{conversation_id}"
        
        system_message = """Eres Mónica, una asistente de IA amigable y profesional. 
Tu rol es ayudar a los usuarios con sus consultas de manera clara y concisa.
Adapta tu idioma al idioma que el usuario utilice en sus mensajes.
Si el usuario escribe en español, responde en español. Si escribe en inglés, responde en inglés.

INSTRUCCIONES CRÍTICAS PARA DOCUMENTOS:
1. Cuando se te proporcione contenido de un documento (PDF o Word), analízalo cuidadosamente.
2. RECUERDA el contenido del documento en TODA la conversación - el usuario puede hacer preguntas de seguimiento.
3. Si el usuario hace preguntas posteriores sobre "el documento", "el libro" o "el archivo", SIEMPRE refiere al último documento que te compartieron en esta conversación.
4. NO pidas que adjunten el documento nuevamente si ya lo analizaste en esta misma conversación.
5. Mantén el contexto del documento a lo largo de toda la conversación.

Cuando analices un documento, extrae y recuerda:
- Título y autor
- Tema principal
- Puntos clave
- Cualquier información relevante que el usuario pueda preguntar después

INSTRUCCIONES PARA BÚSQUEDAS EN INTERNET:
1. Si se te proporcionan resultados de búsqueda en internet, úsalos para dar respuestas actualizadas y precisas.
2. Cuando uses información de internet, menciona la fuente cuando sea relevante.
3. Si la información proviene de búsquedas recientes, indica que es información actual.
4. Puedes combinar tu conocimiento general con la información específica de las búsquedas.

CUANDO EL USUARIO PIDA CORRECCIONES O CAMBIOS A UN DOCUMENTO:
- Si el cambio es puntual o quirúrgico (cambiar una cifra, una frase, una palabra),
  ENTREGA SIEMPRE el resultado en el siguiente formato exacto, palabra por palabra,
  para que el usuario pueda usarlo en Buscar/Reemplazar (Ctrl+H) en Word/Google Docs:

  **BUSCAR:**
  ```
  <texto literal exacto a buscar — copia textualmente del documento original>
  ```

  **REEMPLAZAR:**
  ```
  <texto exacto que debe reemplazar al anterior>
  ```

- Si hay varios cambios, repite el bloque BUSCAR/REEMPLAZAR para cada uno (numerados 1., 2., 3.).
- El texto en BUSCAR debe ser literalmente único en el documento (incluye contexto suficiente
  para que solo coincida una vez); si la frase es ambigua, añade 5–10 palabras alrededor.
- NUNCA inventes texto que no estaba en el documento original; copia textualmente.
- Si el cambio es muy grande (varios párrafos), entrega el bloque entero a buscar y el bloque
  entero a reemplazar."""

        # ─── 📚 Inject ALL previously-attached docs into the system message ───
        # Plan A: persist document content across turns. Append every doc that was
        # ever attached in this conversation to the system prompt so the assistant
        # has reliable access to the FULL text — not just whatever it happened to
        # mention in its first reply.
        attached_docs = conversation.get("attached_documents") or []
        if attached_docs:
            doc_blocks = []
            for i, d in enumerate(attached_docs, 1):
                fname = d.get("filename", f"document_{i}")
                ts    = d.get("uploaded_at", "")
                trunc = " (TRUNCATED to 60k chars — ask user to upload smaller file if needed)" if d.get("truncated") else ""
                content = d.get("content", "") or ""
                doc_blocks.append(
                    f"\n=== DOCUMENT #{i}: {fname} (uploaded {ts}){trunc} ===\n{content}\n=== END DOCUMENT #{i} ==="
                )
            system_message += (
                "\n\n📎 DOCUMENTOS ADJUNTOS DURANTE ESTA CONVERSACIÓN (referénciate a ellos para responder):\n"
                + "\n".join(doc_blocks)
            )
        
        # Load previous messages from this conversation for context
        previous_messages = await db.chat_messages.find(
            {"conversation_id": conversation_id},
            {"_id": 0, "role": 1, "content": 1}
        ).sort("timestamp", 1).to_list(100)  # Last 100 messages max
        
        # Convert to format expected by LlmChat
        initial_messages = []
        for msg in previous_messages:
            initial_messages.append({
                "role": msg["role"],
                "content": msg["content"]
            })
        
        logging.info(f"Loading {len(initial_messages)} previous messages for context")
        
        # ─── 🌐 OPENROUTER PRIMARY (Gemini 3 Pro → Claude Opus 4.6 fallback) ───
        # Why OpenRouter instead of direct Gemini API?
        # The direct Google API rate-limits us aggressively (429 RESOURCE_EXHAUSTED
        # on the free tier). OpenRouter has its own quota pool and routes to the
        # same Gemini 3 model — almost never rate-limited under our usage.
        # Same playbook used elsewhere in the codebase (services/letter_generation_v2.py).
        import httpx as _httpx

        openrouter_key = os.environ.get('OPENROUTER_API_KEY')
        emergent_key   = os.environ.get('EMERGENT_LLM_KEY')

        # Build the chat-history payload OpenRouter expects.
        or_messages = [{"role": "system", "content": system_message}]
        for prev in initial_messages:
            or_messages.append({"role": prev["role"], "content": prev["content"]})
        or_messages.append({"role": "user", "content": full_message})

        OR_HEADERS = {
            "Authorization": f"Bearer {openrouter_key or ''}",
            "Content-Type": "application/json",
            "HTTP-Referer": "https://redaccion.urpeintegralservices.co",
            "X-Title": "SmartDocs Monica Chat",
        }

        async def _try_openrouter(model_id: str) -> str:
            async with _httpx.AsyncClient(timeout=120.0) as cli:
                r = await cli.post(
                    "https://openrouter.ai/api/v1/chat/completions",
                    headers=OR_HEADERS,
                    json={
                        "model": model_id,
                        "messages": or_messages,
                        "temperature": 0.7,
                        "max_tokens": 16000,  # PLAN D: doubled output cap so the assistant can return longer corrected document fragments
                    },
                )
            if r.status_code != 200:
                raise Exception(f"{model_id} HTTP {r.status_code}: {r.text[:200]}")
            return r.json()['choices'][0]['message']['content']

        response = None

        # 1. Gemini 3 Pro via OpenRouter (fast + capable, low rate-limit risk).
        if openrouter_key:
            try:
                logger.info(f"💬 [chat {conversation_id}] Trying Gemini 3 Pro via OpenRouter...")
                response = await _try_openrouter("google/gemini-3-pro-preview")
                logger.info(f"✅ [chat {conversation_id}] Gemini 3 Pro OK ({len(response)} chars)")
            except Exception as e:
                logger.warning(
                    f"⚠️ [chat {conversation_id}] Gemini 3 Pro failed: {str(e)[:160]}. "
                    "Falling back to Claude Opus 4.6..."
                )
                response = None

        # 2. Claude Opus 4.6 via OpenRouter (most powerful fallback).
        if response is None and openrouter_key:
            try:
                logger.info(f"💬 [chat {conversation_id}] Trying Claude Opus 4.6 via OpenRouter...")
                response = await _try_openrouter("anthropic/claude-opus-4.6")
                logger.info(f"✅ [chat {conversation_id}] Claude Opus 4.6 OK ({len(response)} chars)")
            except Exception as e:
                logger.warning(
                    f"⚠️ [chat {conversation_id}] Claude Opus 4.6 failed: {str(e)[:160]}. "
                    "Falling back to direct Gemini API..."
                )
                response = None

        # 3. Last-ditch: direct Gemini API via Emergent LLM Key (legacy path).
        if response is None:
            chat = LlmChat(
                api_key=gemini_api_key,
                session_id=session_id,
                system_message=system_message,
                initial_messages=initial_messages if len(initial_messages) > 0 else None
            ).with_model("gemini", "gemini-2.0-flash")
            user_msg = UserMessage(text=full_message)
            try:
                response = await chat.send_message(user_msg)
                logger.info(f"✅ [chat {conversation_id}] Direct Gemini OK ({len(response)} chars)")
            except Exception as final_exc:
                err_text = str(final_exc)
                logger.error(
                    f"❌ [chat {conversation_id}] All providers failed. Last error: {err_text[:200]}"
                )
                # Final fallback: Sonnet 4.5 via Emergent Universal Key.
                if emergent_key:
                    try:
                        sonnet_chat = LlmChat(
                            api_key=emergent_key,
                            session_id=session_id,
                            system_message=system_message,
                            initial_messages=initial_messages if len(initial_messages) > 0 else None,
                        ).with_model("anthropic", "claude-sonnet-4-5-20250929")
                        response = await sonnet_chat.send_message(user_msg)
                        logger.info(
                            f"✅ [chat {conversation_id}] Sonnet 4.5 last-resort succeeded"
                        )
                    except Exception as sonnet_exc:
                        logger.error(f"❌ Sonnet 4.5 last-resort ALSO failed: {sonnet_exc}")
                        raise HTTPException(
                            status_code=503,
                            detail=(
                                "Los servicios de IA están temporalmente saturados "
                                "(OpenRouter + Gemini + Claude). Por favor intenta de nuevo en unos minutos."
                            ),
                        )
                else:
                    raise HTTPException(
                        status_code=503,
                        detail=(
                            "Los servicios de IA están temporalmente saturados. "
                            "Por favor intenta de nuevo en unos minutos."
                        ),
                    )
        
        # Create assistant message
        assistant_message = {
            "id": str(uuid.uuid4()),
            "conversation_id": conversation_id,
            "user_id": user_id,
            "role": "assistant",
            "content": response,
            "timestamp": datetime.now(timezone.utc).isoformat()
        }
        
        # Save assistant message
        await db.chat_messages.insert_one(assistant_message.copy())
        
        return {
            "success": True,
            "user_message": user_message,
            "assistant_message": assistant_message
        }
        
    except Exception as e:
        logger.error(f"Error sending message: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error sending message: {str(e)}")

@api_router.delete("/chat/conversations/{conversation_id}")
async def delete_conversation(
    conversation_id: str,
    credentials: HTTPAuthorizationCredentials = Depends(security)
):
    """Eliminar una conversación y todos sus mensajes"""
    try:
        # Verify token
        user_email = verify_token(credentials.credentials)
        if not user_email:
            raise HTTPException(status_code=401, detail="Invalid token")
        
        user = await db.users.find_one({"email": user_email}, {"_id": 0})
        if not user:
            raise HTTPException(status_code=404, detail="User not found")
        
        user_id = user["id"]
        
        # Verify conversation belongs to user
        conversation = await db.chat_conversations.find_one(
            {"id": conversation_id, "user_id": user_id},
            {"_id": 0}
        )
        
        if not conversation:
            raise HTTPException(status_code=404, detail="Conversation not found")
        
        # Delete all messages
        await db.chat_messages.delete_many({"conversation_id": conversation_id})
        
        # Delete conversation
        await db.chat_conversations.delete_one({"id": conversation_id})
        
        return {
            "success": True
        }
        
    except Exception as e:
        logger.error(f"Error deleting conversation: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error deleting conversation: {str(e)}")


