@api_router.post("/books/test-prompts/{book_id}")
async def test_prompts_comparison(book_id: str, chapter_number: int = 1, current_user: User = Depends(get_current_user)):
    """Test and compare current prompt vs USCIS-optimized prompt"""
    try:
        book = await db.books_in_progress.find_one({"id": book_id})
        if not book:
            book = await db.books.find_one({"id": book_id})
        if not book:
            raise HTTPException(status_code=404, detail="Book not found")
        
        # Extract CV data if available
        cv_summary = book.get('profile_summary', 'Professional with extensive experience')
        
        # Mock CV data for testing (in production, you'd extract this properly)
        cv_data = {
            'years_experience': 10,
            'specialization': book.get('genre', 'Professional Writing'),
            'cv_summary': cv_summary,
            'achievements': [
                'Led projects resulting in 40% improvement',
                'Trained 500+ professionals',
                'Published in industry journals'
            ],
            'companies': ['Company A', 'Company B'],
            'education': ['Bachelor in relevant field'],
            'certifications': ['Professional Certification'],
            'publications_speaking': ['Conference speaker']
        }
        
        # Build previous chapters context
        previous_chapters = [ch for ch in book.get('chapters', []) if ch['number'] < chapter_number and ch.get('approved', False)]
        previous_content = "\n\n".join([f"Chapter {ch['number']}: {ch['title']}\n{ch.get('content_en', ch.get('content', ''))}" for ch in previous_chapters])
        
        # CURRENT PROMPT (simplified version)
        current_prompt = f"""Write Chapter {chapter_number} of {book['num_chapters']} for the book "{book['title']}".

**BOOK INFORMATION:**
Title: {book['title']}
Genre: {book['genre']}
Synopsis: {book['synopsis']}

{("**CONTEXT:**" + chr(10) + previous_content) if previous_content else "**This is the first chapter.**"}

**REQUIREMENTS:**
- Must be between 2,000 and 5,000 characters
- Include chapter title
- Professional narrative
- NO conclusions at the end

Write the chapter in HTML format."""
        
        # NEW USCIS-OPTIMIZED PROMPT
        uscis_prompt = get_uscis_chapter_prompt(
            chapter_number=chapter_number,
            num_chapters=book['num_chapters'],
            author_name=book.get('author_name', 'Author'),
            cv_data=cv_data,
            book_title=book['title'],
            genre=book['genre'],
            synopsis=book['synopsis'],
            writing_style=book.get('writing_style', 'professional'),
            previous_chapters_content=previous_content
        )
        
        # Generate with BOTH prompts
        current_system_msg = f"You are a professional writer specialized in {book['genre']}."
        uscis_system_msg = get_uscis_system_message(book['genre'], cv_data['specialization'])
        
        # Call GPT-5.1 with current prompt
        logging.info("🔵 Generating with CURRENT prompt...")
        # Use call_openai_gpt5 which has built-in OpenRouter fallback
        current_output = await call_openai_gpt5(
            system_message=current_system_msg,
            user_message=current_prompt,
            temperature=0.7,
            max_tokens=2500
        )
        
        # Call GPT-5.1 with USCIS prompt
        logging.info("🟢 Generating with USCIS-OPTIMIZED prompt...")
        uscis_output = await call_openai_gpt5(
            system_message=uscis_system_msg,
            user_message=uscis_prompt,
            temperature=0.7,
            max_tokens=5000
        )
        
        return {
            "success": True,
            "comparison": {
                "current": {
                    "prompt_length": len(current_prompt),
                    "system_message": current_system_msg,
                    "output": current_output,
                    "output_length": len(current_output),
                    "estimated_read_time": round(len(current_output) / 1000)  # rough estimate
                },
                "uscis_optimized": {
                    "prompt_length": len(uscis_prompt),
                    "system_message": uscis_system_msg,
                    "output": uscis_output,
                    "output_length": len(uscis_output),
                    "estimated_read_time": round(len(uscis_output) / 1000)
                },
                "analysis": {
                    "length_difference": len(uscis_output) - len(current_output),
                    "uscis_is_longer": len(uscis_output) > len(current_output),
                    "current_meets_min": len(current_output) >= 2000,
                    "uscis_meets_min": len(uscis_output) >= 8000,
                    "recommendation": "USCIS version provides more substantive content for immigration cases" if len(uscis_output) > len(current_output) else "Current version is adequate"
                }
            }
        }
        
    except Exception as e:
        logging.error(f"Error in prompt comparison test: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

