# ============================================================================
# AUTO-LIMPIEZA DE PAPELERA - Retención 30 días
# ============================================================================

async def cleanup_old_trash():
    """
    Elimina permanentemente documentos que han estado en papelera por más de 30 días.
    Se ejecuta automáticamente todos los días a las 3:00 AM.
    """
    try:
        cutoff_date = datetime.now(timezone.utc) - timedelta(days=30)
        logger.info(f"🗑️ Iniciando limpieza automática de papelera (documentos anteriores a {cutoff_date.isoformat()})")
        
        # Colecciones a limpiar
        collections_to_clean = [
            ('niw_in_progress', 'NIW'),
            ('business_plans', 'Planes de Negocio'),
            ('patents_in_progress', 'Patentes en Progreso'),
            ('patents', 'Patentes'),
            ('books_in_progress', 'Libros en Progreso'),
            ('books', 'Libros'),
            ('case_studies', 'Casos de Estudio'),
            ('self_petition_letters', 'Cartas'),
            ('clients', 'Clientes')
        ]
        
        total_deleted = 0
        
        for collection_name, friendly_name in collections_to_clean:
            try:
                collection = db[collection_name]
                
                # Encontrar documentos candidatos
                query = {
                    "status": "deleted",
                    "deleted_at": {"$lt": cutoff_date.isoformat()}
                }
                
                # Contar primero
                count = await collection.count_documents(query)
                
                if count > 0:
                    # Eliminar permanentemente
                    result = await collection.delete_many(query)
                    deleted = result.deleted_count
                    total_deleted += deleted
                    logger.info(f"  ✅ {friendly_name}: {deleted} documentos eliminados permanentemente")
                else:
                    logger.info(f"  ⏭️ {friendly_name}: 0 documentos para eliminar")
                    
            except Exception as e:
                logger.error(f"  ❌ Error limpiando {friendly_name}: {str(e)}")
                continue
        
        logger.info(f"🎉 Limpieza completada. Total eliminados: {total_deleted} documentos")
        
        # Log en colección de auditoría (opcional)
        try:
            await db.trash_cleanup_log.insert_one({
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "cutoff_date": cutoff_date.isoformat(),
                "total_deleted": total_deleted,
                "status": "success"
            })
        except:
            pass  # No crítico si falla el log
            
    except Exception as e:
        logger.error(f"❌ Error en limpieza automática de papelera: {str(e)}")
        try:
            await db.trash_cleanup_log.insert_one({
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "error": str(e),
                "status": "failed"
            })
        except:
            pass

async def check_stuck_books():
    """
    Tarea programada para detectar y reintentar libros atascados
    
    Detecta libros que:
    - Tienen status 'generating'
    - No se han actualizado en más de 30 minutos
    
    Los marca como necesitando retry y opcionalmente los reinicia automáticamente
    """
    try:
        logging.info("🔍 [AUTO-RECOVERY] Checking for stuck books...")
        
        # Buscar libros en progreso
        books_in_progress = await db.books_in_progress.find(
            {"status": "generating"},
            {"_id": 0, "id": 1, "title": 1, "updated_at": 1, "progress_percentage": 1, "progress_message": 1}
        ).to_list(100)
        
        if not books_in_progress:
            logging.info("✅ [AUTO-RECOVERY] No books currently generating")
            return
        
        logging.info(f"📚 [AUTO-RECOVERY] Found {len(books_in_progress)} books generating")
        
        now = datetime.now(timezone.utc)
        stuck_books = []
        
        for book in books_in_progress:
            updated_at = book.get('updated_at')
            if isinstance(updated_at, str):
                from dateutil import parser
                updated_at = parser.parse(updated_at)
            
            minutes_since_update = (now - updated_at).total_seconds() / 60
            
            # Consider stuck if no update in 30 minutes
            if minutes_since_update > 30:
                stuck_books.append({
                    'id': book['id'],
                    'title': book.get('title', 'Unknown'),
                    'minutes_stuck': minutes_since_update,
                    'progress': book.get('progress_percentage', 0),
                    'message': book.get('progress_message', '')
                })
                logging.warning(f"⚠️ [AUTO-RECOVERY] STUCK BOOK DETECTED: {book.get('title')} (ID: {book['id']}) - No update for {minutes_since_update:.1f} minutes")
        
        if not stuck_books:
            logging.info(f"✅ [AUTO-RECOVERY] All {len(books_in_progress)} books are progressing normally")
            return
        
        # Mark stuck books and optionally auto-restart them
        for stuck_book in stuck_books:
            book_id = stuck_book['id']
            
            # Mark as failed with detailed error message
            await db.books_in_progress.update_one(
                {"id": book_id},
                {"$set": {
                    "status": "failed",
                    "error_message": f"Generation stuck: No update for {stuck_book['minutes_stuck']:.0f} minutes. Last progress: {stuck_book['progress']}%",
                    "updated_at": datetime.now(timezone.utc).isoformat()
                }}
            )
            
            logging.error(f"❌ [AUTO-RECOVERY] Marked book {stuck_book['title']} as FAILED (stuck for {stuck_book['minutes_stuck']:.1f} min)")
            
            # Log to audit trail
            try:
                await db.auto_recovery_log.insert_one({
                    "timestamp": datetime.now(timezone.utc).isoformat(),
                    "book_id": book_id,
                    "book_title": stuck_book['title'],
                    "action": "marked_as_failed",
                    "reason": f"stuck_for_{stuck_book['minutes_stuck']:.0f}_minutes",
                    "last_progress": stuck_book['progress'],
                    "last_message": stuck_book['message']
                })
            except:
                pass
        
        logging.info(f"🔧 [AUTO-RECOVERY] Processed {len(stuck_books)} stuck books. Users can now click 'Retry' button.")
        
    except Exception as e:
        logging.error(f"❌ [AUTO-RECOVERY] Error in stuck books check: {str(e)}")
        try:
            await db.auto_recovery_log.insert_one({
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "action": "check_failed",
                "error": str(e)
            })
        except:
            pass

# Inicializar scheduler
scheduler = AsyncIOScheduler()

@app.on_event("startup")
async def start_trash_cleanup_scheduler():
    """Iniciar el scheduler de limpieza automática de papelera y detección de libros atascados"""
    try:
        # Agregar job para ejecutar todos los días a las 3:00 AM
        scheduler.add_job(
            cleanup_old_trash,
            CronTrigger(hour=3, minute=0),  # 3:00 AM
            id='trash_cleanup',
            name='Limpieza automática de papelera (30 días)',
            replace_existing=True
        )
        
        # Agregar job para detectar libros atascados cada 10 minutos
        scheduler.add_job(
            check_stuck_books,
            CronTrigger(minute='*/10'),  # Every 10 minutes
            id='stuck_books_check',
            name='Detección automática de libros atascados',
            replace_existing=True
        )
        
        scheduler.start()
        logger.info("✅ Scheduler de limpieza de papelera iniciado (ejecuta diariamente a las 3:00 AM)")
        logger.info("✅ Scheduler de detección de libros atascados iniciado (ejecuta cada 10 minutos)")
        logger.info("📋 Retención configurada: 30 días")
        
        # Migration: Fix econometric studies with incorrect status (non-blocking)
        # Run in background to avoid delaying startup
        async def _run_migrations():
            try:
                await fix_econometric_study_statuses()
            except Exception as migration_err:
                logger.warning(f"⚠️ Startup migration failed (non-critical): {migration_err}")
        
        import asyncio as _asyncio
        _asyncio.ensure_future(_run_migrations())
        
    except Exception as e:
        logger.error(f"❌ Error al iniciar scheduler de limpieza: {str(e)}")

async def fix_econometric_study_statuses():
    """Fix econometric studies that have 'generation_complete' status instead of 'completed'"""
    try:
        # Fix studies in completed collection with wrong status
        result = await db.econometric_studies.update_many(
            {"status": "generation_complete"},
            {"$set": {"status": "completed"}}
        )
        if result.modified_count > 0:
            logger.info(f"✅ Fixed {result.modified_count} econometric studies with incorrect status")
        
        # Also check for studies that should be moved from in_progress to completed
        stuck_completed = await db.econometric_studies_in_progress.find({
            "status": "generation_complete",
            "progress": {"$gte": 100}
        }).to_list(100)
        
        for study in stuck_completed:
            try:
                study_copy = {k: v for k, v in study.items() if k != '_id'}
                study_copy["status"] = "completed"
                study_copy["completed_at"] = datetime.now(timezone.utc).isoformat()
                
                await db.econometric_studies.insert_one(study_copy)
                await db.econometric_studies_in_progress.delete_one({"id": study["id"]})
                
                logger.info(f"✅ Moved stuck study {study['id']} to completed collection")
            except Exception as e:
                logger.warning(f"Could not move study {study.get('id')}: {e}")
                
    except Exception as e:
        logger.warning(f"Migration fix_econometric_study_statuses failed: {e}")

