# --- Translation Models ---

class TranslationRequest(BaseModel):
    text: str
    filename: Optional[str] = None

class TranslationResponse(BaseModel):
    id: str
    original_text: str
    translated_text: str
    filename: Optional[str] = None
    char_count_original: int
    char_count_translated: int
    word_count_original: int
    word_count_translated: int
    created_at: str

class TranslatorProfile(BaseModel):
    id: str = Field(default_factory=lambda: str(uuid.uuid4()))
    full_name: str
    id_number: str
    title: str
    phone: str
    email: str
    certificate_prefix: str = "TRAD"
    next_certificate_number: int = 1
    signature_image: Optional[str] = None  # base64 data URL
    created_at: str = Field(default_factory=lambda: datetime.now(timezone.utc).isoformat())

class CertifiedTranslationRequest(BaseModel):
    original_text: str
    filename: Optional[str] = None
    document_description: Optional[str] = None
    profile_id: Optional[str] = None  # specific profile to use; defaults to first profile

class CertifiedTranslationResponse(BaseModel):
    id: str
    certificate_number: str
    document_description: str
    original_filename: Optional[str] = None
    original_text: str
    translated_text: str
    translator_id: str
    translator_name: str
    translator_id_number: str
    translator_title: str
    translator_phone: str
    translator_email: str
    certification_date: str
    created_at: str

# --- Translation Helper Functions ---

TRANSLATION_SYSTEM_PROMPT = """You are an expert professional translator specializing in Spanish to English translation for legal, business, and academic documents.

YOUR APPROACH:
- Translate for MEANING and CONTEXT, not word-by-word
- Use natural, fluent English that reads as if originally written in English
- Maintain the professional tone and register of the original document
- Adapt idiomatic expressions to their English equivalents

CRITICAL RULES:
1. PRESERVE ALL CONTENT - Do NOT summarize, do NOT shorten, do NOT omit any information
2. PRESERVE EXACT STRUCTURE - Maintain all paragraphs, line breaks, sections, bullet points, and original formatting
3. Keep the same number of paragraphs and the same logical flow
4. Preserve proper nouns, names, acronyms, and technical terms appropriately
5. Numbers, dates, and citations must remain accurate
6. Do NOT add explanations, notes, or comments - ONLY return the translated text
7. Do NOT add headers like "Translation:", "Part 1", "Page X", or any meta-information
8. Do NOT add page markers, section dividers, or any text that was not in the original document
9. If the original has natural paragraph breaks, preserve them exactly as they appear

OUTPUT: Return ONLY the translated document text. The translation must have the EXACT same structure as the original - same paragraphs, same line breaks, no added markers or dividers."""

DOCUMENT_DESCRIPTION_PROMPT = """You are a document analyst. Given a Spanish document, provide a brief, formal description in English suitable for a certified translation certificate.

Format: "[Document type] issued by [issuer], dated [date if available]"

Examples:
- "Certificate of grades issued by Universidad Central de Venezuela, dated March 15, 2023"
- "Birth certificate issued by the Civil Registry of Caracas"
- "Academic diploma issued by Instituto Tecnológico de Monterrey"

Be concise and formal. Output ONLY the description, nothing else."""

async def translate_text_chunk(text: str, retries: int = 3) -> str:
    """Translate a single chunk of text using OpenAI GPT-4o with OpenRouter fallback."""
    for attempt in range(retries):
        try:
            # Use call_openai_gpt4o which has built-in 429 retry + OpenRouter fallback
            return await asyncio.wait_for(
                call_openai_gpt4o(
                    system_message=TRANSLATION_SYSTEM_PROMPT,
                    user_message=text,
                    temperature=0.3,
                    max_tokens=6000
                ),
                timeout=180.0  # Overall timeout (generous to allow fallback chain)
            )
            
        except asyncio.TimeoutError:
            logging.error(f"Translation attempt {attempt + 1} timed out")
            if attempt < retries - 1:
                await asyncio.sleep(3)
            else:
                raise HTTPException(status_code=504, detail="Translation timed out. Try with a smaller document.")
        except Exception as e:
            logging.error(f"Translation attempt {attempt + 1} failed: {str(e)}")
            if attempt < retries - 1:
                wait_time = 3 * (2 ** attempt)  # 3s, 6s, 12s
                await asyncio.sleep(wait_time)
            else:
                raise HTTPException(status_code=500, detail=f"Translation failed after {retries} attempts: {str(e)}")

async def translate_full_document(text: str) -> str:
    """Translate a full document, chunking if necessary for production reliability"""
    # Smaller chunks for faster processing and avoid timeouts
    MAX_CHUNK_SIZE = 4000  # Reduced from 8000 for faster processing
    
    if len(text) <= MAX_CHUNK_SIZE:
        return await translate_text_chunk(text)
    
    # Split by paragraphs first
    paragraphs = text.split('\n\n')
    chunks = []
    current_chunk = ""
    
    for para in paragraphs:
        # If paragraph itself is too long, split by sentences
        if len(para) > MAX_CHUNK_SIZE:
            sentences = para.replace('. ', '.|').split('|')
            for sentence in sentences:
                if len(current_chunk) + len(sentence) + 2 <= MAX_CHUNK_SIZE:
                    current_chunk = current_chunk + " " + sentence if current_chunk else sentence
                else:
                    if current_chunk:
                        chunks.append(current_chunk.strip())
                    current_chunk = sentence
        elif len(current_chunk) + len(para) + 2 <= MAX_CHUNK_SIZE:
            current_chunk = current_chunk + "\n\n" + para if current_chunk else para
        else:
            if current_chunk:
                chunks.append(current_chunk.strip())
            current_chunk = para
    
    if current_chunk:
        chunks.append(current_chunk.strip())
    
    total_chunks = len(chunks)
    logging.info(f"📄 Document split into {total_chunks} chunks for translation")
    
    translated_chunks = []
    for i, chunk in enumerate(chunks):
        logging.info(f"🔄 Translating chunk {i + 1}/{total_chunks} ({len(chunk)} chars)")
        try:
            translated = await translate_text_chunk(chunk)
            translated_chunks.append(translated)
        except Exception as e:
            logging.error(f"❌ Chunk {i + 1} failed: {str(e)}")
            # Continue with remaining chunks, mark failed chunk
            translated_chunks.append(f"[Error en traducción del segmento {i + 1}]")
        
        # Smaller delay between chunks for faster processing
        if i < total_chunks - 1:
            await asyncio.sleep(0.5)  # Reduced from 2s
    
    logging.info(f"✅ Translation complete: {total_chunks} chunks processed")
    return '\n\n'.join(translated_chunks)
    
    # Split by paragraphs
    paragraphs = text.split('\n\n')
    chunks = []
    current_chunk = ""
    
    for para in paragraphs:
        if len(current_chunk) + len(para) + 2 <= MAX_CHUNK_SIZE:
            current_chunk = current_chunk + "\n\n" + para if current_chunk else para
        else:
            if current_chunk:
                chunks.append(current_chunk)
            current_chunk = para
    
    if current_chunk:
        chunks.append(current_chunk)
    
    logging.info(f"📄 Document split into {len(chunks)} chunks for translation")
    
    translated_chunks = []
    for i, chunk in enumerate(chunks):
        logging.info(f"🔄 Translating chunk {i + 1}/{len(chunks)} ({len(chunk)} chars)")
        translated = await translate_text_chunk(chunk)
        translated_chunks.append(translated)
        
        if i < len(chunks) - 1:
            await asyncio.sleep(2)  # Rate limit protection
    
    return '\n\n'.join(translated_chunks)

async def generate_document_description(text: str) -> str:
    """Generate a formal description of the document using OpenAI"""
    try:
        # Use first 2000 chars for description
        sample_text = text[:2000] if len(text) > 2000 else text
        
        # Use call_openai_gpt4o which has built-in 429 retry + OpenRouter fallback
        content = await call_openai_gpt4o(
            system_message=DOCUMENT_DESCRIPTION_PROMPT,
            user_message=sample_text,
            temperature=0.3,
            max_tokens=200
        )
        return content.strip()
        
    except Exception as e:
        logging.error(f"Failed to generate document description: {str(e)}")
        return "Document translated from Spanish to English"

def count_words(text: str) -> int:
    """Count words in text"""
    return len(text.split())

def create_certified_translation_pdf(cert: dict) -> bytes:
    """Create a professional certified translation PDF"""
    buffer = io.BytesIO()
    
    # Get client name for metadata
    client_name = cert.get('client_name', 'Client')
    cert_number = cert.get('certificate_number', 'Certified Translation')
    
    doc = SimpleDocTemplate(
        buffer, 
        pagesize=letter,
        rightMargin=inch,
        leftMargin=inch,
        topMargin=inch,
        bottomMargin=inch,
        title=f"Certified Translation - {client_name} - {cert_number}",
        author=cert.get('translator_name', 'Certified Translator'),
        subject=f"Certified Translation Certificate {cert_number}",
        creator="Monica Redactora - Translation Module"
    )
    
    styles = getSampleStyleSheet()
    
    # Custom styles
    title_style = ParagraphStyle(
        'CertTitle',
        parent=styles['Heading1'],
        fontSize=18,
        alignment=TA_CENTER,
        spaceAfter=30,
        fontName='Helvetica-Bold'
    )
    
    subtitle_style = ParagraphStyle(
        'CertSubtitle',
        parent=styles['Heading2'],
        fontSize=14,
        alignment=TA_CENTER,
        spaceAfter=20,
        fontName='Helvetica-Bold'
    )
    
    heading_style = ParagraphStyle(
        'CertHeading',
        parent=styles['Heading2'],
        fontSize=12,
        alignment=TA_LEFT,
        spaceBefore=15,
        spaceAfter=8,
        fontName='Helvetica-Bold'
    )
    
    body_style = ParagraphStyle(
        'CertBody',
        parent=styles['Normal'],
        fontSize=11,
        alignment=TA_JUSTIFY,
        spaceBefore=6,
        spaceAfter=6,
        leading=16
    )
    
    center_style = ParagraphStyle(
        'CertCenter',
        parent=styles['Normal'],
        fontSize=11,
        alignment=TA_CENTER,
        spaceBefore=20,
        spaceAfter=6
    )
    
    story = []
    
    # Certificate Page
    story.append(Paragraph("CERTIFICATE OF TRANSLATION", title_style))
    
    story.append(Spacer(1, 20))
    
    story.append(Paragraph(f"<b>Certificate No.:</b> {cert['certificate_number']}", body_style))
    story.append(Spacer(1, 20))
    
    cert_text = f"""I, <b>{cert['translator_name']}</b>, <b>{cert['translator_title']}</b>, with ID number <b>{cert['translator_id_number']}</b>, hereby certify that I am competent to translate from Spanish into English and that I have faithfully and accurately translated the attached document."""
    story.append(Paragraph(cert_text, body_style))
    story.append(Spacer(1, 15))
    
    story.append(Paragraph(f"<b>Document Translated:</b> {cert['document_description']}", body_style))
    story.append(Spacer(1, 15))
    
    accuracy_text = """This translation is a true, complete, and correct rendering of the original document presented in Spanish. I further certify that I am qualified by reason of my knowledge, training, and experience to perform such translation."""
    story.append(Paragraph(accuracy_text, body_style))
    story.append(Spacer(1, 20))
    
    story.append(Paragraph("Translator's Information:", heading_style))
    
    info_data = [
        ["Full Name:", cert['translator_name']],
        ["ID:", cert['translator_id_number']],
        ["Title/Position:", cert['translator_title']],
        ["Phone:", cert['translator_phone']],
        ["Email:", cert['translator_email']]
    ]
    
    info_table = Table(info_data, colWidths=[1.5*inch, 4*inch])
    info_table.setStyle(TableStyle([
        ('FONTNAME', (0, 0), (0, -1), 'Helvetica-Bold'),
        ('FONTNAME', (1, 0), (1, -1), 'Helvetica'),
        ('FONTSIZE', (0, 0), (-1, -1), 10),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 8),
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
    ]))
    story.append(info_table)
    story.append(Spacer(1, 30))
    
    story.append(Paragraph("Declaration:", heading_style))
    declaration = """I declare under penalty of perjury under the laws of the United States of America that the foregoing is true and correct."""
    story.append(Paragraph(declaration, body_style))
    story.append(Spacer(1, 40))
    
    # Signature block — use image if available, else text underline
    signature_image_data = cert.get("translator_signature_image")
    if signature_image_data:
        try:
            import base64 as b64_module
            # Handle data URL: "data:image/png;base64,..."
            if ',' in signature_image_data:
                b64_str = signature_image_data.split(',', 1)[1]
            else:
                b64_str = signature_image_data
            img_bytes = b64_module.b64decode(b64_str)
            img_buffer = io.BytesIO(img_bytes)
            
            from reportlab.platypus import Image as RLImage
            from reportlab.lib.utils import ImageReader
            reader = ImageReader(img_buffer)
            img_w, img_h = reader.getSize()
            
            # Scale to max 2.5 inches wide, max 1 inch tall — preserve aspect ratio
            max_w = 2.5 * inch
            max_h = 1.0 * inch
            ratio = min(max_w / img_w, max_h / img_h)
            disp_w = img_w * ratio
            disp_h = img_h * ratio
            
            img_buffer.seek(0)
            sig_img = RLImage(img_buffer, width=disp_w, height=disp_h)
            sig_img.hAlign = 'CENTER'
            story.append(sig_img)
        except Exception as sig_err:
            logging.warning(f"Could not render signature image: {sig_err}")
            story.append(Paragraph("_" * 40, center_style))
    else:
        story.append(Paragraph("_" * 40, center_style))
    
    story.append(Paragraph("SIGNATURE", center_style))
    story.append(Paragraph(f"Printed Name: {cert['translator_name']}", center_style))
    story.append(Paragraph(f"Date: {cert['certification_date']}", center_style))
    
    # Page break before translated document
    story.append(PageBreak())
    
    # Translated Document
    story.append(Paragraph("TRANSLATED DOCUMENT", title_style))
    story.append(Spacer(1, 20))
    
    # Parse translated text preserving paragraphs — skip blank paragraphs to avoid blank pages
    translated_paragraphs = cert['translated_text'].split('\n\n')
    for para in translated_paragraphs:
        if para.strip():
            # Clean HTML tags if present; escape XML special chars
            from xml.sax.saxutils import escape as xml_escape_local
            clean_para = re.sub(r'<[^>]+>', '', para)
            safe_para = xml_escape_local(clean_para)
            safe_para = safe_para.replace('\n', '<br/>')
            try:
                story.append(Paragraph(safe_para, body_style))
                story.append(Spacer(1, 8))
            except Exception:
                story.append(Paragraph(xml_escape_local(clean_para), body_style))
                story.append(Spacer(1, 8))
    
    # Append original document section if original_text is available
    original_text = cert.get('original_text', '')
    if original_text and original_text.strip():
        story.append(PageBreak())
        story.append(Paragraph("ORIGINAL DOCUMENT (SPANISH)", title_style))
        story.append(Spacer(1, 20))
        
        original_paragraphs = original_text.split('\n\n')
        for para in original_paragraphs:
            if para.strip():
                from xml.sax.saxutils import escape as xml_escape_orig
                clean_para = re.sub(r'<[^>]+>', '', para)
                safe_para = xml_escape_orig(clean_para)
                safe_para = safe_para.replace('\n', '<br/>')
                try:
                    story.append(Paragraph(safe_para, body_style))
                    story.append(Spacer(1, 8))
                except Exception:
                    story.append(Paragraph(xml_escape_orig(clean_para), body_style))
                    story.append(Spacer(1, 8))
    
    doc.build(story)
    return buffer.getvalue()

def create_translation_pdf(translated_text: str, title: str = "Translation") -> bytes:
    """Create a simple PDF with just the translated text"""
    from xml.sax.saxutils import escape as xml_escape
    
    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer, 
        pagesize=letter,
        rightMargin=inch,
        leftMargin=inch,
        topMargin=inch,
        bottomMargin=inch,
        title=title,
        author="Monica Redactora",
        subject="Spanish to English Translation",
        creator="Monica Redactora - Translation Module"
    )
    
    styles = getSampleStyleSheet()
    
    title_style = ParagraphStyle(
        'TransTitle',
        parent=styles['Heading1'],
        fontSize=16,
        alignment=TA_CENTER,
        spaceAfter=30
    )
    
    body_style = ParagraphStyle(
        'TransBody',
        parent=styles['Normal'],
        fontSize=11,
        alignment=TA_JUSTIFY,
        spaceBefore=6,
        spaceAfter=6,
        leading=16
    )
    
    story = []
    # Escape title for XML/PDF
    safe_title = xml_escape(title)
    story.append(Paragraph(safe_title, title_style))
    story.append(Spacer(1, 20))
    
    paragraphs = translated_text.split('\n\n')
    for para in paragraphs:
        if para.strip():
            # Remove HTML tags first, then escape special XML chars
            clean_para = re.sub(r'<[^>]+>', '', para)
            # Escape &, <, > for ReportLab XML parser
            safe_para = xml_escape(clean_para)
            # Replace newlines with <br/> for ReportLab
            safe_para = safe_para.replace('\n', '<br/>')
            try:
                story.append(Paragraph(safe_para, body_style))
                story.append(Spacer(1, 8))
            except Exception as e:
                # Fallback: use plain text without any formatting
                logging.warning(f"PDF paragraph error: {e}, using fallback")
                safe_para = ''.join(c if c.isprintable() or c in '\n\t' else ' ' for c in clean_para)
                story.append(Paragraph(xml_escape(safe_para), body_style))
                story.append(Spacer(1, 8))
    
    doc.build(story)
    return buffer.getvalue()

# --- Translation Endpoints ---

# Production limits
MAX_DOCUMENT_CHARS = 100000  # ~25,000 words max
MAX_DOCUMENT_WORDS = 30000

# In-memory store for async translations (for production, use Redis)
translation_tasks = {}

async def run_translation_background(task_id: str, text: str, filename: str, user_id: str, client_id: Optional[str] = None):
    """Background task for translating large documents"""
    try:
        translation_tasks[task_id]["status"] = "processing"
        translation_tasks[task_id]["progress"] = 5
        
        # Split into chunks
        MAX_CHUNK_SIZE = 4000
        paragraphs = text.split('\n\n')
        chunks = []
        current_chunk = ""
        
        for para in paragraphs:
            if len(para) > MAX_CHUNK_SIZE:
                sentences = para.replace('. ', '.|').split('|')
                for sentence in sentences:
                    if len(current_chunk) + len(sentence) + 2 <= MAX_CHUNK_SIZE:
                        current_chunk = current_chunk + " " + sentence if current_chunk else sentence
                    else:
                        if current_chunk:
                            chunks.append(current_chunk.strip())
                        current_chunk = sentence
            elif len(current_chunk) + len(para) + 2 <= MAX_CHUNK_SIZE:
                current_chunk = current_chunk + "\n\n" + para if current_chunk else para
            else:
                if current_chunk:
                    chunks.append(current_chunk.strip())
                current_chunk = para
        
        if current_chunk:
            chunks.append(current_chunk.strip())
        
        total_chunks = len(chunks)
        translation_tasks[task_id]["total_chunks"] = total_chunks
        logging.info(f"📄 [ASYNC] Document split into {total_chunks} chunks for translation")
        
        translated_chunks = []
        for i, chunk in enumerate(chunks):
            try:
                translation_tasks[task_id]["current_chunk"] = i + 1
                translation_tasks[task_id]["progress"] = int(10 + (80 * (i / total_chunks)))
                
                translated = await translate_text_chunk(chunk)
                translated_chunks.append(translated)
                logging.info(f"✅ [ASYNC] Chunk {i + 1}/{total_chunks} translated")
                
            except Exception as e:
                logging.error(f"❌ [ASYNC] Chunk {i + 1} failed: {str(e)}")
                translated_chunks.append(f"[Error en traducción del segmento {i + 1}]")
            
            if i < total_chunks - 1:
                await asyncio.sleep(0.3)
        
        translated_text = '\n\n'.join(translated_chunks)
        
        # Calculate stats
        char_count_original = len(text)
        char_count_translated = len(translated_text)
        word_count_original = count_words(text)
        word_count_translated = count_words(translated_text)
        
        # Save to database
        translation_id = str(uuid.uuid4())
        translation_doc = {
            "id": translation_id,
            "user_id": user_id,
            "client_id": client_id,
            "original_text": text,
            "translated_text": translated_text,
            "filename": filename,
            "char_count_original": char_count_original,
            "char_count_translated": char_count_translated,
            "word_count_original": word_count_original,
            "word_count_translated": word_count_translated,
            "created_at": datetime.now(timezone.utc).isoformat()
        }
        await db.translations.insert_one(translation_doc)
        
        # Update task with result
        translation_tasks[task_id]["status"] = "completed"
        translation_tasks[task_id]["progress"] = 100
        translation_tasks[task_id]["result"] = {
            "id": translation_id,
            "translated_text": translated_text,
            "char_count_original": char_count_original,
            "char_count_translated": char_count_translated,
            "word_count_original": word_count_original,
            "word_count_translated": word_count_translated
        }
        logging.info(f"✅ [ASYNC] Translation complete: {task_id}")
        
    except Exception as e:
        logging.error(f"❌ [ASYNC] Translation failed: {str(e)}")
        translation_tasks[task_id]["status"] = "failed"
        translation_tasks[task_id]["error"] = str(e)


class AsyncTranslationRequest(BaseModel):
    text: str
    filename: Optional[str] = "document.txt"


@api_router.post("/translate-async")
async def start_async_translation(
    request: AsyncTranslationRequest, 
    client_id: Optional[str] = None, 
    background_tasks: BackgroundTasks = None,
    current_user: User = Depends(get_current_user)
):
    """Start async translation for large documents - returns task_id for polling"""
    text_length = len(request.text)
    word_count = count_words(request.text)
    
    logging.info(f"📝 [ASYNC] Starting translation for user {current_user.email}")
    logging.info(f"   Document: {text_length} chars, {word_count} words")
    
    # Validate document size
    if text_length > MAX_DOCUMENT_CHARS:
        raise HTTPException(
            status_code=400, 
            detail=f"El documento es demasiado largo ({text_length:,} caracteres). Máximo permitido: {MAX_DOCUMENT_CHARS:,} caracteres."
        )
    
    # Create task
    task_id = str(uuid.uuid4())
    translation_tasks[task_id] = {
        "status": "queued",
        "progress": 0,
        "total_chunks": 0,
        "current_chunk": 0,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "filename": request.filename,
        "char_count": text_length,
        "word_count": word_count
    }
    
    # Start background task
    asyncio.create_task(run_translation_background(
        task_id, 
        request.text, 
        request.filename or "document.txt",
        current_user.id,
        client_id
    ))
    
    return {
        "task_id": task_id,
        "status": "queued",
        "message": "Traducción iniciada. Use /translate-status/{task_id} para verificar el progreso.",
        "char_count": text_length,
        "word_count": word_count
    }


@api_router.get("/translate-status/{task_id}")
async def get_translation_status(task_id: str, current_user: User = Depends(get_current_user)):
    """Check status of async translation"""
    if task_id not in translation_tasks:
        raise HTTPException(status_code=404, detail="Tarea de traducción no encontrada")
    
    task = translation_tasks[task_id]
    
    response = {
        "task_id": task_id,
        "status": task["status"],
        "progress": task.get("progress", 0),
        "current_chunk": task.get("current_chunk", 0),
        "total_chunks": task.get("total_chunks", 0),
        "filename": task.get("filename", ""),
        "char_count": task.get("char_count", 0),
        "word_count": task.get("word_count", 0)
    }
    
    if task["status"] == "completed":
        response["result"] = task.get("result")
    elif task["status"] == "failed":
        response["error"] = task.get("error", "Error desconocido")
    
    return response


@api_router.post("/translate", response_model=TranslationResponse)
async def translate_document(request: TranslationRequest, client_id: Optional[str] = None, current_user: User = Depends(get_current_user)):
    """Translate a document from Spanish to English (production-ready with chunking)"""
    try:
        text_length = len(request.text)
        word_count = count_words(request.text)
        
        logging.info(f"📝 Starting translation for user {current_user.email}")
        logging.info(f"   Document: {text_length} chars, {word_count} words, client_id: {client_id}")
        
        # Validate document size
        if text_length > MAX_DOCUMENT_CHARS:
            raise HTTPException(
                status_code=400, 
                detail=f"El documento es demasiado largo ({text_length:,} caracteres). Máximo permitido: {MAX_DOCUMENT_CHARS:,} caracteres."
            )
        
        if word_count > MAX_DOCUMENT_WORDS:
            raise HTTPException(
                status_code=400,
                detail=f"El documento es demasiado largo ({word_count:,} palabras). Máximo permitido: {MAX_DOCUMENT_WORDS:,} palabras."
            )
        
        # Translate with chunking
        translated_text = await translate_full_document(request.text)
        
        # Calculate stats
        char_count_original = text_length
        char_count_translated = len(translated_text)
        word_count_original = word_count
        word_count_translated = count_words(translated_text)
        
        # Save to database
        translation_id = str(uuid.uuid4())
        translation_doc = {
            "id": translation_id,
            "user_id": current_user.id,
            "client_id": client_id,
            "original_text": request.text,
            "translated_text": translated_text,
            "filename": request.filename,
            "char_count_original": char_count_original,
            "char_count_translated": char_count_translated,
            "word_count_original": word_count_original,
            "word_count_translated": word_count_translated,
            "created_at": datetime.now(timezone.utc).isoformat()
        }
        
        await db.translations.insert_one(translation_doc)
        logging.info(f"✅ Translation saved with ID: {translation_id}")
        
        return TranslationResponse(**{k: v for k, v in translation_doc.items() if k not in ['user_id', 'client_id']})
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Translation error: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.get("/translations")
async def get_translations(client_id: Optional[str] = None, current_user: User = Depends(get_current_user)):
    """Get all translations, optionally filtered by client - ALL users see ALL translations"""
    query = {"status": {"$ne": "deleted"}}
    if client_id:
        query["client_id"] = client_id
    
    translations = await db.translations.find(query).sort("created_at", -1).to_list(100)
    
    result = []
    for t in translations:
        # Ensure we have a valid id field
        translation_id = t.get("id") or str(t.get("_id", ""))
        
        # Get preview texts
        original_text = t.get("original_text", "")
        translated_text = t.get("translated_text", "")
        
        result.append({
            "id": translation_id,
            "filename": t.get("filename", ""),
            "char_count_original": t.get("char_count_original", len(original_text)),
            "char_count_translated": t.get("char_count_translated", len(translated_text)),
            "word_count_original": t.get("word_count_original", 0),
            "word_count_translated": t.get("word_count_translated", 0),
            "created_at": t.get("created_at", ""),
            "client_id": t.get("client_id"),
            "client_name": None,
            "original_preview": original_text[:150] + "..." if len(original_text) > 150 else original_text,
            "translated_preview": translated_text[:150] + "..." if len(translated_text) > 150 else translated_text
        })
        
        # Add client name
        if t.get("client_id"):
            client = await db.clients.find_one({"id": t["client_id"]}, {"_id": 0, "name": 1})
            if client:
                result[-1]["client_name"] = client.get("name")
    
    return result

@api_router.get("/translations/{translation_id}")
async def get_translation(translation_id: str, current_user: User = Depends(get_current_user)):
    """Get a specific translation - ALL users can access"""
    translation = await db.translations.find_one(
        {"id": translation_id},
        {"_id": 0}
    )
    
    if not translation:
        raise HTTPException(status_code=404, detail="Translation not found")
    
    # Get client name if client_id exists
    client_name = None
    if translation.get("client_id"):
        client = await db.clients.find_one({"id": translation["client_id"]}, {"_id": 0, "name": 1})
        if client:
            client_name = client.get("name")
    
    translation["client_name"] = client_name
    return translation

@api_router.delete("/translations/{translation_id}")
async def delete_translation(translation_id: str, current_user: User = Depends(get_current_user)):
    """Delete a translation - admins can delete any, users can delete their own"""
    logging.info(f"🗑️ Delete request for translation {translation_id} by {current_user.email} (role: {current_user.role})")
    
    # Check admin status (case-insensitive)
    is_admin = current_user.role.upper() == "ADMIN"
    
    # Try to find by 'id' field first, then by MongoDB '_id'
    translation = await db.translations.find_one({"id": translation_id})
    
    if not translation:
        # Try to find by MongoDB ObjectId (for legacy translations)
        try:
            from bson import ObjectId
            if ObjectId.is_valid(translation_id):
                translation = await db.translations.find_one({"_id": ObjectId(translation_id)})
        except Exception as e:
            logging.warning(f"ObjectId conversion failed: {e}")
    
    if not translation:
        logging.warning(f"⚠️ Translation {translation_id} not found in database")
        raise HTTPException(status_code=404, detail="Traducción no encontrada")
    
    # Check permission: admins can delete any, users only their own
    if not is_admin:
        translation_user_id = translation.get("user_id")
        if translation_user_id and translation_user_id != current_user.id:
            logging.warning(f"⚠️ User {current_user.email} tried to delete translation {translation_id} owned by {translation_user_id}")
            raise HTTPException(status_code=403, detail="No tienes permiso para eliminar esta traducción")
    
    # Delete using MongoDB _id for reliability
    result = await db.translations.delete_one({"_id": translation["_id"]})
    
    if result.deleted_count == 0:
        raise HTTPException(status_code=500, detail="Error al eliminar la traducción")
    
    logging.info(f"✅ Translation {translation_id} deleted by {current_user.email}")
    return {"message": "Translation deleted successfully"}

@api_router.get("/export/{translation_id}/pdf")
async def export_translation_pdf(translation_id: str, current_user: User = Depends(get_current_user)):
    """Export a translation as PDF - admins can export any, users can export their own"""
    # Build query - admins can export any, users only their own (case-insensitive role check)
    is_admin = current_user.role.upper() == "ADMIN"
    if is_admin:
        query = {"id": translation_id}
    else:
        query = {"id": translation_id, "user_id": current_user.id}
    
    translation = await db.translations.find_one(query, {"_id": 0})
    
    if not translation:
        raise HTTPException(status_code=404, detail="Translation not found")
    
    # Get client name if client_id exists
    client_name = None
    if translation.get("client_id"):
        client = await db.clients.find_one({"id": translation["client_id"]}, {"_id": 0, "name": 1})
        if client:
            client_name = client.get("name")
    
    # Create title with client name
    base_title = translation.get("filename", "Translation") or "Translation"
    if client_name:
        title = f"{client_name} - {base_title}"
    else:
        title = base_title
    
    pdf_bytes = create_translation_pdf(translation["translated_text"], title)
    
    # Create filename with client name
    if client_name:
        safe_filename = sanitize_filename(f"{client_name}_{base_title}")
    else:
        safe_filename = sanitize_filename(base_title)
    
    return StreamingResponse(
        io.BytesIO(pdf_bytes),
        media_type="application/pdf",
        headers={'Content-Disposition': f'attachment; filename="{safe_filename}_translated.pdf"'}
    )


async def extract_text_from_image_with_vision(image_bytes: bytes, filename: str) -> str:
    """Use GPT-4o Vision to extract text from an image (OCR) - Production ready"""
    import base64
    
    # Validate image size (max 20MB for GPT-4o)
    max_size = 20 * 1024 * 1024
    if len(image_bytes) > max_size:
        raise HTTPException(status_code=400, detail=f"La imagen es demasiado grande ({len(image_bytes) / 1024 / 1024:.1f}MB). Máximo: 20MB")
    
    try:
        # Convert image to base64
        base64_image = base64.b64encode(image_bytes).decode('utf-8')
        
        # Determine mime type
        ext = os.path.splitext(filename)[1].lower()
        mime_types = {
            '.jpg': 'image/jpeg',
            '.jpeg': 'image/jpeg',
            '.png': 'image/png',
            '.webp': 'image/webp',
            '.gif': 'image/gif'
        }
        mime_type = mime_types.get(ext, 'image/jpeg')
        
        # Use call_openai_gpt4o_vision which has built-in 429 retry + OpenRouter fallback
        extracted_text = await asyncio.wait_for(
            call_openai_gpt4o_vision(
                messages=[
                    {
                        "role": "system",
                        "content": """You are an expert OCR system. Extract ALL text from the image exactly as it appears.
                    
For documents like passports, IDs, certificates, and official documents:
- Extract all visible text including names, dates, numbers, and labels
- Preserve the structure and formatting as much as possible
- Include both the field labels and values (e.g., "Nombre / Name: JUAN PEREZ")
- For multilingual documents, include text in all languages
- Include any machine-readable codes (MRZ, barcodes text if visible)

Return ONLY the extracted text, nothing else. No explanations or comments."""
                    },
                    {
                        "role": "user",
                        "content": [
                            {
                                "type": "image_url",
                                "image_url": {
                                    "url": f"data:{mime_type};base64,{base64_image}",
                                    "detail": "high"
                                }
                            },
                            {
                                "type": "text",
                                "text": "Extract all text from this document image. Include all visible text, labels, and values."
                            }
                        ]
                    }
                ],
                max_tokens=4000,
                temperature=0.1
            ),
            timeout=180.0
        )
        logging.info(f"✅ OCR extraction successful for {filename}: {len(extracted_text)} characters")
        return extracted_text
        
    except asyncio.TimeoutError:
        logging.error(f"❌ OCR timeout for {filename}")
        raise HTTPException(status_code=504, detail="OCR timeout. La imagen puede ser demasiado compleja.")
    except Exception as e:
        logging.error(f"❌ OCR extraction failed for {filename}: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error extracting text from image: {str(e)}")


async def extract_text_from_scanned_pdf_with_vision(pdf_bytes: bytes, filename: str) -> str:
    """Use GPT-4o Vision to extract text from a scanned PDF - Production ready with limits"""
    import base64
    import fitz  # PyMuPDF
    
    # Validate PDF size (max 50MB)
    max_size = 50 * 1024 * 1024
    if len(pdf_bytes) > max_size:
        raise HTTPException(status_code=400, detail=f"El PDF es demasiado grande ({len(pdf_bytes) / 1024 / 1024:.1f}MB). Máximo: 50MB")
    
    try:
        pdf_document = fitz.open(stream=pdf_bytes, filetype="pdf")
        total_pages = len(pdf_document)
        
        # Limit pages for production (max 20 pages for OCR)
        max_pages = 20
        if total_pages > max_pages:
            logging.warning(f"⚠️ PDF has {total_pages} pages, limiting OCR to first {max_pages}")
            pages_to_process = max_pages
        else:
            pages_to_process = total_pages
        
        logging.info(f"📄 Processing {pages_to_process}/{total_pages} pages with OCR for {filename}")
        extracted_pages = []
        
        for page_num in range(pages_to_process):
            page = pdf_document[page_num]
            
            # Render page to image at reasonable DPI (144 DPI)
            mat = fitz.Matrix(2.0, 2.0)
            pix = page.get_pixmap(matrix=mat)
            img_bytes = pix.tobytes("png")
            
            # Convert to base64
            base64_image = base64.b64encode(img_bytes).decode('utf-8')
            
            try:
                # Use call_openai_gpt4o_vision which has built-in 429 retry + OpenRouter fallback
                page_text = await asyncio.wait_for(
                    call_openai_gpt4o_vision(
                        messages=[
                            {
                                "role": "system",
                                "content": """You are an expert OCR system. Extract ALL text from this document page exactly as it appears.
Preserve the structure, formatting, and layout as much as possible.
Include all visible text including headers, footers, tables, and any fine print.
Return ONLY the extracted text, nothing else."""
                            },
                            {
                                "role": "user",
                                "content": [
                                    {
                                        "type": "image_url",
                                        "image_url": {
                                            "url": f"data:image/png;base64,{base64_image}",
                                            "detail": "high"
                                        }
                                    },
                                    {
                                        "type": "text",
                                        "text": f"Extract all text from page {page_num + 1} of this document."
                                    }
                                ]
                            }
                        ],
                        max_tokens=4000,
                        temperature=0.1
                    ),
                    timeout=180.0
                )
                if page_text.strip():
                    # Append clean page text without markers
                    extracted_pages.append(page_text.strip())
                
                logging.info(f"✅ OCR page {page_num + 1}/{pages_to_process} extracted: {len(page_text)} chars")
                
            except asyncio.TimeoutError:
                logging.error(f"⚠️ Page {page_num + 1} OCR timeout, skipping")
                # Skip pages with errors silently to preserve document flow
            except Exception as e:
                logging.error(f"⚠️ Page {page_num + 1} OCR failed: {str(e)}")
                # Skip pages with errors silently to preserve document flow
            
            # Small delay between pages
            if page_num < pages_to_process - 1:
                await asyncio.sleep(0.5)
        
        pdf_document.close()
        
        if extracted_pages:
            result = '\n\n'.join(extracted_pages)
            if total_pages > max_pages:
                result += f"\n\n[Nota: Solo se procesaron las primeras {max_pages} páginas de {total_pages}]"
            return result
        else:
            raise HTTPException(status_code=400, detail="No se pudo extraer texto del PDF escaneado")
            
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"❌ Scanned PDF OCR failed for {filename}: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error processing scanned PDF: {str(e)}")


@api_router.post("/upload")
async def upload_document_for_translation(
    file: UploadFile = File(...),
    current_user: User = Depends(get_current_user)
):
    """Upload a document for translation (.txt, .md, .docx, .pdf, images)"""
    allowed_extensions = ['.txt', '.md', '.docx', '.pdf', '.jpg', '.jpeg', '.png', '.webp']
    filename = file.filename or "document"
    ext = os.path.splitext(filename)[1].lower()
    
    if ext not in allowed_extensions:
        raise HTTPException(status_code=400, detail=f"Unsupported file type. Allowed: {', '.join(allowed_extensions)}")
    
    content = ""
    
    try:
        file_content = await file.read()
        logging.info(f"📄 Processing file: {filename} ({len(file_content)} bytes)")
        
        if ext in ['.txt', '.md']:
            content = file_content.decode('utf-8')
            
        elif ext == '.docx':
            doc = docx.Document(io.BytesIO(file_content))
            paragraphs = [p.text for p in doc.paragraphs if p.text.strip()]
            content = '\n\n'.join(paragraphs)
            
        elif ext in ['.jpg', '.jpeg', '.png', '.webp']:
            # Use GPT-4o Vision for image OCR
            logging.info(f"🔍 Using GPT-4o Vision OCR for image: {filename}")
            content = await extract_text_from_image_with_vision(file_content, filename)
            
        elif ext == '.pdf':
            import fitz  # PyMuPDF
            
            pdf_document = fitz.open(stream=file_content, filetype="pdf")
            extracted_text = []
            has_text = False
            
            # First pass: try to extract embedded text
            for page_num in range(len(pdf_document)):
                page = pdf_document[page_num]
                page_text = page.get_text("text").strip()
                
                if page_text:
                    has_text = True
                    # NO agregar marcadores de página para preservar estructura original
                    extracted_text.append(page_text)
            
            pdf_document.close()
            
            if has_text and extracted_text:
                # Unir páginas con doble salto de línea para separación natural
                content = '\n\n'.join(extracted_text)
                logging.info(f"✅ PDF text extraction successful: {len(content)} chars")
            else:
                # PDF is scanned/image-based - use OCR with GPT-4o Vision
                logging.info(f"🔍 PDF appears to be scanned. Using GPT-4o Vision OCR for: {filename}")
                content = await extract_text_from_scanned_pdf_with_vision(file_content, filename)
        
        if not content.strip():
            raise HTTPException(status_code=400, detail="No se pudo extraer texto del documento")
        
        return {
            "filename": filename,
            "content": content,
            "char_count": len(content),
            "word_count": count_words(content)
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error processing file {filename}: {str(e)}")
        raise HTTPException(status_code=500, detail=f"Error processing file: {str(e)}")

