# --- Certified Translation Endpoints ---

@api_router.post("/certified/translate")
async def create_certified_translation(
    request: CertifiedTranslationRequest,
    background_tasks: BackgroundTasks,
    client_id: Optional[str] = None,
    current_user: User = Depends(get_current_user)
):
    """Create a certified translation with certificate - runs as background task to avoid timeouts"""
    # Get translator profile — use specific profile_id if provided
    if request.profile_id:
        profile = await db.translator_profiles.find_one(
            {"id": request.profile_id, "user_id": current_user.id}, {"_id": 0}
        )
    else:
        profile = await db.translator_profiles.find_one({"user_id": current_user.id}, {"_id": 0})

    if not profile:
        raise HTTPException(
            status_code=400,
            detail="Translator profile not configured. Please set up your profile first."
        )
    
    try:
        logging.info(f"📜 Creating certified translation for user {current_user.email}, client_id: {client_id}")
        
        # Generate cert ID and create preliminary record
        cert_id = str(uuid.uuid4())
        cert_prefix = profile.get("certificate_prefix", "TRAD")
        cert_number = profile.get("next_certificate_number", 1)
        year = datetime.now().year
        certificate_number = f"{cert_prefix}{cert_number}{year}"
        
        # Update profile with next certificate number immediately
        await db.translator_profiles.update_one(
            {"id": profile.get("id")},
            {"$inc": {"next_certificate_number": 1}}
        )
        
        # Create initial record with "translating" status
        cert_doc = {
            "id": cert_id,
            "user_id": current_user.id,
            "client_id": client_id,
            "certificate_number": certificate_number,
            "document_description": request.document_description or "",
            "original_filename": request.filename,
            "original_text": request.original_text,
            "translated_text": "",
            "translator_id": profile.get("id"),
            "translator_name": profile.get("full_name"),
            "translator_id_number": profile.get("id_number"),
            "translator_title": profile.get("title"),
            "translator_phone": profile.get("phone"),
            "translator_email": profile.get("email"),
            "translator_signature_image": profile.get("signature_image"),
            "certification_date": datetime.now().strftime("%B %d, %Y"),
            "status": "translating",
            "created_at": datetime.now(timezone.utc).isoformat()
        }
        
        await db.certified_translations.insert_one(cert_doc)
        
        # Launch background task
        background_tasks.add_task(
            _certified_translation_background,
            cert_id, request.original_text, request.document_description, profile
        )
        
        logging.info(f"📜 Certified translation {cert_id} started in background")
        return {"id": cert_id, "status": "translating", "certificate_number": certificate_number}
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Certified translation error: {str(e)}")
        raise HTTPException(status_code=500, detail=str(e))


async def _certified_translation_background(cert_id: str, original_text: str, document_description: str, profile: dict):
    """Background task for certified translation"""
    try:
        # Generate document description if not provided
        if not document_description:
            document_description = await generate_document_description(original_text)
        
        # Translate the document
        translated_text = await translate_full_document(original_text)
        
        # Update record with completed translation
        await db.certified_translations.update_one(
            {"id": cert_id},
            {"$set": {
                "translated_text": translated_text,
                "document_description": document_description,
                "status": "completed",
                "updated_at": datetime.now(timezone.utc).isoformat()
            }}
        )
        logging.info(f"✅ Certified translation {cert_id} completed")
        
    except Exception as e:
        logging.error(f"❌ Certified translation {cert_id} failed: {str(e)}")
        await db.certified_translations.update_one(
            {"id": cert_id},
            {"$set": {
                "status": "failed",
                "error_message": str(e),
                "updated_at": datetime.now(timezone.utc).isoformat()
            }}
        )


