@api_router.get("/certified/export/{cert_id}/pdf")
async def export_certified_translation_pdf(cert_id: str, current_user: User = Depends(get_current_user)):
    """Export a certified translation as PDF with certificate"""
    cert = await db.certified_translations.find_one(
        {"id": cert_id, "user_id": current_user.id},
        {"_id": 0}
    )
    
    if not cert:
        raise HTTPException(status_code=404, detail="Certified translation not found")
    
    # Get client name if client_id exists
    client_name = None
    if cert.get("client_id"):
        client = await db.clients.find_one({"id": cert["client_id"]}, {"_id": 0, "name": 1})
        if client:
            client_name = client.get("name")
    
    # Add client_name to cert dict for PDF generation
    cert["client_name"] = client_name
    
    pdf_bytes = create_certified_translation_pdf(cert)
    
    # Create filename: OriginalFilename_CertNumber_certified.pdf or ClientName_CertNumber_certified.pdf
    original_filename = cert.get('original_filename')
    if original_filename:
        # Strip extension from original filename
        base_name = original_filename.rsplit('.', 1)[0] if '.' in original_filename else original_filename
        safe_filename = sanitize_filename(f"{base_name}_{cert.get('certificate_number', 'certified')}")
    elif client_name:
        safe_filename = sanitize_filename(f"{client_name}_{cert.get('certificate_number', 'certified')}")
    else:
        safe_filename = sanitize_filename(cert.get("certificate_number", "certified_translation"))
    
    return StreamingResponse(
        io.BytesIO(pdf_bytes),
        media_type="application/pdf",
        headers={'Content-Disposition': f'attachment; filename="{safe_filename}_certified.pdf"'}
    )

