class FullModuleUpdateRequest(BaseModel):
    content: str
    notes: Optional[str] = None


# ── Delimiter used in full-module view ──────────────────────────────────────────
_FULL_DELIMITER_TEMPLATE = "\n\n\n╔══════════════════════════════════════════════════════════════╗\n║  PROMPT: {key}\n║  NOMBRE: {label}\n╚══════════════════════════════════════════════════════════════╝\n\n"
_FULL_DELIMITER_PATTERN_START = "╔══════════════════════════════════════════════════════════════╗"


@api_router.get("/admin/prompts-full/{module_id}")
async def pm_get_full_module(module_id: str, current_user: User = Depends(get_current_user)):
    """
    Get all prompts for a module concatenated into one large text blob.
    Each prompt is separated by a clear delimiter showing the key and label.
    """
    if not is_prompt_admin(_get_user_email(current_user)):
        raise HTTPException(status_code=403, detail="Acceso denegado.")
    
    if module_id not in _PROMPT_MODULES:
        raise HTTPException(status_code=404, detail=f"Módulo '{module_id}' no encontrado.")
    
    prompt_defs = _registry_get_module_prompts(module_id) or {}
    
    # Load all overrides
    overrides_raw = {}
    cursor = db.prompt_overrides.find({"module_id": module_id}, {"_id": 0})
    async for doc in cursor:
        overrides_raw[doc["key"]] = doc["content"]
    
    parts = []
    for key, pdef in prompt_defs.items():
        content = overrides_raw.get(key, pdef.get("default", ""))
        label = pdef.get("label", key)
        delimiter = _FULL_DELIMITER_TEMPLATE.format(key=key, label=label)
        parts.append(f"{delimiter}{content}")
    
    full_content = "".join(parts)
    total_chars = sum(len(overrides_raw.get(k, pdef.get("default", ""))) for k, pdef in prompt_defs.items())
    modified_count = sum(1 for k in prompt_defs if k in overrides_raw)
    
    return {
        "content": full_content,
        "total_chars": total_chars,
        "prompt_count": len(prompt_defs),
        "modified_count": modified_count,
        "keys": list(prompt_defs.keys()),
    }


@api_router.post("/admin/prompts-full/{module_id}")
async def pm_save_full_module(
    module_id: str,
    body: FullModuleUpdateRequest,
    current_user: User = Depends(get_current_user)
):
    """
    Parse the combined content (from full-module editor) and save each section individually.
    Only sections whose content has changed will be saved (compared to current value).
    Returns a summary: how many sections were saved/unchanged.
    """
    if not is_prompt_admin(_get_user_email(current_user)):
        raise HTTPException(status_code=403, detail="Acceso denegado.")
    
    if module_id not in _PROMPT_MODULES:
        raise HTTPException(status_code=404, detail=f"Módulo '{module_id}' no encontrado.")
    
    prompt_defs = _registry_get_module_prompts(module_id) or {}
    user_email = _get_user_email(current_user)
    
    # Parse the full content by delimiter
    # Split on the box-drawing delimiter pattern
    raw = body.content
    import re
    
    # Pattern to find delimiter blocks: captures (key, label, content_until_next_delimiter)
    # Delimiter format: \n\n\n╔═══...═╗\n║  PROMPT: {key}\n║  NOMBRE: {label}\n╚═══...═╝\n\n
    delimiter_regex = re.compile(
        r'╔═+╗\s*\n║\s*PROMPT:\s*(\S+)\s*\n║\s*NOMBRE:\s*(.+?)\s*\n╚═+╝\s*\n\n?',
        re.MULTILINE
    )
    
    matches = list(delimiter_regex.finditer(raw))
    
    if not matches:
        raise HTTPException(status_code=400, detail="No se encontraron delimitadores en el contenido. Usa la vista completa original sin modificar los separadores.")
    
    # Extract sections
    parsed_sections = {}
    for i, match in enumerate(matches):
        key = match.group(1).strip()
        # Content is between this match's end and next match's start (or end of string)
        start = match.end()
        end = matches[i + 1].start() if i + 1 < len(matches) else len(raw)
        content = raw[start:end].strip()
        parsed_sections[key] = content
    
    # Compare with current values and save only changes
    overrides_raw = {}
    cursor = db.prompt_overrides.find({"module_id": module_id}, {"_id": 0})
    async for doc in cursor:
        overrides_raw[doc["key"]] = doc["content"]
    
    saved = []
    unchanged = []
    unknown = []
    
    for key, new_content in parsed_sections.items():
        if key not in prompt_defs:
            unknown.append(key)
            continue
        
        # Get current value
        current = overrides_raw.get(key, prompt_defs.get(key, {}).get("default", ""))
        
        if new_content == current.strip():
            unchanged.append(key)
            continue
        
        # Save the override
        await _pm_save_override(
            module_id=module_id,
            key=key,
            content=new_content,
            user_email=user_email,
            notes=body.notes or f"Guardado desde Vista Completa",
            db=db
        )
        saved.append(key)
    
    logging.info(f"💾 [PromptManager] Full save: {module_id} — {len(saved)} saved, {len(unchanged)} unchanged by {user_email}")
    
    return {
        "success": True,
        "saved_count": len(saved),
        "unchanged_count": len(unchanged),
        "unknown_keys": unknown,
        "saved_keys": saved,
        "message": f"{len(saved)} sección(es) guardadas, {len(unchanged)} sin cambios."
    }


@api_router.get("/admin/json-export/{module_id}")
async def pm_export_module_json(module_id: str, current_user: User = Depends(get_current_user)):
    """Export all active prompts for a module as a clean JSON dict (base + overrides merged).
    The output is ready to be pasted directly into the JSON Import editor."""
    if not is_prompt_admin(_get_user_email(current_user)):
        raise HTTPException(status_code=403, detail="Acceso denegado.")

    prompt_defs = _registry_get_module_prompts(module_id)
    if not prompt_defs:
        raise HTTPException(status_code=404, detail=f"Módulo '{module_id}' no encontrado.")

    # Load all per-key overrides from DB in one query
    overrides_map = {}
    async for doc in db.prompt_overrides.find({"module_id": module_id}, {"_id": 0}):
        overrides_map[doc["key"]] = doc["content"]

    # Build the export: for each key, use override if available, else default
    result = {}
    for key, prompt_def in prompt_defs.items():
        if key in overrides_map:
            result[key] = overrides_map[key]
        else:
            result[key] = prompt_def.get("default", "")

    return JSONResponse(content=result)


