class JsonOverrideRequest(BaseModel):
    json_content: str
    notes: Optional[str] = None


@api_router.get("/admin/json-override/{module_id}")
async def pm_get_json_override(module_id: str, current_user: User = Depends(get_current_user)):
    """Get the current JSON override for a module (if any)."""
