@api_router.get("/admin/json-override/{module_id}/history")
async def pm_get_json_override_history(module_id: str, current_user: User = Depends(get_current_user)):
    """Get all saved versions of JSON override for a module."""
    if not is_prompt_admin(_get_user_email(current_user)):
        raise HTTPException(status_code=403, detail="Acceso denegado.")

    active = await db.json_overrides.find_one({"module_id": module_id}, {"_id": 0, "current_version": 1})
    active_version = active.get("current_version") if active else None

    versions = []
    async for doc in db.json_override_history.find(
        {"module_id": module_id}, {"_id": 0}
    ).sort("version", -1):
        versions.append({
            "version": doc["version"],
            "notes": doc.get("notes", ""),
            "result_notes": doc.get("result_notes", ""),
            "saved_at": doc.get("saved_at"),
            "saved_by": doc.get("saved_by"),
            "key_count": doc.get("key_count", 0),
            "documents_generated": doc.get("documents_generated", []),
            "doc_count": len(doc.get("documents_generated", [])),
            "is_active": doc["version"] == active_version,
            "restored_from": doc.get("restored_from"),
        })
    return versions


