# ============================================================
# SSO ENDPOINT - Single Sign-On via external token (iframe del panel)
# Validación 100% LOCAL — sin llamadas HTTP al panel
# ============================================================

class SSOLoginRequest(BaseModel):
    external_token: str

def _map_external_role_sso(external_role: str) -> str:
    role_map = {"super_admin": "ADMIN", "admin": "ADMIN"}
    return role_map.get(external_role, "USER")

def _decode_token_payload(token: str) -> dict:
    """Decode JWT payload without signature verification."""
    try:
        import base64 as _b64, json as _json
        parts = token.split(".")
        if len(parts) != 3:
            return {}
        padded = parts[1] + "=" * (4 - len(parts[1]) % 4)
        return _json.loads(_b64.urlsafe_b64decode(padded).decode("utf-8"))
    except Exception:
        return {}

@api_router.post("/auth/sso", response_model=dict)
async def sso_login(request: SSOLoginRequest):
    """
    SSO Login — 100% LOCAL, sin llamadas HTTP al panel.
    Decodifica el JWT del panel, verifica estructura y expiración,
    encuentra/crea usuario en Monica, retorna token propio de Monica.
    """
    external_token = request.external_token
    if not external_token or len(external_token) < 10:
        raise HTTPException(status_code=401, detail="Token externo inválido o vacío")

    # 1. Decodificar JWT (sin verificar firma — confiamos en el iframe del panel)
    payload = _decode_token_payload(external_token)
    if not payload:
        raise HTTPException(status_code=401, detail="No se pudo decodificar el token. Formato inválido.")

    logging.info(f"🔐 SSO: JWT payload keys: {list(payload.keys())}")

    # 2. Extraer email
    email = None
    for field in ["email", "sub", "userEmail", "emailAddress", "user_email", "mail"]:
        val = payload.get(field)
        if val and isinstance(val, str) and "@" in val:
            email = val
            break

    if not email:
        raise HTTPException(status_code=401, detail="Token no contiene email válido.")

    # 3. Verificar expiración
    token_exp = payload.get("exp")
    if token_exp:
        import time
        if token_exp < time.time():
            raise HTTPException(
                status_code=401,
                detail="Token expirado. Solicita un nuevo enlace desde el panel."
            )

    # 4. Extraer campos adicionales
    full_name = payload.get("name") or payload.get("full_name") or payload.get("fullName") or ""
    external_role = payload.get("role") or payload.get("type") or ""
    email = email.lower().strip()
    monica_role = _map_external_role_sso(external_role)

    # 5. Buscar o crear usuario en Monica
    existing_user = await db.users.find_one(
        {"email": email, "status": {"$ne": "deleted"}}, {"_id": 0}
    )

    if existing_user:
        user_id = existing_user["id"]
        await db.users.update_one(
            {"id": user_id},
            {"$set": {
                "external_token": external_token,
                "last_sso_login": datetime.now(timezone.utc).isoformat(),
                "role": monica_role if monica_role == "ADMIN" else existing_user.get("role", "USER")
            }}
        )
        user_data = {
            "id": user_id,
            "email": existing_user["email"],
            "full_name": existing_user.get("full_name") or full_name,
            "role": monica_role if monica_role == "ADMIN" else existing_user.get("role", "USER"),
            "language_preference": existing_user.get("language_preference", "es")
        }
    else:
        import uuid
        user_id = str(uuid.uuid4())
        new_user = {
            "id": user_id,
            "email": email,
            "full_name": full_name or email.split("@")[0],
            "role": monica_role,
            "language_preference": "es",
            "password": None,
            "status": "active",
            "external_token": external_token,
            "created_at": datetime.now(timezone.utc).isoformat(),
            "last_sso_login": datetime.now(timezone.utc).isoformat()
        }
        await db.users.insert_one(new_user)
        user_data = {
            "id": user_id,
            "email": email,
            "full_name": new_user["full_name"],
            "role": monica_role,
            "language_preference": "es"
        }
        logging.info(f"🔐 SSO: Nuevo usuario creado: {email} ({monica_role})")

    # 6. Crear token propio de Monica (30 días)
    access_token = create_access_token(
        data={"sub": email},
        expires_delta=timedelta(minutes=30 * 24 * 60)
    )

    logging.info(f"✅ SSO OK: {email} ({monica_role})")

    return {
        "access_token": access_token,
        "token_type": "bearer",
        "user": user_data
    }


PANEL_BASE_URL = os.environ.get("PANEL_BASE_URL", "https://panel.urpeintegralservices.co")
PANEL_ADMIN_EMAIL = os.environ.get("PANEL_ADMIN_EMAIL", "")
PANEL_ADMIN_PASSWORD = os.environ.get("PANEL_ADMIN_PASSWORD", "")

# Token cache: {"token": str, "expires_at": float}
_panel_admin_token_cache: dict = {}


async def _get_panel_admin_token() -> str:
    """Auto-login to the external panel and return a fresh admin token. Cached until expiry."""
    import time
    now = time.time()
    cached = _panel_admin_token_cache
    if cached.get("token") and cached.get("expires_at", 0) > now + 60:
        return cached["token"]

    if not PANEL_ADMIN_EMAIL or not PANEL_ADMIN_PASSWORD:
        raise HTTPException(status_code=503, detail="Credenciales del panel externo no configuradas en el servidor.")

    try:
        async with httpx.AsyncClient(timeout=15.0) as client:
            r = await client.post(
                f"{PANEL_BASE_URL}/api/admin/auth/login",
                json={"email": PANEL_ADMIN_EMAIL, "password": PANEL_ADMIN_PASSWORD},
            )
        if r.status_code != 200:
            raise HTTPException(status_code=503, detail=f"No se pudo autenticar con el panel externo (HTTP {r.status_code}).")
        data = r.json()
        token = data.get("token")
        if not token:
            raise HTTPException(status_code=503, detail="El panel externo no devolvió un token de autenticación.")
        # Decode expiry from JWT payload (no signature check needed)
        import base64
        try:
            payload_b64 = token.split(".")[1]
            # Fix base64 padding
            payload_b64 += "=" * (4 - len(payload_b64) % 4)
            payload = json.loads(base64.b64decode(payload_b64).decode())
            expires_at = float(payload.get("exp", now + 3600))
        except Exception:
            expires_at = now + 3600
        _panel_admin_token_cache["token"] = token
        _panel_admin_token_cache["expires_at"] = expires_at
        logging.info("✅ Panel admin token refreshed, valid until %s", expires_at)
        return token
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error auto-login panel: {e}")
        raise HTTPException(status_code=503, detail="Error conectando con el panel externo.")


def _extract_client_fields(case: dict, source: str) -> dict:
    """Normalize a case record from the external panel into Monica's client fields."""
    def _first(*keys):
        for k in keys:
            v = case.get(k)
            if v:
                return str(v)
        return ""

    # visa-cases uses userName/userEmail/userPhone; classic-cases uses applicantName/applicantEmail
    name = _first("userName", "applicantName", "fullName", "full_name", "name", "nombre", "client_name", "candidateName")
    email = _first("userEmail", "applicantEmail", "email", "correo", "emailAddress")
    phone = _first("userPhone", "phone", "phoneNumber", "telefono", "mobile", "cel")
    country = _first("country", "pais", "nationality", "applicantCountry")
    city = _first("city", "ciudad")
    state = _first("state", "estado", "province")
    company = _first("company", "employer", "organization", "empresa", "workPlace")
    industry = _first("industry", "field", "sector", "industria")
    notes_parts = []
    for k in ("visaType", "caseType", "petitionType", "status", "notes"):
        if case.get(k):
            notes_parts.append(f"{k}: {case[k]}")
    notes = " | ".join(notes_parts) if notes_parts else ""
    external_id = str(case.get("_id") or case.get("id") or "")
    return {
        "name": name,
        "email": email,
        "phone": phone,
        "country": country,
        "city": city,
        "state": state,
        "company": company,
        "industry": industry,
        "notes": notes,
        "external_id": external_id,
        "external_source": source,
    }


@api_router.get("/external/search-clients")
async def search_external_clients(
    q: str = Query("", description="Search query — filters by name/email"),
    panel_token: str = Query("", description="(Deprecated, ignored) — kept for backwards compatibility with old frontend builds"),
    include_imported: bool = Query(False, description="If true, include cases already imported into Redactora"),
    current_user: User = Depends(get_current_user),
):
    """Search Portal cases (visa_cases + classic_cases) directly from the shared
    Supabase database. Replaces the previous HTTP proxy that depended on a
    panel JWT (which had token-expiration and role-rejection issues).

    Only cases with `is_redactora = false` are returned by default — once a
    case has been imported into Redactora via POST /clients (with
    external_id/external_source), the source row is flagged and excluded
    from subsequent searches.
    """
    import re as _re

    if not supabase:
        return {"clients": [], "total": 0, "errors": ["Supabase no inicializado en el backend."]}

    # Sanitize the search term for PostgREST `or` filters — these reserve
    # commas, parentheses, and a few other chars. Strip them; keep alphanumerics
    # and common name/email characters.
    q_raw = (q or "").strip()
    q_safe = _re.sub(r'[,()\\%*]', '', q_raw)

    results = []
    errors = []

    # Frontend gates with min 2 chars — if no query, return empty fast.
    if not q_safe:
        return {"clients": [], "total": 0, "errors": []}

    # ── classic_cases: only `name`, `email`, `status` exist as top-level cols
    # on this schema. Everything else (phone, country, city, state, etc.)
    # lives inside the `data` JSONB.
    try:
        cq = (
            supabase.table("classic_cases")
            .select("id, name, email, status, data, is_redactora")
            .limit(100)
        )
        if not include_imported:
            cq = cq.eq("is_redactora", False)
        cq = cq.or_(f"name.ilike.%{q_safe}%,email.ilike.%{q_safe}%")
        cres = cq.execute()
        for c in (cres.data or [])[:100]:
            d = c.get("data") or {}
            merged = {
                **d,
                "id": c.get("id"),
                "status": c.get("status"),
                "applicantName": c.get("name"),
                "applicantEmail": c.get("email"),
            }
            results.append(_extract_client_fields(merged, "classic"))
    except Exception as e:
        logging.warning(f"search-clients classic_cases query failed: {type(e).__name__}: {e}")
        errors.append(f"classic_cases: {type(e).__name__}")

    # ── visa_cases: name lives on the case row as `client_name`; full user
    # info (email, phone, profession) lives in the `users` view via
    # `client_id`. Two-step query because postgrest in this supabase-py
    # version doesn't support filtering on embedded resources cleanly.
    try:
        # 1) Find users whose name/email match the query.
        users_res = (
            supabase.table("users")
            .select("id, name, email, phone, profession, user_state")
            .or_(f"name.ilike.%{q_safe}%,email.ilike.%{q_safe}%")
            .limit(200)
            .execute()
        )
        users_by_id = {u["id"]: u for u in (users_res.data or [])}

        # 2) Get visa_cases for those users (if any), plus visa_cases
        #    whose client_name matches directly (in case the case row
        #    has a name that diverges from the user record).
        case_rows = []

        if users_by_id:
            vq = (
                supabase.table("visa_cases")
                .select("id, status, visa_type, client_id, client_name, metadata, is_redactora")
                .in_("client_id", list(users_by_id.keys()))
                .limit(100)
            )
            if not include_imported:
                vq = vq.eq("is_redactora", False)
            case_rows.extend((vq.execute()).data or [])

        # Also catch cases where client_name on the case matches even
        # though the linked user record doesn't.
        vq_name = (
            supabase.table("visa_cases")
            .select("id, status, visa_type, client_id, client_name, metadata, is_redactora")
            .ilike("client_name", f"%{q_safe}%")
            .limit(100)
        )
        if not include_imported:
            vq_name = vq_name.eq("is_redactora", False)
        case_rows.extend((vq_name.execute()).data or [])

        # Backfill user info for any case whose user wasn't fetched above.
        missing_user_ids = [
            c.get("client_id") for c in case_rows
            if c.get("client_id") and c["client_id"] not in users_by_id
        ]
        if missing_user_ids:
            extra_users = (
                supabase.table("users")
                .select("id, name, email, phone, profession, user_state")
                .in_("id", list(set(missing_user_ids)))
                .execute()
            )
            for u in (extra_users.data or []):
                users_by_id[u["id"]] = u

        # Dedupe case_rows by id (the two queries can overlap)
        seen_case_ids = set()
        unique_cases = []
        for c in case_rows:
            if c.get("id") in seen_case_ids:
                continue
            seen_case_ids.add(c.get("id"))
            unique_cases.append(c)

        for c in unique_cases[:100]:
            u = users_by_id.get(c.get("client_id"), {}) or {}
            metadata = c.get("metadata") or {}
            merged = {
                **(metadata if isinstance(metadata, dict) else {}),
                "id": c.get("id"),
                "status": c.get("status"),
                "visaType": c.get("visa_type"),
                "userName": u.get("name") or c.get("client_name") or "",
                "userEmail": u.get("email") or "",
                "userPhone": u.get("phone") or "",
                "industry": u.get("profession") or "",
            }
            results.append(_extract_client_fields(merged, "visa"))
    except Exception as e:
        logging.warning(f"search-clients visa_cases query failed: {type(e).__name__}: {e}")
        errors.append(f"visa_cases: {type(e).__name__}")

    # Drop entries without a name (defensive)
    results = [r for r in results if r.get("name")]

    # Deduplicate by email, falling back to external_id
    seen = set()
    deduped = []
    for r in results:
        key = (r.get("email") or "").lower() or r.get("external_id") or r.get("name", "")
        if key and key not in seen:
            seen.add(key)
            deduped.append(r)

    return {"clients": deduped, "total": len(deduped), "errors": errors}

