# ════════════════════════════════════════════════════════════════════════════
# 📄 WORD (.docx) DOWNLOAD ENDPOINTS — Universal across all document modules
# ════════════════════════════════════════════════════════════════════════════
# Native Word format imports cleanly into Google Docs preserving headings,
# tables, lists, bold/italic — so users can edit their generated documents
# without losing formatting (which they would lose if they tried to convert
# the PDF to Google Docs).  Each endpoint mirrors its PDF sibling but emits
# .docx via `docx_utils.build_docx_response`.

from docx_utils import build_docx_response as _docx_response  # noqa: E402


def _looks_like_html(text: str) -> bool:
    """Heuristic: does the content blob already contain block-level HTML?"""
    return bool(re.search(r'<(p|h[1-6]|div|table|ul|ol)\b', text or '', re.IGNORECASE))


def _compile_sectioned_content(sections: list, language: str) -> str:
    """Concatenate a list of `{number, title, content_en, content_es}` sections
    into one big markdown blob suitable for `_docx_response`."""
    out_parts = []
    for s in sorted(sections, key=lambda x: x.get('number', 0)):
        num = s.get('number', '')
        title = s.get('title', '')
        content = (
            s.get(f'content_{language}')
            or s.get('content_en')
            or s.get('content', '')
            or ''
        )
        if title:
            out_parts.append(f"# {num}. {title}" if num else f"# {title}")
        if content:
            out_parts.append(content)
    return "\n\n".join(out_parts)


@api_router.get("/business-plans/{plan_id}/download-docx")
async def download_business_plan_docx(plan_id: str, language: str = "en"):
    """Download business plan as Microsoft Word (.docx)."""
    plan = (await db.business_plans.find_one({"id": plan_id}, {"_id": 0})
            or await db.niw_in_progress.find_one({"id": plan_id}, {"_id": 0})
            or await db.business_plans_in_progress.find_one({"id": plan_id}, {"_id": 0}))
    if not plan:
        raise HTTPException(status_code=404, detail="Business plan not found")

    title = plan.get('project_title') or plan.get('business_name', 'Business Plan')
    applicant = plan.get('applicant_name', '') or ''
    if not applicant and plan.get('client_id'):
        c = await db.clients.find_one({"id": plan['client_id']}, {"_id": 0, "name": 1})
        if c:
            applicant = c.get('name', '')
    content = plan.get(f'content_{language}') or plan.get('content_en') or ''
    if not content:
        raise HTTPException(status_code=404, detail=f"Content in {language} not available")
    is_niw = bool(plan.get('project_title'))
    return _docx_response(
        content=content,
        title=title,
        filename_stem=f"BusinessPlan_{(applicant or 'Applicant').replace(' ', '_')}",
        doc_type="EB-2 NIW Project Proposal" if is_niw else ("Business Plan" if language == 'en' else "Plan de Negocio"),
        author=applicant or None,
        language=language,
        is_html=_looks_like_html(content),
    )


@api_router.get("/books/{book_id}/download-docx")
async def download_book_docx(book_id: str, language: str = "en"):
    """Download book as Microsoft Word (.docx).

    Uses the shared `book_utils` helpers so the `.docx` output stays in
    lockstep with the PDF cover/title/heading cleanup:
      * English downloads always prefer `title_en` / `synopsis_en` and
        never leak Spanish metadata into the cover.
      * Chapter headings are emitted exactly once — the LLM's own
        `<h2>Chapter N …` at the top of each chapter body is stripped.
      * The synopsis is rendered as the cover subtitle (cleaned), not
        dumped into the body as raw LLM scaffolding.
    """
    from book_utils import (
        clean_book_synopsis,
        clean_book_chapter_title,
        strip_leading_chapter_heading,
        extract_leading_chapter_title,
    )

    book = (await db.books.find_one({"id": book_id}, {"_id": 0})
            or await db.books_in_progress.find_one({"id": book_id}, {"_id": 0}))
    if not book:
        raise HTTPException(status_code=404, detail="Book not found")

    chapters = book.get('chapters', [])
    if not chapters:
        raise HTTPException(status_code=404, detail="Book has no chapters")

    # ── Pick title/synopsis for the requested language ──────────────────
    if language == 'en':
        title = (book.get('title_en') or book.get('title') or 'Book').strip()
        synopsis_raw = book.get('synopsis_en') or ''
        # If the English synopsis is missing but a Spanish one exists,
        # fall back to a CLEANED version of the Spanish synopsis.
        # (A synchronous GPT call here would slow the download and risk
        # timing out — better a clean Spanish subtitle than nothing.)
        if not synopsis_raw:
            synopsis_raw = book.get('synopsis') or ''
    else:
        title = (book.get('title') or 'Libro').strip()
        synopsis_raw = book.get('synopsis') or ''

    synopsis_clean = clean_book_synopsis(synopsis_raw)

    # ── Author / project proponent ──────────────────────────────────────
    author = (book.get('author_name') or '').strip()
    if not author and book.get('client_id'):
        c = await db.clients.find_one(
            {"id": book['client_id']}, {"_id": 0, "name": 1, "full_name": 1}
        )
        if c:
            author = (c.get('name') or c.get('full_name') or '').strip()

    chapter_label = "Capítulo" if language == 'es' else "Chapter"

    # ── Build the HTML body (not markdown) so we control the headings.
    #    We also strip the LLM-prepended chapter title from each content
    #    block to avoid the famous "double subtitle" bug.
    body_parts: list[str] = []
    for i, ch in enumerate(chapters, 1):
        raw_content = (
            ch.get(f'content_{language}')
            or ch.get('content_en')
            or ch.get('content', '')
            or ''
        )

        # Prefer the in-content heading (which is written in the
        # requested language) over the stored `title` field (which is
        # often only populated in one language).  Fall back to the
        # stored title only when the content had no leading heading.
        in_content_title = extract_leading_chapter_title(raw_content)
        raw_title = in_content_title or ch.get('title') or f"{chapter_label} {i}"
        clean_title = clean_book_chapter_title(raw_title, i, language=language)
        heading = f"{chapter_label} {i}: {clean_title}"

        stripped = strip_leading_chapter_heading(raw_content)

        body_parts.append(f"<h1>{heading}</h1>")
        body_parts.append(stripped)

    body_html = "\n".join(body_parts)

    return _docx_response(
        content=body_html,
        title=title,
        filename_stem=f"Book_{title.replace(' ', '_')[:60]}",
        doc_type="Book" if language == 'en' else "Libro",
        author=author or None,
        language=language,
        cover_subtitle=synopsis_clean[:300] if synopsis_clean else None,
        is_html=True,
    )


