# SPA catch-all: serve the React app for any non-API route.
# MUST be the last route registered.
from fastapi.responses import FileResponse as _FR
@app.get("/{full_path:path}")
async def spa_fallback(full_path: str):
    if full_path.startswith(("api/", "health", "static/", "static-backend/")):
        from fastapi import HTTPException
        raise HTTPException(status_code=404)
    index = _FRONTEND_BUILD / "index.html"
    if not index.exists():
        from fastapi import HTTPException
        raise HTTPException(status_code=404, detail="Frontend not built")
    # If a real file in the build folder is requested (e.g. favicon.ico), serve it
    candidate = _FRONTEND_BUILD / full_path if full_path else None
    if candidate and candidate.is_file():
        return _FR(str(candidate))
    return _FR(str(index))